        public LegacyNotesViewModel LoadLegacyNoteAndRenderTemplate(List<NotesComponents> objListNotesComponents)
        {
            LegacyNotesViewModel model = new LegacyNotesViewModel();
            SmartThreadPool threadPool = new SmartThreadPool();
            try
            {
                Dictionary<String, IWorkItemResult> threadList = new Dictionary<string, IWorkItemResult>();

                ThreadParams threadParams = new ThreadParams();

                CommonSearch objCommonSearch = new CommonSearch();
                objCommonSearch.NotesId = objListNotesComponents.FirstOrDefault().NotesId;
                objCommonSearch.PatientId = objListNotesComponents.FirstOrDefault().PatientId;
                objCommonSearch.ProviderId = objListNotesComponents.FirstOrDefault().ProviderId;

                threadParams.NoteId = objListNotesComponents.FirstOrDefault().NotesId;
                threadParams.PatientId = objListNotesComponents.FirstOrDefault().PatientId;

                threadParams.UserId = MDVUtility.ToInt64(MDVSession.Current.AppUserId);
                threadParams.EntityId = MDVUtility.ToInt64(MDVSession.Current.EntityId);
                threadParams.Sharedobj = SharedVariable.GetSharedVariable();
                threadParams.objCommonSearch = objCommonSearch;

                //var task = threadPool.QueueWorkItem(new WorkItemCallback(NotesNoteHeaderDataSelect), threadParams);
                threadList.Add("NoteHeaderData", threadPool.QueueWorkItem(new WorkItemCallback(NotesNoteHeaderDataSelect), threadParams));

                if (objListNotesComponents.FirstOrDefault(m => m.Component == "NotesComponent") != null)
                {
                    var task = threadPool.QueueWorkItem(new WorkItemCallback(NotesComponentSelect), threadParams);
                    threadList.Add("NotesComponent", task);
                }
                //string NoteText = model.NoteText;
                // Temporary Remove Check until Note Component Popup is fixed
                if (objListNotesComponents.FirstOrDefault(m => m.Component == "Complaints") != null)
                {
                    var task = threadPool.QueueWorkItem(new WorkItemCallback(NotesComplaintsSelect), threadParams);
                    threadList.Add("Complaints", task);
                }

                if (objListNotesComponents.FirstOrDefault(m => m.Component == "SocialHx") != null)
                {
                    var task = threadPool.QueueWorkItem(new WorkItemCallback(NotesSocialHxSelect), threadParams);
                    threadList.Add("SocialHx", task);
                }
                if (objListNotesComponents.FirstOrDefault(m => m.Component == "MedicalHx") != null)
                {
                    var task = threadPool.QueueWorkItem(new WorkItemCallback(NotesMedicalHxSelect), threadParams);
                    threadList.Add("MedicalHx", task);
                }
                if (objListNotesComponents.FirstOrDefault(m => m.Component == "BirthHx") != null)
                {
                    var task = threadPool.QueueWorkItem(new WorkItemCallback(NotesBirthHxSelect), threadParams);
                    threadList.Add("BirthHx", task);
                }
                if (objListNotesComponents.FirstOrDefault(m => m.Component == "Allergies") != null)
                {
                    var task = threadPool.QueueWorkItem(new WorkItemCallback(NotesAllergyHxSelect), threadParams);
                    threadList.Add("AllergyHx", task);
                }
                if (objListNotesComponents.FirstOrDefault(m => m.Component == "Immunization") != null)
                {
                    var task = threadPool.QueueWorkItem(new WorkItemCallback(NotesImmunizationHxSelect), threadParams);
                    threadList.Add("ImmunizationHx", task);
                }
                if (objListNotesComponents.FirstOrDefault(m => m.Component == "Medications") != null)
                {
                    var task = threadPool.QueueWorkItem(new WorkItemCallback(NotesMedicationsSelect), threadParams);
                    threadList.Add("MedicationHx", task);
                }
                if (objListNotesComponents.FirstOrDefault(m => m.Component == "Problems") != null)
                {
                    var task = threadPool.QueueWorkItem(new WorkItemCallback(NotesProblemHxSelect), threadParams);
                    threadList.Add("ProblemHx", task);
                }
                if (objListNotesComponents.FirstOrDefault(m => m.Component == "FamilyHx") != null)
                {
                    var task = threadPool.QueueWorkItem(new WorkItemCallback(NotesFamilyHxSelect), threadParams);
                    threadList.Add("FamilyHx", task);
                }
                if (objListNotesComponents.FirstOrDefault(m => m.Component == "SurgicalHx") != null)
                {
                    var task = threadPool.QueueWorkItem(new WorkItemCallback(NotesSurgicalHxSelect), threadParams);
                    threadList.Add("SurgicalHx", task);
                }
                if (objListNotesComponents.FirstOrDefault(m => m.Component == "HospitalizationHx") != null)
                {
                    var task = threadPool.QueueWorkItem(new WorkItemCallback(NotesHospitalizationHxSelect), threadParams);
                    threadList.Add("HospitalizationHx", task);
                }
                if (objListNotesComponents.FirstOrDefault(m => m.Component == "Vitals") != null)
                {
                    var task = threadPool.QueueWorkItem(new WorkItemCallback(NotesVitalSignsSelect), threadParams);
                    threadList.Add("VitalSigns", task);
                }
                if (objListNotesComponents.FirstOrDefault(m => m.Component == "LabOrder") != null || objListNotesComponents.FirstOrDefault(m => m.Component == "LabOrders") != null)
                {
                    var task = threadPool.QueueWorkItem(new WorkItemCallback(NotesLabOrderSelect), threadParams);
                    threadList.Add("LabOrder", task);
                }
                if (objListNotesComponents.FirstOrDefault(m => m.Component == "Letter") != null)
                {
                    var task = threadPool.QueueWorkItem(new WorkItemCallback(NotesLetterSelect), threadParams);
                    threadList.Add("PatientLetter", task);
                }
                if (objListNotesComponents.FirstOrDefault(m => m.Component == "LabResults") != null)
                {
                    var task = threadPool.QueueWorkItem(new WorkItemCallback(NotesLabOrderResultSelect), threadParams);
                    threadList.Add("LabOrderResult", task);
                }
                if (objListNotesComponents.FirstOrDefault(m => m.Component == "DiagnosticImagingOrder") != null)
                {
                    var task = threadPool.QueueWorkItem(new WorkItemCallback(NotesRadOrderSelect), threadParams);
                    threadList.Add("RadOrder", task);
                }
                if (objListNotesComponents.FirstOrDefault(m => m.Component == "DiagnosticImagingResults") != null)
                {
                    var task = threadPool.QueueWorkItem(new WorkItemCallback(NotesRadOrderResultSelect), threadParams);
                    threadList.Add("RadOrderResult", task);
                }
                if (objListNotesComponents.FirstOrDefault(m => m.Component == "Procedures") != null)
                {
                    var task = threadPool.QueueWorkItem(new WorkItemCallback(NotesProcedureSelect), threadParams);
                    threadList.Add("Procedure", task);
                }
                if (objListNotesComponents.FirstOrDefault(m => m.Component == "Referrals") != null)
                {
                    var task = threadPool.QueueWorkItem(new WorkItemCallback(NotesReferralsSelect), threadParams);
                    threadList.Add("Referrals", task);
                }
                if (objListNotesComponents.FirstOrDefault(m => m.Component == "ProcedureOrder") != null)
                {
                    var task = threadPool.QueueWorkItem(new WorkItemCallback(NotesProcedureOrderSelect), threadParams);
                    threadList.Add("ProcedureOrder", task);
                }
                if (objListNotesComponents.FirstOrDefault(m => m.Component == "ConsultationOrder") != null)
                {
                    var task = threadPool.QueueWorkItem(new WorkItemCallback(NotesConsultationOrderSelect), threadParams);
                    threadList.Add("ConsultationOrder", task);
                }
                //if (objListNotesComponents.FirstOrDefault(m => m.Component == "FollowUp") != null)
                //{
                //    var task = threadPool.QueueWorkItem(new WorkItemCallback(NotesFollowUpSelect), threadParams);
                //    threadList.Add("FollowUp", task);
                //}
                if (objListNotesComponents.FirstOrDefault(m => m.Component == "FunctionalAndCognitive") != null)
                {
                    var task = threadPool.QueueWorkItem(new WorkItemCallback(NotesFunctionalCognitiveSelect), threadParams);
                    threadList.Add("FunctionalCognitive", task);
                }
                if (objListNotesComponents.FirstOrDefault(m => m.Component == "PatientEducation") != null)
                {
                    var task = threadPool.QueueWorkItem(new WorkItemCallback(NotesPatientEducationSelect), threadParams);
                    threadList.Add("PatientEducation", task);
                }
                if (objListNotesComponents.FirstOrDefault(m => m.Component.Contains("PhysicalExam")) != null)
                {
                    var task = threadPool.QueueWorkItem(new WorkItemCallback(NotesPhysicalExamSelect), threadParams);
                    threadList.Add("PhysicalExam", task);
                }
                if (objListNotesComponents.FirstOrDefault(m => m.Component == "eSuperbill") != null)
                {
                    var task = threadPool.QueueWorkItem(new WorkItemCallback(NoteseSuperbillSelect), threadParams);
                    threadList.Add("eSuperbill", task);
                }
                if (objListNotesComponents.FirstOrDefault(m => m.Component == "Prescription") != null)
                {
                    var task = threadPool.QueueWorkItem(new WorkItemCallback(NotesPrescriptionSelect), threadParams);
                    threadList.Add("Prescription", task);
                }



                bool success = SmartThreadPool.WaitAll(threadList.Values.ToArray());
                if (success)
                {
                    foreach (var key in threadList.Keys)
                    {
                        try
                        {
                            PropertyInfo propertyInfo = model.GetType().GetProperty(key);
                            propertyInfo.SetValue(model, Convert.ChangeType(threadList[key].Result, propertyInfo.PropertyType), null);
                        }
                        catch (Exception ex)
                        {
                            continue;
                        }
                    }
                    threadPool.Shutdown();
                    return model;
                }


            }
            catch (Exception ex)
            {
                MDVLogger.BLLErrorLog("BLLClinical::LoadLegacyNoteAndRenderTemplate", ex);
            }
            finally
            {
                threadPool.Shutdown();
            }
            return null;
        }

