        /// <summary>
        /// Loads Questions.
        /// </summary>
        public BLObject<DSTemplateBuilder> LoadClinicalQuestion(long QuestionID, string ShortName, string Description, string IsActive, string questionTypeID, Int64 rpp, Int64 pageNo)
        {
            try
            {
                DSTemplateBuilder ds = new DSTemplateBuilder();
                ds = new DALQuestions().LoadClinicalQuestion(QuestionID, ShortName, Description, IsActive, questionTypeID, rpp, pageNo);

                return new BLObject<DSTemplateBuilder>(ds);
            }
            catch (Exception ex)
            {
                MDVLogger.BLLErrorLog("BLLQuestions::LoadQuestions", ex);
                return new BLObject<DSTemplateBuilder>(null, ex.Message);
            }
        }

        /// <summary>
        /// Inserts the Clinical Question.
        /// </summary>
        /// <param name="ds">The ds.</param>
        ///
        public BLObject<DSTemplateBuilder> InsertQuestions(DSTemplateBuilder ds)
        {
            try
            {
                ds = new DALQuestions().InsertQuestions(ds);
                return new BLObject<DSTemplateBuilder>(ds);
            }
            catch (Exception ex)
            {
                MDVLogger.BLLErrorLog("BLLQuestions::InsertQuestion", ex);
                return new BLObject<DSTemplateBuilder>(null, ex.Message);
            }
        }

        /// <summary>
        /// Updates the Clinical Question.
        /// </summary>
        /// <param name="ds">The ds.</param>
        ///
        public BLObject<DSTemplateBuilder> UpdateQuestions(DSTemplateBuilder ds)
        {
            try
            {
