            VitalsModelWaper model = new VitalsModelWaper();
            model.VitalsModel = dalVitals.getNoteVitalByPatientId(Parameters.PatientId, Parameters.UserId, Parameters.EntityId);
            if (model.VitalsModel.VitalSignId > 0)
            {
                DSVitals ds = dalVitals.attachVitalSignFromNotes(model.VitalsModel.VitalSignId.ToString(), Parameters.PatientId, Parameters.VisitId, Parameters.NoteId, MDVUtility.DecryptFrom64(Parameters.Sharedobj.UserName));
