        private Object GetImmunizationByPatient(Object p)
        {
            var Parameters = p as ThreadParams;
            var dalVaccineHx = new DALImmunization(Parameters.Sharedobj);

            List<VaccineSoapModel> Vaccines_List = dalVaccineHx.LoadVaccine("", Parameters.PatientId, Parameters.UserId, Parameters.EntityId, Parameters.OrderSetId);
            List<TherapeuticInjectionSoapModel> Therapeutic_List = dalVaccineHx.LoadImmTherapeuticInjectionForSoapText("", Parameters.PatientId, Parameters.UserId, Parameters.EntityId, Parameters.OrderSetId);

            string VaccineHxIds = string.Join(",", Vaccines_List.Select(n => n.VaccineHxId.ToString()).ToArray());
            string ImmTherInjectionIds = string.Join(",", Therapeutic_List.Select(n => n.ImmTherInjectionId.ToString()).ToArray());

            DSImmunization dsVaccine = new DSImmunization();
            DSImmunization dsTherInjection = new DSImmunization();
            if (!string.IsNullOrEmpty(VaccineHxIds))
                dsVaccine = dalVaccineHx.attachVaccineWithNotes(VaccineHxIds, Parameters.NoteId);

            if (!string.IsNullOrEmpty(ImmTherInjectionIds))
                dsTherInjection = dalVaccineHx.attachTheraInjectionwithnotes(ImmTherInjectionIds, Parameters.NoteId);

            string Vaccine_json = MDVUtility.JSON_DataTable(dsVaccine.Tables[dsVaccine.VaccineHx.TableName]);
            string TherInjection_json = MDVUtility.JSON_DataTable(dsTherInjection.Tables[dsTherInjection.VaccineHx.TableName]);

            Immunization wrapper = new Immunization(Vaccines_List, Therapeutic_List, TherInjection_json, Vaccine_json);

            return wrapper;
        }


