        private Object GetComplaintsByPatient(Object p)
        {
            var Parameters = p as ThreadParams;
            string complaintExists = string.Empty;
            var dalComplaint = new DALComplaint(Parameters.Sharedobj);
            ComplaintsModelWaper waper = new ComplaintsModelWaper();
            if (Parameters.IsPrevNoteComplaints)
            {
                complaintExists = dalComplaint.isPatientComplaintExists(Parameters.PatientId, Parameters.UserId, Parameters.EntityId);
            }

            if (complaintExists == "1")
            {
                waper = dalComplaint.GetLatestComplaintsByPatientId(Parameters.PatientId, Parameters.NoteId);
                waper.isComplaintExists = true;
            }
            else if (Parameters.IsDefaultHPI == true && Parameters.HPITemplateId > 0)
            {
                List<HPITemplateModel> result = new DALHPI(Parameters.Sharedobj).fillHPITemplate(Parameters.HPITemplateId);

                if (result.Count > 0)
                {
                    List<HPINotesFindings> HPITemplateSymptoms = new List<HPINotesFindings>();
                    List<HPITemplateSymptomsModel> listHPISymModel = new List<HPITemplateSymptomsModel>(result[0].SymptomData);
                    List<HPITemplateSymptomsModel> HPISym = listHPISymModel.GroupBy(s => s.HPISymptomId).Select(x => x.First()).ToList();

                    foreach (HPITemplateModel Temp_item in result)
                    {
                        foreach (var Symp_item in HPISym)
                        {
                            if (Symp_item.IsSelectedSymptom == "True" && Temp_item.HPITemplateId == Symp_item.HPITemplateId)
                            {
                                var doc = new HtmlDocument();
                                doc.LoadHtml(Temp_item.TemplatePreview);

                                HtmlNode node = doc.DocumentNode.Elements("div").Where(q => q.Attributes["id"] != null)
                                               .FirstOrDefault(n => n.Attributes["id"].Value == "divSymptom" + Symp_item.HPISymptomId);
                                string nodehtml = "";
                                if (node != null)
                                    nodehtml = node.OuterHtml;

                                HPINotesFindings obj_ = new HPINotesFindings();
                                obj_.HPINotesFindingsId = "-1";
                                obj_.HPITemplateSymptomId = Symp_item.HPITemplateSymptomId;
                                obj_.NotesId = Parameters.NoteId.ToString();
                                obj_.Desc = nodehtml;
                                obj_.Action = "-1";
                                obj_.HPISymptomsAnswersId = Symp_item.HPISymptomsAnswersId;
                                HPITemplateSymptoms.Add(obj_);
                            }
                        }
                    }

                    XmlSerializer xmlSerializer = new XmlSerializer(typeof(List<HPINotesFindings>));
                    StringWriter textWriter = new StringWriter();
                    xmlSerializer.Serialize(textWriter, HPITemplateSymptoms);
                    string xmlNotesFindings = textWriter.ToString();

                    waper.HPINotesFindings = new DALHPI(Parameters.Sharedobj).saveHPIComplaintNotesFinding(xmlNotesFindings, MDVUtility.DecryptFrom64(Parameters.Sharedobj.UserName));
                    waper.HPINotesFindings = waper.HPINotesFindings.Where(a => a.NotesId == Parameters.NoteId.ToString()).ToList();
                }
                else
                {
                    throw new Exception("HPI Template not loaded.");
                }
            }
            else
            {
                // waper.Complaints = dalComplaint.GetNoteSoapComplaintsWithDetails(Parameters.NoteId);
                // waper = dalComplaint.GetLatestComplaintsByPatientId(Parameters.PatientId, Parameters.NoteId);

            }

            return waper;
        }

