        {
            var Parameters = p as ThreadParams;
            DataSet result = null;
            var dalReviewOfSystem = new DALReviewofSystems(Parameters.Sharedobj);
            if (Parameters.IsPrevNotesROS)
                result = dalReviewOfSystem.GetROSSystemPatientInfoFromNotes(Parameters.UserId, Parameters.PatientId, Parameters.NoteId, Parameters.ROSDataTemptId, Parameters.PrevNotesIdROS);
            else
                result = dalReviewOfSystem.GetROSSystemPatientInfoFromNotes(Parameters.UserId, Parameters.PatientId, Parameters.NoteId, Parameters.ROSDataTemptId);
            ROSSoapNote returnObj = new ROSSoapNote();

            if (result != null && result.Tables.Count > 0)
            {
                returnObj.SoapText = createROSsoapText(result, Parameters.NoteId, Parameters.ROSDataTemptId);
                returnObj.ROSSystemInfoID = Parameters.ROSDataTemptId;
            }

            return returnObj;
        }
        private Object GetPhysicalExamFromNotes(Object p)
        {
            var Parameters = p as ThreadParams;

            Model.Clinical.Notes.PhysicalExam model = new Model.Clinical.Notes.PhysicalExam();
            var dalPhySicalExam = new DALPhysicalExamECW(Parameters.Sharedobj);

            DSPhysicalExamECW ds = new DSPhysicalExamECW();
            ds = dalPhySicalExam.LoadPhyscialExamForSOAPNote(Parameters.PETemplateId);
            if (ds != null)
            {
                DataView view = new DataView(ds.PETemplateSystemObservations);
                DataTable PETemp = view.ToTable(true, "PETemplateId", "TemplateName", "SpecialityIds", "ProviderIds", "CreatedOn", "CreatedBy", "ModifiedBy", "TemplatePreview",
                    "ModifiedOn");
                DataTable PETempSystem = view.ToTable(true, "PETemplateId", "TemplateName", "PESystemId", "SystemName", "IsSelectedSystem", "PETemplateSystemId");
                DataTable PESysObservations = view.ToTable(true, "PESystemId", "SystemName", "PEObservationId", "ObservationName", "IsSelected", "ObservationOrder");
                List<PhysExamNotesObservationModelECW> PETemplateSystems = new List<PhysExamNotesObservationModelECW>();

                foreach (DataRow template_item in PETemp.Rows)
                {
                    foreach (DataRow system_item in PETempSystem.Rows)
                    {
                        var PETemplateId = MDVUtility.ToLong(template_item["PETemplateId"]);
                        var SysTemplateId = MDVUtility.ToLong(system_item["PETemplateId"]);
                        if (MDVUtility.ToStr(system_item["IsSelectedSystem"]).ToLower() == "true" && SysTemplateId == PETemplateId)
                        {
                            List<string> observations_ = new List<string>();
                            DataRow[] tempObsRows = PESysObservations.Select("IsSelected = 1", "ObservationOrder ASC");
                            foreach (DataRow observation_item in tempObsRows)
                            {
                                if (MDVUtility.ToLong(observation_item["PESystemId"]) == MDVUtility.ToLong(system_item["PESystemId"])
                                    && MDVUtility.ToStr(observation_item["IsSelected"]).ToLower() == "true")
                                {
                                    observations_.Add(MDVUtility.ToStr(observation_item["ObservationName"]));
                                }
                            }
                            if (observations_.Count > 0)
                            {
                                PhysExamNotesObservationModelECW obj_ = new PhysExamNotesObservationModelECW();
                                obj_.PENotesObservationId = "-1";
                                obj_.PETemplateSystemId = system_item["PETemplateSystemId"].ToString();
                                obj_.NotesId = Parameters.NoteId.ToString();
                                obj_.Descr = string.Join(", ", observations_.Select(n => n.ToString()).ToArray());
                                obj_.Action = "-1";
                                PETemplateSystems.Add(obj_);
                            }
                        }
                    }
                }


                if (PETemplateSystems.Count > 0)
                {
                    XmlSerializer xmlSerializer = new XmlSerializer(typeof(List<PhysExamNotesObservationModelECW>));
                    StringWriter textWriter = new StringWriter();
                    xmlSerializer.Serialize(textWriter, PETemplateSystems);
                    string xmlNotesObservation = textWriter.ToString();
                    ds.Merge(dalPhySicalExam.SavePhysicalExamNotesObservation(xmlNotesObservation, MDVUtility.DecryptFrom64(Parameters.Sharedobj.UserName)));
                }


                if (ds.PENotesObservation.Rows.Count > 0)
                {
                    DataView view_ = new DataView(ds.PENotesObservation);
                    DataTable PETemp_ = view_.ToTable(true, "PETemplateId", "TemplateName", "NotesId");
                    DataTable PETempSystem_ = view_.ToTable(true, "PETemplateId", "TemplateName", "PESystemId", "SystemName", "SystemDescription", "PETemplateSystemId", "PENotesObservationId", "IsSelected");

                    JavaScriptSerializer js = new JavaScriptSerializer();
                    model.Notes_PETemplate_JSON = js.Serialize(MDVUtility.JSON_DataTable(PETemp_));
                    model.Notes_PETemplateCount = PETemp_.Rows.Count;
                    model.Notes_PETemplateSystems_JSON = js.Serialize(MDVUtility.JSON_DataTable(PETempSystem_));
                    model.Notes_PETemplateSystemsCount = PETempSystem_.Rows.Count;
                }
            }
            else
                throw new Exception("Physcial Exam not loaded.");

            return model;

        }

        private Object GetPhysicalExamFromPreviousNotes(Object p)
        {
            var Parameters = p as ThreadParams;

            Model.Clinical.Notes.PhysicalExam model = new Model.Clinical.Notes.PhysicalExam();
            var dalPhySicalExam = new DALPhysicalExamECW(Parameters.Sharedobj);

            DSPhysicalExamECW ds = new DSPhysicalExamECW();
            if (Parameters.IsPrevNotesPE)
                ds = dalPhySicalExam.SelectPhysicalExamPrevNotesObservation(Parameters.NoteId, Parameters.PrevNotesIdPE, Parameters.UserName);

            if (ds != null)
            {
                if (ds.PENotesObservation.Rows.Count > 0)
                {
                    DataView view_ = new DataView(ds.PENotesObservation);
                    DataTable PETemp_ = view_.ToTable(true, "PETemplateId", "TemplateName", "NotesId");
                    DataTable PETempSystem_ = view_.ToTable(true, "PETemplateId", "TemplateName", "PESystemId", "SystemName", "SystemDescription", "PETemplateSystemId", "PENotesObservationId", "IsSelected");

                    JavaScriptSerializer js = new JavaScriptSerializer();
                    model.Notes_PETemplate_JSON = js.Serialize(MDVUtility.JSON_DataTable(PETemp_));
                    model.Notes_PETemplateCount = PETemp_.Rows.Count;
                    model.Notes_PETemplateSystems_JSON = js.Serialize(MDVUtility.JSON_DataTable(PETempSystem_));
                    model.Notes_PETemplateSystemsCount = PETempSystem_.Rows.Count;
                }
            }
            else
                throw new Exception("Physcial Exam not loaded.");

            return model;

        }

