        #region Soap Text for ROS




        public string createROSsoapText(DataSet ResultDataSet, long NotesId, long TemplateId)
        {
            try
            {
                DataTable ROSTemplate = null;
                DataTable ROSTempSystem = null;
                DataTable ROSSysCharatristics = null;
                DataTable ROSSysCharatristicsDetail = null;
                if (ResultDataSet.Tables.Count > 0)
                {
                    DataView view = new DataView(ResultDataSet.Tables[0]);
                    DataView viewdetail = new DataView(ResultDataSet.Tables[1]);

                    ROSTemplate = view.ToTable(true, "ROSTemplateId", "TemplateName", "IsNormalAll", "SpecialtyIds", "ProviderIds", "CreatedOn", "CreatedBy", "ModifiedBy",
                        "ModifiedOn", "TemplateComments");
                    ROSTempSystem = view.ToTable(true, "ROSTemplateId", "TemplateName", "ROSSystemId", "SystemName",
                        "NormalComments", "IsNormal");
                    ROSSysCharatristics = view.ToTable(true, "ROSSystemId", "SystemName", "ROSCharacteristicsId", "CharacteristicsName",
                        "TempSysCharComments", "isPositive");
                    ROSSysCharatristicsDetail = viewdetail.ToTable(true, "ROSSystemId", "ROSCharacteristicsId", "LookUpId", "LookupTypeName", "Value", "LookupName");

                }
                StringBuilder sb = new StringBuilder();
                if (ROSTemplate.Rows.Count > 0)
                {
                    if (ROSTemplate != null && ROSTemplate.Rows.Count > 0)
                    {

                        string overAllComments = string.Empty;
                        foreach (DataRow templateRow in ROSTemplate.Rows)
                        {
                            string GlobalNormalDescription = templateRow["IsNormalAll"].ToString();
                            overAllComments = (templateRow["TemplateComments"] != DBNull.Value ? templateRow["TemplateComments"].ToString() : string.Empty);
                            if (!bool.Parse(templateRow["IsNormalAll"].ToString()))
                            {
                                if (bool.Parse(templateRow["IsNormalAll"].ToString()) == true)
                                {
                                    if (!string.IsNullOrEmpty(GlobalNormalDescription))
                                    {
                                        sb.Append(GlobalNormalDescription + "<br>");
                                    }

                                }
                            }

                        }
                        if (ROSTempSystem != null && ROSTempSystem.Rows.Count > 0)
                        {
                            foreach (DataRow RosTempSysRow in ROSTempSystem.Rows)
                            {
                                string SystemName = RosTempSysRow["SystemName"] != DBNull.Value ? RosTempSysRow["SystemName"].ToString() : "";
                                long SystemId = RosTempSysRow["ROSSystemId"] != DBNull.Value ? MDVUtility.ToLong(RosTempSysRow["ROSSystemId"]) : 0;


                                string SystemNormalDescription = RosTempSysRow["NormalComments"] != DBNull.Value ? RosTempSysRow["NormalComments"].ToString() : "";


                                //if (!bool.Parse(RosTempSysRow["IsNormal"].ToString()))
                                //{

                                if (bool.Parse(RosTempSysRow["IsNormal"].ToString()) == true)
                                {
                                    sb.Append("<div> ");
                                    sb.Append(generateSoapTextSystemName(true, SystemName, SystemId, SystemNormalDescription, TemplateId));

                                    foreach (DataRow ROSTempSysChar in ROSSysCharatristics.Rows)
                                    {
                                        if (int.Parse(ROSTempSysChar["ROSSystemId"].ToString()) == int.Parse(RosTempSysRow["ROSSystemId"].ToString()))
                                        {
                                            sb.Append("<span id='divCharc_" + ROSTempSysChar["ROSCharacteristicsId"] + "' title='Characteristics'  name='Characteristics'>" + ((ROSTempSysChar["CharacteristicsName"] != DBNull.Value) ? ROSTempSysChar["CharacteristicsName"].ToString() + " is Normal." : ""));
                                            sb.Append("</span> ");
                                        }
                                    }
                                    sb.Append("</div> ");
                                }
                                else
                                {

                                    if (ROSSysCharatristics != null && ROSSysCharatristics.Rows.Count > 0)
                                    {

                                        bool systemExists = true;

                                        foreach (DataRow RosTempSysRow1 in ROSSysCharatristics.Rows)
                                        {

                                            if (long.Parse(RosTempSysRow1["ROSSystemId"].ToString()) == long.Parse(RosTempSysRow["ROSSystemId"].ToString()))
                                            {
                                                string soapTextCharcName = generateSoapTextCharcName(RosTempSysRow1, SystemName, SystemId, NotesId, TemplateId);
                                                if (!string.IsNullOrEmpty(soapTextCharcName))
                                                {
                                                    if (systemExists)
                                                    {

                                                        sb.Append(generateSoapTextSystemName(false, SystemName, SystemId, String.Empty, TemplateId));//"<div id='divSys_" + SystemId + "' title='System'  name='System'><strong>" + SystemName + " : </strong><br/>");
                                                        systemExists = false;
                                                    }
                                                    sb.Append(soapTextCharcName);
                                                    if (bool.Parse(RosTempSysRow1["isPositive"].ToString()) == true)
                                                    {
                                                        sb.Append("<span id='divCharc_" + RosTempSysRow1["ROSCharacteristicsId"].ToString() + "' title='Characteristics'  name='Characteristics'>" + ((RosTempSysRow1["CharacteristicsName"].ToString() != "") ? RosTempSysRow1["CharacteristicsName"].ToString() : ""));
                                                    }
                                                    else
                                                    {
                                                        sb.Append("<span id='divCharc_" + RosTempSysRow1["ROSCharacteristicsId"].ToString() + "' title='Characteristics'  name='Characteristics'>" + ((RosTempSysRow1["CharacteristicsName"].ToString() != "") ? RosTempSysRow1["CharacteristicsName"].ToString() : ""));
                                                    }

                                                   

                                                    if (ROSSysCharatristicsDetail != null && ROSSysCharatristicsDetail.Rows.Count > 0)
                                                    {

                                                        bool detailExists = false;
                                                        foreach (DataRow detailRow in ROSSysCharatristicsDetail.Rows)
                                                        {
                                                            if (int.Parse(detailRow["ROSSystemId"].ToString()) == int.Parse(RosTempSysRow1["ROSSystemId"].ToString()) && int.Parse(detailRow["ROSCharacteristicsId"].ToString()) == int.Parse(RosTempSysRow1["ROSCharacteristicsId"].ToString()))
                                                            {
                                                                string soapTextCharc = generateSoapTextForROSCharcDetails(detailRow);
                                                                detailExists = true;
                                                                if (!string.IsNullOrEmpty(soapTextCharc))
                                                                {

                                                                    sb.Append(" " + soapTextCharc);
                                                                    sb.Append("</span> ");
                                                                }
                                                                else
                                                                {
                                                                    sb.Append("</span>, ");
                                                                }
                                                                // break;
                                                            }
                                                        }
                                                        if (!detailExists)
                                                        {
                                                            sb.Append("</span>, ");
                                                        }
                                                    }
                                                    else
                                                    {
                                                        sb.Append("</span> ");

                                                    }
                                                }
                                            }
                                        }
                                        if (!systemExists)
                                        {
                                            sb.Append("</div>");
                                            string updatedSOAP = sb.ToString();
                                            if (!string.IsNullOrEmpty(updatedSOAP) && updatedSOAP.Length > 8 && updatedSOAP.Substring(updatedSOAP.Length - 8).Equals(", </div>"))
                                            {
                                                updatedSOAP = updatedSOAP.Remove(updatedSOAP.Length - 8);
                                                updatedSOAP += "</div>";
                                            }
                                            sb = new StringBuilder();
                                            sb.Append(updatedSOAP);
                                        }
                                    }

                                }
                                //  }
                            }
                            sb.Append("<br>" + overAllComments);
                        }
                    }



                }

                string returnResult = sb.ToString();
                if (!string.IsNullOrEmpty(returnResult) && returnResult.Length > 8 && returnResult.Substring(returnResult.Length - 8).Equals(", </div>"))
                {
                    returnResult = returnResult.Remove(returnResult.Length - 8);
                    returnResult += "</div>";
                }
                return returnResult;
            }
            catch (Exception ex)
            {
                MDVLogger.BLLErrorLog("BLLClinical::createROSsoapText", ex);
                return "";
            }
        }//End of function.

        public string generateSoapTextSystemName(bool IsNormal, string SystemName, long SystemId, string SystemNormalDescription, long TemplateId)
        {
            try
            {
                if (IsNormal)
                {

                    return ("<span id='divSys_" + SystemId + "'  name='ROSSystem'><a class='btn btn-link btn-xs pl-none' style='color:#000000' title='ROS System' onclick='Clinical_ProgressNote.OpenROSSysCharcDetail(this," + TemplateId + "," + SystemId + ")' ><strong>" + SystemName + "</strong></a> is Normal. " + (string.IsNullOrEmpty(SystemNormalDescription) ? "" : SystemNormalDescription + ". ") + "</span>");

                }
                else
                {
                    return ("<div id='divSys_" + SystemId + "' name='ROSSystem'><a class='btn btn-link btn-xs pl-none' style='color:#000000' title='ROS System' onclick='Clinical_ProgressNote.OpenROSSysCharcDetail(this," + TemplateId + "," + SystemId + ")' ><strong>" + SystemName + "</strong>: </a>");
                }
            }
            catch (Exception ex)
            {
                MDVLogger.BLLErrorLog("BLLClinical::generateSoapTextSystemName", ex);
                return "";
            }
        }

        public string generateSoapTextCharcName(DataRow CharRow, string SystemName, long SystemId, long NotesId, long TemplateId)
        {
            try
            {
                StringBuilder sb = new StringBuilder();


                // return charc name and positive and descriptoin
                if (CharRow["isPositive"].ToString() != null && CharRow["isPositive"].ToString() != "")
                {
                    if (CharRow["CharacteristicsName"].ToString() != "")
                    {
                        bool isPositive = bool.Parse(CharRow["isPositive"].ToString());
                        string jQueryFunction = " onclick='Clinical_ROSTemplateDetailRevamp.toggleAttribute(this," + (isPositive ? "true" : "false") + "," + NotesId + "," + TemplateId + "," + SystemId + "," + int.Parse(CharRow["ROSCharacteristicsId"].ToString()) + ",event);'";
                        string cssClass = isPositive ? "red" : "green";
                        string actionLink = "<a href='javascript:void(0);' " + jQueryFunction + " class='hoverToggle " + cssClass + "' >";
                        sb.Append("<b>" + actionLink + (isPositive ? " ( + ) " : " ( - ) ") + "</a></b>");
                    }

                }
                if (!string.IsNullOrEmpty(CharRow["TempSysCharComments"].ToString()) && !string.IsNullOrEmpty(CharRow["isPositive"].ToString()))
                {
                    sb.Append((string.IsNullOrEmpty(CharRow["TempSysCharComments"].ToString()) ? "" : CharRow["TempSysCharComments"].ToString()));
                }
                return sb.ToString();
            }
            catch (Exception ex)
            {
                MDVLogger.BLLErrorLog("BLLClinical::generateSoapTextCharcName", ex);
                return "";
            }
        }

        public string generateSoapTextForROSCharcDetails(DataRow detailRow)
        {
            try
            {

                // (true, "ROSSystemId", "ROSCharacteristicsId", "LookUpId", "LookupTypeName", "Value", "LookupName")
                StringBuilder sb = new StringBuilder();

                if (detailRow["LookupTypeName"].ToString() == "PreviousHistory")
                {
                    sb.Append((string.IsNullOrEmpty(detailRow["Value"].ToString()) ? "" : " Previous history is  " + detailRow["Value"].ToString() + "."));

                }
                if (detailRow["LookupTypeName"].ToString() == "ROSCharacteristicsDetailStatus")
                {
                    sb.Append((string.IsNullOrEmpty(detailRow["LookupName"].ToString()) ? "" : " Status is  " + detailRow["LookupName"].ToString() + "."));
                }
                if (detailRow["LookupTypeName"].ToString() == "ROSOnset")
                {
                    sb.Append((string.IsNullOrEmpty(detailRow["Value"].ToString()) ? "" : " Onset is  " + detailRow["Value"].ToString() + "."));
                }
                if (detailRow["LookupTypeName"].ToString() == "ROSDuration")
                {
                    sb.Append((string.IsNullOrEmpty(detailRow["Value"].ToString()) ? "" : " Duration is  " + detailRow["Value"].ToString()));

                }
                if (detailRow["LookupTypeName"].ToString() == "ROSCharacteristicsDetailDuration")
                {
                    sb.Append((string.IsNullOrEmpty(detailRow["LookupName"].ToString()) ? "" : "  " + detailRow["LookupName"].ToString() + "."));
                }
                if (detailRow["LookupTypeName"].ToString() == "ROSCharacteristicsDetailPattern")
                {
                    sb.Append((string.IsNullOrEmpty(detailRow["LookupName"].ToString()) ? "" : " Pattern is  " + detailRow["LookupName"].ToString() + "."));
                }
                if (detailRow["LookupTypeName"].ToString() == "ROSCharacteristicsDetailSeverity")
                {
                    sb.Append((string.IsNullOrEmpty(detailRow["LookupName"].ToString()) ? "" : " Severity is  " + detailRow["LookupName"].ToString() + "."));
                }
                if (detailRow["LookupTypeName"].ToString() == "ROSCharacteristicsDetailCourse")
                {
                    sb.Append((string.IsNullOrEmpty(detailRow["LookupName"].ToString()) ? "" : " Course is  " + detailRow["LookupName"].ToString() + "."));
                }
                if (detailRow["LookupTypeName"].ToString() == "ROSCharacteristicsDetailRadiation")
                {
                    sb.Append((string.IsNullOrEmpty(detailRow["LookupName"].ToString()) ? "" : " Radiation to  " + detailRow["LookupName"].ToString() + "."));
                }
                if (detailRow["LookupTypeName"].ToString() == "ROSCharacteristicsDetailFrequency")
                {
                    sb.Append((string.IsNullOrEmpty(detailRow["LookupName"].ToString()) ? "" : " Frequency is  " + detailRow["LookupName"].ToString() + "."));
                }
                if (detailRow["LookupTypeName"].ToString() == "ROSCharacteristicsDetailContext")
                {
                    sb.Append((string.IsNullOrEmpty(detailRow["LookupName"].ToString()) ? "" : " Context is  " + detailRow["LookupName"].ToString() + "."));
                }
                if (detailRow["LookupTypeName"].ToString() == "ROSCharacteristicsDetailCharacterCSZ")
                {
                    sb.Append((string.IsNullOrEmpty(detailRow["LookupName"].ToString()) ? "" : " Character is  " + detailRow["LookupName"].ToString() + "."));
                }
                if (detailRow["LookupTypeName"].ToString() == "ROSCharacteristicsDetailAggravedBy")
                {
                    sb.Append((string.IsNullOrEmpty(detailRow["LookupName"].ToString()) ? "" : " It is aggravated by  " + detailRow["LookupName"].ToString() + "."));
                }
                if (detailRow["LookupTypeName"].ToString() == "ROSCharacteristicsDetailRelievedBy")
                {
                    sb.Append((string.IsNullOrEmpty(detailRow["LookupName"].ToString()) ? "" : " It is relieved by  " + detailRow["LookupName"].ToString() + "."));
                }
                //End   || 12 July, 2016 || ZeeshanAK || Fix for EMR-1474
                if (detailRow["LookupTypeName"].ToString() == "Location")
                {
                    sb.Append((string.IsNullOrEmpty(detailRow["Value"].ToString()) ? "" : " Location is  " + detailRow["Value"].ToString() + "."));
                }
                if (detailRow["LookupTypeName"].ToString() == "PrecipitatedBy")
                {
                    sb.Append((string.IsNullOrEmpty(detailRow["Value"].ToString()) ? "" : " Precipitated by  " + detailRow["Value"].ToString() + "."));
                }
                if (detailRow["LookupTypeName"].ToString() == "AssociatedBy")
                {
                    sb.Append((string.IsNullOrEmpty(detailRow["Value"].ToString()) ? "" : " Associated feature are  " + detailRow["Value"].ToString() + "."));
                }

                return sb.ToString();

            }
            catch (Exception ex)
            {
                MDVLogger.BLLErrorLog("BLLClinical::generateSoapTextForROSCharcDetails", ex);
                return "";
            }
        }



