        private Object GetPrevTreatmentPlan(Object p)
        {
            var Parameters = p as ThreadParams;
            string complaintExists = string.Empty;
            var dalTreatment = new DAL_Treatment(Parameters.Sharedobj);
            TreatmentPlanCommentModel  model = new TreatmentPlanCommentModel();
            if (Parameters.IsPrevNoteTreatmentComents)
            {
                model = dalTreatment.GetPrevTreatmentPlanComments(Parameters.PatientId, Parameters.UserId, Parameters.EntityId, Parameters.ProviderId);
                if (model != null && !string.IsNullOrWhiteSpace(model.SoapText))
                {
                    var doc = new HtmlDocument();
                    doc.LoadHtml(model.SoapText);
                    HtmlNode node = doc.GetElementbyId("Comments_Treatment");
                    string nodehtml = "";
                    if (node != null)
                        nodehtml = node.InnerHtml;

                    model.SoapText = nodehtml;
                }
            }
            return model;
        }
