        public BLObject<ClinicalNotesWaper> load_Clinical_Progress_Note(long PatientId, long NoteId, long ProviderId, long OrderSetId, bool PreviousNoteROS, bool PreviousNotePE, bool PreviousNoteComplaints, bool PreviousNoteProblems)
        {
            try
            {
                ClinicalNotesWaper model = new ClinicalNotesWaper();
                model.ClinicalNotesModel = new DALNotes().loadClinical_Note_By_NoteID(PatientId, NoteId);

                if (!string.IsNullOrEmpty(model.ClinicalNotesModel.NoteText) && model.ClinicalNotesModel.NoteText.Contains("{{ ") && model.ClinicalNotesModel.NoteText.Contains(" }}"))
                {
                    try
                    {
                        ClinicalNotesModel modelPrevious = new DALNotes().LoadPreviouNotePEAndROS(PatientId, model.ClinicalNotesModel.IsPhoneEncounter, ProviderId);
                        if (modelPrevious != null)
                        {
                            if (PreviousNotePE)
                            {
                                if (!string.IsNullOrWhiteSpace(modelPrevious.PETemplateId) && modelPrevious.PETemplateId != "0")
                                {
                                    model.ClinicalNotesModel.PETemplateId = modelPrevious.PETemplateId;
                                    model.ClinicalNotesModel.IsPrevNotesPE = true;
                                    model.ClinicalNotesModel.PrevNotesIdPE = modelPrevious.PrevNotesIdPE;
                                }
                                else
                                {
                                    model.ClinicalNotesModel.IsPrevNotesPE = false;
                                }

                            }
                            else
                            {
                                model.ClinicalNotesModel.IsPrevNotesPE = false;
                            }

                            if (PreviousNoteROS)
                            {
                                if (!string.IsNullOrWhiteSpace(modelPrevious.ROSTemplateId) && modelPrevious.ROSTemplateId != "0")
                                {
                                    model.ClinicalNotesModel.ROSTemplateId = modelPrevious.ROSTemplateId;
                                    model.ClinicalNotesModel.ROSDataTemptId = modelPrevious.ROSTemplateId;
                                    model.ClinicalNotesModel.IsPrevNotesROS = true;
                                    model.ClinicalNotesModel.PrevNotesIdROS = modelPrevious.PrevNotesIdROS;
                                }
                                else { model.ClinicalNotesModel.IsPrevNotesROS = false; }
                            }
                            else
                            {
                                model.ClinicalNotesModel.IsPrevNotesROS = false;

                            }
                        }

                        model.ClinicalNotesModel.IsPrevNoteComplaints = PreviousNoteComplaints;
                        model.ClinicalNotesModel.IsPrevNoteProblems = PreviousNoteProblems;
                        model = LoadNoteTagsAndRenderTemplate(model, NoteId, PatientId, OrderSetId, ProviderId);
                    }
                    catch (Exception ex)
                    {
                        MDVLogger.BLLErrorLog("BLLClinical::loadClinical_Note_By_NoteID", ex);
                        return new BLObject<ClinicalNotesWaper>(null, ex.Message, "RenderNoteTemplateTags");
                    }

                }

                return new BLObject<ClinicalNotesWaper>(model);

            }
            catch (Exception ex)
            {
                MDVLogger.BLLErrorLog("BLLClinical::load_Clinical_Progress_Note", ex);
                return new BLObject<ClinicalNotesWaper>(null, ex.Message);
            }
        }

        private ClinicalNotesWaper LoadNoteTagsAndRenderTemplate(ClinicalNotesWaper model, long NoteId, long PatientId, long OrderSetId, long ProviderId = 0, string componenetsIds = "")
        {
            try
            {
                Dictionary<String, IWorkItemResult> threadList = new Dictionary<string, IWorkItemResult>();

                SmartThreadPool threadPool = new SmartThreadPool();
                ThreadParams threadParams = new ThreadParams();

                threadParams.NoteId = NoteId;
                threadParams.VisitId = MDVUtility.ToLong(model.ClinicalNotesModel.VisitId);
                threadParams.PatientId = PatientId;
                threadParams.HPITemplateId = MDVUtility.ToLong(model.ClinicalNotesModel.HPITemplateId);
                threadParams.IsDefaultHPI = MDVUtility.ToBool(MDVSession.Current.IsDefaultHPI);
                threadParams.ProviderId = ProviderId;
                threadParams.UserId = MDVUtility.ToInt64(MDVSession.Current.AppUserId);
                threadParams.EntityId = MDVUtility.ToInt64(MDVSession.Current.EntityId);
                threadParams.Sharedobj = SharedVariable.GetSharedVariable();
                threadParams.PrevNotesIdPE = model.ClinicalNotesModel.PrevNotesIdPE;
                threadParams.PrevNotesIdROS = model.ClinicalNotesModel.PrevNotesIdROS;
                threadParams.IsPrevNotesPE = model.ClinicalNotesModel.IsPrevNotesPE;
                threadParams.IsPrevNotesROS = model.ClinicalNotesModel.IsPrevNotesROS;
                threadParams.UserName = MDVUtility.DecryptFrom64(MDVSession.Current.AppUserName);
                threadParams.OrderSetId = OrderSetId;
                threadParams.IsPrevNoteComplaints = model.ClinicalNotesModel.IsPrevNoteComplaints;
                threadParams.Model = model;
                threadParams.componenetsIds = componenetsIds;
                threadParams.IsPrevNoteProblems = model.ClinicalNotesModel.IsPrevNoteProblems;
                threadParams.IsPrevNoteTreatmentComents = MDVUtility.ToBool(MDVSession.Current.IsPrevNoteTreatmentComents);

                string NoteText = model.ClinicalNotesModel.NoteText;

                var task1 = threadPool.QueueWorkItem(new WorkItemCallback(Task1), threadParams);
                threadList.Add("Task1", task1);

                var task2 = threadPool.QueueWorkItem(new WorkItemCallback(Task2), threadParams);
                threadList.Add("Task2", task2);

                var task3 = threadPool.QueueWorkItem(new WorkItemCallback(Task3), threadParams);
                threadList.Add("Task3", task3);

                var task4 = threadPool.QueueWorkItem(new WorkItemCallback(Task4), threadParams);
                threadList.Add("Task4", task4);

                bool success = SmartThreadPool.WaitAll(threadList.Values.ToArray());
                threadPool.Shutdown();

                if (success)
                {
                    foreach (var key in threadList.Keys)
                    {
                        Dictionary<string, object> Results = (Dictionary<string, object>)threadList[key].Result;
                        foreach (var item in Results)
                        {
                            PropertyInfo propertyInfo = model.ClinicalNoteComponents.GetType().GetProperty(item.Key);
                            propertyInfo.SetValue(model.ClinicalNoteComponents, Convert.ChangeType(item.Value, propertyInfo.PropertyType), null);
                        }
                    }
                }

                return model;
            }
            catch (Exception ex)
            {
                MDVLogger.BLLErrorLog("BLLClinical::LoadNoteTagsAndRenderTemplate", new Exception(ex.InnerException.Message));
                throw new Exception(ex.InnerException.Message);
            }
        }

        private Object Task1(Object p)
        {
            Dictionary<string, object> Result = new Dictionary<string, object>();
            var Parameters = p as ThreadParams;
            if (Parameters.Model.ClinicalNotesModel.NoteText.Contains("{{ Clinical Vitals }}") && !Parameters.componenetsIds.ToLower().Contains("vitals"))
            {
                Result.Add("Vitals", GetVitalsByPatient(Parameters));
            }

            if (Parameters.Model.ClinicalNotesModel.NoteText.Contains("{{ Clinical Problems }}") && !Parameters.componenetsIds.ToLower().Contains("problems"))
            {
                Result.Add("Problems", GetProblemListByPatient(Parameters));
            }

            if (Parameters.Model.ClinicalNotesModel.NoteText.Contains("{{ Clinical Allergies }}") && !Parameters.componenetsIds.ToLower().Contains("allergies"))
            {
                Result.Add("Allergies", GetAllergiesByPatient(Parameters));
            }

            if (Parameters.Model.ClinicalNotesModel.NoteText.Contains("{{ Clinical Social Hx }}") && !Parameters.componenetsIds.ToLower().Contains("socialhx"))
            {
                Result.Add("SocialHistory", GetSocialHistoryByPatient(Parameters));
            }

            if (Parameters.Model.ClinicalNotesModel.NoteText.Contains("{{ Clinical Medical Hx }}") && !Parameters.componenetsIds.ToLower().Contains("medicalhx"))
            {
                Result.Add("MedicalHistory", GetMedicalHistoryByPatient(Parameters));
            }

            if (Parameters.Model.ClinicalNotesModel.NoteText.Contains("{{ Clinical Birth Hx }}") && !Parameters.componenetsIds.ToLower().Contains("birthhx"))
            {
                Result.Add("BirthHistory", GetBirthHistoryByPatient(Parameters));
            }

            return Result;
        }

        private Object Task2(Object p)
        {
            Dictionary<string, object> Result = new Dictionary<string, object>();
            var Parameters = p as ThreadParams;

            if (Parameters.Model.ClinicalNotesModel.NoteText.Contains("{{ Clinical Immunization }}") && !Parameters.componenetsIds.ToLower().Contains("immunization")) // there are two calls,
            {
                Result.Add("Immunization", GetImmunizationByPatient(Parameters));
            }

            if (Parameters.Model.ClinicalNotesModel.NoteText.Contains("{{ Clinical Referrals }}") && !Parameters.componenetsIds.ToLower().Contains("referrals"))
            {
                //response = new PatientReferralHelper().getLatestReferralByPatientId(MDVUtility.ToInt64(model.PatientId));
            }

            if (Parameters.Model.ClinicalNotesModel.NoteText.Contains("{{ Clinical Family Hx }}") && !Parameters.componenetsIds.ToLower().Contains("familyhx"))
            {
                Result.Add("FamilyHistory", GetFamilyHistoryByPatient(Parameters));
            }

            if (Parameters.Model.ClinicalNotesModel.NoteText.Contains("{{ Clinical Surgical Hx }}") && !Parameters.componenetsIds.ToLower().Contains("surgicalhx"))
            {
                Result.Add("SurgicalHistory", GetSurgicalHistoryByPatient(Parameters));
            }

            if (Parameters.Model.ClinicalNotesModel.NoteText.Contains("{{ Clinical Hospitalization Hx }}") && !Parameters.componenetsIds.ToLower().Contains("hospitalizationhx"))
            {
                Result.Add("HospitalizationHistory", GetHospitalizationHistoryByPatient(Parameters));
            }

            if (Parameters.Model.ClinicalNotesModel.NoteText.Contains("{{ Clinical Complaints }}") && !Parameters.componenetsIds.ToLower().Contains("complaints"))
            {
                Result.Add("Complaints", GetComplaintsByPatient(Parameters));
            }

            return Result;
        }

        private Object Task3(Object p)
        {
            Dictionary<string, object> Result = new Dictionary<string, object>();
            var Parameters = p as ThreadParams;

            if (Parameters.Model.ClinicalNotesModel.NoteText.Contains("{{ Clinical Medication }}") && !Parameters.componenetsIds.ToLower().Contains("medications"))
            {
                Result.Add("Medications", GetMedicationsByPatient(Parameters));
            }

            if (Parameters.Model.ClinicalNotesModel.NoteText.Contains("{{ Clinical Prescription }}") && !Parameters.componenetsIds.ToLower().Contains("prescriptions"))
            {
                Result.Add("Prescription", GetPrescriptionsByPatient(Parameters));
            }

            if (Parameters.Model.ClinicalNotesModel.NoteText.Contains("{{ Clinical Review of System }}") && !string.IsNullOrEmpty(Parameters.Model.ClinicalNotesModel.ROSDataTemptId) && !Parameters.componenetsIds.ToLower().Contains("reviewofsystems"))
            {
                Parameters.ROSDataTemptId = MDVUtility.ToLong(Parameters.Model.ClinicalNotesModel.ROSDataTemptId);
                Result.Add("ReviewofSystem", GetROSSystemPatientInfoFromNotes(Parameters));
            }

            //// Following Sections are left because not needed for Note Load

            if (Parameters.Model.ClinicalNotesModel.NoteText.Contains("{{ Clinical Procedures }}") && !Parameters.componenetsIds.ToLower().Contains("procedures"))
            {
                Result.Add("Procedures", GetProceduresByPatientId(Parameters));
            }

            if (Parameters.Model.ClinicalNotesModel.NoteText.Contains("{{ Clinical Physical Exam }}") && !string.IsNullOrEmpty(Parameters.Model.ClinicalNotesModel.PETemplateId))
            {
                Parameters.PETemplateId = MDVUtility.ToLong(Parameters.Model.ClinicalNotesModel.PETemplateId);
                if (Parameters.Model.ClinicalNotesModel.IsPrevNotesPE)
                {
                    Result.Add("PhysicalExam", GetPhysicalExamFromPreviousNotes(Parameters));
                }
                else
                {
                    Result.Add("PhysicalExam", GetPhysicalExamFromNotes(Parameters));
                }
            }
            if (Parameters.Model.ClinicalNotesModel.NoteText.Contains("{{ Clinical Social, Psychological and Behavior Hx }}") && !Parameters.componenetsIds.ToLower().Contains("SocPsyandBehaviorHx"))
            {
                Result.Add("SocPsyandBehaviorHx", GetSocPsyandBehaviorHxByPatient(Parameters));
            }

            return Result;
        }

        private Object Task4(Object p)
        {
            Dictionary<string, object> Result = new Dictionary<string, object>();
            var Parameters = p as ThreadParams;

            if (Parameters.Model.ClinicalNotesModel.NoteText.Contains("{{ Clinical Patient Education }}") && !Parameters.componenetsIds.ToLower().Contains("patienteducation"))
            {
                Result.Add("PatientEducation", GetPatientEducationByPatientId(Parameters));
            }

            if (Parameters.Model.ClinicalNotesModel.NoteText.Contains("{{ Clinical Follow Up }}") && !Parameters.componenetsIds.ToLower().Contains("followup"))
            {
                Result.Add("FollowUp", GetFollowUpByPatient(Parameters));
            }

            if (Parameters.Model.ClinicalNotesModel.NoteText.Contains("{{ Clinical Lab Order }}") && Parameters.OrderSetId > 0 && !Parameters.componenetsIds.ToLower().Contains("clinicallaborder"))
            {
                Result.Add("ClinicalLabOrder", GetLabOrderForOrderSetByOrderSetId(Parameters));
            }

            if (Parameters.Model.ClinicalNotesModel.NoteText.Contains("{{ Clinical Procedure Order }}") && Parameters.OrderSetId > 0 && !Parameters.componenetsIds.ToLower().Contains("clinicalprocedureorder"))
            {
                Result.Add("ClinicalProcedureOrder", GetProcedureOrderForOrderSetByOrderSetId(Parameters));
            }

            if ((Parameters.Model.ClinicalNotesModel.NoteText.Contains("{{ Clinical Radiology Order }}") || Parameters.Model.ClinicalNotesModel.NoteText.Contains("{{ Clinical Diagnostic Imaging Order }}")) && Parameters.OrderSetId > 0 && !Parameters.componenetsIds.ToLower().Contains("clinicaldiagnosticimagingorder"))
            {
                Result.Add("ClinicalDiagnosticImagingOrder", GetDiagnosticImagingOrderForOrderSetByOrderSetId(Parameters));
            }
            if (Parameters.Model.ClinicalNotesModel.NoteText.Contains("{{ Clinical Treatment Plan }}"))
            {
                Result.Add("TreatmentPlanCommentModel", GetPrevTreatmentPlan(Parameters));
            }
            return Result;
        }

