        /// Method Name: loadClinicalNoteHeaderData
        /// Date: 13-07-2016
        /// Description: To load clinical Note's Header Data, DR Hajjar's Feedback after demo
        /// </summary>
        /// <param name="PatientId"></param>
        /// <param name="ProviderId"></param>
        /// <param name="NoteId"></param>
        /// <returns></returns>
        public BLObject<DSNotes> loadClinicalNoteHeaderData(long PatientId, long ProviderId, long NoteId)
        {
            try
            {
                DSNotes ds = new DSNotes();
                if (NoteId > 0)
                {
                    ds = new DALNotes().loadClinical_Notes(PatientId, NoteId, 0, 1, 2000);
                }

                if (PatientId > 0)
                {
                    DSPatient dsPatientInfo = new DALPatient().FillPatient(PatientId, "", "");
                    if (dsPatientInfo != null)
                    {
                        ds.Merge(dsPatientInfo);
                        if (dsPatientInfo.Patients.Rows.Count > 0)
                        {
                            try
                            {
                                int PracticeId = MDVUtility.ToInt32(dsPatientInfo.Patients.Rows[0][dsPatientInfo.Patients.PracticeIdColumn.ColumnName]);
                                DSProfile dsProfile = new DSProfile();
                                dsProfile = new DALPractice().LoadPractice(PracticeId, string.Empty, string.Empty, string.Empty, string.Empty, string.Empty);
                                if (dsProfile != null)
                                {
                                    ds.Merge(dsProfile);
                                }
                            }
                            catch (Exception ex)
                            {

                            }

                        }
                    }
                }

                if (ProviderId > 0)
                {
                    DSProfile dsProvider = new DALProvider().LoadProvider(ProviderId, "", "", "", "", "", "", "", 1, 2000);
                    if (dsProvider != null)
                    {
                        ds.Merge(dsProvider);
                    }
                }

                return new BLObject<DSNotes>(ds);
            }
            catch (Exception ex)
            {
                MDVLogger.BLLErrorLog("BLLClinical::LoadClinical_Notes", ex);
                return new BLObject<DSNotes>(null, ex.Message);
            }
        }


