        /// <summary>
        /// Loads the Notess.
        /// </summary>
        /// <param name="PatientId">The patient identifier.</param>
        /// <param name="NoteId">The Notes identifier.</param>
        /// <returns>BLObject&lt;DSNotes&gt;.</returns>PatientID, NotesID, AppointmentID, ShortName, AssignedToId, PageNumber, RowsPerPage
        public BLObject<byte[]> previewClinical_Notes(long PatientId, long NoteId, long AppointmentID, Int32 PageNumber, Int32 RowsPerPage)
        {
            try
            {
                DSNotes ds = new DSNotes();
                ds = new DALNotes().loadClinical_Notes(PatientId, NoteId, AppointmentID, PageNumber, RowsPerPage);

                try
                {
                    if (ds.Notes.Rows.Count <= 0)
                        throw new Exception("No Data found.");

                    byte[] newByteArr = null;
                    using (MemoryStream stream_ = new MemoryStream())
                    {
                        //Creating Document Object
                        Document document = new Document(PageSize.LETTER, 20f, 20f, 30f, 30f);
                        //Creating Pdf Creator Object
                        MDVUtility.PDFCreator pdf = new MDVUtility.PDFCreator(ref document, stream_);
                        pdf.Document.Open();
                        pdf.Document.NewPage();
                        //Setting Margins to Document
                        pdf.Document.SetMargins(20f, 20f, 20f, 20f);
                        // Function To Create PDF
                        createPage(pdf, ds);
                        pdf.Document.Close();
                        pdf.Writer.Close();

                        newByteArr = stream_.GetBuffer();
                    }

                    return new BLObject<byte[]>(newByteArr);
                }
                catch (Exception ex)
                {
                    MDVLogger.BLLErrorLog("BLLBillingClaim::PreviewClinical_Notes", ex);
                    return new BLObject<byte[]>(null, ex.Message);
                }
            }
            catch (Exception ex)
            {
                MDVLogger.BLLErrorLog("BLLClinical::PreviewClinical_Notes", ex);
                return new BLObject<byte[]>(null, ex.Message);
            }
        }

