        //this functions Creats Pages For PDF and than call body Functions to add body Text
        private void createPage(MDVUtility.PDFCreator pdf, DSNotes dsTemp)
        {
            try
            {
                foreach (DSNotes.NotesRow notesObj in dsTemp.Notes)
                {
                    StringBuilder sb = new StringBuilder();
                    sb.Append(notesObj.NoteText.ToString());
                    if (!string.IsNullOrEmpty(notesObj.NoteStatus) && notesObj.NoteStatus.Equals("Signed"))
                    {
                        customPDf(sb, pdf, true);
                    }
                    else
                    {
                        customPDf(sb, pdf, false);
                    }
                    //Recursive function to add HTML of Each row of dataset

                }
            }
            catch (Exception ex)
            {
                MDVLogger.BLLErrorLog("BLLBillingClaim::CreatePage", ex);

            }
        }
        //Recursive function to add HTML of Each row of dataset
        public void customPDf(StringBuilder sb, MDVUtility.PDFCreator pdf, bool SignedBy)
        {
            try
            {

                HtmlDocument doc = new HtmlDocument() { OptionAutoCloseOnEnd = true };
                HtmlNode.ElementsFlags.Remove("meta");
                HtmlNode.ElementsFlags.Remove("link");
                HtmlNode.ElementsFlags.Remove("a");
                doc.LoadHtml("@" + sb.ToString());

                HtmlNodeCollection mainOls = doc.DocumentNode.SelectNodes("ul");
                if (mainOls != null)
                {
                    foreach (HtmlAgilityPack.HtmlNode node in mainOls)
                    {
                        recursive(node, pdf);
                    }
                }

            }
            catch (Exception)
            {

                throw;
            }

        }

        private void recursive(HtmlNode nodeOl, MDVUtility.PDFCreator pdf)
        {
            try
            {
                HtmlNodeCollection lis = nodeOl.ChildNodes;
                foreach (var li in lis)
                {
                    //li.SelectSingleNode("header") InnerText
                    //li.SelectSingleNode("section") InnerText
                    foreach (var item in li.ChildNodes)
                    {
                        if (item.Name.Equals("header"))
                        {
                            createHeader(item, pdf);
                        }
                        else if (item.Name.Equals("section") || item.Name.Equals("div"))
                        {
                            createSection(item, pdf);
                        }
                        else if (item.Name.Equals("#text") && item.NextSibling == null)
                        {
                            Font verdana = FontFactory.GetFont("Verdana", 9, BaseColor.GRAY);
                            Paragraph p = new Paragraph();
                            Phrase phrase = new Phrase();

                            Chunk chunk = new Chunk(item.InnerText + Environment.NewLine, verdana);
                            chunk.setLineHeight(5);
                            phrase.Add(chunk);

                            p.IndentationLeft = 2;
                            p.SpacingBefore = 10;
                            p.SpacingAfter = 5;
                            p.Add(phrase);
                            pdf.Document.Add(p);

                        }
                    }

                }
            }
            catch (Exception ex)
            {

                throw ex;
            }

        }

