        private void createSection(HtmlNode itemParent, MDVUtility.PDFCreator pdf)
        {
            Font verdana = FontFactory.GetFont("Verdana", 10, BaseColor.BLACK);

            if (itemParent.ChildNodes != null && itemParent.ChildNodes.Count > 0)
            {
                foreach (var item in itemParent.ChildNodes)
                {
                    if (item.Name.Equals("div") && item.LastChild != null && item.LastChild.Name.Equals("ul"))
                    {
                        if (item.LastChild.ChildNodes != null && item.LastChild.ChildNodes.Count > 0 && item.LastChild.LastChild.Name.Equals("li"))
                        {
                            if (item.LastChild.ChildNodes != null && item.LastChild.ChildNodes.Count > 0)
                            {
                                Paragraph p = new Paragraph();
                                // Phrase phrase = new Phrase();
                                foreach (var itemChild in item.LastChild.ChildNodes)
                                {

                                    if (itemChild.LastChild != null && !itemChild.LastChild.Name.Equals("#text"))
                                    {

                                        p.Add(createSimpleHtmlParagraph(itemChild.InnerHtml));

                                    }
                                    else
                                    {
                                        Chunk chunk = new Chunk(itemChild.InnerText + Environment.NewLine, verdana);
                                        chunk.setLineHeight(5);
                                        //  phrase.Add(chunk);
                                        p.Add(chunk);
                                    }
                                }

                                p.IndentationLeft = 20;
                                p.SpacingBefore = 5;
                                p.SpacingAfter = 5;
                                //   p.Add(phrase);
                                pdf.Document.Add(p);
                            }
                        }
                        else
                        {
                            if (item.LastChild.ChildNodes != null && item.LastChild.ChildNodes.Count > 0)
                            {
                                createSection(item, pdf);
                            }
                        }

                    }

                }
            }
            else
            {
                Paragraph p = new Paragraph();
                Phrase phrase = new Phrase();
                Chunk chunk = new Chunk(itemParent.InnerText + Environment.NewLine, FontFactory.GetFont("dax-black"));
                chunk.setLineHeight(2);
                phrase.Add(chunk);
                p.IndentationLeft = 20;
                p.SpacingBefore = 15;
                p.SpacingAfter = 15;
                p.Add(phrase);
                pdf.Document.Add(p);
            }


        }
        private Phrase createSimpleHtmlParagraph(String text)
        {
            //Our return object
            Phrase p = new Phrase();
            Font Verdana = FontFactory.GetFont("Verdana", 10, BaseColor.BLACK);
            //ParseToList requires a StreamReader instead of just text
            using (StringReader sr = new StringReader(text))
            {
                //Parse and get a collection of elements
                System.Collections.Generic.List<IElement> elements = iTextSharp.text.html.simpleparser.HTMLWorker.ParseToList(sr, null);
                foreach (IElement e in elements)
                {
                    foreach (var item in e.Chunks)
                    {
                        item.Font.Size = 10;
                        item.Font.SetFamily("Verdana");

                    }
                    //Add those elements to the paragraph
                    p.Add(e);
                }
            }
            //Return the paragraph
            return p;
        }

        private void createHeader(HtmlNode item, MDVUtility.PDFCreator pdf)
        {
            Font arialHeader = FontFactory.GetFont("'Open Sans', Arial, sans-serif", 12);//#0088cc
            var color = System.Drawing.ColorTranslator.FromHtml("#0088cc");
            arialHeader.Color = new BaseColor(color);
            arialHeader.IsBold();
            Phrase phrase = new Phrase();
            Paragraph p = new Paragraph();
            Chunk chunk = new Chunk(item.InnerText, arialHeader);
            chunk.setLineHeight(1);
            phrase.Add(chunk);
            p.IndentationLeft = 2;
            p.SpacingBefore = 10;
            p.Add(phrase);
            pdf.Document.Add(p);
        }
