        #region UPDATE VITALS MOVED FROM HELPER

        public BLObject<DSVitals> UpdateVitals(VitalModel model, Int64 VitalSignsId, List<object> lstBloodPressureObjects, List<object> lstPulseObjects, List<object> lstTemperatureObjects, List<object> lstRespirationObjects, bool isFromGrid = false)
        {
            DSDBAudit dsVitalsDbAudit = new DSDBAudit();
            DataTable dtVitalChanges = null;

            DSDBAudit dsBloodPressureDbAudit = new DSDBAudit();
            DataTable dtBloodPressureChanges = null;

            DSDBAudit dsPulseDbAudit = new DSDBAudit();
            DataTable dtPulseChanges = null;

            DSDBAudit dsTemperatureDbAudit = new DSDBAudit();
            DataTable dtTemperatureChanges = null;

            DSDBAudit dsRespirationDbAudit = new DSDBAudit();
            DataTable dtRespirationChanges = null;

            IDBManager dbManager = ClientConfiguration.GetDBManager();
            //  IDBManager dbManagerAudit = ClientConfiguration.GetDBManager();

            BLObject<DSVitals> objUpdate = new BLObject<DSVitals>();
            try
            {

                DSVitals dsVitals = new DSVitals();
                BLObject<DSVitals> obj = LoadVitals(MDVUtility.ToInt64(model.PatientId), VitalSignsId, 1, 1000);
                dsVitals = obj.Data;
                foreach (DSVitals.VitalSignsRow dr in dsVitals.Tables[dsVitals.VitalSigns.TableName].Rows)
                {
                    if (isFromGrid == false)
                    {
                        if (!string.IsNullOrEmpty(model.OxygenSource))
                            dr.OxygenSource = MDVUtility.ToStr(model.OxygenSource);
                        if (!string.IsNullOrEmpty(model.PeakFlow))
                            dr.PeakFlow = MDVUtility.ToStr(model.PeakFlow);
                        if (!string.IsNullOrEmpty(model.SeverityofPain))
                            dr.PainId = MDVUtility.ToInt32(model.SeverityofPain);
                        if (!string.IsNullOrEmpty(model.SmokingStatus))
                            dr.SmokeStatusId = MDVUtility.ToInt32(model.SmokingStatus);

                        if (!string.IsNullOrEmpty(model.HeadCir))
                            dr.HeadCr = MDVUtility.ToDouble(model.HeadCir);
                        if (!string.IsNullOrEmpty(model.BloodType))
                            dr.BloodType = MDVUtility.ToInt32(model.BloodType);
                        if (model.RiskAssessmentId > 0)
                        {
                            dr.RiskAssessmentId = model.RiskAssessmentId;
                        }
                        else
                        {
                            dr[dsVitals.VitalSigns.RiskAssessmentIdColumn.ColumnName] = DBNull.Value;
                        }
                        dr.InhaledO2Concentration = MDVUtility.ToStr(model.InhaledO2Concentration);
                    }
                    if (!string.IsNullOrEmpty(model.Weight))
                        dr.Weight = MDVUtility.ToDouble(model.Weight);
                    else
                        dr[dsVitals.VitalSigns.WeightColumn.ColumnName] = DBNull.Value;
                    // if (!string.IsNullOrEmpty(model.Height))
                    dr.Height = model.Height;

                    if (!string.IsNullOrEmpty(model.NegationReason))
                        dr.NegationReasonId = model.NegationReason;
                    else
                        dr[dsVitals.VitalSigns.NegationReasonIdColumn.ColumnName] = DBNull.Value;

                    dr.ModifiedBy = MDVUtility.DecryptFrom64(MDVSession.Current.AppUserName);
                    dr.ModifiedOn = DateTime.Now;


                    //newly added
                    if (!string.IsNullOrEmpty(model.SPO2))
                    {
                        dr.SPO2 = MDVUtility.ToStr(model.SPO2);
                    }
                    else
                    {
                        dr[dsVitals.VitalSigns.SPO2Column] = DBNull.Value;
                    }
                    if (!string.IsNullOrEmpty(model.Comments))
                        dr.Comments = MDVUtility.ToStr(model.Comments);
                    else
                    {
                        dr[dsVitals.VitalSigns.CommentsColumn] = DBNull.Value;
                    }

                    if (!string.IsNullOrEmpty(model.VitalSignDate))
                        dr.VitalSignDate = MDVUtility.ToDateTime(model.VitalSignDate);
                    if (!string.IsNullOrEmpty(model.VitalsTime))
                        dr.VitalSignTime = MDVUtility.ToStr(model.VitalsTime);
                    if (!string.IsNullOrEmpty(model.BSA))
                        dr.BSA = MDVUtility.ToDouble(model.BSA);
                    else
                        dr[dsVitals.VitalSigns.BSAColumn.ColumnName] = DBNull.Value;
                    if (!string.IsNullOrEmpty(model.BMI))
                        dr.BMI = MDVUtility.ToDouble(model.BMI);
                    else
                        dr[dsVitals.VitalSigns.BMIColumn.ColumnName] = DBNull.Value;

                    if (!string.IsNullOrEmpty(model.NotesId) && model.NotesId != "0")
                    {
                        dr.NotesId = MDVUtility.ToInt64(model.NotesId);
                        //dr.IsFromNote = true;
                    }
                    else
                    {
                        dr[dsVitals.VitalSigns.NotesIdColumn.ColumnName] = DBNull.Value;
                        //dr.IsFromNote = false;
                    }

                    if (!string.IsNullOrEmpty(model.VisitId) && model.NotesId != "0")
                        dr.NotesId = MDVUtility.ToInt64(model.VisitId);
                    else
                        dr[dsVitals.VitalSigns.VisitIdColumn.ColumnName] = DBNull.Value;

                    //end newly added
                }
                dtVitalChanges = dsVitals.VitalSigns.GetChanges();
                dbManager.BeginTransaction();
                if (lstBloodPressureObjects.Count > 0)
                {
                    insertUpdateBloodPressure(ref dsVitals, true, VitalSignsId, lstBloodPressureObjects, ref dtBloodPressureChanges, isFromGrid, false, PatientId: model.PatientId, isInsertCase: false, dbManager: dbManager);

                    //  string responseBloodPressure = insertUpdateCurrentVitalChilds(dsVitals,  true, null, VitalSignsId, lstBloodPressureObjects, isFromGrid, false, PatientId: model.PatientId, isInsertCase: false);
                    //(DSVitals dsVitals, string RowType, bool isNewRow, object objRow, Int64 VitalSignId, List<object> lstObjects, bool isFromGrid = false, bool AddFirstChild = true, string PatientId = "", bool isInsertCase = false)
                }
                if (lstPulseObjects.Count > 0)
                {
                    insertUpdatePulse(ref dsVitals, true, VitalSignsId, lstPulseObjects, ref dtPulseChanges, isFromGrid, false, PatientId: model.PatientId, isInsertCase: false, dbManager: dbManager);
                    // string responsePulse = insertUpdateCurrentVitalChilds(dsVitals, "VitalSignsPulseRow", true, null, VitalSignsId, lstPulseObjects, isFromGrid, false, PatientId: model.PatientId, isInsertCase: false);
                }
                if (lstTemperatureObjects.Count > 0)
                {
                    insertUpdateTemperature(ref dsVitals, true, VitalSignsId, lstTemperatureObjects, ref dtTemperatureChanges, isFromGrid, false, PatientId: model.PatientId, isInsertCase: false, dbManager: dbManager);
                    // string responsePulse = insertUpdateCurrentVitalChilds(dsVitals, "VitalSignsTempratureRow", true, null, VitalSignsId, lstTemperatureObjects, isFromGrid, false, PatientId: model.PatientId, isInsertCase: false);
                }
                if (lstRespirationObjects.Count > 0)
                {
                    insertUpdateRespiration(ref dsVitals, true, VitalSignsId, lstRespirationObjects, ref dtRespirationChanges, isFromGrid, false, PatientId: model.PatientId, isInsertCase: false, dbManager: dbManager);
                    //string responsePulse = insertUpdateCurrentVitalChilds(dsVitals, "VitalSignsRespirationRow", true, null, VitalSignsId, lstRespirationObjects, isFromGrid, false, PatientId: model.PatientId, isInsertCase: false);
                }
                #region Database Updation
                if (dsVitals.Tables[dsVitals.VitalSigns.TableName].Rows.Count > 0)
                {

                    objUpdate = UpdateVitals(dsVitals, dbManager);
                }
                dsVitals.AcceptChanges();
                dbManager.CommitTransaction();

                if (dtVitalChanges != null)
                {
                    dsVitalsDbAudit = new DBActivityAudit().InsertDBAudit(dtVitalChanges, dbManager, dsVitals.VitalSigns.Rows[0][dsVitals.VitalSigns.VitalSignIdColumn].ToString(), null, dsVitals.VitalSigns.Rows[0][dsVitals.VitalSigns.VitalSignIdColumn].ToString(), patientId: dsVitals.VitalSigns.Rows[0][dsVitals.VitalSigns.PatientIdColumn].ToString());
                    dsVitalsDbAudit.AcceptChanges();
                }
                if (dtBloodPressureChanges != null)
                {
                    dsBloodPressureDbAudit = new DBActivityAudit().InsertDBAudit(dtBloodPressureChanges, dbManager, dsVitals.VitalSignsBloodPressure.Rows[0][dsVitals.VitalSignsBloodPressure.BPIdColumn].ToString(), null, dsVitals.VitalSignsBloodPressure.Rows[0][dsVitals.VitalSignsBloodPressure.VitalSignIdColumn].ToString(), patientId: model.PatientId);
                    dsBloodPressureDbAudit.AcceptChanges();
                }

                if (dtPulseChanges != null)
                {
                    dsPulseDbAudit = new DBActivityAudit().InsertDBAudit(dtPulseChanges, dbManager, dsVitals.VitalSignsPulse.Rows[0][dsVitals.VitalSignsPulse.PulseIdColumn].ToString(), null, dsVitals.VitalSignsPulse.Rows[0][dsVitals.VitalSignsPulse.VitalSignIdColumn].ToString(), patientId: model.PatientId);
                    dsPulseDbAudit.AcceptChanges();
                }

                if (dtTemperatureChanges != null)
                {
                    dsTemperatureDbAudit = new DBActivityAudit().InsertDBAudit(dtTemperatureChanges, dbManager, dsVitals.VitalSignsTemperature.Rows[0][dsVitals.VitalSignsTemperature.TempratureIdColumn].ToString(), null, dsVitals.VitalSignsTemperature.Rows[0][dsVitals.VitalSignsTemperature.VitalSignIdColumn].ToString(), patientId: model.PatientId);
                    dsTemperatureDbAudit.AcceptChanges();
                }

                if (dtRespirationChanges != null)
                {
                    dsRespirationDbAudit = new DBActivityAudit().InsertDBAudit(dtRespirationChanges, dbManager, dsVitals.VitalSignsRespiration.Rows[0][dsVitals.VitalSignsRespiration.RespirationIdColumn].ToString(), null, dsVitals.VitalSignsRespiration.Rows[0][dsVitals.VitalSignsRespiration.VitalSignIdColumn].ToString(), patientId: model.PatientId);
                    dsRespirationDbAudit.AcceptChanges();
                }

                #endregion
                return objUpdate;
            }
            catch (Exception ex)
            {
                dbManager.RollBackTransaction();
                throw ex;
            }
            finally
            {
                dbManager.Dispose();
                // dbManagerAudit.Dispose();
            }
        }

        #endregion



        private BLObject<DSVitals> InsertVitals(ref DSVitals ds, IDBManager dbManager)
        {
            try
            {
                ds = new DALVitals().InsertVitals(ref ds, dbManager);
                return new BLObject<DSVitals>(ds);
            }
            catch (Exception ex)
            {
                MDVLogger.BLLErrorLog("BLLClinical::InsertVitals", ex);
                return new BLObject<DSVitals>(null, ex.Message);
            }
        }


        public BLObject<DSVitals> updateVitalsActiveInActive(DSVitals dsVitals)
        {
            IDBManager dbManager = ClientConfiguration.GetDBManager();

            BLObject<DSVitals> objUpdate = null;
            try
            {
                dbManager.BeginTransaction();
                objUpdate = UpdateVitals(dsVitals, dbManager);
                dbManager.CommitTransaction();
                dsVitals.AcceptChanges();
                return objUpdate;
            }
            catch (Exception ex)
            {
                dbManager.RollBackTransaction();
                throw ex;
            }
        }

        public BLObject<DSVitals> UpdateVitals(DSVitals ds, IDBManager dbManager = null)
