        public BLObject<DSVitals> attachVitalSignFromNotes(string VitalSignId, long PatientId, long VisitId, long NotesId, string username)
        {
            try
            {
                DSVitals ds = new DSVitals();
                ds = new DALVitals().attachVitalSignFromNotes(VitalSignId, PatientId, VisitId, NotesId, username);

                #region Dbaudit for copied vital
                if (ds.Tables[ds.VitalSigns.TableName].Rows.Count > 0 && !string.IsNullOrEmpty(MDVUtility.ToStr(ds.Tables[ds.VitalSigns.TableName].Rows[0][ds.VitalSigns.CopyParentIdColumn.ColumnName])))
                {
                    DSDBAudit dsDBAudit = new DSDBAudit();

                    IDBManager dbManager = ClientConfiguration.GetDBManager();
                    try
                    {
                        DSVitals dsNew = new DSVitals();

                        foreach (DataRow dr in ds.Tables[ds.VitalSigns.TableName].Rows)
                        {
                            dsNew.Tables[dsNew.VitalSigns.TableName].Rows.Add(dr.ItemArray);
                        }

                        DataTable dtTemp = dsNew.VitalSigns.GetChanges();
                        dbManager.BeginTransaction();
                        if (dtTemp != null && ds.VitalSigns.Rows.Count > 0)
                        {
                            dsDBAudit = new DBActivityAudit().InsertDBAudit(dtTemp, dbManager, dsNew.VitalSigns.Rows[0][dsNew.VitalSigns.VitalSignIdColumn].ToString(), null, dsNew.VitalSigns.Rows[0][dsNew.VitalSigns.VitalSignIdColumn].ToString());
                            dsDBAudit.AcceptChanges();

                            long newVitalId = MDVUtility.ToInt64(dsNew.VitalSigns.Rows[0][dsNew.VitalSigns.VitalSignIdColumn].ToString());
                            DSVitals dsVitalsBP = new DALVitals().LoadVitalSignsBloodPressure(0, newVitalId);
                            dsNew.Clear();

                            foreach (DataRow dr in dsVitalsBP.Tables[dsVitalsBP.VitalSignsBloodPressure.TableName].Rows)
                            {
                                dsNew.Tables[dsNew.VitalSignsBloodPressure.TableName].Rows.Add(dr.ItemArray);
                            }
                            dtTemp = dsNew.VitalSignsBloodPressure.GetChanges();
                            if (dtTemp != null)
                            {
                                dsDBAudit = new DBActivityAudit().InsertDBAudit(dtTemp, dbManager, dsNew.VitalSignsBloodPressure.Rows[0][dsNew.VitalSignsBloodPressure.BPIdColumn].ToString(), null, dsNew.VitalSignsBloodPressure.Rows[0][dsNew.VitalSignsBloodPressure.VitalSignIdColumn].ToString());
                                dsDBAudit.AcceptChanges();
                            }

                            DSVitals dsVitalsPulse = new DALVitals().LoadVitalSignsPulse(0, newVitalId);
                            dsNew.Clear();

                            foreach (DataRow dr in dsVitalsPulse.Tables[dsVitalsPulse.VitalSignsPulse.TableName].Rows)
                            {
                                dsNew.Tables[dsNew.VitalSignsPulse.TableName].Rows.Add(dr.ItemArray);
                            }
                            dtTemp = dsNew.VitalSignsPulse.GetChanges();
                            if (dtTemp != null)
                            {
                                dsDBAudit = new DBActivityAudit().InsertDBAudit(dtTemp, dbManager, dsNew.VitalSignsPulse.Rows[0][dsNew.VitalSignsPulse.PulseIdColumn].ToString(), null, dsNew.VitalSignsPulse.Rows[0][dsNew.VitalSignsPulse.VitalSignIdColumn].ToString());
                                dsDBAudit.AcceptChanges();
                            }

                            DSVitals dsVitalsTemp = new DALVitals().LoadVitalSignsTemperature(0, newVitalId);
                            dsNew.Clear();

                            foreach (DataRow dr in dsVitalsTemp.Tables[dsVitalsTemp.VitalSignsTemperature.TableName].Rows)
                            {
                                dsNew.Tables[dsNew.VitalSignsTemperature.TableName].Rows.Add(dr.ItemArray);
                            }
                            dtTemp = dsNew.VitalSignsTemperature.GetChanges();
                            if (dtTemp != null)
                            {
                                dsDBAudit = new DBActivityAudit().InsertDBAudit(dtTemp, dbManager, dsNew.VitalSignsTemperature.Rows[0][dsNew.VitalSignsTemperature.TempratureIdColumn].ToString(), null, dsNew.VitalSignsTemperature.Rows[0][dsNew.VitalSignsTemperature.VitalSignIdColumn].ToString());
                                dsDBAudit.AcceptChanges();
                            }
                            DSVitals dsVitalsRP = new DALVitals().LoadVitalSignsRespiration(0, newVitalId);
                            dsNew.Clear();
                            dsNew.Tables[dsNew.VitalSignsRespiration.TableName].Columns.Add("RhythmId", typeof(int));
                            foreach (DataRow dr in dsVitalsRP.Tables[dsVitalsRP.VitalSignsRespiration.TableName].Rows)
                            {
                                dsNew.Tables[dsNew.VitalSignsRespiration.TableName].Rows.Add(dr.ItemArray);
                            }
                            dtTemp = dsNew.VitalSignsRespiration.GetChanges();
                            if (dtTemp != null)
                            {
                                dsDBAudit = new DBActivityAudit().InsertDBAudit(dtTemp, dbManager, dsNew.VitalSignsRespiration.Rows[0][dsNew.VitalSignsRespiration.RespirationIdColumn].ToString(), null, dsNew.VitalSignsRespiration.Rows[0][dsNew.VitalSignsRespiration.VitalSignIdColumn].ToString());
                                dsDBAudit.AcceptChanges();
                            }
                        }
                        dbManager.CommitTransaction();
                    }
                    catch (Exception ex)
                    {
                        dsDBAudit.RejectChanges();
                        dbManager.RollBackTransaction();
                        throw ex;
                    }
                }

                #endregion Dbaudit for copied vital

                return new BLObject<DSVitals>(ds);
            }
            catch (Exception ex)
            {
                MDVLogger.BLLErrorLog("BLLClinical::AttachVitalSignFromNotes", ex);
                return new BLObject<DSVitals>(null, ex.Message);
            }
        }

