        public BLObject<DSVitals> LoadVitals(long patientId, long VitalSignId, int? pageNumber = 1, int? rowsPerPage = 1000, string isViewVitals = "", string isPrintVitals = "", long NotesId = 0)
        {
            try
            {
                DSVitals ds = new DSVitals();
                ds = new DALVitals().LoadVitals(patientId, VitalSignId, pageNumber, rowsPerPage, isViewVitals, isPrintVitals, NotesId);
                if (VitalSignId > 0)
                {
                    // Load VitalSigns BloodPressure
                    DSVitals dsVitalsBloodPressure = new DALVitals().LoadVitalSignsBloodPressure(0, VitalSignId);
                    if (dsVitalsBloodPressure != null)
                    {
                        ds.Merge(dsVitalsBloodPressure);
                    }

                    //Load VitalSigns Pulse
                    DSVitals dsVitalsPulse = new DALVitals().LoadVitalSignsPulse(0, VitalSignId);
                    if (dsVitalsPulse != null)
                    {
                        ds.Merge(dsVitalsPulse);
                    }

                    //Load VitalSigns Temperature
                    DSVitals dsVitalsTemperature = new DALVitals().LoadVitalSignsTemperature(0, VitalSignId);
                    if (dsVitalsTemperature != null)
                    {
                        ds.Merge(dsVitalsTemperature);
                    }

                    //Load VitalSigns Respiration
                    DSVitals dsVitalsRespiration = new DALVitals().LoadVitalSignsRespiration(0, VitalSignId);
                    if (dsVitalsRespiration != null)
                    {
                        ds.Merge(dsVitalsRespiration);
                    }

                }
                return new BLObject<DSVitals>(ds);
            }
            catch (Exception ex)
            {
                MDVLogger.BLLErrorLog("BLLClinical::LoadVitals", ex);
                return new BLObject<DSVitals>(null, ex.Message);
            }
        }


