        public BLObject<DSProcedures> saveProcedure(Model.Clinical.Medical.ProceduresModel model, IDBManager dbManager = null)
        {
            try
            {
                DSProcedures dsprocedures = new DSProcedures();
                for (int i = 0; i < model.procedureDetailModel.Count; i++)
                {

                    DSProcedures.ProceduresRow procModel = dsprocedures.Procedures.NewProceduresRow();
                    procModel.ProcedureId = -i;
                    procModel.Modifier = model.procedureDetailModel[i].Modifier;
                    procModel.Unit = model.procedureDetailModel[i].Unit;
                    procModel.IsLabBasedCPT = model.procedureDetailModel[i].IsLabBasedCPT;
                    if (!string.IsNullOrEmpty(model.procedureDetailModel[i].ProblemListId))
                    {
                        procModel.ProblemListId = MDVUtility.ToLong(model.procedureDetailModel[i].ProblemListId);
                        procModel.ICD9_DESCRIPTION = model.procedureDetailModel[i].ProblemListId_text;
                    }
                    else
                    {
                        procModel[dsprocedures.Procedures.ProblemListIdColumn] = DBNull.Value;
                        procModel.ICD9_DESCRIPTION = model.procedureDetailModel[i].ProblemListId_text;
                    }

                    if (!string.IsNullOrEmpty(model.procedureDetailModel[i].SNOMEDID))
                        procModel.SNOMEDID = model.procedureDetailModel[i].SNOMEDID;
                    else
                        procModel[dsprocedures.Procedures.SNOMEDIDColumn] = DBNull.Value;
                    if (!string.IsNullOrEmpty(model.procedureDetailModel[i].SNOMED_DESCRIPTION))
                        procModel.SNOMED_DESCRIPTION = model.procedureDetailModel[i].SNOMED_DESCRIPTION;
                    else
                        procModel[dsprocedures.Procedures.SNOMED_DESCRIPTIONColumn] = DBNull.Value;

                    if (!string.IsNullOrEmpty(model.procedureDetailModel[i].ReasonId))
                    {
                        procModel.ReasonId = model.procedureDetailModel[i].ReasonId;
                    }
                    else
                    {
                        procModel[dsprocedures.Procedures.ReasonIdColumn] = DBNull.Value;
                    }

                    if (!string.IsNullOrEmpty(model.procedureDetailModel[i].StartDate))
                    {
                        procModel.StartDate = MDVUtility.ToDateTime(model.procedureDetailModel[i].StartDate);
                    }
                    else
                    {
                        procModel[dsprocedures.Procedures.StartDateColumn] = DBNull.Value;
                    }
                    if (!string.IsNullOrEmpty(model.procedureDetailModel[i].EndDate))
                    {
                        procModel.EndDate = MDVUtility.ToDateTime(model.procedureDetailModel[i].EndDate);
                    }
                    else
                    {
                        procModel[dsprocedures.Procedures.EndDateColumn] = DBNull.Value;
                    }

                    if (!string.IsNullOrEmpty(model.procedureDetailModel[i].Comments))
                    {
                        procModel.Comments = MDVUtility.ToStr(model.procedureDetailModel[i].Comments);
                    }
                    else
                    {
                        procModel[dsprocedures.Procedures.CommentsColumn] = DBNull.Value;
                    }


                    procModel.PatientId = MDVUtility.ToLong(model.procedureDetailModel[i].PatientId);
                    if (!string.IsNullOrEmpty(model.procedureDetailModel[i].NotesId) && MDVUtility.ToLong(model.procedureDetailModel[i].NotesId) != -1 && MDVUtility.ToLong(model.procedureDetailModel[i].NotesId) != 0)
                    {
                        procModel.NoteId = MDVUtility.ToLong(model.procedureDetailModel[i].NotesId);
                    }
                    else
                    {
                        procModel[dsprocedures.Procedures.NoteIdColumn] = DBNull.Value;
                    }

                    if (MDVUtility.ToStr(model.procedureDetailModel[i].VaccineHxId) != "")
                    {
                        procModel.VaccineHxId = MDVUtility.ToLong(model.procedureDetailModel[i].VaccineHxId);
                    }
                    else
                    {
                        procModel[dsprocedures.Procedures.VaccineHxIdColumn] = DBNull.Value;
                    }
                    if (MDVUtility.ToStr(model.procedureDetailModel[i].ImmTherInjectionId) != "")
                    {
                        procModel.ImmTherInjectionId = MDVUtility.ToLong(model.procedureDetailModel[i].ImmTherInjectionId);
                    }
                    else
                    {
                        procModel[dsprocedures.Procedures.ImmTherInjectionIdColumn] = DBNull.Value;
                    }

                    if (MDVUtility.ToStr(model.procedureDetailModel[i].CPTId) != "")
                    {
                        procModel.CPTId = MDVUtility.ToLong(model.procedureDetailModel[i].CPTId);
                    }
                    else
                    {
                        procModel[dsprocedures.Procedures.CPTIdColumn] = DBNull.Value;
                    }
                    if (!string.IsNullOrEmpty(model.procedureDetailModel[i].IsFromSupperBill) && model.procedureDetailModel[i].IsFromSupperBill == "1")
                    {
                        procModel[dsprocedures.Procedures.IsFromSupperBillColumn] = true;
                    }
                    else
                    {
                        procModel[dsprocedures.Procedures.IsFromSupperBillColumn] = DBNull.Value;
                    }

                    if (MDVUtility.ToInt64(model.CustomFormId) > 0)
                        procModel.CustomFormId = MDVUtility.ToInt64(model.CustomFormId);
                    else
                        procModel[dsprocedures.Procedures.CustomFormIdColumn] = DBNull.Value;

                    procModel.IsActive = true;
                    procModel.ProblemListId = MDVUtility.ToLong(model.procedureDetailModel[i].ProblemListId);
                    procModel.CPTCode = MDVUtility.ToStr(model.procedureDetailModel[i].CPTCode);
                    procModel.CPT_DESCRIPTION = MDVUtility.ToStr(model.procedureDetailModel[i].CPT_DESCRIPTION);
                    procModel.CreatedBy = MDVUtility.DecryptFrom64(MDVSession.Current.AppUserName);
                    procModel.CreatedOn = DateTime.Now;
                    procModel.ModifiedBy = MDVUtility.DecryptFrom64(MDVSession.Current.AppUserName);
                    procModel.ModifiedOn = DateTime.Now;
                    procModel.Surgical = model.procedureDetailModel[i].Surgical;
                    dsprocedures.Procedures.AddProceduresRow(procModel);
                }

                BLObject<DSProcedures> obj = new BLObject<DSProcedures>();
                if (dbManager != null)
                    obj = insertProcedure(dbManager, dsprocedures);
                else
                    obj = insertProcedure(dsprocedures);

                if (obj.Data != null)
                {
                    dsprocedures = obj.Data;
                }
                else
                {
                    throw new Exception(obj.Message);
                }

                return new BLObject<DSProcedures>(dsprocedures);
            }
            catch (Exception ex)
            {
                return new BLObject<DSProcedures>(null, ex.Message);
            }
        }

        public BLObject<DSProcedures> updateProcedures(List<ProceduresDetailModel> model, IDBManager dbManager = null)
        {
            try
            {
                if (MDVUtility.ToInt32(model[0].ProcedureId) > 0)
                {
                    DSProcedures dsProcedures = null;
                    BLObject<DSProcedures> obj;
                    obj = loadProcedures_Obsolete(MDVUtility.ToInt32(model[0].ProcedureId), MDVUtility.ToInt64(model[0].PatientId), MDVUtility.ToInt64(model[0].NotesId), "1", MDVUtility.ToStr(model[0].IsActive), MDVUtility.ToInt32(model[0].PageNumber), MDVUtility.ToInt32(model[0].RowsPerPage), "", "", "", "1", "", "1");
                    dsProcedures = obj.Data;
                    //-----------------------------------
                    foreach (DSProcedures.ProceduresRow dr in dsProcedures.Tables[dsProcedures.Procedures.TableName].Rows)
                    {
                        if (!string.IsNullOrEmpty(model[0].StartDate))
                        {
                            dr.StartDate = MDVUtility.ToDateTime(model[0].StartDate);
                        }
                        else
                        {
                            dr[dsProcedures.Procedures.StartDateColumn] = DBNull.Value;
                        }
                        if (!string.IsNullOrEmpty(model[0].EndDate))
                        {
                            dr.EndDate = MDVUtility.ToDateTime(model[0].EndDate);
                        }
                        else
                        {
                            dr[dsProcedures.Procedures.EndDateColumn] = DBNull.Value;
                        }
                        if (!string.IsNullOrEmpty(model[0].ReasonId))
                        {
                            dr.ReasonId = model[0].ReasonId;
                        }
                        else
                        {
                            dr[dsProcedures.Procedures.ReasonIdColumn] = DBNull.Value;
                        }

                        if (!string.IsNullOrEmpty(model[0].CQMEncounterTypeId))
                        {
                            dr.CQMEncounterTypeId = MDVUtility.ToInt64(model[0].CQMEncounterTypeId);
                        }
                        else
                        {
                            dr[dsProcedures.Procedures.CQMEncounterTypeIdColumn] = DBNull.Value;
                        }

                        dr.Comments = MDVUtility.ToStr(model[0].Comments);
                        if (!string.IsNullOrEmpty(model[0].PatientId))
                            dr.PatientId = MDVUtility.ToInt64(model[0].PatientId);
                        if (model[0].IsActive != null)
                        {
                            if (model[0].IsActive == "1") model[0].IsActive = "true"; else model[0].IsActive = "false";
                        }


                        if (!string.IsNullOrEmpty(model[0].IsActive))
                            dr.IsActive = Boolean.Parse(model[0].IsActive);

                        dr.ModifiedBy = MDVUtility.DecryptFrom64(MDVSession.Current.AppUserName);
                        dr.ModifiedOn = DateTime.Now;
                        if (!string.IsNullOrEmpty(model[0].InActiveChkBoxValue))
                            dr.InActiveChkBoxValue = MDVUtility.ToStr(model[0].InActiveChkBoxValue);
                        if (!string.IsNullOrEmpty(model[0].InActiveReason))
                            dr.InActiveReason = MDVUtility.ToStr(model[0].InActiveReason);
                        if (!string.IsNullOrEmpty(model[0].ProblemListId))
                            dr.ProblemListId = MDVUtility.ToInt64(model[0].ProblemListId);
                        //Start 28-09-2017 Edit By Humaira Yousaf Bug# EMR-4849
                        else
                        {
                            dr[dsProcedures.Procedures.ProblemListIdColumn] = DBNull.Value;
                        }
                        //End 28-09-2017 Edit By Humaira Yousaf Bug# EMR-4849
                        if (!string.IsNullOrEmpty(model[0].CPTCode))
                            dr.CPTCode = MDVUtility.ToStr(model[0].CPTCode);
                        if (!string.IsNullOrEmpty(model[0].CPT_DESCRIPTION))
                            dr.CPT_DESCRIPTION = MDVUtility.ToStr(model[0].CPT_DESCRIPTION);

                        var ICD10description = "";
                        var Code9 = "";
                        var Code10 = "";
                        if (model[0].ProblemListId_text != null && model[0].ProblemListId_text != "")
                        {
                            var SplitedProblemListText = model[0].ProblemListId_text.ToString().Split('-');
                            if (SplitedProblemListText.Count() >= 1)
                            {
                                Code9 = SplitedProblemListText[0];
                            }
                            if (SplitedProblemListText.Count() > 1)
                            {
                                Code10 = SplitedProblemListText[1];
                            }
                            for (int j = 2; j < SplitedProblemListText.Count(); j++)
                            {
                                ICD10description += SplitedProblemListText[j];
                            }
                        }
                        if (MDVUtility.ToLong(model[0].NotesId) != -1 && MDVUtility.ToLong(model[0].NotesId) != 0)
                        {
                            dr.NoteId = MDVUtility.ToLong(model[0].NotesId);
                        }
                        else
                        {
                            dr[dsProcedures.Procedures.NoteIdColumn] = DBNull.Value;
                        }
                        dr.Modifier = model[0].Modifier;
                        dr.Unit = model[0].Unit;
                        dr.ICD9 = Code9;
                        dr.ICD9_DESCRIPTION = Code9;
                        dr.ICD10 = Code10;
                        dr.ICD10_DESCRIPTION = ICD10description;
                        //     procModel.ProblemListId = MDVUtility.ToLong(model.procedureDetailModel[i].ProblemListId);
                        dr.Surgical = model[0].Surgical;

                    }

                    #region Database Updation

                    if (obj.Data != null)
                    {
                        BLObject<DSProcedures> objUpdate = new BLObject<DSProcedures>();
                        if (dbManager != null)
                            objUpdate = updateProcedure(dbManager, dsProcedures);
                        else
                            objUpdate = updateProcedure(dsProcedures);

                        if (objUpdate.Data != null)
                        {
                            dsProcedures = objUpdate.Data;
                        }
                        else
                        {
                            throw new Exception(objUpdate.Message);
                        }
                    }
                    else
                    {
                        throw new Exception("Procedures not found.");
                    }

                    return new BLObject<DSProcedures>(dsProcedures);

                    #endregion
                }
                else
                {
                    throw new Exception("Procedures not found.");
                }
            }
            catch (Exception ex)
            {
                return new BLObject<DSProcedures>(null, MDVCustomException.HumanReadableMessage(ex.Message));
            }
        }

