        public BLObject<string> detachProblemListFromNotes(string ProblemListId, long NotesId)
        {
            try
            {
                var msgProblemListId = new DALProblemLists().detachProblemListsFromNotes(ProblemListId, NotesId);
                return new BLObject<string>(msgProblemListId);
            }
