        // Author:  Muhammad Arshad
        // Created Date: 04/12/2015
        //OverView: Loads SocialHx on basis of patientId, SocialHxId, SocialHxType

        public BLObject<DSSocialHistory> LoadSocialHx(long patientId, long SocialHxId, string SocialHxType = "", string isViewSocialHx = "", string isPrintSocialHx = "")
        {
            try
            {
                DSSocialHistory ds = new DSSocialHistory();
                ds = new DALSocialHistory().LoadSocialHx(patientId, SocialHxId);
                if (ds.Tables[ds.SocialHx.TableName].Rows.Count > 0 && SocialHxType != "")
                {
                    Int64 currentSocialHxId = MDVUtility.ToInt64(ds.Tables[ds.SocialHx.TableName].Rows[0][ds.SocialHx.SocialHxIdColumn.ColumnName]);
                    if (currentSocialHxId > 0)
                    {
                        if (SocialHxType.ToLower() == "tobacco")
                        {
                            //Load SocialHx Tobacco
                            DSSocialHistory dsSocialHxTobacco = new DALSocialHistory().LoadTobaccoHistory(0, currentSocialHxId, isViewSocialHx, isPrintSocialHx);
                            if (dsSocialHxTobacco != null)
                            {
                                ds.Merge(dsSocialHxTobacco);
                            }
                        }

                        else if (SocialHxType.ToLower() == "alcohol")
                        {
                            //Load SocialHx Alcohol
                            DSSocialHistory dsSocialHxAlcohol = new DALSocialHistory().LoadAlcoholHistory(0, currentSocialHxId, isViewSocialHx, isPrintSocialHx);
                            if (dsSocialHxAlcohol != null)
                            {
                                ds.Merge(dsSocialHxAlcohol);
                            }
                        }

                        else if (SocialHxType.ToLower() == "drug")
                        {
                            //Load SocialHx Drug
                            DSSocialHistory dsSocialHxDrug = new DALSocialHistory().LoadDrugHistory(0, currentSocialHxId, isViewSocialHx, isPrintSocialHx);
                            if (dsSocialHxDrug != null)
                            {
                                ds.Merge(dsSocialHxDrug);
                            }
                        }
                        else if (SocialHxType.ToLower() == "sexual")
                        {
                            //Load SocialHx Drug
                            DSSocialHistory dsSocialHxSexualHistory = new DALSocialHistory().LoadSexualHistory(0, currentSocialHxId, isViewSocialHx, isPrintSocialHx);
                            if (dsSocialHxSexualHistory != null)
                            {
                                ds.Merge(dsSocialHxSexualHistory);
                            }
                        }
                        else if (SocialHxType.ToLower().IndexOf("miscellaneous") > -1)
                        {
                            //Load MiscHx against current SocialHx
                            DSSocialHistory dsMiscHx = new DALSocialHistory().LoadMiscHx(0, currentSocialHxId);
                            if (dsMiscHx != null)
                            {
                                ds.Merge(dsMiscHx);
                            }

                            //Start 13/01/2016 Muhammad Arshad Load MiscHx Components for MiscHxTab
                            DSSocialHistory dsMiscHxComponent = new DALSocialHistory().loadMiscHx_Component(0);
                            if (dsMiscHxComponent != null)
                            {
                                if (dsMiscHxComponent.SocialHx_MiscHx_Component.Rows.Count < 1)
                                {
                                    DSSocialHistory.SocialHx_MiscHx_ComponentRow drComponent = dsMiscHxComponent.SocialHx_MiscHx_Component.NewSocialHx_MiscHx_ComponentRow();
                                    drComponent.ComponentId = -1;
                                    drComponent.UserId = MDVSession.Current.AppUserId;
                                    drComponent[dsMiscHxComponent.SocialHx_MiscHx_Component.ComponentNameColumn] = DBNull.Value;
                                    drComponent[dsMiscHxComponent.SocialHx_MiscHx_Component.ComponentOrderColumn] = DBNull.Value;
                                    drComponent[dsMiscHxComponent.SocialHx_MiscHx_Component.SortOrderColumn] = DBNull.Value;
                                    drComponent.IsActive = true;
                                    drComponent.CreatedBy = MDVUtility.DecryptFrom64(MDVSession.Current.AppUserName);
                                    drComponent.CreatedOn = DateTime.Now;
                                    drComponent.ModifiedBy = MDVUtility.DecryptFrom64(MDVSession.Current.AppUserName);
                                    drComponent.ModifiedOn = DateTime.Now;
                                    dsMiscHxComponent.SocialHx_MiscHx_Component.AddSocialHx_MiscHx_ComponentRow(drComponent);
                                    dsMiscHxComponent = new DALSocialHistory().insertUpdateMiscHx_Component(dsMiscHxComponent);
                                    dsMiscHxComponent = new DALSocialHistory().loadMiscHx_Component(0);
                                }

                                ds.Merge(dsMiscHxComponent);
                            }
                            //End 13/01/2016 Muhammad Arshad Load MiscHx Components for MiscHxTab

                            //Start 08-01-2016 Muhammad Arshad Load MiscHx Childs Tabs against current MiscHx
                            if (dsMiscHx.Tables[dsMiscHx.SocialHx_MiscHx.TableName].Rows.Count > 0)
                            {
                                Int64 currentMiscHxId = MDVUtility.ToInt64(ds.Tables[ds.SocialHx_MiscHx.TableName].Rows[0][ds.SocialHx_MiscHx.MiscHxIdColumn.ColumnName]);
                                //Start 28-10-2016 Humaira Yousaf to only load selected tab data
                                //if (SocialHxType.ToLower().Equals("miscellaneous_occupation"))
                                //{
                                //    //Start 08-01-2016 Muhammad Arshad Load Occupation Tab against current MiscHx
                                //    DSSocialHistory dsMiscHxOccupationHx = new DALSocialHistory().loadMiscHxOccupationHx(0, currentMiscHxId, "1", "");
                                //    if (dsMiscHxOccupationHx != null)
                                //    {
                                //        ds.Merge(dsMiscHxOccupationHx);
                                //    }
                                //    //End 08-01-2016 Muhammad Arshad Load Occupation Tab against current MiscHx
                                //}
                                if (SocialHxType.ToLower().Equals("miscellaneous_sleep"))
                                {
                                    //Start 08-01-2016 Muhammad Arshad Load Sleep Tab against current MiscHx
                                    DSSocialHistory dsMiscHxSleepHx = new DALSocialHistory().loadMiscHxSleepHx(0, currentMiscHxId, "1", "");
                                    if (dsMiscHxSleepHx != null)
                                    {
                                        ds.Merge(dsMiscHxSleepHx);
                                    }

                                    //End 08-01-2016 Muhammad Arshad Load Sleep Tab against current MiscHx
                                }
                                if (SocialHxType.ToLower().Equals("miscellaneous_exercises"))
                                {
                                    //Start 08-01-2016 Muhammad Arshad Load Exercises Tab against current MiscHx
                                    DSSocialHistory dsMiscHxExercisesHx = new DALSocialHistory().loadMiscHxExercisesHx(0, currentMiscHxId, "1", "");
                                    if (dsMiscHxExercisesHx != null)
                                    {
                                        ds.Merge(dsMiscHxExercisesHx);
                                    }
                                    //End 08-01-2016 Muhammad Arshad Load Exercises Tab against current MiscHx
                                }
                                if (SocialHxType.ToLower().Equals("miscellaneous_housing"))
                                {
                                    //Start 08-01-2016 Muhammad Arshad Load Housing Tab against current MiscHx

                                    DSSocialHistory dsMiscHxHousingHx = new DALSocialHistory().loadMiscHxHousingHx(0, currentMiscHxId, "1", "");
                                    if (dsMiscHxHousingHx != null)
                                    {
                                        ds.Merge(dsMiscHxHousingHx);
                                    }
                                    //End 08-01-2016 Muhammad Arshad Load Housing Tab against current MiscHx
                                }
                                if (SocialHxType.ToLower().Equals("miscellaneous_caffeineintake"))
                                {
                                    //Start 08-01-2016 syed Zia Load CaffeineIntake Tab against current MiscHx
                                    DSSocialHistory dsMiscHxCaffeineIntakeHx = new DALSocialHistory().loadMiscHxCaffeineIntakeHx(0, currentMiscHxId, "1", "");//new DALSocialHistory().loadMiscHxOccupationHx(0, currentMiscHxId);
                                    if (dsMiscHxCaffeineIntakeHx != null)
                                    {
                                        ds.Merge(dsMiscHxCaffeineIntakeHx);
                                    }
                                    //End 08-01-2016 Muhammad Arshad Load CaffeineIntake Tab against current MiscHx
                                }
                                //if (SocialHxType.ToLower().Equals("miscellaneous_travel"))
                                //{
                                //    DSSocialHistory dsMiscHxTravelHx = new DALSocialHistory().loadMiscHxTravelHx(0, currentMiscHxId, "1", "");
                                //    if (dsMiscHxTravelHx != null)
                                //        ds.Merge(dsMiscHxTravelHx);
                                //}
                                //End 28-10-2016 Humaira Yousaf to only load selected tab data
                            }
                            //End 08-01-2016 Syed Zia Load MiscHx Childs Tabs against current MiscHx
                        }
                    }

                }
                else
                {
                    if (SocialHxType.ToLower().IndexOf("miscellaneous") > -1)
                    {
                        //Start 13/01/2016 Muhammad Arshad Load MiscHx Components for MiscHxTab
                        DSSocialHistory dsMiscHxComponent = new DALSocialHistory().loadMiscHx_Component(0);
                        if (dsMiscHxComponent != null)
                        {
                            if (dsMiscHxComponent.SocialHx_MiscHx_Component.Rows.Count < 1)
                            {
                                DSSocialHistory.SocialHx_MiscHx_ComponentRow drComponent = dsMiscHxComponent.SocialHx_MiscHx_Component.NewSocialHx_MiscHx_ComponentRow();
                                drComponent.ComponentId = -1;
                                drComponent.UserId = MDVSession.Current.AppUserId;
                                drComponent[dsMiscHxComponent.SocialHx_MiscHx_Component.ComponentNameColumn] = DBNull.Value;
                                drComponent[dsMiscHxComponent.SocialHx_MiscHx_Component.ComponentOrderColumn] = DBNull.Value;
                                drComponent[dsMiscHxComponent.SocialHx_MiscHx_Component.SortOrderColumn] = DBNull.Value;
                                drComponent.IsActive = true;
                                drComponent.CreatedBy = MDVUtility.DecryptFrom64(MDVSession.Current.AppUserName);
                                drComponent.CreatedOn = DateTime.Now;
                                drComponent.ModifiedBy = MDVUtility.DecryptFrom64(MDVSession.Current.AppUserName);
                                drComponent.ModifiedOn = DateTime.Now;
                                dsMiscHxComponent.SocialHx_MiscHx_Component.AddSocialHx_MiscHx_ComponentRow(drComponent);
                                dsMiscHxComponent = new DALSocialHistory().insertUpdateMiscHx_Component(dsMiscHxComponent);
                                dsMiscHxComponent = new DALSocialHistory().loadMiscHx_Component(0);
                            }

                            ds.Merge(dsMiscHxComponent);
                        }
                    }
                }
                return new BLObject<DSSocialHistory>(ds);
            }
            catch (Exception ex)
            {
                MDVLogger.BLLErrorLog("BLLClinical::LoadSocialHx", ex);
                return new BLObject<DSSocialHistory>(null, ex.Message);
            }
        }

