        public BLObject<DSHxMobileApp> LoadSocialHxMobileApp(long PatientId, string Status)
        {
            try
            {
                DSHxMobileApp ds = new DSHxMobileApp();
                #region Tabacco
                DSHxMobileApp dsSocialHxTobacco = new DALSocialHistory().LoadTobaccoHxMobileApp(PatientId, Status);
                if (dsSocialHxTobacco != null)
                {
                    ds.Merge(dsSocialHxTobacco);
                }
                #endregion
                #region Alcohol
                DSHxMobileApp dsSocialHxAlcohol = new DALSocialHistory().LoadAlcoholHxMobileApp(PatientId, Status);
                if (dsSocialHxAlcohol != null)
                {
                    ds.Merge(dsSocialHxAlcohol);
                }
                #endregion
                #region Drug
                DSHxMobileApp dsSocialHxDrug = new DALSocialHistory().LoadDrugHxMobileApp(PatientId, Status);
                if (dsSocialHxDrug != null)
                {
                    ds.Merge(dsSocialHxDrug);
                }
                #endregion
                #region Sexual
                DSHxMobileApp dsSocialHxSexualHistory = new DALSocialHistory().LoadSexualHxMobileApp(PatientId, Status);
                if (dsSocialHxSexualHistory != null)
                {
                    ds.Merge(dsSocialHxSexualHistory);
                }
                #endregion
                #region Occupation
                DSHxMobileApp dsMiscHxOccupationHx = new DALSocialHistory().loadMiscHxOccupationHxMobileApp(PatientId, Status);
                if (dsMiscHxOccupationHx != null)
                {
                    ds.Merge(dsMiscHxOccupationHx);
                }
                #endregion
                #region Exercise
                DSHxMobileApp dsMiscHxExercisesHx = new DALSocialHistory().loadMiscHxExercisesHxMobileApp(PatientId, Status);
                if (dsMiscHxExercisesHx != null)
                {
                    ds.Merge(dsMiscHxExercisesHx);
                }
                #endregion
                #region Sleep
                DSHxMobileApp dsMiscHxSleepHx = new DALSocialHistory().loadMiscHxSleepHxMobileApp(PatientId, Status);
                if (dsMiscHxSleepHx != null)
                {
                    ds.Merge(dsMiscHxSleepHx);
                }
                #endregion
                #region Housing
                DSHxMobileApp dsMiscHxHousingHx = new DALSocialHistory().loadMiscHxHousingHxMobileApp(PatientId, Status);
                if (dsMiscHxHousingHx != null)
                {
                    ds.Merge(dsMiscHxHousingHx);
                }
                #endregion
                #region Cafeine
                DSHxMobileApp dsMiscHxCaffeineIntakeHx = new DALSocialHistory().loadMiscHxCaffeineIntakeHxMobileApp(PatientId, Status);//new DALSocialHistory().loadMiscHxOccupationHx(0, currentMiscHxId);
                if (dsMiscHxCaffeineIntakeHx != null)
                {
                    ds.Merge(dsMiscHxCaffeineIntakeHx);
                }
                #endregion
                #region Travel
                DSHxMobileApp dsMiscHxTravelHx = new DALSocialHistory().loadMiscHxTravelHxMobileApp(PatientId, Status);
                if (dsMiscHxTravelHx != null)
                {
                    ds.Merge(dsMiscHxTravelHx);
                }
                #endregion
                return new BLObject<DSHxMobileApp>(ds);
            }
            catch (Exception ex)
            {
                MDVLogger.BLLErrorLog("BLLClinical::LoadSocialHx", ex);
                return new BLObject<DSHxMobileApp>(null, ex.Message);
            }
        }

        public BLObject<DSSocialHistory> CheckSocialHxExists(long PatientId)
        {
            try
            {
                DSSocialHistory ds = new DSSocialHistory();
                ds = new DALSocialHistory().CheckSocialHxExists(PatientId);

                return new BLObject<DSSocialHistory>(ds);

            }
            catch (Exception ex)
            {
                MDVLogger.BLLErrorLog("BLLAdminProfile::LoadSpecialty", ex);
                return new BLObject<DSSocialHistory>(null, ex.Message);
            }
        }
