        #region SurgicalHx

        /// <summary>
        /// Author:  Muhammad Arshad
        /// Date:    28/01/2016
        /// Reason:  This function will load  surgicalhx
        /// </summary>
        /// <param name="PatientId"></param>
        /// <param name="SurgicalHxId"></param>
        /// <param name="DiseaseId"></param>
        /// <returns></returns>
        public BLObject<DSSurgicalHx> LoadSurgicalHx(long PatientId, long SurgicalHxId, long DiseaseId = 0, string isViewSurgicalHx = "", string isPrintSurgicalHx = "")
        {
            try
            {
                DSSurgicalHx ds = new DSSurgicalHx();
                ds = new DALSurgicalHx().LoadSurgicalHx(PatientId, SurgicalHxId, isViewSurgicalHx, isPrintSurgicalHx);

                if (ds.Tables[ds.SurgicalHx.TableName].Rows.Count > 0)
                {
                    Int64 currentSurgicalHxId = MDVUtility.ToInt64(ds.Tables[ds.SurgicalHx.TableName].Rows[0][ds.SurgicalHx.SurgicalHxIdColumn.ColumnName]);
                    if (currentSurgicalHxId > 0)
                    {
                        DSSurgicalHx dsSurgicalHxDisease = new DSSurgicalHx();
                        dsSurgicalHxDisease = new DALSurgicalHx().LoadSurgicalHx_Disease(currentSurgicalHxId, DiseaseId, "1", "");
                        if (dsSurgicalHxDisease != null)
                        {
                            ds.Merge(dsSurgicalHxDisease);
                        }
                    }
                }

                return new BLObject<DSSurgicalHx>(ds);
            }
            catch (Exception ex)
            {
                MDVLogger.BLLErrorLog("BLLClinical::LoadSurgicalHx", ex);
                return new BLObject<DSSurgicalHx>(null, ex.Message);
            }
        }

