        /// <summary>
        /// Author : Khaleel Ur Rehman
        /// Purpose : loookup for Load BirthHx.
        /// Date : 6 january 2016
        /// </summary>
        /// <param name="patientId"></param>
        /// <param name="birthHxId"></param>
        /// <param name="isChildRequired">if BirthHistory General, Newborn, Maternal & Delivery Info Is also required</param>
        /// <returns></returns>
        public BLObject<DSBirthHistory> loadBirthHx(long patientId, long birthHxId, bool isChildRequired, string isViewMedicalHx = "", string isPrintMedicalHx = "")
        {
            try
            {
                DSBirthHistory ds = new DSBirthHistory();
                ds = new DALBirthHistory().loadBirthHx(patientId, birthHxId, isViewMedicalHx, isPrintMedicalHx);
                if (ds.Tables[ds.BirthHx.TableName].Rows.Count > 0)
                {
                    Int64 currentBirthHxId = MDVUtility.ToInt64(ds.Tables[ds.BirthHx.TableName].Rows[0][ds.BirthHx.BirthHxIdColumn.ColumnName]);
                    Int64 currentGeneralId = MDVUtility.ToInt64(ds.Tables[ds.BirthHx.TableName].Rows[0][ds.BirthHx.GeneralIdColumn.ColumnName]);
                    Int64 currentMaternalDeliveryId = MDVUtility.ToInt64(ds.Tables[ds.BirthHx.TableName].Rows[0][ds.BirthHx.MaternalDeliveryIdColumn.ColumnName]);
                    Int64 currentNewbornId = MDVUtility.ToInt64(ds.Tables[ds.BirthHx.TableName].Rows[0][ds.BirthHx.NewbornIdColumn.ColumnName]);
                    if (currentBirthHxId > 0 && isChildRequired)
                    {
                        if (currentGeneralId > 0)
                        {
                            //Load BirthHx General
                            DSBirthHistory dsBirthHxGeneral = new DALBirthHistory().loadBirthHxGeneral(currentBirthHxId, currentGeneralId, isViewMedicalHx, isPrintMedicalHx);
                            if (dsBirthHxGeneral != null)
                            {
                                ds.Merge(dsBirthHxGeneral);
                            }
                        }

                        if (currentNewbornId > 0)
                        {
                            //Load BirthHx Newborn
                            DSBirthHistory dsBirthHxNewBorn = new DALBirthHistory().loadBirthHistoryNewBorn(currentBirthHxId, currentNewbornId, isViewMedicalHx, isPrintMedicalHx);
                            if (dsBirthHxNewBorn != null)
                            {
                                ds.Merge(dsBirthHxNewBorn);
                            }
                        }

                        if (currentMaternalDeliveryId > 0)
                        {
                            //Load BirthHx Maternal
                            DSBirthHistory dsBirthHxMaternalDelivery = new DALBirthHistory().loadBirthHxMaternalDelivery(currentBirthHxId, currentMaternalDeliveryId, isViewMedicalHx, isPrintMedicalHx);
                            if (dsBirthHxMaternalDelivery != null)
                            {
                                ds.Merge(dsBirthHxMaternalDelivery);
                            }
                        }

                    }

                }
                return new BLObject<DSBirthHistory>(ds);
            }
            catch (Exception ex)
            {
                MDVLogger.BLLErrorLog("BLLClinical::loadBirthHx", ex);
                return new BLObject<DSBirthHistory>(null, ex.Message);
            }
        }
