        #region"pdf creation for face sheet"
        /* Start 07/01/2016 Muhammad Irfan create pdf for face sheet */
        public BLObject<byte[]> previewFaceSheet(long UserId, long PatientId)
        {
            try
            {
                DSFaceSheet ds = new DSFaceSheet();
                List<FSImplantableDevicesModel> listImplantableDevices = new List<FSImplantableDevicesModel>();


                ds = new DALFaceSheet().loadFaceSheet_DS(0, UserId, PatientId, "", "1");

                ds.Merge(new DALPatient().FillPatient(PatientId, "", ""));

                foreach (DSFaceSheet.FaceSheetRow dr in ds.Tables[ds.FaceSheet.TableName].Rows)
                {
                    if (dr.ComponentName == "Allergies")
                        ds.Merge(new DALAllergies().loadAllergies_Obsolete(0, PatientId, 0, "0", "1", 1, 4));
                    if (dr.ComponentName == "Problem List")
                        ds.Merge(new DALProblemLists().LoadProblemLists(0, PatientId, 0, "0", "1", 1, 4));
                    if (dr.ComponentName == "Vitals")
                        ds.Merge(new DALVitals().LoadVitals(PatientId, 0, 1, 4));
                    if (dr.ComponentName == "Notes")
                        ds.Merge(new DALNotes().loadClinical_Notes(PatientId, 0, 0, 1, 4));
                    if (dr.ComponentName == "Appointments")
                        ds.Merge(new DALAppointment().LoadAppointmentsVisits(0, 0, 0, "", "", "", "", "", "0", 1, 15, "", PatientId, "1"));
                    if (dr.ComponentName == "History")
                        ds.Merge(new DALHistorySummary().loadHistorySummaryForSoap_Obsolete(PatientId, -1));
                    //Start//14-06-2016//Ahmad Raza// merging Medications data in facesheet dataset
                    if (dr.ComponentName == "Medications")
                        ds.Merge(new DALMedications().loadMedications(0, PatientId, 0, true, 1, 4, "", "", "", false));
                    //End//14-06-2016//Ahmad Raza// merging Medications data in facesheet dataset

                    //Start//14-06-2016//Ahmad Raza// merging Lab Result data in facesheet dataset
                    if (dr.ComponentName == "Lab Results")
                        ds.Merge(new DALLabResult().loadLabResultDetailForFaceSheet(PatientId));
                    //End//14-06-2016//Ahmad Raza// merging Lab Result data in facesheet dataset

                    //Start//15-06-2016//Ahmad Raza// merging Lab Order data in facesheet dataset
                    if (dr.ComponentName == "Lab Orders")
                        ds.Merge(new DALLabOrder().LoadLabOrder(0, PatientId, 0, "1", "4", "", "", 0, "", "", "", 0, "", ""));
                    //End//15-06-2016//Ahmad Raza// merging Lab Order data in facesheet dataset

                    //Start//15-06-2016//Ahmad Raza// merging Procedure Order data in facesheet dataset
                    if (dr.ComponentName == "Procedure Orders")
                        ds.Merge(new DALProcedureOrder().loadProcedureOrder(0, PatientId, "", "", 0, "", "", "", 1, 4, "", ""));
                    //End//15-06-2016//Ahmad Raza// merging Procedure Order data in facesheet dataset

                    //Start//15-06-2016//Ahmad Raza// merging Radiology Order data in facesheet dataset
                    if (dr.ComponentName == "Radiology Orders")
                        ds.Merge(new DALRadiologyOrder().LoadRadiologyOrder(0, PatientId, 0, "1", "4", "", "", 0, "", "", "", 0, "", ""));
                    //End//15-06-2016//Ahmad Raza// merging Radiology Order data in facesheet dataset

                    //Start//16-06-2016//Ahmad Raza// merging Patient Referrals data in facesheet dataset
                    if (dr.ComponentName == "Referrals")
                        //Start 15-08-2016 Humaira Yousaf for new parameters
                        ds.Merge(new DALPatientReferral().loadReferral(0, "1", 0, PatientId, "", 0, 0, "", "", 0, "", "", 0, 0, 0, 0, 1, 4, "", ""));
                    //End 15-08-2016 Humaira Yousaf for new parameters
                    //End//16-06-2016//Ahmad Raza// merging Patient Referrals data in facesheet dataset

                    //Start//16-06-2016//Ahmad Raza// merging Immunization data in facesheet dataset
                    if (dr.ComponentName == "Immunization")
                        ds.Merge(new DALImmunization().loadImmunizationForFaceSheet(PatientId));
                    //End//16-06-2016//Ahmad Raza// merging Immunization data in facesheet dataset

                    //Start//30-06-2016//Ahmad Raza// merging Chief Complaints data in facesheet dataset
                    if (dr.ComponentName == "Complaints")
                        ds.Merge(new DALComplaint().loadComplaintsForFaceSheet(PatientId, 1, 4));
                    //End//30-06-2016//Ahmad Raza// merging Chief Complaints data in facesheet dataset

                    //Start//30-06-2016//Ahmad Raza// merging Chief Complaints data in facesheet dataset
                    if (dr.ComponentName == "Patient Document")
                        ds.Merge(new DALPatientDocument().loadPatientDocumentForFaceSheet(PatientId, 1, 4));
                    //End//30-06-2016//Ahmad Raza// merging Chief Complaints data in facesheet dataset      

                    if (dr.ComponentName == "Implantable Devices")
                    {
                        BLObject<List<FSImplantableDevicesModel>> obj = loadFaceSheetImplantableDevices(PatientId);

                        if (obj.Data != null)
                        {
                            listImplantableDevices = obj.Data;
                        }
                    }
                }


                DSReportHeader.ReportHeaderTagsDataTable dtReportHeaderTags;

                bool IsReportHeaderApplied = false;
                var dsReportHeader = new MDVision.DataAccess.DAL.ReportHeader.DALReportHeader().getReportHeaderTagsValue(PatientId, 0, -1, "Face Sheet");
                IsReportHeaderApplied = dsReportHeader.ReportHeaderTags.Count > 0;
                dtReportHeaderTags = dsReportHeader.ReportHeaderTags;
                if (IsReportHeaderApplied &&
                     (
                            !string.IsNullOrEmpty(dsReportHeader.ReportHeaderTags[0]["PatientText"].ToString()) ||
                            !string.IsNullOrEmpty(dsReportHeader.ReportHeaderTags[0]["ProviderText"].ToString()) ||
                            !string.IsNullOrEmpty(dsReportHeader.ReportHeaderTags[0]["PracticeText"].ToString()) ||
                            !string.IsNullOrEmpty(dsReportHeader.ReportHeaderTags[0]["HeaderLogo"].ToString())
                            )
                    )
                {
                    IsReportHeaderApplied = true;
                }
                // return new BLObject<DSReportHeader>(dsReportHeader);

                byte[] newByteArr = null;
                using (MemoryStream stream_ = new MemoryStream())
                {
                    // Heading Font Style
                    var fontColour = new BaseColor(102, 178, 255);
                    iTextSharp.text.Font patientNameFont = FontFactory.GetFont("Arial", 12, iTextSharp.text.Font.BOLD, fontColour);
                    iTextSharp.text.Font bodyFont = FontFactory.GetFont("Arial", 10, iTextSharp.text.Font.NORMAL, iTextSharp.text.BaseColor.BLACK);
                    iTextSharp.text.Font componentHeadingFont = FontFactory.GetFont("Arial", 10, iTextSharp.text.Font.NORMAL, fontColour);
                    iTextSharp.text.Font componentHeaderFont = FontFactory.GetFont("Arial", 10, iTextSharp.text.Font.BOLD, iTextSharp.text.BaseColor.BLACK);
                    iTextSharp.text.Font BMIRedFont = FontFactory.GetFont("Arial", 10, iTextSharp.text.Font.NORMAL, iTextSharp.text.BaseColor.RED);

                    bool IsFooterExist = false;
                    string FooterGeneratedBy = "";
                    PdfPTable ReportHeaderTable = new PdfPTable(2);
                    if (IsReportHeaderApplied)
                    {
                        DSReportHeader.ReportHeaderTagsRow drReportHeader = (DSReportHeader.ReportHeaderTagsRow)dtReportHeaderTags.Rows[0];
                        #region Report Header

                        try
                        {
                            //------------------------------------  DSReportHeader.ReportHeaderTags dtReportHeaderTags =
                            if (IsReportHeaderApplied)
                            {
                                ReportHeaderTable.TotalWidth = 630f;
                                ReportHeaderTable.LockedWidth = true;
                                ReportHeaderTable.DefaultCell.Border = Rectangle.NO_BORDER;

                                IsFooterExist = drReportHeader.Field<string>("FooterText") != null;
                                if (IsFooterExist)
                                {
                                    FooterGeneratedBy = drReportHeader.FooterText;
                                }
                                #region Header Logo
                                if (drReportHeader.Field<string>("HeaderLogo") != null && drReportHeader.Field<string>("HeaderLogo") != "")
                                {
                                    PdfPTable headerTable = new PdfPTable(1);
                                    headerTable.TotalWidth = 575f;
                                    headerTable.LockedWidth = true;
                                    headerTable.DefaultCell.Border = Rectangle.NO_BORDER;

                                    Byte[] buffer = Convert.FromBase64String(drReportHeader.HeaderLogo.Split(new string[] { "base64," }, StringSplitOptions.None)[1]);
                                    var memoryStream = new MemoryStream(buffer); //new MemoryStream(buffer, offset, count);
                                    System.Drawing.Image newImagej = System.Drawing.Image.FromStream(memoryStream);

                                    iTextSharp.text.Image logo = iTextSharp.text.Image.GetInstance(buffer, false);
                                    logo.ScalePercent(59f);
                                    logo.ScaleAbsoluteHeight(100);
                                    logo.ScaleAbsoluteWidth(150);

                                    PdfPCell cell1 = new PdfPCell();
                                    cell1.AddElement(logo);
                                    cell1.Border = Rectangle.NO_BORDER;
                                    cell1.HorizontalAlignment = Element.ALIGN_LEFT;
                                    ReportHeaderTable.AddCell(cell1);
                                }

                                else
                                {
                                    PdfPTable EmptyHeaderTable = new PdfPTable(1);
                                    EmptyHeaderTable.DefaultCell.Border = Rectangle.NO_BORDER;
                                    EmptyHeaderTable.AddCell(new Paragraph("", bodyFont));
                                    ReportHeaderTable.AddCell(EmptyHeaderTable);
                                }

                                #endregion

                                #region practice

                                PdfPTable PracticeTable = new PdfPTable(1);
                                PracticeTable.DefaultCell.Border = Rectangle.NO_BORDER;
                                //Begin Edited By Fahad Malik on 28-11-2016 to fix bug#: EMR-2090
                                PracticeTable.DefaultCell.HorizontalAlignment = Element.ALIGN_RIGHT;
                                PracticeTable.DefaultCell.PaddingRight = 50;
                                //End Edited By Fahad Malik on 28-11-2016 to fix bug#: EMR-2090
                                if (drReportHeader.Field<string>("PracticeText") != null)
                                {
                                    string[] PracticeColumns = drReportHeader.PracticeText.Split(new string[] { "<br/>" }, StringSplitOptions.None);
                                    foreach (string PracticeColumn in PracticeColumns)
                                    {
                                        if (!string.IsNullOrEmpty(PracticeColumn) && !string.IsNullOrWhiteSpace(PracticeColumn))
                                        {
                                            PracticeTable.AddCell(new Paragraph(PracticeColumn, bodyFont));
                                        }
                                    }
                                }
                                else
                                {
                                    PracticeTable.AddCell(new Paragraph("", bodyFont));
                                }
                                ReportHeaderTable.AddCell(PracticeTable);
                                #endregion

                                #region  Patient

                                PdfPTable PatientTable = new PdfPTable(1);
                                PatientTable.DefaultCell.Border = Rectangle.NO_BORDER;

                                if (drReportHeader.Field<string>("PatientText") != null)
                                {
                                    string[] PatientColumns = drReportHeader.PatientText.Split(new string[] { "<br/>" }, StringSplitOptions.None);
                                    foreach (string PatientColumn in PatientColumns)
                                    {
                                        if (!string.IsNullOrEmpty(PatientColumn) && !string.IsNullOrWhiteSpace(PatientColumn))
                                        {
                                            PatientTable.AddCell(new Paragraph(PatientColumn, bodyFont));
                                        }
                                    }
                                }
                                else
                                {
                                    PatientTable.AddCell(new Paragraph("", bodyFont));
                                }
                                PatientTable.DefaultCell.Padding = 0f;
                                PatientTable.DefaultCell.UseAscender = true;
                                ReportHeaderTable.AddCell(PatientTable);
                                #endregion

                                #region  Provider

                                PdfPTable ProviderTable = new PdfPTable(1);
                                ProviderTable.DefaultCell.Border = Rectangle.NO_BORDER;
                                //Begin Edited By Fahad Malik on 28-11-2016 to fix bug#: EMR-2090
                                ProviderTable.DefaultCell.HorizontalAlignment = Element.ALIGN_RIGHT;
                                ProviderTable.DefaultCell.PaddingRight = 50;
                                //Begin Edited By Fahad Malik on 28-11-2016 to fix bug#: EMR-2090
                                if (drReportHeader.Field<string>("ProviderText") != null)
                                {
                                    string[] ProviderColumns = drReportHeader.ProviderText.Split(new string[] { "<br/>" }, StringSplitOptions.None);

                                    foreach (string ProviderColumn in ProviderColumns)
                                    {
                                        if (!string.IsNullOrEmpty(ProviderColumn) && !string.IsNullOrWhiteSpace(ProviderColumn))
                                        {
                                            ProviderTable.AddCell(new Paragraph(ProviderColumn, bodyFont));
                                        }
                                    }

                                }
                                else
                                {
                                    ProviderTable.AddCell(new Paragraph("", bodyFont));
                                }
                                ReportHeaderTable.AddCell(ProviderTable);
                                #endregion
                                //ReportHeaderTable.DefaultCell.Padding = -1;
                            }
                        }
                        catch (Exception ex)
                        {
                            MDVLogger.BLLErrorLog("BLLAdminClinical::getReportHeaderTagsValue", ex);
                            // return new BLObject<DSReportHeader>(null, ex.Message);
                        }


                        #endregion
                    }
                    float bottomMargin = 22;
                    float topMargin = 20;
                    if (IsReportHeaderApplied)
                    {
                        topMargin = ReportHeaderTable.CalculateHeights() + 33;
                        bottomMargin = 52;
                    }

                    Document pdfDocument = new Document(PageSize.LETTER, 20, 20, topMargin, bottomMargin);
                    MDVUtility.PDFCreator pdf = new MDVUtility.PDFCreator(ref pdfDocument, stream_, false, ClientConfiguration.DecryptFrom64(MDVSession.Current.AppUserName), ClientConfiguration.DecryptFrom64(MDVSession.Current.AppUserName), "Face Sheet");
                    pdf.Writer.PageEvent = new MDVision.Common.Utilities.MDVUtility.AddFooterHeader(ReportHeaderTable, IsFooterExist, FooterGeneratedBy, null);

                    //  PdfWriter writer = PdfWriter.GetInstance(pdfDocument, stream_);
                    //using footer class


                    pdf.Document.Open();

                    DSProblemLists dsProblemList = new DSProblemLists();
                    DSAllergies dsAllergies = new DSAllergies();
                    DSPatient dsPatient = new DSPatient();
                    DSVitals dsVitals = new DSVitals();
                    DSHistorySummary dsHistory = new DSHistorySummary();
                    DSClinicalMedication dsMedications = new DSClinicalMedication();
                    DSLabOrder dsLabOrder = new DSLabOrder();
                    DSLabResult dsLabResult = new DSLabResult();
                    DSProcedureOrder dsProcedureOrder = new DSProcedureOrder();
                    DSRadiologyOrder dsRadiologyOrder = new DSRadiologyOrder();
                    DSPatientReferral dsPatientReferral = new DSPatientReferral();
                    DSImmunization dsImmunization = new DSImmunization();
                    DSClinicalComplaint dsComplaints = new DSClinicalComplaint();
                    DSPatient dsPatientDocument = new DSPatient();
                    //Start 27-01-2016 Muhammad Arshad EMR-233	Face Sheet in Clinical -> Print Preview
                    DSNotes dsNotes = new DSNotes();
                    DSAppointment dsAppointment = new DSAppointment();
                    //End 27-01-2016 Muhammad Arshad EMR-233	Face Sheet in Clinical -> Print Preview




                    Paragraph faceSheet_Heading = new Paragraph("Clinical Summary".ToString(), patientNameFont);
                    LineSeparator line = new LineSeparator(1f, 100f, iTextSharp.text.BaseColor.BLACK,
                        iTextSharp.text.Element.ALIGN_CENTER, -1);
                    line.Offset = 1;

                    pdfDocument.Add(new Chunk(line));
                    faceSheet_Heading.SpacingAfter = -12;
                    faceSheet_Heading.SpacingBefore = -5;
                    pdfDocument.Add(faceSheet_Heading);
                    Chunk c = new Chunk(line);

                    pdfDocument.Add(new Chunk(line));
                    pdfDocument.Add(Chunk.NEWLINE);

