                            Paragraph implantable_Heading = new Paragraph("Implantable Devices (Last 4, Active)\n".ToString(), componentHeadingFont);
                            implantable_Heading.SpacingBefore = implantable_Heading.SpacingAfter = 5;

                            pdfDocument.Add(implantable_Heading);
                            PdfPTable implantabletTable = new PdfPTable(5);
                            float[] widths = new float[] { 1f, 8f, 8f, 8f, 8f };
                            implantabletTable.SetWidths(widths);
                            implantabletTable.TotalWidth = 575f;
                            implantabletTable.LockedWidth = true;
                            implantabletTable.DefaultCell.Border = Rectangle.NO_BORDER;
                            implantabletTable.AddCell(string.Empty);
                            implantabletTable.AddCell(new Paragraph("Device Name", componentHeaderFont));
                            implantabletTable.AddCell(new Paragraph("Device ID", componentHeaderFont));
                            implantabletTable.AddCell(new Paragraph("Status", componentHeaderFont));
                            implantabletTable.AddCell(new Paragraph("Expiry", componentHeaderFont));

                            foreach (FSImplantableDevicesModel dev in listImplantableDevices)
                            {
                                implantabletTable.AddCell(string.Empty);
                                implantabletTable.AddCell(new Paragraph(dev.GMDNPName, bodyFont));
                                implantabletTable.AddCell(new Paragraph(dev.DI, bodyFont));
                                implantabletTable.AddCell(new Paragraph(dev.Status, bodyFont));
                                implantabletTable.AddCell(new Paragraph(MDVUtility.ToDateTime(dev.Expiration_Date).ToShortDateString(), bodyFont));
                            }
                            pdfDocument.Add(implantabletTable);
                        }
                        else
                        {

                            Paragraph implantable_Heading = new Paragraph("Implantable Devices (Last 4, Active)\n".ToString(), componentHeadingFont);
                            implantable_Heading.SpacingBefore = implantable_Heading.SpacingAfter = 5;
                            pdfDocument.Add(implantable_Heading);

                            PdfPTable implantabletTable = new PdfPTable(5);
                            float[] widths = new float[] { 1f, 8f, 8f, 8f, 8f };
                            implantabletTable.SetWidths(widths);
                            implantabletTable.TotalWidth = 575f;
                            implantabletTable.LockedWidth = true;
                            implantabletTable.DefaultCell.Border = Rectangle.NO_BORDER;
                            implantabletTable.AddCell(string.Empty);
                            implantabletTable.AddCell(new Paragraph("Device Name", componentHeaderFont));
                            implantabletTable.AddCell(new Paragraph("Device ID", componentHeaderFont));
                            implantabletTable.AddCell(new Paragraph("Status", componentHeaderFont));
                            implantabletTable.AddCell(new Paragraph("Expiry", componentHeaderFont));
                            implantabletTable.AddCell(string.Empty);
                            pdfDocument.Add(implantabletTable);
                            Paragraph noImplantable = new Paragraph("No Implantable Devices Found".ToString(), bodyFont);
                            noImplantable.Alignment = Element.ALIGN_CENTER;
                            pdfDocument.Add(noImplantable);
                        }
                    }
                    #endregion                  

                    pdf.Document.Close();
                    pdf.Writer.Close();

                    pdfDocument.Close();
                    // adding paging label in footer
                    MemoryStream stream = new MemoryStream(stream_.ToArray());
                    bottomMargin = bottomMargin > 30 ? bottomMargin - 20 : 30;
                    PdfReader npdf = new PdfReader(stream);
                    MemoryStream outstream = new MemoryStream();
                    #region footer
                    var colors = System.Drawing.ColorTranslator.FromHtml("#fff");
                    var fontcolors = new BaseColor(colors);
                    Font componentFooterFonts = FontFactory.GetFont("Arial", 8, Font.NORMAL, fontcolors);
                    if (!IsFooterExist)
                    {
                        componentFooterFonts = bodyFont;
                    }

                    using (PdfStamper stamper = new PdfStamper(npdf, outstream, '\0', true))
                    {
                        stamper.Writer.CloseStream = false;
                        int PageCount = npdf.NumberOfPages;
                        for (int i = 1; i <= PageCount; i++)
                            ColumnText.ShowTextAligned(stamper.GetOverContent(i), Element.ALIGN_CENTER, new Paragraph(String.Format("Page {0} of {1}", i, PageCount), componentFooterFonts), 555, 18, 0);
                    }
                    #endregion
                    newByteArr = outstream.GetBuffer();
                }

                return new BLObject<byte[]>(newByteArr);
            }
            catch (Exception ex)
            {
                MDVLogger.BLLErrorLog("BLLClinical::ClinicalSummaryCustomizePreview", ex);
                return new BLObject<byte[]>(null, ex.Message);
            }
        }
        private DSFaceSheet LoadClinicalSummaryPrintComponents(long PatientId, List<string> PrintComponents)
        {
            try
            {
                DSFaceSheet ds = new DSFaceSheet();

                Dictionary<String, IWorkItemResult> threadList = new Dictionary<string, IWorkItemResult>();

                SmartThreadPool threadPool = new SmartThreadPool();
                ThreadParams threadParams = new ThreadParams();

                threadParams.PatientId = PatientId;
                threadParams.UserId = MDVUtility.ToInt64(MDVSession.Current.AppUserId);
                threadParams.EntityId = MDVUtility.ToInt64(MDVSession.Current.EntityId);
                threadParams.Sharedobj = SharedVariable.GetSharedVariable();

                var taskP = threadPool.QueueWorkItem(new WorkItemCallback(GetPatientForClinicalSummary), threadParams);
                threadList.Add("Patient", taskP);

                if (PrintComponents.Contains("Allergies"))
                {
                    var task = threadPool.QueueWorkItem(new WorkItemCallback(GetAllergiesForClinicalSummary), threadParams);
                    threadList.Add("Allergies", task);
                }
                if (PrintComponents.Contains("Problem List"))
                {
                    var task = threadPool.QueueWorkItem(new WorkItemCallback(GetProblemsForClinicalSummary), threadParams);
                    threadList.Add("Problem List", task);
                }

                if (PrintComponents.Contains("Vitals"))
                {
                    var task = threadPool.QueueWorkItem(new WorkItemCallback(GetVitalsForClinicalSummary), threadParams);
                    threadList.Add("Vitals", task);
                }
                if (PrintComponents.Contains("Notes"))
                {
                    var task = threadPool.QueueWorkItem(new WorkItemCallback(GetNotesForClinicalSummary), threadParams);
                    threadList.Add("Notes", task);
                }
                if (PrintComponents.Contains("Appointments"))
                {
                    var task = threadPool.QueueWorkItem(new WorkItemCallback(GetAppointmentsForClinicalSummary), threadParams);
                    threadList.Add("Appointments", task);
                }
                if (PrintComponents.Contains("History"))
                {
                    var task = threadPool.QueueWorkItem(new WorkItemCallback(GetHistoryForClinicalSummary), threadParams);
                    threadList.Add("History", task);
                }
                if (PrintComponents.Contains("Medications"))
                {
                    var task = threadPool.QueueWorkItem(new WorkItemCallback(GetMedicationsForClinicalSummary), threadParams);
                    threadList.Add("Medications", task);
                }
                if (PrintComponents.Contains("Lab Results"))
                {
                    var task = threadPool.QueueWorkItem(new WorkItemCallback(GetLabResultsForClinicalSummary), threadParams);
                    threadList.Add("Lab Results", task);
                }
                if (PrintComponents.Contains("Lab Orders"))
                {
                    var task = threadPool.QueueWorkItem(new WorkItemCallback(GetLabOrdersForClinicalSummary), threadParams);
                    threadList.Add("Lab Orders", task);
                }
                if (PrintComponents.Contains("Procedure Orders"))
                {
                    var task = threadPool.QueueWorkItem(new WorkItemCallback(GetProcedureOrdersForClinicalSummary), threadParams);
                    threadList.Add("Procedure Orders", task);
                }
                if (PrintComponents.Contains("Radiology Orders"))
                {
                    var task = threadPool.QueueWorkItem(new WorkItemCallback(GetRadiologyOrdersForClinicalSummary), threadParams);
                    threadList.Add("Radiology Orders", task);
                }
                if (PrintComponents.Contains("Referrals"))
                {
                    var task = threadPool.QueueWorkItem(new WorkItemCallback(GetReferralsForClinicalSummary), threadParams);
                    threadList.Add("Referrals", task);
                }
                if (PrintComponents.Contains("Immunization"))
                {
                    var task = threadPool.QueueWorkItem(new WorkItemCallback(GetImmunizationForClinicalSummary), threadParams);
                    threadList.Add("Immunization", task);
                }
                if (PrintComponents.Contains("Complaints"))
                {
                    var task = threadPool.QueueWorkItem(new WorkItemCallback(GetComplaintsForClinicalSummary), threadParams);
                    threadList.Add("Complaints", task);
                }
                if (PrintComponents.Contains("Patient Document"))
                {
                    var task = threadPool.QueueWorkItem(new WorkItemCallback(GetDocumentsForClinicalSummary), threadParams);
                    threadList.Add("Patient Document", task);
                }

                bool success = SmartThreadPool.WaitAll(threadList.Values.ToArray());

                if (success)
                {
                    foreach (var key in threadList.Keys)
                    {
                        ds.Merge((DataSet)threadList[key].Result);
                    }
                }

                threadPool.Shutdown();

                return ds;
            }
            catch (Exception ex)
            {
                MDVLogger.BLLErrorLog("BLLClinical::LoadClinicalSummaryPrintComponents", new Exception(ex.InnerException.Message));
                throw new Exception(ex.InnerException.Message);
            }
        }
