        /// <summary>
        /// Author:  Muhammad Arshad
        /// Created Date: 08/01/2016
        /// OverView: Loads MedicalHx on basis of patientId, MedicalHxId, MedicalHxType
        /// </summary>
        /// <param name="patientId"></param>
        /// <param name="MedicalHxId"></param>
        /// <param name="MedicalHxType"></param>
        /// <returns></returns>
        public BLObject<DSMedicalHx> LoadMedicalHx(long patientId, long MedicalHxId, long diseaseId = 0, string MedicalHxType = "", string isViewMedicalHx = "", string isPrintMedicalHx = "")
        {
            try
            {
                DSMedicalHx ds = new DSMedicalHx();
                ds = new DALMedicalHx().LoadMedicalHx(patientId, MedicalHxId, isViewMedicalHx, isPrintMedicalHx);
                if (ds.Tables[ds.MedicalHx.TableName].Rows.Count > 0)
                {
                    Int64 currentSocialHxId = MDVUtility.ToInt64(ds.Tables[ds.MedicalHx.TableName].Rows[0][ds.MedicalHx.MedicalHxIdColumn.ColumnName]);
                    if (currentSocialHxId > 0)
                    {
                        DSMedicalHx dsMedicalHxDisease = new DSMedicalHx();
                        dsMedicalHxDisease = new DALMedicalHx().LoadMedicalHx_Disease(currentSocialHxId, diseaseId, "1", "");
                        if (dsMedicalHxDisease != null)
                        {
                            ds.Merge(dsMedicalHxDisease);
                        }
                    }
                }

                return new BLObject<DSMedicalHx>(ds);
            }
            catch (Exception ex)
            {
                MDVLogger.BLLErrorLog("BLLClinical::LoadMedicalHx", ex);
                return new BLObject<DSMedicalHx>(null, ex.Message);
            }
        }
