        public BLObject<DSHospitalizationHx> LoadHospitalizationHx(long patientId, long hospitalizationHxId, long diseaseId = 0, string hospitalizationHxType = "", string isViewHospitalizationHx = "", string isPrintHospitalizationHx = "")
