                DSHospitalizationHx ds = new DSHospitalizationHx();
                ds = new DALHospitalizationHx().LoadHospitalizationHx(patientId, hospitalizationHxId, isViewHospitalizationHx, isPrintHospitalizationHx);
                if (ds.Tables[ds.HospitalizationHx.TableName].Rows.Count > 0)
                {
                    Int64 currentHospitalizationHxId = MDVUtility.ToInt64(ds.Tables[ds.HospitalizationHx.TableName].Rows[0][ds.HospitalizationHx.HospitalizationHxIdColumn.ColumnName]);
                    if (currentHospitalizationHxId > 0)
                    {
                        DSHospitalizationHx dsHospitalizationHxDisease = new DSHospitalizationHx();
                        dsHospitalizationHxDisease = new DALHospitalizationHx().LoadHospitalizationHx_Disease(currentHospitalizationHxId, diseaseId, isViewHospitalizationHx, isPrintHospitalizationHx);
                        if (dsHospitalizationHxDisease != null)
                        {
                            ds.Merge(dsHospitalizationHxDisease);
                        }
                    }
                }

                return new BLObject<DSHospitalizationHx>(ds);
            }
            catch (Exception ex)
            {
                MDVLogger.BLLErrorLog("BLLClinical::LoadHospitalizationHx", ex);
                return new BLObject<DSHospitalizationHx>(null, ex.Message);
