        public BLObject<DSClinicalMedication> InsertPrescription(DSClinicalMedication ds, SharedVariable sharedVariable = null)
        {
            try
            {

                string IsPrescriptionDelete = "false";
                string IsPrescriptionSaved = "false";
                if (sharedVariable == null)
                {
                    ds = new DALMedications().insertDrug(ds);
                }
                else
                {
                    ds = new DALMedications(sharedVariable).insertDrug(ds);
                }

                foreach (DSClinicalMedication.DrugRow drug in ds.Drug)
                {
                    foreach (DSClinicalMedication.MedicationRow dr in ds.Medication)
                    {
                        if (dr.PrescriptionRcopiaID.ToString() == drug.PrescriptionRcopiaId.ToString())
                        {
                            dr.DrugID = drug.DrugId;
                        }
                    }

                }
                if (ds.Tables["Pharmacy"].Rows.Count > 0)
                {
                    if (sharedVariable == null)
                    {
                        ds = new DALMedications().InsertPharamacy(ds);
                    }
                    else
                    {
                        ds = new DALMedications(sharedVariable).InsertPharamacy(ds);
                    }

                }
                for (int i = 0; i < ds.Tables["Prescription"].Rows.Count; i++)
                {
                    long pharmacyId = 0;
                    if (ds.Tables["Prescription"].Rows[i]["PharmacyRcopiaId"] != null)
                    {

                        string pharmacyRcopiaId = ds.Tables["Prescription"].Rows[i]["PharmacyRcopiaId"].ToString();
                        for (int j = 0; j < ds.Tables["Pharmacy"].Rows.Count; j++)
                        {
                            if (MDVUtility.ToStr(ds.Tables["Pharmacy"].Rows[j]["RcopiaID"]) == pharmacyRcopiaId)
                            {
                                pharmacyId = MDVUtility.ToLong(ds.Tables["Pharmacy"].Rows[j]["PharmacyId"]);
                                break;
                            }
                        }
                    }
                    if (pharmacyId != 0)
                    {
                        ds.Prescription.Rows[i]["PharmacyID"] = pharmacyId;
                    }
                }
                var patientIds = "";
                foreach (DSClinicalMedication.PrescriptionRow dr in ds.Prescription.Rows)
                {
                    patientIds = string.Concat(patientIds, MDVUtility.ToStr(dr[ds.Prescription.PatientIDColumn.ColumnName]), ",");
                }
                if (patientIds.Length > 0)
                {
                    patientIds = patientIds.Substring(0, patientIds.Length - 1);
                }
                DSClinicalMedication dsPatient = new DSClinicalMedication();
                if (sharedVariable == null)
                {
                    dsPatient = new DALMedications().GetExsistingPatients(patientIds);
                }
                else
                {
                    dsPatient = new DALMedications(sharedVariable).GetExsistingPatients(patientIds);
                }

                ds.Merge(dsPatient);
                DSClinicalMedication dsPrescriptionnew = new DSClinicalMedication();
                DSClinicalMedication dsPrescriptionDeleted = new DSClinicalMedication();
                foreach (DataRow pre in ds.Prescription.Rows)
                {
                    var bisAdded = false;
                    foreach (DataRow pa in ds.Patients.Rows)
                    {
                        if (pre["PatientID"].ToString().Trim().ToString() == pa["PatientId"].ToString().Trim().ToString())
                        {
                            bisAdded = true;
                        }
                    }
                    if (!bisAdded)
                    {
                        if (Convert.ToBoolean(pre["IsDeleted"]))
                        {
                            dsPrescriptionDeleted.Prescription.Rows.Add(pre.ItemArray);
                        }
                        else
                        {
                            dsPrescriptionnew.Prescription.Rows.Add(pre.ItemArray);
                        }

                    }
                }
                if (dsPrescriptionnew.Prescription.Rows.Count > 0)
                {
                    if (sharedVariable == null)
                    {
                        ds = new DALMedications().InsertPrescription(dsPrescriptionnew);
                    }
                    else
                    {
                        ds = new DALMedications(sharedVariable).InsertPrescription(dsPrescriptionnew, sharedVariable);
                    }

                    IsPrescriptionSaved = "true";
                }
                //handle delete case of prescription
                //M Ahmad Imran
                if (dsPrescriptionDeleted.Prescription.Rows.Count > 0)
                {
                    IsPrescriptionDelete = "true";
                    foreach (DSClinicalMedication.PrescriptionRow dr in dsPrescriptionDeleted.Prescription)
                    {
                        string PrecriptionDelete = "";
                        if (sharedVariable == null)
                        {
                            PrecriptionDelete = new DALMedications().DeletePrescription(dr["RcopiaID"].ToString());
                        }
                        else
                        {
                            PrecriptionDelete = new DALMedications(sharedVariable).DeletePrescription(dr["RcopiaID"].ToString(), sharedVariable);
                        }

                        if (PrecriptionDelete != "")
                        {
                            DSNotes dsNote = new DSNotes();
                            if (sharedVariable == null)
                            {
                                dsNote = new DALMedications().AttachWithWhichNote(dr["RcopiaID"].ToString());
                            }
                            else
                            {
                                dsNote = new DALMedications(sharedVariable).AttachWithWhichNote(dr["RcopiaID"].ToString());
                            }

                            if (dsNote.Notes.Rows.Count > 0)
                            {
                                foreach (DSNotes.NotesRow note in dsNote.Notes.Rows)
                                {
                                    if (note[dsNote.Notes.NoteStatusColumn.ColumnName].ToString() == "Draft")
                                    {
                                        var msgPrescriptionId = "";
                                        if (sharedVariable == null)
                                        {
                                            msgPrescriptionId = new DALMedications().detachPrescriptionsFromNotes("", MDVUtility.ToInt64(note[dsNote.Notes.NotesIdColumn.ColumnName]), dr["RcopiaID"].ToString());
                                        }
                                        else
                                        {
                                            msgPrescriptionId = new DALMedications(sharedVariable).detachPrescriptionsFromNotes("", MDVUtility.ToInt64(note[dsNote.Notes.NotesIdColumn.ColumnName]), dr["RcopiaID"].ToString());
                                        }
                                        if (msgPrescriptionId != "")
                                        {
                                            throw new Exception("Error in detach Prescription From Notes");
                                        }
                                        else
                                        {
                                            List<NoteComponentModel> NotesSoapTextList = new List<NoteComponentModel>();
                                            if (sharedVariable == null)
                                            {
                                                NotesSoapTextList = new DALNotes().loadNoteComponents(MDVUtility.ToInt64(note[dsNote.Notes.NotesIdColumn.ColumnName]), "Prescription");
                                            }
                                            else
                                            {
                                                NotesSoapTextList = new DALNotes(sharedVariable).loadNoteComponents(MDVUtility.ToInt64(note[dsNote.Notes.NotesIdColumn.ColumnName]), "Prescription");
                                            }
                                            DSClinicalMedication dsprescription = new DSClinicalMedication();
                                            if (sharedVariable == null)
                                            {
                                                dsprescription = new DALMedications().loadPrescriptions(0, 0, 0, 1, 15, "0", "0", MDVUtility.ToStr(dr["RcopiaID"]));
                                            }
                                            else
                                            {
                                                dsprescription = new DALMedications(sharedVariable).loadPrescriptions(0, 0, 0, 1, 15, "0", "0", MDVUtility.ToStr(dr["RcopiaID"]));
                                            }


                                            if (NotesSoapTextList.Count > 0)
                                            {

                                                var soaptext = MDVUtility.ToStr(NotesSoapTextList[0].SOAPText);
                                                string DeletePrescriptionId = "Cli_Prescription_Main" + dsprescription.Prescription.Rows[0][dsprescription.Prescription.PrescriptionIDColumn.ColumnName].ToString();
                                                HtmlDocument doc = new HtmlDocument() { OptionAutoCloseOnEnd = true };
                                                HtmlNode.ElementsFlags.Remove("meta");
                                                HtmlNode.ElementsFlags.Remove("link");
                                                HtmlNode.ElementsFlags.Remove("a");
                                                doc.LoadHtml(soaptext.ToString());
                                                doc.DocumentNode.SelectSingleNode("//section[@id='" + DeletePrescriptionId + "']").Remove();
                                                var NoteSoapText = doc.DocumentNode.OuterHtml;



                                                #region Binding DataSet Information

                                                NoteComponentModel NoteComp = new NoteComponentModel();
                                                NoteComp.NoteComponentId = NotesSoapTextList[0].NoteComponentId;
                                                NoteComp.NoteComponentsLookupId = NotesSoapTextList[0].NoteComponentsLookupId;
                                                NoteComp.NotesId = NotesSoapTextList[0].NotesId;
                                                NoteComp.SOAPText = NoteSoapText;
                                                NoteComp.OrderNo = NotesSoapTextList[0].OrderNo;
                                                NoteComp.NoteSectionsLookupId = NotesSoapTextList[0].NoteSectionsLookupId;
                                                #endregion
                                                #region Database Updation
                                                var componentId = updateNoteComponent(NoteComp, sharedVariable);
                                                if (componentId.Data != null)
                                                {
                                                    string PrecriptionDeleteAgain = "";
                                                    if (sharedVariable == null)
                                                    {
                                                        PrecriptionDeleteAgain = new DALMedications().DeletePrescription(dr["RcopiaID"].ToString());
                                                    }
                                                    else
                                                    {
                                                        PrecriptionDeleteAgain = new DALMedications(sharedVariable).DeletePrescription(dr["RcopiaID"].ToString(), sharedVariable);
                                                    }

                                                    if (PrecriptionDeleteAgain != "")
                                                    {
                                                        throw new Exception("Error in delete Prescription");
                                                    }
                                                }
                                                else
                                                {
                                                    throw new Exception("Error in update soap text");
                                                }

                                                #endregion
                                            }
                                        }
                                    }
                                    else if (note[dsNote.Notes.NoteStatusColumn.ColumnName].ToString() == "Signed")
                                    {
                                        var msgPrescriptionId = "";
                                        if (sharedVariable == null)
                                        {
                                            msgPrescriptionId = new DALMedications().detachPrescriptionsFromNotes("", MDVUtility.ToInt64(note[dsNote.Notes.NotesIdColumn.ColumnName]), dr["RcopiaID"].ToString());
                                        }
                                        else
                                        {
                                            msgPrescriptionId = new DALMedications(sharedVariable).detachPrescriptionsFromNotes("", MDVUtility.ToInt64(note[dsNote.Notes.NotesIdColumn.ColumnName]), dr["RcopiaID"].ToString());
                                        }

                                        if (msgPrescriptionId != "")
                                        {
                                            throw new Exception("Error in detach Prescription From Notes");
                                        }
                                        else
                                        {
                                            string PrecriptionDeleteAgain = "";
                                            if (sharedVariable == null)
                                            {
                                                PrecriptionDeleteAgain = new DALMedications().DeletePrescription(dr["RcopiaID"].ToString());
                                            }
                                            else
                                            {
                                                PrecriptionDeleteAgain = new DALMedications(sharedVariable).DeletePrescription(dr["RcopiaID"].ToString());
                                            }

                                            if (PrecriptionDeleteAgain != "")
                                            {
                                                throw new Exception("Error in delete Prescription");
                                            }
                                            else
                                            {

                                            }
                                        }
                                    }
                                }
                            }
                            else
                            {
                                throw new Exception("rather then notes");
                            }
                        }

                    }
                }

                return new BLObject<DSClinicalMedication>(ds, IsPrescriptionSaved + "," + IsPrescriptionDelete);
            }
            catch (Exception ex)
            {

                MDVLogger.SendExcepToDB(ex, "BLLClinical::insertDrug", null);
                return new BLObject<DSClinicalMedication>(null, ex.Message);
            }
        }
