        /// <summary>
        /// Author : Khaleel Ur Rehman
        /// Purpose : function to load Medications.
        /// Date : 14 january 2016
        /// </summary>
        /// <param name="medicationId"></param>
        /// <param name="pageNo"></param>
        /// <param name="rpp"></param>
        /// <returns></returns>
        public BLObject<DSClinicalMedication> loadMedications(long medicationId, long patientId, long noteId, bool isCurrent, int pageNo, int rpp, string isHistory = "0", string isViewAllergy = "", string isPrintAllergy = "", bool isFromCDS = false)
        {
            try
            {
                DSClinicalMedication ds = new DSClinicalMedication();
                ds = new DALMedications().loadMedications(medicationId, patientId, noteId, true, pageNo, rpp, isHistory, isViewAllergy, isPrintAllergy, isFromCDS);
                try
                {
                    DSClinicalMedication dsMdr = new DSClinicalMedication();
                    //dsMdr = new DALMedications().loadMedicationsReviewedBy_Obsolete(patientId);
