        /// <summary>
        /// Author : Wasim Malik
        /// Purpose : function insert Prescription.
        /// Date : 14 january 2016
        #region insertMedication
        public BLObject<DSClinicalMedication> insertMedication(DSClinicalMedication ds, SharedVariable sharedVariable = null)
        {
            try
            {
                if (sharedVariable == null)
                {
                    ds = new DALMedications().insertDrug(ds);
                }
                else
                {
                    ds = new DALMedications(sharedVariable).insertDrug(ds);
                }

                foreach (DSClinicalMedication.DrugRow drug in ds.Drug)
                {
                    foreach (DSClinicalMedication.MedicationRow dr in ds.Medication)
                    {
                        if (dr.RcopiaID.ToString() == drug.MedicationRcopiaId.ToString())
                        {
                            dr.DrugID = drug.DrugId;
                        }
                    }

                }
                //ds.AcceptChanges();
                var patientIds = "";

                foreach (DSClinicalMedication.MedicationRow dr in ds.Medication.Rows)
                {
                    patientIds = string.Concat(patientIds, MDVUtility.ToStr(dr[ds.Medication.PatientIDColumn.ColumnName]), ",");
                }
                if (patientIds.Length > 0)
                {
                    patientIds = patientIds.Substring(0, patientIds.Length - 1);
                }
                DSClinicalMedication dsPatient = new DSClinicalMedication();
                if (sharedVariable == null)
                {
                    dsPatient = new DALMedications().GetExsistingPatients(patientIds);
                }
                else
                {
                    dsPatient = new DALMedications(sharedVariable).GetExsistingPatients(patientIds);
                }

                ds.Merge(dsPatient);

                DSClinicalMedication dsMedicationnew = new DSClinicalMedication();
                foreach (DataRow med in ds.Medication.Rows)
                {
                    var bisAdded = false;
                    foreach (DataRow pa in ds.Patients.Rows)
                    {
                        if (med["PatientID"].ToString().Trim().ToString() == pa["PatientId"].ToString().Trim().ToString())
                        {
                            bisAdded = true;
                        }
                    }
                    if (!bisAdded)
                    {
                        dsMedicationnew.Medication.Rows.Add(med.ItemArray);
                    }
                }
                if (dsMedicationnew.Medication.Rows.Count > 0)
                {
                    if (sharedVariable == null)
                    {
                        ds = new DALMedications().insertMedication(dsMedicationnew);
                    }
                    else
                    {
                        ds = new DALMedications(sharedVariable).insertMedication(dsMedicationnew, sharedVariable);
                    }

                }
                return new BLObject<DSClinicalMedication>(ds);
            }
            catch (Exception ex)
            {
                //MDVLogger.BLLErrorLog("BLLClinical::DSMedication", ex);
                MDVLogger.SendExcepToDB(ex, "BLLClinical::InsertMedication", null);
                return new BLObject<DSClinicalMedication>(null, ex.Message);
            }
        }
        #endregion
