        /// <summary>
        /// Author:  Muhammad Irfan
        /// Date:  22/01/2016
        /// Reason:  This function will handle load of FamilyHx
        /// </summary>
        /// <param name="ds"></param>
        /// <returns></returns>
        public BLObject<DSFamilyHx> LoadFamilyHx(long patientId, long FamilyHxId, string FamilyHxType = "", string isViewFamilyHx = "", string isPrintFamilyHx = "")
        {
            try
            {
                DSFamilyHx ds = new DSFamilyHx();
                ds = new DALFamilyHx().LoadFamilyHx(patientId, FamilyHxId, isViewFamilyHx, isPrintFamilyHx);
                if (ds.Tables[ds.FamilyHx.TableName].Rows.Count > 0)
                {
                    Int64 currentFamilyHxId = MDVUtility.ToInt64(ds.Tables[ds.FamilyHx.TableName].Rows[0][ds.FamilyHx.FamilyHxIdColumn.ColumnName]);
                    if (currentFamilyHxId > 0)
                    {
                        DSFamilyHx dsFamilyMemberDisease = new DSFamilyHx();
                        dsFamilyMemberDisease = new DALFamilyHx().FamilyHxMemberHasDisease(currentFamilyHxId);
                        if (dsFamilyMemberDisease != null)
                        {
                            ds.Merge(dsFamilyMemberDisease);
                        }
                        DSFamilyHx dsFamilyHxDisease = new DSFamilyHx();
                        dsFamilyHxDisease = new DALFamilyHx().LoadFamilyHx_Disease(currentFamilyHxId, 0, 0, "1", "");
                        if (dsFamilyHxDisease != null)
                        {
                            ds.Merge(dsFamilyHxDisease);
                        }
                    }
                }

                return new BLObject<DSFamilyHx>(ds);
            }
            catch (Exception ex)
            {
                MDVLogger.BLLErrorLog("BLLClinical::LoadFamilyHx", ex);
                return new BLObject<DSFamilyHx>(null, ex.Message);
            }
        }

