        /// Author: ZeeshanAK
        /// Purpose:  to load Medications For SOAP
        /// Date : January 15, 2016
        ///

        #region "Medications For Notes Soap Text
        public BLObject<DSClinicalMedication> loadMedicationsForSoap(string medicationID, long patientId)
        {
            try
            {
                DSClinicalMedication ds = new DSClinicalMedication();
                ds = new DALMedications().loadMedicationsForSoap(medicationID, patientId);
                try
                {
                    DSClinicalMedication dsMdr = new DSClinicalMedication();
                    dsMdr = new DALMedications().loadMedicationsReviewedBy_Obsolete(patientId);
                    ds.Merge(dsMdr);
                }
                catch (Exception ex)
                {
                    MDVLogger.BLLErrorLog("BLLClinical::loadMedicationsForSoap", ex);
                    return new BLObject<DSClinicalMedication>(null, ex.Message);
                }
                return new BLObject<DSClinicalMedication>(ds);
            }
            catch (Exception ex)
            {
                MDVLogger.BLLErrorLog("BLLClinical::loadMedicationsForSoap", ex);
                return new BLObject<DSClinicalMedication>(null, ex.Message);
            }
        }
        #endregion

