        /// <summary>
        /// Author : Khaleel Ur Rehman.
        /// Purpose : load ROS System PatientCharacteristics.
        /// Date : 01 Feb 2016.
        /// </summary>
        /// <param name="patientId"></param>
        /// <param name="rOSSystemPatientCharacteristicsId"></param>
        /// <returns></returns>
        public BLObject<DSClinicalReviewofSystem> loadROSSystemPatientCharacteristics(long notesId, long rOSSystemPatientCharacteristicsId, long ROSSystemPatientID)
        {
            try
            {
                DSClinicalReviewofSystem ds = new DSClinicalReviewofSystem();
                ds = new DALReviewofSystem().loadROSSystemPatientCharacteristics(notesId, rOSSystemPatientCharacteristicsId, ROSSystemPatientID);
                if (ds.Tables[ds.ROSSystemPatientCharacteristics.TableName].Rows.Count > 0)
                {
                    Int64 currentROSSysPatCharId = MDVUtility.ToInt64(ds.Tables[ds.ROSSystemPatientCharacteristics.TableName].Rows[0][ds.ROSSystemPatientCharacteristics.ROSSystemPatientCharacteristicsIDColumn.ColumnName]);
                    //Int64 currentDetaisId = MDVUtility.ToInt64(ds.Tables[ds.ROSSystemPatientCharacteristics.TableName].Rows[0][ds.BirthHx.GeneralIdColumn.ColumnName]);
                    if (currentROSSysPatCharId > 0)
                    {
                        /*if (currentGeneralId > 0)
                        {
                            DSBirthHistory dsBirthHxGeneral = new DALBirthHistory().loadBirthHxGeneral(currentBirthHxId, currentGeneralId);
                            if (dsBirthHxGeneral != null)
                            {
                                ds.Merge(dsBirthHxGeneral);
                            }
                        }*/
                    }
                }
                return new BLObject<DSClinicalReviewofSystem>(ds);
            }
            catch (Exception ex)
            {
                MDVLogger.BLLErrorLog("BLLClinical::loadROSSystemPatientCharacteristics", ex);
                return new BLObject<DSClinicalReviewofSystem>(null, ex.Message);
            }
        }
