        // Author:  Farooq Ahmad
        // Created Date: 04/02/2016
        //OverView: Methods to Load PhysicalExamUserSystems

        public BLObject<DSPhysicalExam> LoadPhysicalExamUserSystems(long templateId = 0)
        {
            try
            {
                DSPhysicalExam ds = new DSPhysicalExam();


                DSPhysicalExam dsPhysicalExam = new DALPhysicalExam().loadPhysicalExamUserSystem(0, templateId);
                if (dsPhysicalExam != null)
                {
                    if (dsPhysicalExam.PhysicalExam_UserSystem.Rows.Count < 1)
                    {
                        DSPhysicalExam.PhysicalExam_UserSystemRow drUserSystem = dsPhysicalExam.PhysicalExam_UserSystem.NewPhysicalExam_UserSystemRow();
                        drUserSystem.UserSystemId = -1;
                        drUserSystem.UserId = MDVSession.Current.AppUserId;
                        drUserSystem[dsPhysicalExam.PhysicalExam_UserSystem.SystemOrderColumn] = DBNull.Value;
                        drUserSystem[dsPhysicalExam.PhysicalExam_UserSystem.SortOrderColumn] = DBNull.Value;
                        drUserSystem.IsActive = true;
                        drUserSystem.CreatedBy = MDVUtility.DecryptFrom64(MDVSession.Current.AppUserName);
                        drUserSystem.CreatedOn = DateTime.Now;
                        drUserSystem.ModifiedBy = MDVUtility.DecryptFrom64(MDVSession.Current.AppUserName);
                        drUserSystem.ModifiedOn = DateTime.Now;
                        if (templateId < 1)
                        {
                            drUserSystem[dsPhysicalExam.PhysicalExam_UserSystem.TemplateIdColumn] = DBNull.Value;
                        }
                        else
                        {
                            drUserSystem[dsPhysicalExam.PhysicalExam_UserSystem.TemplateIdColumn] = templateId;
                        }
                        dsPhysicalExam.PhysicalExam_UserSystem.AddPhysicalExam_UserSystemRow(drUserSystem);
                        dsPhysicalExam = new DALPhysicalExam().insertUpdatePhysicalExamUserSystem(dsPhysicalExam);
                        dsPhysicalExam = new DALPhysicalExam().loadPhysicalExamUserSystem(0, templateId);
                    }

                    ds.Merge(dsPhysicalExam);
                }




                return new BLObject<DSPhysicalExam>(ds);
            }
            catch (Exception ex)
            {
                MDVLogger.BLLErrorLog("BLLClinical::LoadPhysicalExamSystems", ex);
                return new BLObject<DSPhysicalExam>(null, ex.Message);
            }
        }


