        #region Physical Exam Data Template

        // Author:  Abid Ali
        // Created Date: 15/June/2016
        //OverView: this function will load physical exam data template
        public BLObject<DSPhysicalExamDataTemplate> loadPhysicalExamDataTemplate(long dataTemplateId, long templateId, long entityId = 0, string providerIds = "", string specialtyIds = "", int pageNumber = 0, int rpp = 0, int isActive = -1)
        {
            try
            {
                DSPhysicalExamDataTemplate dsPhysicalExamDataTemplates = null;
                dsPhysicalExamDataTemplates = new DALPhysicalExamDataTemplate().loadPhysicalExamDataTemplate(dataTemplateId, templateId, entityId, providerIds, specialtyIds, pageNumber, rpp, isActive);
                return new BLObject<DSPhysicalExamDataTemplate>(dsPhysicalExamDataTemplates);
            }
            catch (Exception ex)
            {
                MDVLogger.BLLErrorLog("BLLClinical::Load_PhysicalExam_Data_Template", ex);
                return new BLObject<DSPhysicalExamDataTemplate>(null, ex.Message);
            }
        }

        public BLObject<DSPhysicalExamDataTemplate> lookupPhysicalExamDataTemplateSystem(long dataTemplateId, long templateId)
        {
            try
            {
                DSPhysicalExamDataTemplate dsPhysicalExamDataTemplates = new DSPhysicalExamDataTemplate();
                DSPhysicalExamTemplate dsTemplateSystem = new DALPhysicalExamTemplate().LoadPhysicalExamTemplateSystem(templateId, "", "");
                //DSPhysicalExamTemplate dsTemplateSection = new DALPhysicalExamTemplate().LoadPhysicalExamTemplateSection(templateId, "", "");
                if (dataTemplateId > 0)
                {

                    DSPhysicalExamDataTemplate dsDataTemplateSys = new DALPhysicalExamDataTemplate().LoadPhysicalExamDataTemplateSystem(dataTemplateId);
                    DataTable dtFoundSystem = new DataTable("dtFoundSystem");
                    dtFoundSystem.Columns.Add("SystemId");
                    dtFoundSystem.Columns.Add("SystemName");
                    dtFoundSystem.Columns.Add("IsNormal");
                    dtFoundSystem.Columns.Add("IsFound");
                    // To Show only selected Systems Of tempaltes

                    DataRow[] dRows = dsTemplateSystem.Tables[dsTemplateSystem.PhysExamTemplateSys.TableName].Select("IsChecked=1");
                    foreach (DataRow item in dRows)
                    {
                        DataRow[] arrFoundSystem = dsDataTemplateSys.PhysExamDataTemplateSys.Select(dsDataTemplateSys.PhysExamDataTemplateSys.SystemIdColumn.ColumnName + "=" + item["SystemId"]);
                        DataRow drNew = dtFoundSystem.NewRow();

                        if (arrFoundSystem.Length > 0)
                        {
                            drNew["SystemId"] = arrFoundSystem[0]["SystemId"];
                            drNew["SystemName"] = arrFoundSystem[0]["SystemName"];
                            drNew["IsNormal"] = arrFoundSystem[0]["IsNormal"];
                            drNew["IsFound"] = "1";
                        }
                        else
                        {
                            drNew["SystemId"] = item["SystemId"];
                            drNew["SystemName"] = item["SystemName"];
                            drNew["IsNormal"] = "False";
                            drNew["IsFound"] = "0";
                        }

                        dtFoundSystem.Rows.Add(drNew);
                    }

                    if (dtFoundSystem.Rows.Count > 0)
                    {
                        dsPhysicalExamDataTemplates.Merge(dtFoundSystem);
                    }


                }
                else
                {
                    if (dsTemplateSystem != null)
                    {
                        dsPhysicalExamDataTemplates.Merge(dsTemplateSystem.PhysExamTemplateSys);
                    }
                }
                return new BLObject<DSPhysicalExamDataTemplate>(dsPhysicalExamDataTemplates);
            }
            catch (Exception ex)
            {
