        public BLObject<DSPhysicalExamDataTemplate> LookupPhysicalExamDataTemplateSystemSection(long dataTemplateId, long templateId, long systemId)
        {
            try
            {
                DSPhysicalExamDataTemplate ds = new DSPhysicalExamDataTemplate();
                DSPhysicalExamTemplate dsTemplateSection = new DALPhysicalExamTemplate().LoadPhysicalExamTemplateSectionForDataTemplate(templateId, systemId, "", "");

                DataTable dtTemplateSection = new DataTable("dtFoundSections");
                dtTemplateSection.Columns.Add("SectionId");
                dtTemplateSection.Columns.Add("SectionName");
                dtTemplateSection.Columns.Add("Comments");
                dtTemplateSection.Columns.Add("IsNormal");
                dtTemplateSection.Columns.Add("IsFound");

                ds = new DALPhysicalExamDataTemplate().LoadPhysicalExamDataTemplateSection(dataTemplateId, systemId);
                if (dataTemplateId > 0)
                {

                    foreach (DataRow item in dsTemplateSection.PhysExamTemplateSection.Rows)
                    {
                        DataRow drNew = dtTemplateSection.NewRow();
                        DataRow[] arrFoundSections = ds.PhysExamDataTemplateSection.Select(ds.PhysExamDataTemplateSection.SectionIdColumn.ColumnName + "=" + item["SectionId"]);
                        if (arrFoundSections.Length > 0)
                        {
                            drNew["SectionId"] = arrFoundSections[0]["SectionId"];
                            drNew["SectionName"] = arrFoundSections[0]["SectionName"];
                            drNew["Comments"] = "";
                            drNew["IsFound"] = "1";
                            drNew["IsNormal"] = "False";
                        }
                        else
                        {
                            drNew["SectionId"] = item["SectionId"];
                            drNew["SectionName"] = item["SectionName"];
                            drNew["Comments"] = "";
                            drNew["IsFound"] = "0";
                            drNew["IsNormal"] = "False";
                        }
                        dtTemplateSection.Rows.Add(drNew);
                    }

                    if (dtTemplateSection.Rows.Count > 0)
                    {
                        ds.Merge(dtTemplateSection);
                    }
                }
                else
                {
                    if (dsTemplateSection != null)
                    {
                        ds.Merge(dsTemplateSection.PhysExamTemplateSection);
                    }
                }
                return new BLObject<DSPhysicalExamDataTemplate>(ds);
            }
            catch (Exception ex)
            {
                MDVLogger.BLLErrorLog("BLLClinical::LoadPhysicalExamDataTemplateSystemSection", ex);
                return new BLObject<DSPhysicalExamDataTemplate>(null, ex.Message);
            }
        }

