        public BLObject<DSPhysicalExamDataTemplate> LookupPhysicalExamDataTemplateSystemChar(long dataTemplateId, long templateId, long sectionId)
        {
            try
            {
                const string Characteristic = "characteristic";

                DSPhysicalExamDataTemplate ds = new DSPhysicalExamDataTemplate();
                DSPhysicalExamTemplate dsTemplateChar = new DALPhysicalExamTemplate().LoadPhysicalExamTemplateCharForDataTemplate(templateId, sectionId, "", "");

                DataTable dtTemplateChar = new DataTable("dtFoundChars");
                dtTemplateChar.Columns.Add("CharId");
                dtTemplateChar.Columns.Add("CharName");
                dtTemplateChar.Columns.Add("Comments");
                dtTemplateChar.Columns.Add("IsPositive");
                dtTemplateChar.Columns.Add("IsNegative");
                dtTemplateChar.Columns.Add("IsFound");
                dtTemplateChar.Columns.Add("SectionCharacteristicDetailModel");


                ds = new DALPhysicalExamDataTemplate().LoadPhysicalExamDataTemplateChar(dataTemplateId, sectionId);
                if (dataTemplateId > 0)
                {

                    foreach (DataRow item in dsTemplateChar.PhysExamTemplateChar.Rows)
                    {
                        DataRow drNew = dtTemplateChar.NewRow();
                        DataRow[] arrFoundChars = ds.PhysExamDataTemplateChar.Select(ds.PhysExamDataTemplateChar.CharIdColumn.ColumnName + "=" + item["CharId"]);
                        if (arrFoundChars.Length > 0)
                        {
                            drNew["CharId"] = arrFoundChars[0]["CharId"];
                            drNew["CharName"] = arrFoundChars[0]["CharName"];
                            drNew["IsPositive"] = arrFoundChars[0]["IsPositive"];
                            drNew["IsNegative"] = arrFoundChars[0]["IsNegative"];
                            drNew["Comments"] = item["bSubCharacteristicExist"];
                            drNew["IsFound"] = "1";

                            //Start//Add char detail model data
                            DSPhysicalExamDataTemplate dsPhysExamDataTemplateDetail = new DSPhysicalExamDataTemplate();
                            BLObject<DSPhysicalExamDataTemplate> objDetail = LoadPhysicalExamDataTemplateDetail(dataTemplateId, MDVUtility.ToInt64(arrFoundChars[0]["CharId"].ToString()), Characteristic, 0);
                            dsPhysExamDataTemplateDetail = objDetail.Data;

                            if (objDetail.Data != null && dsPhysExamDataTemplateDetail.PhysExamDataTemplateDetail.Rows.Count > 0)
                            {
                                drNew["SectionCharacteristicDetailModel"] = MDVUtility.JSON_DataTable(dsPhysExamDataTemplateDetail.PhysExamDataTemplateDetail);

                            }
                            else
                            {
                                drNew["SectionCharacteristicDetailModel"] = "";
                            }
                            //End//Add char detail model data
                        }
                        else
                        {
                            drNew["CharId"] = item["CharId"];
                            drNew["CharName"] = item["CharName"];
                            drNew["Comments"] = item["bSubCharacteristicExist"];
                            drNew["IsPositive"] = "False";
                            drNew["IsNegative"] = "False";
                            drNew["IsFound"] = "0";
                            drNew["SectionCharacteristicDetailModel"] = "";
                        }
                        dtTemplateChar.Rows.Add(drNew);
                    }

                    if (dtTemplateChar.Rows.Count > 0)
                    {
                        ds.Merge(dtTemplateChar);
                    }
                }
                else
                {
                    if (dsTemplateChar != null)
                    {
                        ds.Merge(dsTemplateChar.PhysExamTemplateChar);
                    }
                }
                return new BLObject<DSPhysicalExamDataTemplate>(ds);
            }
            catch (Exception ex)
            {
                MDVLogger.BLLErrorLog("BLLClinical::LoadPhysicalExamDataTemplateSystemChar", ex);
                return new BLObject<DSPhysicalExamDataTemplate>(null, ex.Message);
            }
        }
