        public BLObject<DSClinicalComplaint> InsertComplaintForOrthopedic(DSClinicalComplaint ds, long NotesId)
        {
            try
            {
                BLObject<DSClinicalComplaint> obj = GetComplaintInfo(MDVUtility.ToLong(NotesId));
                if (obj.Data != null)
                {
                    DSClinicalComplaint dsComplaint = obj.Data;
                    if (dsComplaint.Complaint.Rows.Count > 0 && MDVUtility.ToInt(dsComplaint.Complaint.Rows[0]["ComplaintId"]) != 0)
                    {
                        ds.Complaint.Rows[0]["ComplaintId"] = dsComplaint.Complaint.Rows[0]["ComplaintId"];
                    }
                }

                return InsertComplaint(ds);


            }
            catch (Exception ex)
            {

                MDVLogger.BLLErrorLog("BLLClinical::InsertComplaintForOrthopedic", ex);
                return new BLObject<DSClinicalComplaint>(null, ex.Message);
            }
        }
        #region cheif Complaints
        // Created By:  Muhammad Ahmad Imran
        // Created Date: 08/02/2016
        //OverView: Methods "InsertComplaint" for save complaint
        public BLObject<DSClinicalComplaint> InsertComplaint(DSClinicalComplaint ds)
        {
            try
            {
                bool ComplaintAdd;

                if (MDVUtility.ToInt(ds.Complaint.Rows[0]["ComplaintId"]) != 0)
                {
                    ComplaintAdd = true;
                    for (int i = 0; i < ds.ComplaintDetail.Rows.Count; i++)
                    {
                        ds.ComplaintDetail.Rows[i]["ComplaintId"] = ds.Complaint.Rows[0]["ComplaintId"];
                    }
                    ds.NotesComplaint.Rows[0]["ComplaintId"] = ds.Complaint.Rows[0]["ComplaintId"];
                    ds = new DALComplaint().InsertComplaint(ds);
                }
                else
                {
                    ds = new DALComplaint().InsertComplaint(ds);
                    for (int i = 0; i < ds.ComplaintDetail.Rows.Count; i++)
                    {
                        ds.ComplaintDetail.Rows[i]["ComplaintId"] = ds.Complaint.Rows[0]["ComplaintId"];
                    }
                    ds.NotesComplaint.Rows[0]["ComplaintId"] = ds.Complaint.Rows[0]["ComplaintId"];
                }
                //if note id is 0 from facesheet
                if (Convert.ToString(ds.NotesComplaint.Rows[0]["NotesId"]) != "0")
                    ds = new DALComplaint().InsertNotesComplaint(ds);
                ds = new DALComplaint().InsertComplaintDetail(ds);
                return new BLObject<DSClinicalComplaint>(ds);
            }
            catch (Exception ex)
            {
                MDVLogger.BLLErrorLog("BLLClinical::InsertComplaint", ex);
                return new BLObject<DSClinicalComplaint>(null, ex.Message);
            }
        }

