        /// Author : Wasim Malik
        /// Purpose : function Get ComplaintDetail.
        /// Date : 12 Feb 2016
        public BLObject<DSClinicalComplaint> GetComplaintInfo(long NotesID)
        {
            try
            {
                DSClinicalComplaint dsComplaintNotes = new DSClinicalComplaint();
                DSClinicalComplaint dsComplaint = new DSClinicalComplaint();
                DSClinicalComplaint dsComplaintDetails = new DSClinicalComplaint();
                DSClinicalComplaint ds = new DSClinicalComplaint();
                long ComplaintID = 0;
                dsComplaintNotes = new DALComplaint().GetNotesComplaintID(NotesID);
                if (dsComplaintNotes.NotesComplaint.Count > 0)
                {
                    if (Convert.ToInt32(dsComplaintNotes.NotesComplaint.Rows[0]["ComplaintId"]) > 0)
                    {
                        ComplaintID = MDVUtility.ToLong(dsComplaintNotes.NotesComplaint.Rows[0]["ComplaintId"]);
                    }
                    dsComplaint = new DALComplaint().GetNotesComplaint(ComplaintID);
                    dsComplaintDetails = new DALComplaint().GetComplaintDetailsID(ComplaintID);
                    ds.Merge(dsComplaint);
                    ds.Merge(dsComplaintNotes);
                    ds.Merge(dsComplaintDetails);
                }

                return new BLObject<DSClinicalComplaint>(ds);
            }
            catch (Exception ex)
            {
                MDVLogger.BLLErrorLog("BLLClinical::GetComplaintInfo", ex);
                return new BLObject<DSClinicalComplaint>(null, ex.Message);
            }
        }

