        public bool isPatientMatched(Int64 PatientId, string CDSQuery)
        {

            if (!string.IsNullOrEmpty(CDSQuery))
            {
                string genderValues = "";
                string ethnicityValues = "";
                string raceIdValues = "";
                string prefLanguageIdValues = "";
                string ageOperator = "";
                int fromAgeValue = 0;
                int toAgeValue = 0;
                string[] arrCDSQuery = CDSQuery.Split(new string[] { "and" }, StringSplitOptions.None);
                foreach (string item in arrCDSQuery)
                {

                    // Gender in ('Male') and EthnicityId in(1) and RaceId in(1) and PrefLanguageId in(1) and ( Age >=  5 and Age <= 10)
                    if (item.ToLower().IndexOf("gender") > -1)
                    {
                        genderValues = item.Substring(item.IndexOf("(")).Replace("('", "").Replace("')", "").Replace("','", ",").Trim();
                        //if (genderValues.Contains(","))
                        //{
                        //    genderValues = "'" + genderValues + "'";
                        //}
                    }
                    else if (item.ToLower().IndexOf("ethnicityid") > -1)
                    {
                        ethnicityValues = item.Substring(item.IndexOf("(")).Replace("(", "").Replace(")", "").Trim();
                    }
                    else if (item.ToLower().IndexOf("raceid") > -1)
                    {
                        raceIdValues = item.Substring(item.IndexOf("(")).Replace("(", "").Replace(")", "").Trim();
                    }
                    else if (item.ToLower().IndexOf("preflanguageid") > -1)
                    {
                        prefLanguageIdValues = item.Substring(item.IndexOf("(")).Replace("(", "").Replace(")", "").Trim();
                    }
                    else if (item.ToLower().IndexOf("age") > -1)
                    {
                        string ageAllValues = "";
                        if (item.Contains("(") && item.Contains(")"))
                        {
                            ageAllValues = item.Substring(item.IndexOf("(")).Replace("(", "").Replace(")", "").Trim();
                        }
                        else
                        {
                            ageAllValues = item.Trim();
                        }
                        string[] arrageValues = ageAllValues.Split(new string[] { "or" }, StringSplitOptions.None);
                        if (arrageValues.Length > 1)
                        {
                            ageOperator = "between";
                            fromAgeValue = MDVUtility.ToInt(arrageValues[0].Replace("Age", "").Replace(">=", "").Trim());
                            toAgeValue = MDVUtility.ToInt(arrageValues[1].Replace("Age", "").Replace("<=", "").Trim());
                        }
                        else if (arrageValues.Length > 0)
                        {
                            string singleAgeValues = arrageValues[0].Replace("Age", "").Trim();
                            string[] arrsingleValues = singleAgeValues.Split(new string[] { " " }, StringSplitOptions.None);
                            ageOperator = arrsingleValues.Length > 0 ? arrsingleValues[0] : "";
                            fromAgeValue = arrsingleValues.Length > 1 ? Convert.ToInt32(arrsingleValues[1]) : 0;
                        }
                    }

                }
                DataTable dtMatchedPatient = new DALCDS().loadCDSPatient(genderValues, raceIdValues, ethnicityValues, prefLanguageIdValues, ageOperator, fromAgeValue, toAgeValue, PatientId);
                if (dtMatchedPatient.Rows.Count > 0)
                {
                    return true;
                }
                else
                {
                    return false;
                }
            }
            return false;
        }

        /// <summary>
        /// Module Name: loadCDSList
        /// Author: Humaira Yousaf
        /// Created Date: 03-03-2016
        /// Description: Loads CDS
        /// </summary>
        /// <param name="CDSId" type="long">CDS Id to load</param>
        /// <param name="pageNumber" type="int">pageNumber</param>
        /// <param name="rowsPerPage" type="int">rowsPerPage</param>
        public BLObject<DSCDS> loadCDS(long CDSId, byte IsActive = 1, int pageNumber = 1, int rowsPerPage = 1000, string isViewCDS = "", string isPrintCDS = "", long PatientId = 0)
        {
            try
            {
                DSCDS dsCDS = new DALCDS().loadCDS(CDSId, IsActive, pageNumber, rowsPerPage, isViewCDS, isPrintCDS, PatientId);

                if (CDSId > 0)
                {
                    //Start 08-03-2016 Humaira Yousaf to get CDS Vitals
                    DSCDS dsCDSVitals = new DALCDS().loadCDSVitals(CDSId, 0);
                    dsCDS.Merge(dsCDSVitals);
                    //End 08-03-2016 Humaira Yousaf to get CDS Vitals

                    //Start 10-03-2016 Humaira Yousaf to get CDS Medications
                    DSCDS dsCDSMedication = new DALCDS().loadCDSMedication(CDSId, 0);
                    dsCDS.Merge(dsCDSMedication);
                    DSCDS dsCDSAllergy = new DALCDS().loadCDSAllergy(CDSId, 0);
                    dsCDS.Merge(dsCDSAllergy);
                    DSCDS dsCDSProblem = new DALCDS().loadCDSProblemList(CDSId, 0);
                    dsCDS.Merge(dsCDSProblem);
                    DSCDS dsCDSLabResult = new DALCDS().loadCDSLabResult(CDSId, 0);
                    dsCDS.Merge(dsCDSLabResult);
                    DSCDS dsCDSQuestionnaire = new DALCDS().loadCDSQuestionnaire(CDSId, 0);
                    dsCDS.Merge(dsCDSQuestionnaire);
                    //End 10-03-2016 Humaira Yousaf to get CDS Medications

                    DSCDS dsCDSInsurance = new DALCDS().loadCDSInsurance(CDSId, 0);
                    dsCDS.Merge(dsCDSInsurance);
                }

                return new BLObject<DSCDS>(dsCDS);
            }
            catch (Exception ex)
            {
                MDVLogger.BLLErrorLog("BLLClinical::loadCDS", ex);
                return new BLObject<DSCDS>(null, ex.Message);
            }
        }

