        public BLObject<DSCDS> cdsActualConditions(bool isCurrent, long problemListId, long medicationId, long labResultId, long noteId, long vitalSignId, long AllergyId, long patientId, string isHistory, string isActive, int pageNumber = 1, int rowsPerPage = 1000)
        {
            try
            {
                DSCDS dsCDS = new DSCDS();
                dsCDS.Merge(new DALAllergies().loadAllAllergies_Obsolete(AllergyId, patientId, noteId, isHistory, isActive));
                dsCDS.Merge(new DALProblemLists().LoadAllProblemLists(problemListId, patientId, noteId, isHistory, isActive));
                dsCDS.Merge(new DALVitals().LoadAllVitals(patientId, vitalSignId));
                dsCDS.Merge(new DALMedications().loadAllMedications(medicationId, patientId, noteId, isCurrent));
                dsCDS.Merge(new DALLabResult().LoadLabResultForCDS(patientId));
                dsCDS.Merge(new DALPatientInsurance().LookupPatientInsurance(patientId, null));
                return new BLObject<DSCDS>(dsCDS);
            }
            catch (Exception ex)
            {
                MDVLogger.BLLErrorLog("BLLClinical::cdsActualConditions", ex);
                return new BLObject<DSCDS>(null, ex.Message);
            }
        }


