        public BLObject<DSLabOrder> InsertUpdateLabOrder(DSLabOrder ds, IDBManager dbManager = null)
        {
            try
            {
                ds = new DALLabOrder().InsertUpdateLabOrder(ds, dbManager);
                return new BLObject<DSLabOrder>(ds);
            }
            catch (Exception ex)
            {
                MDVLogger.BLLErrorLog("BLLClinical::InsertUpdateLabOrder", ex);
                if (dbManager != null)
                {
                    throw ex;
                }
                else
                {
                    return new BLObject<DSLabOrder>(null, ex.Message);
                }
            }
        }

        public BLObject<DSLabOrder> InsertUpdateLabOrder(LabOrderModel model, List<LabOrderTestModel> IstLabObjects)
        {
            IDBManager dbManager = ClientConfiguration.GetDBManager();

            StringBuilder laborderIDs = new StringBuilder();
            string InsertType = "";
            // status, message, LabOrderId, OrderNo
            Tuple<bool, string, long, string> response = null;
            // If tests are added from favorite groups then save multi lab orders according to LabId
            try
            {
                dbManager.BeginTransaction();

                if (model.IsFavoriteGroupTypeSave)
                {
                    InsertType = "FavoriteGroup";

                    var LabsArray = model.LabIds.Split(',');
                    foreach (var Lab in LabsArray)
                    {
                        List<LabOrderTestModel> LabOrderTests = new List<LabOrderTestModel>();
                        List<LabOrderTestModel> SeperateLabOrderTests = new List<LabOrderTestModel>();
                        // Lab specific tests
                        LabOrderTests = IstLabObjects.Where(t => t.FavoriteGroupTestLabId == Lab && t.IsSeperateTestOrder.ToLower() != "true").ToList();

                        if (LabOrderTests != null && LabOrderTests.Count > 0)
                        {
                            model.LabId = LabOrderTests[0].FavoriteGroupTestLabId;
                            response = insertUpdateLabOrder(model, LabOrderTests, dbManager);
                            var LabOrderId = response.Item3;
                            laborderIDs.Append(',');
                            laborderIDs.Append(LabOrderId);
                        }

                        // Seperate Favorite Group Lab Tests to be ordered solely (VitalAxis)
                        // Lab - Vital Axis seperate test orders
                        SeperateLabOrderTests = IstLabObjects.Where(t => t.FavoriteGroupTestLabId == Lab && t.IsSeperateTestOrder.ToLower() == "true").ToList();

                        if (SeperateLabOrderTests != null && SeperateLabOrderTests.Count > 0)
                        {
                            model.LabId = SeperateLabOrderTests[0].FavoriteGroupTestLabId;
                            foreach (LabOrderTestModel item in SeperateLabOrderTests)
                            {
                                List<LabOrderTestModel> SeperateList = new List<LabOrderTestModel>();
                                SeperateList.Add(item);
                                response = insertUpdateLabOrder(model, SeperateList, dbManager);
                                var LabOrderId = response.Item3;
                                laborderIDs.Append(',');
                                laborderIDs.Append(LabOrderId);
                            }
                        }
                    }
                    //var response = new
                    //{
                    //    status = true,
                    //    LabOrderIDs = laborderIDs.ToString(),
                    //    InsertType = "FavoriteGroup",
                    //    Message = "Successfully Saved"
                    //};
                }
                else
                {
                    response = insertUpdateLabOrder(model, IstLabObjects, dbManager);
                }

                // throw new Exception("notsaved");

                dbManager.CommitTransaction();

                DSLabOrder ds = new DSLabOrder();
                var dr = ds.BLLCustomReturn.NewBLLCustomReturnRow();

                dr.LabOrderId = response.Item3;
                dr.Message = response.Item2;
                dr.InsertType = InsertType;
                dr.Status = response.Item1;
                dr.LabOrderIDs = laborderIDs.ToString();
                dr.OrderNo = response.Item4;

                ds.BLLCustomReturn.AddBLLCustomReturnRow(dr);
                return new BLObject<DSLabOrder>(ds);

            }
            catch (Exception ex)
            {
                dbManager.RollBackTransaction();
                throw ex;
            }
        }
        public Tuple<bool, string, long, string> insertUpdateLabOrder(LabOrderModel model, List<LabOrderTestModel> lstLabObjects, IDBManager dbManager)
        {
            try
