        public BLObject<DSLabOrder> GetLabOrderPatientInfo(long labOrderId, long patientId, long noteid = -1)
        {
            try
            {
                DSLabOrder dsLabOrder = new DSLabOrder();

                dsLabOrder = new DALLabOrder().LoadLabOrder(labOrderId, patientId, noteid, "", "", "", "", 0, "", "", "", 0);
                dsLabOrder.Merge(new DALPatient().FillPatient(patientId, "", ""));
                dsLabOrder.Merge(new DALLabOrder().loadLabOrderProblems(0, labOrderId, patientId));
                dsLabOrder.Merge(new DALLabOrder().LoadLabOrderTest(labOrderId, 0, patientId, "", ""));
                return new BLObject<DSLabOrder>(dsLabOrder);
            }
            catch (Exception ex)
            {
                MDVLogger.BLLErrorLog("BLLClinical::detachLabOrderFromNotes", ex);
                return new BLObject<DSLabOrder>(null, ex.Message);
            }
        }

