                var insuredFirstName = string.IsNullOrEmpty(drLabOrderExternalBillingInfoPrimary[dsLabOrderExternalBillingInfoPrimary.External_PatientInsurancePlanAddress.InsuredFirstNameColumn.ColumnName].ToString()) ? "N/A" : drLabOrderExternalBillingInfoPrimary[dsLabOrderExternalBillingInfoPrimary.External_PatientInsurancePlanAddress.InsuredFirstNameColumn.ColumnName].ToString();
                Paragraph value = new Paragraph((insuredLastName + ", " + insuredFirstName), bodyFont);
                Paragraph relName = new Paragraph("Insured Relation: ", componentHeaderFont);
                Paragraph relValue = new Paragraph(string.IsNullOrEmpty(drLabOrderExternalBillingInfoPrimary[dsLabOrderExternalBillingInfoPrimary.External_PatientInsurancePlanAddress.InsuredRelationshipColumn.ColumnName].ToString()) ? "N/A" : drLabOrderExternalBillingInfoPrimary[dsLabOrderExternalBillingInfoPrimary.External_PatientInsurancePlanAddress.InsuredRelationshipColumn.ColumnName].ToString(), bodyFont);
                Paragraph paraAddress = new Paragraph("Insured Address: ", componentHeaderFont);
                Paragraph relAddValue = new Paragraph(string.IsNullOrEmpty(drLabOrderExternalBillingInfoPrimary[dsLabOrderExternalBillingInfoPrimary.External_PatientInsurancePlanAddress.InsuredAddressColumn.ColumnName].ToString()) ? "N/A" : drLabOrderExternalBillingInfoPrimary[dsLabOrderExternalBillingInfoPrimary.External_PatientInsurancePlanAddress.InsuredAddressColumn.ColumnName].ToString(), bodyFont);
