                    pdfDocument.Add(line2);
                    #region Patient/Provider Segment
                    string AccountNumber = dsLabOrder.Tables[dsPatient.Patients.TableName].Rows[0]["AccountNumber"].ToString();
                    try
                    {
                        PdfPTable ReportPatientProvider = new PdfPTable(2);
                        ReportPatientProvider.TotalWidth = 575f;
                        ReportPatientProvider.SpacingBefore = 3f;
                        ReportPatientProvider.SpacingAfter = 8f;
                        ReportPatientProvider.LockedWidth = true;
                        ReportPatientProvider.DefaultCell.Border = Rectangle.NO_BORDER;

                        ReportPatientProvider.AddCell(SetLabPatient(patientId, patientName, fontColour, bodyFont, componentHeadingFont, patientNameFont, AccountNumber));
                        ReportPatientProvider.AddCell(SetLabProvider(providerId, patientNameFont, bodyFont));
                        pdfDocument.Add(ReportPatientProvider);
                    }
                    catch (Exception ex)
                    {
                        MDVLogger.BLLErrorLog("BLLAdminClinical::LabOrderPreview, Patient or Provider Segment", ex);
                    }

                    BaseColor myColor = WebColors.GetRGBColor("#66B2FF");
                    LineSeparator Borderline = new LineSeparator(1f, 100f, myColor, Element.ALIGN_CENTER, 4);
                    pdfDocument.Add(Borderline);

                    Paragraph requisitionHeading = new Paragraph("Lab Requisition".ToString(), patientNameFont);
                    LineSeparator requisitionHeadingLine = new LineSeparator(1f, 100f, iTextSharp.text.BaseColor.BLACK, iTextSharp.text.Element.ALIGN_CENTER, -1);
                    requisitionHeadingLine.Offset = 1;
                    pdfDocument.Add(requisitionHeading);


                    #endregion

                    #region Lab Requisition

                    // Order Information & Insured Relationship
                    labOrderInformation(pdfDocument, dsLabOrder, componentHeaderFont, componentHeadingFont, bodyFont);
                    // Billing Information
                    labOrderInformationANDInsuredInformation(pdfDocument, dsLabOrder, componentHeaderFont, componentHeadingFont, bodyFont, dsLabOrderExternalBillingInfoPrimary, drLabOrderExternalBillingInfoPrimary, dsLab);

                    // Guarantor
                    labOrderGuarantor(pdfDocument, componentHeadingFont, componentHeaderFont, bodyFont, dsLabOrder);

                    // Test Information
                    labOrderTestInformation(pdfDocument, componentHeadingFont, componentHeaderFont, bodyFont, testDetailFont, dsLabOrder);

                    // Diagnosis Codes
                    labOrderDiagnosisCodes(pdfDocument, componentHeadingFont, bodyFont, dsLabOrder);

                    #endregion

                    #region Comments

                    Paragraph comments_Heading = new Paragraph("Comments\n".ToString(), componentHeadingFont);
                    pdfDocument.Add(comments_Heading);
                    pdfDocument.Add(new Paragraph(dsLabOrder.Tables[dsLabOrder.LabOrderTest.TableName].Rows[0][dsLabOrder.LabOrderTest.FillerInstructionColumn.ColumnName].ToString(), bodyFont));

                    #endregion

                    #region e-Signed

                    pdfDocument.Add(Chunk.NEWLINE);
                    pdfDocument.Add(Chunk.NEWLINE);
                    Paragraph signedBy = new Paragraph("e-Signed By: " + MDVUtility.ToStr(dsLabOrder.Tables[dsLabOrder.LabOrder.TableName].Rows[0][dsLabOrder.LabOrder.ModifiedByColumn.ColumnName]) + " on " + MDVUtility.ToDateTime(dsLabOrder.Tables[dsLabOrder.LabOrder.TableName].Rows[0][dsLabOrder.LabOrder.ModifiedOnColumn.ColumnName]).ToLongDateString() + " at " + MDVUtility.ToDateTime(dsLabOrder.Tables[dsLabOrder.LabOrder.TableName].Rows[0][dsLabOrder.LabOrder.ModifiedOnColumn.ColumnName]).ToLongTimeString(), bodyFont);
                    signedBy.Alignment = Element.ALIGN_LEFT;
                    pdfDocument.Add(signedBy);

                    #endregion



                    #region But in the end It doesn't even matter

                    pdf.Document.Close();
                    pdf.Writer.Close();
                    pdfDocument.Close();

                    MemoryStream stream = new MemoryStream(stream_.ToArray());
                    PdfReader npdf = new PdfReader(stream);
                    MemoryStream outstream = new MemoryStream();

                    var color = System.Drawing.ColorTranslator.FromHtml("#fff");
                    var fontcolor = new BaseColor(color);
                    Font componentFooterFont = FontFactory.GetFont("Arial", 8, Font.NORMAL, fontcolor);
                    using (PdfStamper stamper = new PdfStamper(npdf, outstream, '\0', true))
                    {
                        stamper.Writer.CloseStream = false;
                        int PageCount = npdf.NumberOfPages;
                        for (int i = 1; i <= PageCount; i++)
                            ColumnText.ShowTextAligned(stamper.GetOverContent(i), Element.ALIGN_CENTER, new Paragraph(String.Format("Page {0} of {1}", i, PageCount), componentFooterFont), 555, 18, 0);
                    }
                    newByteArr = outstream.GetBuffer();

                    #endregion


                }
                return new BLObject<byte[]>(newByteArr);
            }
            catch (Exception ex)
            {
                MDVLogger.BLLErrorLog("BLLClinical::previewLabOrder", ex);
                return new BLObject<byte[]>(null, ex.Message);
            }
        }
        #endregion

        // Author: Ahsan Nasir
        /// <summary>
        /// previewLabOrderABN
        /// </summary>
        /// <param name="labId"></param>
        /// <param name="patientId"></param>
        /// <param name="BarCodeHtml"></param>
        /// <param name="ImagePath"></param>
        /// <param name="Tests"></param>
        /// <returns></returns>
        public BLObject<byte[]> previewLabOrderABN(long labId, long patientId, string BarCodeHtml, string ImagePath, string[] Tests)
        {
            var filePath = string.Empty;
            try
            {

                DSLabOrder dsLabOrder = new DSLabOrder();
                DSInsurance dsInsurance = new DSInsurance();
                DSPatient dsPatient = new DSPatient();
                DSProfile dsProfile = new DSProfile();


                dsLabOrder = new DALLabOrder().LoadLabOrder(labId, patientId, 0, "", "", "", "", 0, "", "", "", 0, "", "1");
                DSLab dsLab = new DALLab().GetLab(MDVUtility.ToLong(dsLabOrder.LabOrder.Rows[0][dsLabOrder.LabOrder.LabIdColumn.ColumnName]), MDVUtility.ToLong(dsLabOrder.LabOrder.Rows[0][dsLabOrder.LabOrder.ProviderIdColumn.ColumnName]), MDVUtility.ToLong(dsLabOrder.LabOrder.Rows[0][dsLabOrder.LabOrder.FacilityIdColumn.ColumnName]));

                if (patientId == 0)
                {
                    if (dsLabOrder.Tables[dsLabOrder.LabOrder.TableName].Rows.Count > 0)
                    {
                        patientId = MDVUtility.ToInt64(dsLabOrder.Tables[dsLabOrder.LabOrder.TableName].Rows[0][dsLabOrder.LabOrder.PatientIdColumn.ColumnName]);
                    }
                }

                dsLabOrder.Merge(new DALPatient().FillPatient(patientId, "", ""));
                long practiceId = MDVUtility.ToInt64(dsLabOrder.Tables[dsPatient.Patients.TableName].Rows[0][dsPatient.Patients.PracticeIdColumn.ColumnName]);
                long providerId = MDVUtility.ToInt64(dsLabOrder.Tables[dsPatient.Patients.TableName].Rows[0][dsPatient.Patients.ProviderIdColumn.ColumnName]);
                if (dsLabOrder.Tables[dsLabOrder.LabOrder.TableName].Rows.Count > 0)
                {
                    providerId = MDVUtility.ToInt64(dsLabOrder.Tables[dsLabOrder.LabOrder.TableName].Rows[0][dsLabOrder.LabOrder.ProviderIdColumn.ColumnName]);
                }

                dsLabOrder.Merge(new DALPractice().LoadPractice(practiceId, string.Empty, string.Empty, string.Empty, string.Empty, string.Empty));

                byte[] newByteArr = null;
                using (MemoryStream stream_ = new MemoryStream())
                {
                    Document pdfDocument = new Document(PageSize.LETTER, 20, 20, 20, 35);
                    // Heading Font Style
                    BaseColor myColor1 = WebColors.GetRGBColor("#66B2FF");
                    var fontColour = new BaseColor(102, 178, 255);
                    iTextSharp.text.Font patientNameFont = FontFactory.GetFont("Arial", 12, iTextSharp.text.Font.BOLD, fontColour);
                    iTextSharp.text.Font bodyFont = FontFactory.GetFont("Arial", 10, iTextSharp.text.Font.NORMAL, iTextSharp.text.BaseColor.BLACK);
                    iTextSharp.text.Font bodyFontUn = FontFactory.GetFont("Arial", 8, iTextSharp.text.Font.UNDERLINE, myColor1);

                    iTextSharp.text.Font bodyFontBlue = FontFactory.GetFont("Arial", 10, iTextSharp.text.Font.BOLD, myColor1);
                    iTextSharp.text.Font bodyFontSmall = FontFactory.GetFont("Arial", 8, iTextSharp.text.Font.NORMAL, BaseColor.GRAY);
                    iTextSharp.text.Font componentHeadingFont = FontFactory.GetFont("Arial", 10, iTextSharp.text.Font.BOLD, fontColour);
                    iTextSharp.text.Font componentHeaderFont = FontFactory.GetFont("Arial", 10, iTextSharp.text.Font.NORMAL, iTextSharp.text.BaseColor.BLACK);
                    iTextSharp.text.Font componentGridHeaderFont = FontFactory.GetFont("Arial", 10, iTextSharp.text.Font.NORMAL, new BaseColor(102, 178, 255));
                    iTextSharp.text.Font gridbodyFont = FontFactory.GetFont("Arial", 10, iTextSharp.text.Font.BOLD, iTextSharp.text.BaseColor.BLACK);
                    iTextSharp.text.Font bodyFontParent = FontFactory.GetFont("Arial", 10, iTextSharp.text.Font.BOLD, iTextSharp.text.BaseColor.BLACK);
                    iTextSharp.text.Font gridbodyFontTest = FontFactory.GetFont("Arial", 10, iTextSharp.text.Font.BOLD, iTextSharp.text.BaseColor.BLUE);

                    MDVUtility.PDFCreator pdf = new MDVUtility.PDFCreator(ref pdfDocument, stream_, false, ClientConfiguration.DecryptFrom64(MDVSession.Current.AppUserName), ClientConfiguration.DecryptFrom64(MDVSession.Current.AppUserName), "Requisition");
                    pdf.Document.Open();

                    DSPatient dsPat = new DSPatient();
                    dsPat = new DALPatient().FillPatient(patientId, "", "");
                    string PatHtml = string.Empty;

                    if (dsPat.Patients.Rows.Count > 0)
                    {
                        PatHtml = string.Concat(MDVUtility.ToStr(dsPat.Patients.Rows[0][dsPat.Patients.LastNameColumn.ColumnName]) + ", ", string.IsNullOrEmpty(MDVUtility.ToStr(dsPat.Patients.Rows[0][dsPat.Patients.MIColumn.ColumnName])) ? "" : MDVUtility.ToStr(dsPat.Patients.Rows[0][dsPat.Patients.MIColumn.ColumnName]) + ", ", MDVUtility.ToStr(dsPat.Patients.Rows[0][dsPat.Patients.FirstNameColumn.ColumnName]));
                    }


                    PdfPTable headerNotifierTable = new PdfPTable(2);
                    float[] notifierHeaderWidths = new float[] { 3f, 18f };
                    headerNotifierTable.SetWidths(notifierHeaderWidths);
                    headerNotifierTable.TotalWidth = 575f;
                    headerNotifierTable.LockedWidth = true;
                    headerNotifierTable.HorizontalAlignment = Element.ALIGN_CENTER;
                    headerNotifierTable.DefaultCell.Border = Rectangle.NO_BORDER;

                    string clientDetails = "";
                    if (dsLab.Lab.Rows.Count > 0)
                    {
                        clientDetails = string.Concat(clientDetails, dsLab.Lab.Rows[0][dsLab.Lab.NameColumn.ColumnName] + ", ");
                        clientDetails = string.Concat(clientDetails, dsLab.Lab.Rows[0][dsLab.Lab.AddressColumn.ColumnName], ", ");
                        clientDetails = string.Concat(clientDetails, dsLab.Lab.Rows[0][dsLab.Lab.ClientNoColumn.ColumnName], ", ");
                        clientDetails = string.Concat(clientDetails, string.IsNullOrEmpty(dsLab.Lab.Rows[0][dsLab.Lab.CityColumn.ColumnName].ToString()) ? "" : dsLab.Lab.Rows[0][dsLab.Lab.CityColumn.ColumnName] + ", ");
                        clientDetails = string.Concat(clientDetails, string.IsNullOrEmpty(dsLab.Lab.Rows[0][dsLab.Lab.StateColumn.ColumnName].ToString()) ? "" : dsLab.Lab.Rows[0][dsLab.Lab.StateColumn.ColumnName] + ", ");
                        clientDetails = string.Concat(clientDetails, string.IsNullOrEmpty(dsLab.Lab.Rows[0][dsLab.Lab.ZIPCodeColumn.ColumnName].ToString()) ? "" : dsLab.Lab.Rows[0][dsLab.Lab.ZIPCodeColumn.ColumnName] + ", ");
                        clientDetails = string.Concat(clientDetails, dsLab.Lab.Rows[0][dsLab.Lab.PhoneNoColumn.ColumnName]);
                    }

                    Paragraph notifierHeading = new Paragraph("Notifier(s):", componentHeadingFont);
                    Paragraph notifierDetail = new Paragraph(clientDetails, bodyFont);
                    notifierHeading.Alignment = Element.ALIGN_LEFT;
                    notifierDetail.Alignment = Element.ALIGN_LEFT;
                    headerNotifierTable.AddCell(notifierHeading);
                    headerNotifierTable.AddCell(notifierDetail);

                    pdfDocument.Add(headerNotifierTable);

                    PdfPTable HeaderPatientTable = new PdfPTable(4);
                    float[] HeaderPatientWidths = new float[] { 3f, 10f, 5f, 4f };
                    HeaderPatientTable.SetWidths(HeaderPatientWidths);
                    HeaderPatientTable.TotalWidth = 575f;
                    HeaderPatientTable.LockedWidth = true;
                    HeaderPatientTable.HorizontalAlignment = Element.ALIGN_CENTER;
                    HeaderPatientTable.DefaultCell.Border = Rectangle.NO_BORDER;

                    Paragraph patientName = new Paragraph("Patient Name:", componentHeadingFont);
                    Paragraph patientNameVal = new Paragraph(PatHtml, bodyFont);

                    Paragraph patientID = new Paragraph("Identification Number: ", componentHeadingFont);
                    Paragraph patientIDVal = new Paragraph(HttpUtility.HtmlDecode(MDVUtility.ToStr(dsLabOrder.Tables[dsLabOrder.LabOrder.TableName].Rows[0][dsLabOrder.LabOrder.OrderNoColumn.ColumnName])), bodyFont);
                    var x2 = new MyPdfPageEventHelpPageNo(PatHtml, bodyFont, MDVUtility.ToStr(dsLabOrder.Tables[dsLabOrder.LabOrder.TableName].Rows[0][dsLabOrder.LabOrder.OrderNoColumn.ColumnName]), componentHeadingFont);
                    pdf.Writer.PageEvent = x2;

                    HeaderPatientTable.AddCell(patientName);
                    HeaderPatientTable.AddCell(patientNameVal);
                    HeaderPatientTable.AddCell(patientID);
                    HeaderPatientTable.AddCell(patientIDVal);

                    PdfPTable lineTable = new PdfPTable(1);
                    lineTable.TotalWidth = 575f;
                    lineTable.LockedWidth = true;
                    lineTable.HorizontalAlignment = Element.ALIGN_CENTER;
                    lineTable.DefaultCell.Border = Rectangle.NO_BORDER;

                    LineSeparator line2 = new LineSeparator(1f, 100f, myColor1, iTextSharp.text.Element.ALIGN_CENTER, -1);
                    line2.Offset = 1;

                    PdfPCell lineCell11 = new PdfPCell();
                    lineCell11.Colspan = 2;
                    lineCell11.Border = Rectangle.NO_BORDER;
                    lineCell11.AddElement(new Chunk(line2));
                    lineTable.AddCell(lineCell11);

                    pdfDocument.Add(HeaderPatientTable);
                    pdfDocument.Add(lineTable);

                    // ABN Begins
                    Paragraph ABNHeading = new Paragraph("Advance Beneficiary Notice of Noncoverage (ABN)", patientNameFont);
                    ABNHeading.Alignment = Element.ALIGN_CENTER;
                    Chunk testChunk = null;
                    if (Tests.Length <= 1)
                    {
                        testChunk = new Chunk("Laboratory Test", componentHeadingFont);
                    }
                    else
                    {
                        testChunk = new Chunk("Laboratory Tests", componentHeadingFont);
                    }
                    pdfDocument.Add(ABNHeading);
                    Paragraph ABNNote = new Paragraph("NOTE: ", componentHeadingFont);
                    ABNNote.Add(new Chunk("if Medicare doesn't pay for ", bodyFont));
                    ABNNote.Add(testChunk);
                    ABNNote.Add(new Chunk(" below. You may have to pay.", bodyFont));
                    pdfDocument.Add(ABNNote);

                    Paragraph ABNNoteTwo = new Paragraph("Medicare does not pay for everything, even some care that you or your health care provider have good reason to think you need. We expect Medicare may not pay for ", bodyFont);
                    ABNNoteTwo.Add(testChunk);
                    ABNNoteTwo.Add(new Chunk(" below.", bodyFont));
                    pdfDocument.Add(ABNNoteTwo);

                    Paragraph labHeading = new Paragraph("Laboratory Test", componentHeadingFont);
                    labHeading.Alignment = Element.ALIGN_CENTER;
                    Paragraph labReasonHeading = new Paragraph("Reason Medicare May Not Pay", componentHeadingFont);
                    labReasonHeading.Alignment = Element.ALIGN_CENTER;
                    Paragraph labCostHeading = new Paragraph("Estimated Cost", componentHeadingFont);
                    labCostHeading.Alignment = Element.ALIGN_CENTER;

                    PdfPTable labTestTable = new PdfPTable(3);
                    float[] labTestWidths = new float[] { 6.3f, 6.3f, 6.3f };
                    labTestTable.SetWidths(labTestWidths);
                    labTestTable.SpacingBefore = 15f;
                    labTestTable.SpacingAfter = 5f;
                    // labTestTable.DefaultCell.Border = Rectangle.NO_BORDER;
                    labTestTable.TotalWidth = 500f;
                    labTestTable.LockedWidth = true;
                    labTestTable.HorizontalAlignment = Element.ALIGN_CENTER;

                    labTestTable.AddCell(labHeading);
                    labTestTable.AddCell(labReasonHeading);
                    labTestTable.AddCell(labCostHeading);

                    //    dsLabOrder.Merge(new DALLabOrder().GetLabOrderABN(Convert.ToInt64(dsLabOrder.Tables[dsLabOrder.LabOrder.TableName].Rows[0][dsLabOrder.LabOrder.LabOrderIdColumn.ColumnName])));

                    if (Tests[0] != "")
                    {
                        foreach (string test in Tests)
                        {
                            labTestTable.AddCell(new Paragraph(test, bodyFont));
                            labTestTable.AddCell(new Paragraph("Medicare does not pay for this test or service for this condition.", bodyFont));
                            labTestTable.AddCell(new Paragraph("($_________)", bodyFont));
                        }
                    }


                    //// these values will come in a loop
                    //if (dsLabOrder.Tables[dsLabOrder.LabOrderTest.TableName].Rows.Count > 0) {

                    //    foreach (DSLabOrder.LabOrderTestRow dr in dsLabOrder.Tables[dsLabOrder.LabOrderTest.TableName].Rows)
                    //    {
                    //        labTestTable.AddCell(new Paragraph(MDVUtility.ToStr(dr[dsLabOrder.LabOrderTest.CPTCodeDescriptionColumn.ColumnName]), bodyFont));
                    //        labTestTable.AddCell(new Paragraph("Medicare does not pay for this test or service for this condition.", bodyFont));
                    //        labTestTable.AddCell(new Paragraph("($_________)", bodyFont));
                    //    }

                    //}
                    else
                    {
                        PdfPCell noLabCell = new PdfPCell();
                        noLabCell.Colspan = 3;
                        noLabCell.AddElement(new Paragraph("No Tests Found. Please check some tests first.", bodyFont));
                        labTestTable.AddCell(noLabCell);
                    }
                    // total cost comes here


                    pdfDocument.Add(labTestTable);

                    // Paragraphs

                    Paragraph ABNNote2 = new Paragraph("What you need to do now:", componentHeadingFont);
                    pdfDocument.Add(ABNNote2);

                    Paragraph bullet = new Paragraph("Choose an option below about whether to receive the ", bodyFont);
                    bullet.Add(testChunk);
                    bullet.Add(new Chunk(" listed above.", bodyFont));

                    List list = new List(List.UNORDERED, 10f);
                    list.SetListSymbol("\u2022");
                    list.IndentationLeft = 30f;
                    list.Add(new ListItem("Read this notice, so you can make an uninformed decision about your care.", bodyFont));
                    list.Add(new ListItem("Ask us any questions, if you may have after you finish reading.", bodyFont));
                    list.Add(new ListItem(bullet));

                    pdfDocument.Add(list);

                    Paragraph ABNNoteThree = new Paragraph("Note: If you choose option 1 or 2, we may help you use any other insurance that you might have, but Medicare cannot require us to do this.", bodyFont);
                    pdfDocument.Add(ABNNoteThree);

                    LineSeparator line3 = new LineSeparator(1f, 100f, myColor1, iTextSharp.text.Element.ALIGN_CENTER, -10);
                    pdfDocument.Add(line3);

                    PdfPTable optionsTable = new PdfPTable(1);
                    optionsTable.TotalWidth = 500f;
                    optionsTable.SpacingBefore = 15f;
                    optionsTable.SpacingAfter = 10f;
                    optionsTable.LockedWidth = true;
                    optionsTable.DefaultCell.Border = Rectangle.NO_BORDER;
                    optionsTable.HorizontalAlignment = Element.ALIGN_CENTER;
                    Paragraph optionsHeading = new Paragraph("OPTIONS: Check only one box. We cannot choose a box for you.", componentHeadingFont);

                    Paragraph optionOneText = new Paragraph("      OPTION 1. I want the ", bodyFont);
                    optionOneText.Add(testChunk);
                    optionOneText.Add(new Chunk(" listed above. You may ask to be payed now, but I also want Medicare billed for an official decision on payment, which is sent to me on a Medicare Summary Notice (MSN) I understand that if Medicare doesn't pay, I am responsible for payment,", bodyFont));
                    optionOneText.Add(new Chunk(" but I can appeal to Medicare ", bodyFontBlue));
                    optionOneText.Add(new Chunk("by following the directions on MSN. If Medicare does pay, you will refund any payments I made to you, less co-pays or deductibles.", bodyFont));

                    var curY = pdf.Writer.GetVerticalPosition(true);  // get x,y coordinate for current position of writer for Checkboxes
                    curY -= 41;

                    PdfContentByte over = pdf.Writer.DirectContent;
                    over.SaveState();
                    over.Rectangle(60, curY, 10, 10);
                    over.Rectangle(60, (curY - 55), 10, 10);
                    over.Rectangle(60, (curY - 79), 10, 10);
                    over.SetColorFill(myColor1);
                    over.SetColorStroke(myColor1);
                    over.Stroke();
                    over.Fill();
                    over.RestoreState();

                    Paragraph optionTwoText = new Paragraph("       OPTION 2. I want the ", bodyFont);
                    optionTwoText.Add(testChunk);
                    optionTwoText.Add(new Chunk(" listed above, but do not bill Medicare. You may ask to be paid now as I am responsible for the payment.", bodyFont));
                    optionTwoText.Add(new Chunk(" I cannot appeal if the Medicare is not billed.", bodyFontBlue));

                    Paragraph optionThreeText = new Paragraph("       OPTION 3. I want the ", bodyFont);
                    optionThreeText.Add(testChunk);
                    optionThreeText.Add(new Chunk(" listed above. I understand with this choice I am not responsible for payment, and", bodyFont));
                    optionThreeText.Add(new Chunk(" I cannot appeal to see if Medicare would pay. ", bodyFontBlue));

                    optionsTable.AddCell(optionsHeading);
                    optionsTable.AddCell(optionOneText);
                    optionsTable.AddCell(optionTwoText);
                    optionsTable.AddCell(optionThreeText);
                    pdfDocument.Add(optionsTable);
                    LineSeparator line4 = new LineSeparator(1f, 100f, myColor1, iTextSharp.text.Element.ALIGN_CENTER, -1);

                    pdfDocument.Add(line4);

                    PdfPTable additionalTable = new PdfPTable(1);
                    additionalTable.TotalWidth = 558f;
                    additionalTable.SpacingBefore = 5f;
                    additionalTable.SpacingAfter = 5f;
                    additionalTable.DefaultCell.Border = Rectangle.NO_BORDER;
                    additionalTable.LockedWidth = true;
                    additionalTable.HorizontalAlignment = Element.ALIGN_CENTER;

                    additionalTable.AddCell(new Paragraph("Additional Information: \n", componentHeadingFont));

                    Paragraph additionalText = new Paragraph("This notice gives our opinion, not an official Medicare decision. ", bodyFontBlue);
                    additionalText.Add(new Paragraph("If you have any other questions on this notice, or medical billing, call ", bodyFont));
                    additionalText.Add(new Paragraph("1-800-MEDICINE", bodyFontBlue));
                    additionalText.Add(new Paragraph(" (1-833-633-4227/TTY: 1-877-486-2048). \nSigning below means that you have received and understand this notice. You also receive a copy.", bodyFont));

                    additionalTable.AddCell(additionalText);
                    pdfDocument.Add(additionalTable);

                    LineSeparator line5 = new LineSeparator(1f, 100f, myColor1, iTextSharp.text.Element.ALIGN_CENTER, -5);
                    pdfDocument.Add(line5);

                    PdfPTable signatureTable = new PdfPTable(2);
                    signatureTable.TotalWidth = 500f;
                    signatureTable.SpacingBefore = 8f;
                    signatureTable.SpacingAfter = 8f;
                    signatureTable.DefaultCell.Border = Rectangle.NO_BORDER;
                    signatureTable.LockedWidth = true;
                    signatureTable.HorizontalAlignment = Element.ALIGN_CENTER;

                    signatureTable.AddCell(new Paragraph("Signature: \n", bodyFont));
                    signatureTable.AddCell(new Paragraph("Date: \n", bodyFont));

                    pdfDocument.Add(signatureTable);

                    LineSeparator line6 = new LineSeparator(1f, 100f, myColor1, iTextSharp.text.Element.ALIGN_CENTER, -1);
                    line6.Offset = 1;
                    pdfDocument.Add(line6);

                    Paragraph bottomText = new Paragraph("According to the paperwork, Reduction act of 1995, no persons are required to respond to a collection of information unless it displays a valid OMB control number. The valid OMB control number for this information collection is 0938-0566. The time required to complete this information collection is estimated to average 7 minutes per response, including the time to review instructions, search existing data resources, gather the data needed and review the information collection. If you have comments concerning the accuracy of time estimate or suggestions for improving this form, Please write to: CMS, 7500 Security Boulevard, Attn: PRA reports clearance officer, Baltimore, Maryland 21244-1850.", bodyFontSmall);
                    pdfDocument.Add(bottomText);

                    LineSeparator line7 = new LineSeparator(1f, 100f, myColor1, iTextSharp.text.Element.ALIGN_CENTER, -8);
                    pdfDocument.Add(line7);

                    PdfPTable footerTable = new PdfPTable(2);

                    float[] footerWidths = new float[] { 14f, 8f };
                    footerTable.SetWidths(footerWidths);
                    footerTable.TotalWidth = 535f;
                    footerTable.LockedWidth = true;
                    footerTable.HorizontalAlignment = Element.ALIGN_CENTER;
                    footerTable.DefaultCell.Border = Rectangle.NO_BORDER;

                    Paragraph form = new Paragraph("\nForm CMS-R-131 (03/11)", componentHeaderFont);
                    form.Alignment = Element.ALIGN_LEFT;
                    Paragraph cnn = new Paragraph("\nForm Approved OMB No. 0938-0566", componentHeaderFont);
                    cnn.Alignment = Element.ALIGN_RIGHT;

                    footerTable.AddCell(form);
                    footerTable.AddCell(cnn);

                    pdfDocument.Add(footerTable);

                    PdfPTable footer = new PdfPTable(1);
                    footer.TotalWidth = 575f;
                    footer.LockedWidth = true;
                    footer.HorizontalAlignment = Element.ALIGN_CENTER;
                    footer.DefaultCell.Border = Rectangle.NO_BORDER;
                    footer.SpacingBefore = 5f;

                    PdfPCell footerCell = new PdfPCell();

                    var color = System.Drawing.ColorTranslator.FromHtml("#005da9");
                    footerCell.BackgroundColor = new BaseColor(color);
                    color = System.Drawing.ColorTranslator.FromHtml("#fff");
                    var fontcolor = new BaseColor(color);
                    iTextSharp.text.Font componentFooterFont = FontFactory.GetFont("Arial", 8, iTextSharp.text.Font.NORMAL, fontcolor);

                    Paragraph footerPara = new Paragraph("Generated by: MDVision PM EMR", componentFooterFont);
                    footerPara.SpacingAfter = 5f;
                    footerCell.AddElement(footerPara);

                    footer.AddCell(footerCell);
                    //  pdfDocument.Add(footer);

                    pdf.Document.Close();
                    pdf.Writer.Close();
                    pdfDocument.Close();

                    MemoryStream stream = new MemoryStream(stream_.ToArray());

                    PdfReader npdf = new PdfReader(stream);
                    MemoryStream outstream = new MemoryStream();
                    #region footer
                    var colors = System.Drawing.ColorTranslator.FromHtml("#fff");
                    var fontcolors = new BaseColor(colors);
                    Font componentFooterFonts = FontFactory.GetFont("Arial", 8, Font.NORMAL, fontcolors);
                    using (PdfStamper stamper = new PdfStamper(npdf, outstream, '\0', true))
                    {
                        stamper.Writer.CloseStream = false;
                        int PageCount = npdf.NumberOfPages;
                        for (int i = 1; i <= PageCount; i++)
                            ColumnText.ShowTextAligned(stamper.GetOverContent(i), Element.ALIGN_CENTER, new Paragraph(String.Format("Page {0} of {1}", i, PageCount), componentFooterFonts), 555, 18, 0);
                    }
                    #endregion
                    newByteArr = outstream.GetBuffer();

                }
                return new BLObject<byte[]>(newByteArr);

            }
            catch (Exception ex)
            {
                MDVLogger.BLLErrorLog("BLLClinical::previewLabOrderABN", ex);
                return new BLObject<byte[]>(null, ex.Message);
            }
        }
        private string GetPracticeText(long practiceId)
        {
            DSProfile ds = new DSProfile();
            ds = new DALPractice().LoadPractice(practiceId, string.Empty, string.Empty, string.Empty, string.Empty, string.Empty);
            string PatientHtml = string.Empty;
            if (ds != null)
            {
                if (ds.Tables[ds.Practice.TableName].Rows.Count > 0)
                {
                    DataRow drPractice = ds.Tables[ds.Practice.TableName].Rows[ds.Tables[ds.Practice.TableName].Rows.Count - 1];

                    PatientHtml = string.Concat(PatientHtml, MDVUtility.ToStr(drPractice[ds.Practice.DescriptionColumn.ColumnName]), "<br/>");
                    PatientHtml = string.Concat(PatientHtml, MDVUtility.ToStr(drPractice[ds.Practice.AddressColumn.ColumnName]), "<br/>");
                    PatientHtml = string.Concat(PatientHtml, MDVUtility.ToStr(drPractice[ds.Practice.Address2Column.ColumnName]));
                    PatientHtml = MDVUtility.ToStr(drPractice[ds.Practice.CityColumn.ColumnName]) == string.Empty ? string.Empty : string.Concat(PatientHtml, MDVUtility.ToStr(drPractice[ds.Practice.CityColumn.ColumnName]), ", ");
                    PatientHtml = MDVUtility.ToStr(drPractice[ds.Practice.StateColumn.ColumnName]) == string.Empty ? string.Empty : string.Concat(PatientHtml, MDVUtility.ToStr(drPractice[ds.Practice.StateColumn.ColumnName]), ", ");
                    PatientHtml = MDVUtility.ToStr(drPractice[ds.Practice.ZIPCodeColumn.ColumnName]) == string.Empty ? string.Empty : string.Concat(PatientHtml, MDVUtility.ToStr(drPractice[ds.Practice.ZIPCodeColumn.ColumnName]));
                    PatientHtml = string.Concat(PatientHtml, "<br/>");
                    PatientHtml = string.Concat(PatientHtml, MDVUtility.ToStr(drPractice[ds.Practice.PhoneNoColumn.ColumnName]), "<br/>");

                }

            }
            return PatientHtml;
        }
        private string GetProviderText(long providerId)
        {

            DSProfile ds = new DALProvider().LoadProvider(providerId, "", "", "", "", "", "", "", 1, 2000);
            string PatientHtml = string.Empty;
            if (ds != null)
            {
                if (ds.Provider.Rows.Count > 0)
                {
                    DataRow drProvider = ds.Tables[ds.Provider.TableName].Rows[ds.Tables[ds.Provider.TableName].Rows.Count - 1];
                    var providerFullName = MDVUtility.ToStr(drProvider[ds.Provider.LastNameColumn.ColumnName]) + ", " + MDVUtility.ToStr(drProvider[ds.Provider.FirstNameColumn.ColumnName]);
                    var providerNPI = MDVUtility.ToStr(drProvider[ds.Provider.NPIColumn.ColumnName]);
                    var providerOfficeAddress = MDVUtility.ToStr(drProvider[ds.Provider.OfficeAddressColumn.ColumnName]);
                    var providerOfficePhone = MDVUtility.ToStr(drProvider[ds.Provider.PhoneNoColumn.ColumnName]);
                    PatientHtml = string.Concat(PatientHtml, "Provider", "", "<br/>");
                    PatientHtml = string.Concat(PatientHtml, "Provider Name: ", providerFullName, "<br/>");
                    PatientHtml = string.Concat(PatientHtml, "Provider NPI: ", providerNPI, "<br/>");
                    PatientHtml = string.Concat(PatientHtml, "Specialty: ", MDVUtility.ToStr(drProvider["SpecialtyName"]), "<br/>");
                }
            }
            return PatientHtml;
        }
        private string GetPatientText(long patientId, string componentName = "")
        {
            DSPatient ds = new DSPatient();
            ds = new DALPatient().FillPatient(patientId, "", "");
            string PatientHtml = string.Empty;
            if (ds != null)
            {
                if (ds.Patients.Rows.Count > 0)
                {
                    PatientHtml = string.Concat("Patient", "<br/>");
                    PatientHtml = string.Concat(MDVUtility.ToStr(ds.Patients.Rows[0][ds.Patients.LastNameColumn.ColumnName]), ", ", MDVUtility.ToStr(ds.Patients.Rows[0][ds.Patients.FirstNameColumn.ColumnName]), " ", MDVUtility.ToStr(ds.Patients.Rows[0][ds.Patients.MIColumn.ColumnName]));
                    PatientHtml = string.Concat(PatientHtml, "<br/>");
                    PatientHtml = string.Concat(PatientHtml, MDVUtility.ToStr(ds.Patients.Rows[0][ds.Patients.AgeColumn.ColumnName]), " Y, ", MDVUtility.ToStr(ds.Patients.Rows[0][ds.Patients.GenderColumn.ColumnName]), ", ");
                    PatientHtml = string.Concat(PatientHtml, "DOB: ", Convert.ToDateTime(MDVUtility.ToStr(ds.Patients.Rows[0][ds.Patients.DOBColumn.ColumnName])).ToString("MM/dd/yyyy"), "<br/>");
                    if (componentName != "Radiology" && componentName != "Procedure")
                    {
                        PatientHtml = string.Concat(PatientHtml, "Patient ID: ", MDVUtility.ToStr(ds.Patients.Rows[0][ds.Patients.AccountNumberColumn.ColumnName]), "<br/>");
                    }
                    if (!string.IsNullOrWhiteSpace(MDVUtility.ToStr(ds.Patients.Rows[0][ds.Patients.HomePhoneNoColumn.ColumnName])))
                        PatientHtml = string.Concat(PatientHtml, "Ph: ", MDVUtility.ToStr(ds.Patients.Rows[0][ds.Patients.HomePhoneNoColumn.ColumnName]), "<br/>");
                    PatientHtml = string.Concat(PatientHtml,
                                (ds.Patients.Rows[0][ds.Patients.Address1Column.ColumnName].ToString() == "" ? "" : (MDVUtility.ToStr(ds.Patients.Rows[0][ds.Patients.Address1Column.ColumnName])).ToString() + "<br/>")
                                + (ds.Patients.Rows[0][ds.Patients.Address2Column.ColumnName].ToString() == "" ? "" : (MDVUtility.ToStr(ds.Patients.Rows[0][ds.Patients.Address2Column.ColumnName])).ToString() + "<br/>")
                                + (ds.Patients.Rows[0][ds.Patients.CityColumn.ColumnName].ToString() == "" ? "" : (MDVUtility.ToStr(ds.Patients.Rows[0][ds.Patients.CityColumn.ColumnName])).ToString())
                                + (ds.Patients.Rows[0][ds.Patients.StateColumn.ColumnName].ToString() == "" ? "" : (", " + MDVUtility.ToStr(ds.Patients.Rows[0][ds.Patients.StateColumn.ColumnName])).ToString())
                                + (ds.Patients.Rows[0][ds.Patients.ZIPCodeColumn.ColumnName].ToString() == "" ? "" : (", " + MDVUtility.ToStr(ds.Patients.Rows[0][ds.Patients.ZIPCodeColumn.ColumnName])).ToString()), "<br/>");

                }
            }
            return PatientHtml;

        }

        private string GetFacilityText(long facilityId)
        {
            DSProfile ds = new DSProfile();
            ds = new DALFacility().LoadFacility(facilityId, string.Empty, string.Empty, string.Empty, string.Empty, string.Empty);
            string PatientHtml = string.Empty;
            if (ds != null)
            {
                if (ds.Tables[ds.Facility.TableName].Rows.Count > 0)
                {
                    DataRow drPractice = ds.Tables[ds.Facility.TableName].Rows[ds.Tables[ds.Facility.TableName].Rows.Count - 1];

                    PatientHtml = string.Concat(PatientHtml, MDVUtility.ToStr(drPractice[ds.Practice.ShortNameColumn.ColumnName]), "<br/>");
                    PatientHtml = string.Concat(PatientHtml, MDVUtility.ToStr(drPractice[ds.Practice.AddressColumn.ColumnName]), "<br/>");
                    PatientHtml = MDVUtility.ToStr(drPractice[ds.Practice.CityColumn.ColumnName]) == string.Empty ? string.Empty : string.Concat(PatientHtml, MDVUtility.ToStr(drPractice[ds.Practice.CityColumn.ColumnName]), ", ");
                    PatientHtml = MDVUtility.ToStr(drPractice[ds.Practice.StateColumn.ColumnName]) == string.Empty ? string.Empty : string.Concat(PatientHtml, MDVUtility.ToStr(drPractice[ds.Practice.StateColumn.ColumnName]), ", ");
                    PatientHtml = MDVUtility.ToStr(drPractice[ds.Practice.ZIPCodeColumn.ColumnName]) == string.Empty ? string.Empty : string.Concat(PatientHtml, MDVUtility.ToStr(drPractice[ds.Practice.ZIPCodeColumn.ColumnName]));
                    PatientHtml = string.Concat(PatientHtml, "<br/>");

                }

            }
            return PatientHtml;
        }
