        #region Lab Order AOE
        public BLObject<DSLabOrder> LoadLabOrderAOE(string testCode, long LabOrderTestId)
        {
            try
            {
                DSLabOrder ds = new DSLabOrder();
                ds = new DALLabOrder().LoadLabOrderAOE(testCode);
                if (LabOrderTestId > 0)
                {
                    DSLabOrder dsAnswers = new DALLabOrder().LoadLabOrderAOEAnswers(testCode, MDVUtility.ToStr(LabOrderTestId));
                    if (dsAnswers != null)
                    {
                        ds.Merge(dsAnswers);
                    }
                }
                return new BLObject<DSLabOrder>(ds);
            }
            catch (Exception ex)
            {
                MDVLogger.BLLErrorLog("BLLClinical::LoadLabOrder", ex);
                return new BLObject<DSLabOrder>(null, ex.Message);
            }
        }


        public BLObject<DSLabOrder> LoadLabOrderAOEAnswer(string testCode, string testId)
        {
            try
            {
                DSLabOrder ds = new DSLabOrder();
                ds = new DALLabOrder().LoadLabOrderAOEAnswers(testCode, testId);
                return new BLObject<DSLabOrder>(ds);
            }
            catch (Exception ex)
