        public bool CheckDocumentIsReviewed(long LabOrderResultId, long PatientId, string FolderName)
        {
            try
            {
                if (FolderName == "Lab Result")
                {
                    FolderName = "Lab Results";
                }
                else if (FolderName.ToLower() == "psa")
                {
                    FolderName = "PSA";
                }
                else if (FolderName.ToLower() == "urine")
                {
                    FolderName = "Urine Results";
                }
                return new DALLabResult().CheckDocumentIsReviewed(LabOrderResultId, PatientId, FolderName);
            }
            catch (Exception ex)
            {
                return false;
            }
        }
