                                    int patientCounter = 0;
                                    string[] PatientColumns = drReportHeader.PatientText.Split(new string[] { "<br/>" }, StringSplitOptions.None);
                                    foreach (string PatientColumn in PatientColumns)
                                    {
                                        if (!string.IsNullOrEmpty(PatientColumn) && !string.IsNullOrWhiteSpace(PatientColumn))
                                        {
                                            if (patientCounter < 7)
                                            {
                                                PatientTable.AddCell(new Paragraph(PatientColumn, bodyFont));
                                                patientCounter++;
                                            }
                                        }
                                    }
                                }
                                else
                                {
                                    PatientTable.AddCell(new Paragraph("", bodyFont));
                                }
                                PatientTable.DefaultCell.Padding = 0f;
                                PatientTable.DefaultCell.UseAscender = true;
                                ReportHeaderTable.AddCell(PatientTable);
                                #endregion

                                #region  Provider

                                PdfPTable ProviderTable = new PdfPTable(1);
                                ProviderTable.DefaultCell.Border = Rectangle.NO_BORDER;
                                //Begin Edited By Fahad Malik on 28-11-2016 to fix bug#: EMR-2090
                                ProviderTable.DefaultCell.HorizontalAlignment = Element.ALIGN_RIGHT;
                                ProviderTable.DefaultCell.PaddingRight = 50;
                                //End Edited By Fahad Malik on 28-11-2016 to fix bug#: EMR-2090
                                if (drReportHeader.Field<string>("ProviderText") != null)
                                {
                                    int providerCounter = 0;
                                    string[] ProviderColumns = drReportHeader.ProviderText.Split(new string[] { "<br/>" }, StringSplitOptions.None);

                                    foreach (string ProviderColumn in ProviderColumns)
                                    {
                                        if (!string.IsNullOrEmpty(ProviderColumn) && !string.IsNullOrWhiteSpace(ProviderColumn))
                                        {
                                            if (providerCounter < 7)
                                            {
                                                ProviderTable.AddCell(new Paragraph(ProviderColumn, bodyFont));
                                                providerCounter++;
                                            }
                                        }
                                    }

                                }
                                else
                                {
                                    ProviderTable.AddCell(new Paragraph("", bodyFont));
                                }
                                ReportHeaderTable.AddCell(ProviderTable);
                                #endregion
                                //ReportHeaderTable.DefaultCell.Padding = -1;
                            }
                        }
                        catch (Exception ex)
                        {
                            MDVLogger.BLLErrorLog("BLLAdminClinical::getReportHeaderTagsValue", ex);
                            // return new BLObject<DSReportHeader>(null, ex.Message);
                        }


                        #endregion
                    }
                    else
                    {
                        #region Patient's Data

                        #region Header Segment
                        ReportHeaderTable = setLabHeaderPDF(practiceId, patientId, dsLab, dsLabOrder, bodyFont, "", true);

                        //if (IsReportHeaderApplied)
                        //{
                        topMargin = ReportHeaderTable.CalculateHeights() + 33;
                        bottomMargin = 52;
                        //}
                        #endregion
                        #region MD Vision Footer

                        footer = setLabOrder_ResultFooterPDF(FooterGeneratedBy);
                        // ReportHeaderTable.AddCell(footer);

                        #endregion




                        #endregion
                    }

                    if (IsReportHeaderApplied)
                    {
                        topMargin = ReportHeaderTable.CalculateHeights() + 33;
                        bottomMargin = 52;
                    }
                    PdfPTable emptyTable = new PdfPTable(1);
                    //pdfDocument.SetMargins(20, 20, topMargin, bottomMargin);
                    pdfDocument.SetMargins(20, 20, 20, bottomMargin);
                    //Document pdfDocument = new Document(PageSize.LETTER, 20, 20, topMargin, bottomMargin);
                    MDVUtility.PDFCreator pdf = new MDVUtility.PDFCreator(ref pdfDocument, stream_, false, ClientConfiguration.DecryptFrom64(MDVSession.Current.AppUserName), ClientConfiguration.DecryptFrom64(MDVSession.Current.AppUserName), "Lab Result");
                    pdf.Writer.PageEvent = new MDVision.Common.Utilities.MDVUtility.AddFooterHeader(null, true, null, footer);


                    pdf.Document.Open();
                    pdfDocument.Add(ReportHeaderTable);
                    DSPatient dsPatientHeader = new DALPatient().FillPatient(patientId, "", "");
                    var x2 = new MyPdfPageEventHelpPageNo(MDVUtility.ToStr(dsPatientHeader.Tables[dsPatientHeader.Patients.TableName].Rows[0][dsPatientHeader.Patients.LastNameColumn.ColumnName].ToString() + ", " + dsPatientHeader.Tables[dsPatientHeader.Patients.TableName].Rows[0][dsPatientHeader.Patients.FirstNameColumn.ColumnName].ToString()), bodyFont, MDVUtility.ToStr(dsLabOrder.Tables[dsLabOrder.LabOrder.TableName].Rows[0][dsLabOrder.LabOrder.OrderNoColumn.ColumnName]), componentHeadingFont);
                    pdf.Writer.PageEvent = x2;
                    BaseColor myColor1 = WebColors.GetRGBColor("#66B2FF");
                    LineSeparator line2 = new LineSeparator(1f, 100f, myColor1, iTextSharp.text.Element.ALIGN_CENTER, 0);
                    pdfDocument.Add(line2);

                    if (!IsReportHeaderApplied)
                    {
                        #region Patient/Provider Segment
                        string AccountNumber = dsLabResult.Tables[dsPatient.Patients.TableName].Rows[0]["AccountNumber"].ToString();
                        try
                        {
                            PdfPTable ReportPatientProvider = new PdfPTable(2);
                            ReportPatientProvider.TotalWidth = 575f;
                            ReportPatientProvider.SpacingBefore = 3f;
                            ReportPatientProvider.SpacingAfter = 8f;
                            ReportPatientProvider.LockedWidth = true;
                            ReportPatientProvider.DefaultCell.Border = Rectangle.NO_BORDER;

                            ReportPatientProvider.AddCell(SetLabPatient(patientId, patientName, fontColour, bodyFont, componentHeadingFont, patientNameFont, AccountNumber));
                            ReportPatientProvider.AddCell(SetLabProvider(providerId, patientNameFont, bodyFont));
                            pdfDocument.Add(ReportPatientProvider);

                        }
                        catch (Exception ex)
                        {
                            MDVLogger.BLLErrorLog("BLLAdminClinical::LabOrderPreview, Patient or Provider Segment", ex);
                        }
                        pdfDocument.Add(line2);
                    }

                    #endregion









                    #endregion


                    #region Lab, OrderNumber, Facility and Assigne Information Segment

                    setLabResultOrderInformation(pdfDocument, dsLabResult, dsLabOrder, componentHeaderFont, componentHeadingFont, bodyFont);

                    #endregion

                    #region Sample Segment

                    Paragraph SampleHeading = new Paragraph("Sample", componentHeadingFont);
                    pdfDocument.Add(SampleHeading);

                    if (dsLabResult.Tables[dsLabResult.LabResultSpecimen.TableName].Rows.Count > 0)
                    {
                        if (!string.IsNullOrEmpty(dsLabResult.Tables[dsLabResult.LabResultSpecimen.TableName].Rows[0][dsLabResult.LabResultSpecimen.ExternalSpecimenIdColumn.ColumnName].ToString()))
                        {
                            pdfDocument.Add(setLabResultSample(dsLabOrder, dsLabResult, componentHeaderFont, bodyFont));
                        }
                        else
                        {
                            Paragraph noProblems = new Paragraph("No Sample Found".ToString(), bodyFont);
                            noProblems.Alignment = Element.ALIGN_CENTER;
                            pdfDocument.Add(noProblems);
                        }
                    }

                    #endregion

                    #region Result Information Segment

                    setLabresultInformation(pdfDocument, dsLabOrder, dsLabResult, componentHeadingFont, componentHeaderFont, componentGridHeaderFont, bodyFont, uomFont, uomFontOrange, gridbodyFont, bodyFontSmall);

                    #endregion

                    #region CLIA

                    setCLIA(pdfDocument, dsLab, componentHeaderFont);

                    #endregion

                    #endregion

                    #region Remarks

                    Paragraph remarks_Heading = new Paragraph("Remarks \n".ToString(), componentHeadingFont);
                    remarks_Heading.SpacingBefore = remarks_Heading.SpacingAfter = 5;
                    pdfDocument.Add(remarks_Heading);
                    Paragraph remarks = new Paragraph(MDVUtility.ToStr(dsLabResult.Tables[dsLabResult.LabOrderResult.TableName].Rows[0][dsLabResult.LabOrderResult.RemarksColumn.ColumnName]), bodyFont);
                    remarks.Alignment = Element.ALIGN_LEFT;
                    pdfDocument.Add(remarks);

                    #endregion

                    #region Comments

                    Paragraph comments_Heading = new Paragraph("Comments \n".ToString(), componentHeadingFont);
                    comments_Heading.SpacingBefore = comments_Heading.SpacingAfter = 5;
                    pdfDocument.Add(comments_Heading);

                    Paragraph comments = new Paragraph(MDVUtility.ToStr(dsLabResult.Tables[dsLabResult.LabOrderResult.TableName].Rows[0][dsLabResult.LabOrderResult.CommentsColumn.ColumnName]), bodyFont);
                    comments.Alignment = Element.ALIGN_LEFT;
                    pdfDocument.Add(comments);

                    pdfDocument.Add(Chunk.NEWLINE);
                    pdfDocument.Add(Chunk.NEWLINE);

                    #endregion

                    #region e-Signed

                    string modifiedDate = MDVUtility.ToDateTime(dsLabResult.Tables[dsLabResult.LabOrderResult.TableName].Rows[0][dsLabResult.LabOrderResult.ModifiedOnColumn.ColumnName]).ToLongDateString();

                    if (!string.IsNullOrEmpty(modifiedDate))
                    {
                        modifiedDate = modifiedDate + " at ";
                    }
                    string modifiedTime = MDVUtility.ToDateTime(dsLabResult.Tables[dsLabResult.LabOrderResult.TableName].Rows[0][dsLabResult.LabOrderResult.ModifiedOnColumn.ColumnName]).ToLongTimeString();

                    Paragraph signedByPara = new Paragraph("e-Signed By: " + MDVUtility.ToStr(dsLabResult.Tables[dsLabResult.LabOrderResult.TableName].Rows[0][dsLabResult.LabOrderResult.ModifiedByColumn.ColumnName])
                       + " on " + modifiedDate + modifiedTime, bodyFont);
                    signedByPara.Alignment = Element.ALIGN_LEFT;
                    pdfDocument.Add(signedByPara);

                    #endregion

                    #region Footer

                    #endregion


                    #region But in the end It doesn't even matter

                    newByteArr = stream_.GetBuffer();
                    pdf.Document.Close();
                    pdf.Writer.Close();
                    pdfDocument.Close();

                    MemoryStream stream = new MemoryStream(stream_.ToArray());
                    PdfReader npdf = new PdfReader(stream);
                    MemoryStream outstream = new MemoryStream();
                    using (PdfStamper stamper = new PdfStamper(npdf, outstream, '\0', true))
                    {
                        stamper.Writer.CloseStream = false;
                        int PageCount = npdf.NumberOfPages;
                        for (int i = 1; i <= PageCount; i++)
                        {
                            Paragraph para = new Paragraph(String.Format("Page {0}/{1}", i, PageCount), bodyFont);
                            para.Add(setLabOrder_ResultFooter(pdfDocument));
                            ColumnText.ShowTextAligned(stamper.GetOverContent(i), Element.ALIGN_CENTER, para, 555, 20, 0);
                        }
                    }
                    newByteArr = outstream.GetBuffer();
                }
                return new BLObject<byte[]>(newByteArr);

                #endregion
            }
            catch (Exception ex)
            {
                MDVLogger.BLLErrorLog("BLLClinical::previewLabResult", ex);
                return new BLObject<byte[]>(null, ex.Message);
            }
        }

        #endregion
        //Overriden by Ahsan Nasir
        public class MyPdfPageEventHelpPageNo : iTextSharp.text.pdf.PdfPageEventHelper
        {
            Font bodyFont = null;
            Font bodyFontBlue = null;
            string patientName = "";
            string orderNo = "";
            public MyPdfPageEventHelpPageNo(string patientName, Font bodyFont, string orderNo, Font ComponentHeader)
            {
                this.bodyFont = bodyFont;
                this.patientName = patientName;//patientName;
                this.orderNo = orderNo;
                this.bodyFontBlue = ComponentHeader;
            }

            public MyPdfPageEventHelpPageNo()
            {
            }
            public override void OnStartPage(PdfWriter writer, Document document)
            {
                // base.OnStartPage(writer, document);
                document.Add(new Paragraph("\n" + "     ", bodyFont));

                //PatientName
                ColumnText.ShowTextAligned(writer.DirectContent, Element.ALIGN_LEFT, new Paragraph("Patient Name: ", bodyFontBlue), 20, 750, 0);
                ColumnText.ShowTextAligned(writer.DirectContent, Element.ALIGN_LEFT, new Paragraph(patientName, bodyFont), 100, 750, 0);

                //Order No
                ColumnText.ShowTextAligned(writer.DirectContent, Element.ALIGN_LEFT, new Paragraph("Order No: ", bodyFontBlue), 400, 750, 0);
                ColumnText.ShowTextAligned(writer.DirectContent, Element.ALIGN_LEFT, new Paragraph(orderNo, bodyFont), 460, 750, 0);
                BaseColor myColor1 = WebColors.GetRGBColor("#66B2FF");
                LineSeparator line2 = new LineSeparator(1f, 100f, myColor1, iTextSharp.text.Element.ALIGN_CENTER, 0);
                document.Add(line2);
                document.Add(new Paragraph("\n" + "     ", bodyFont));
            }
        }


        /// <summary>
        /// Module Name: viewPdfLabResult
        /// Author: Humaira Yousaf
        /// Created Date: 06-05-2016
        /// Description: Creates PDF to view Lab Result
        /// </summary>
        /// <param name="labResultId" type="long">labResultId</param>
        /// <param name="labOrderId" type="long">labOrderId</param>
        /// <param name="patientId" type="long">patientId</param>
        public BLObject<byte[]> viewPdfLabResult(long labOrderResultId, long labOrderId, long patientId)
        {
            try
            {
                byte[] newByteArr = null;

                DSLabResult dsLabResult = new DSLabResult();
                DSPatient dsPatient = new DSPatient();
                DSLabOrder dsLabOrder = new DSLabOrder();
                DSProfile dsProfile = new DSProfile();

                dsLabResult = new DALLabResult().LoadLabResult(labOrderResultId, labOrderId, "", "", "", "", 0, "", "", "", "", 0, patientId);
                if (dsLabResult.LabOrderResult.Rows.Count == 0)
                {
                    BLObject<byte[]> blankByteArr = viewBlankPdfLabResult(labOrderResultId, labOrderId, patientId);
                    return blankByteArr;
                }
                string resultStatus = MDVUtility.ToStr(dsLabResult.LabOrderResult.Rows[0][dsLabResult.LabOrderResult.StatusColumn.ColumnName]);
                dsLabResult.Merge(new DALPatient().FillPatient(patientId, "", ""));
                dsLabResult.Merge(new DALLabResult().loadLabResultDetail(0, MDVUtility.ToInt64(dsLabResult.LabOrderResult.Rows[0][dsLabResult.LabOrderResult.LabOrderResultIdColumn.ColumnName])));
                //dsLabResult.Merge(new DALLabOrder().LoadLabOrder(labOrderId, patientId, 0, "", "", "", "", 0, "", "", "", 0));
                dsLabResult.Merge(new DALLabOrder().loadLabOrderforPDF(labOrderId, patientId));
                dsLabResult.Merge(new DALLabOrder().LoadLabOrderTest(labOrderId, 0, 0, "", ""));
                long practiceId = MDVUtility.ToInt64(dsLabResult.Tables[dsPatient.Patients.TableName].Rows[0][dsPatient.Patients.PracticeIdColumn.ColumnName]);
                dsLabResult.Merge(new DALPractice().LoadPractice(practiceId, string.Empty, string.Empty, string.Empty, string.Empty, string.Empty));
                string firstName = MDVUtility.ToStr(dsLabResult.Tables[dsPatient.Patients.TableName].Rows[0][dsPatient.Patients.FirstNameColumn.ColumnName]);
                string lastName = MDVUtility.ToStr(dsLabResult.Tables[dsPatient.Patients.TableName].Rows[0][dsPatient.Patients.LastNameColumn.ColumnName]);
                using (MemoryStream stream_ = new MemoryStream())
                {
                    Document pdfDocument = new Document(PageSize.LETTER, 20, 20, 20, 20);
                    // Heading Font Style
                    var fontColour = new BaseColor(102, 178, 255);
                    iTextSharp.text.Font patientNameFont = FontFactory.GetFont("Arial", 10, iTextSharp.text.Font.BOLD, fontColour);
                    iTextSharp.text.Font bodyFont = FontFactory.GetFont("Arial", 10, iTextSharp.text.Font.NORMAL, iTextSharp.text.BaseColor.BLACK);
                    iTextSharp.text.Font bodyFontParent = FontFactory.GetFont("Arial", 10, iTextSharp.text.Font.BOLD, iTextSharp.text.BaseColor.BLACK);
                    iTextSharp.text.Font componentHeadingFont = FontFactory.GetFont("Arial", 10, iTextSharp.text.Font.NORMAL, fontColour);
                    iTextSharp.text.Font componentHeaderFont = FontFactory.GetFont("Arial", 10, iTextSharp.text.Font.NORMAL, iTextSharp.text.BaseColor.BLACK);
                    iTextSharp.text.Font componentGridHeaderFont = FontFactory.GetFont("Arial", 10, iTextSharp.text.Font.NORMAL, new BaseColor(102, 178, 255));
                    iTextSharp.text.Font tableHeaderFont = FontFactory.GetFont("Arial", 10, iTextSharp.text.Font.BOLD, iTextSharp.text.BaseColor.BLACK);
                    iTextSharp.text.Font tableHeaderRowFont = FontFactory.GetFont("Arial", 10, iTextSharp.text.Font.BOLD, iTextSharp.text.BaseColor.WHITE);

                    MDVUtility.PDFCreator pdf = new MDVUtility.PDFCreator(ref pdfDocument, stream_, false, ClientConfiguration.DecryptFrom64(MDVSession.Current.AppUserName), ClientConfiguration.DecryptFrom64(MDVSession.Current.AppUserName), "Requisition");
                    pdf.Document.Open();

                    PdfPTable headerTable = new PdfPTable(1);
                    headerTable.TotalWidth = 575f;
                    headerTable.LockedWidth = true;
                    headerTable.DefaultCell.Border = Rectangle.NO_BORDER;

                    iTextSharp.text.Image logo = iTextSharp.text.Image.GetInstance(HttpContext.Current.Server.MapPath(@"~\content\images\mdvision-logo.png"));
                    logo.ScalePercent(59f);
                    PdfPCell cell1 = new PdfPCell();
                    cell1.AddElement(logo);
                    cell1.Border = Rectangle.NO_BORDER;
                    cell1.HorizontalAlignment = Element.ALIGN_LEFT;
                    headerTable.AddCell(cell1);

                    pdfDocument.Add(headerTable);

                    #region Patient's Data

                    // Start Append Patient's Data
                    Paragraph faceSheet_Heading = new Paragraph("Patient Information".ToString(), tableHeaderFont);
                    faceSheet_Heading.SpacingAfter = 4;
                    faceSheet_Heading.SpacingBefore = -5;
                    faceSheet_Heading.Alignment = Element.ALIGN_CENTER;
                    pdfDocument.Add(faceSheet_Heading);
                    //pdfDocument.Add(Chunk.NEWLINE);

                    PdfPTable patientTable = new PdfPTable(2);
                    float[] widths = new float[] { 12f, 12f };
                    patientTable.TotalWidth = 575f;
                    patientTable.LockedWidth = true;

                    PdfPCell cellElement = new PdfPCell(new Phrase("Element Name", tableHeaderRowFont));
                    cellElement.BackgroundColor = new BaseColor(70, 130, 180);
                    cellElement.PaddingTop = 5;
                    cellElement.PaddingBottom = 5;
                    cellElement.HorizontalAlignment = Element.ALIGN_CENTER;
                    cellElement.VerticalAlignment = Element.ALIGN_CENTER;

                    PdfPCell cellData = new PdfPCell(new Phrase("Data", tableHeaderRowFont));
                    cellData.BackgroundColor = new BaseColor(70, 130, 180);
                    cellData.PaddingTop = 5;
                    cellData.PaddingBottom = 5;
                    cellData.HorizontalAlignment = Element.ALIGN_CENTER;
                    cellData.VerticalAlignment = Element.ALIGN_CENTER;

                    patientTable.AddCell(cellElement);
                    patientTable.AddCell(cellData);

                    foreach (DSPatient.PatientsRow dr in dsLabResult.Tables[dsPatient.Patients.TableName].Rows)
                    {
                        patientTable.AddCell(new Paragraph("Patient ID", bodyFont));
                        patientTable.AddCell(new Paragraph(dr[dsPatient.Patients.PatientIdColumn.ColumnName].ToString(), bodyFont));
                        patientTable.AddCell(new Paragraph("Patient Name", bodyFont));
                        patientTable.AddCell(new Paragraph(dr[dsPatient.Patients.FullNameColumn.ColumnName].ToString(), bodyFont));
                        patientTable.AddCell(new Paragraph("Date/Time of Birth", bodyFont));
                        patientTable.AddCell(new Paragraph(dr[dsPatient.Patients.DOBColumn.ColumnName].ToString(), bodyFont));
                        patientTable.AddCell(new Paragraph("Administrative Sex", bodyFont));
                        patientTable.AddCell(new Paragraph(dr[dsPatient.Patients.GenderColumn.ColumnName].ToString(), bodyFont));
                        patientTable.AddCell(new Paragraph("Race", bodyFont));
                        patientTable.AddCell(new Paragraph(dr[dsPatient.Patients.RaceNameColumn.ColumnName].ToString(), bodyFont));
                        patientTable.AddCell(new Paragraph("Alt Race", bodyFont));
                        patientTable.AddCell(new Paragraph("", bodyFont));
                        patientTable.AddCell(new Paragraph("Assigning Authority", bodyFont));
                        patientTable.AddCell(new Paragraph("NIST MPI", bodyFont));
                        patientTable.AddCell(new Paragraph("Identifier Type Code", bodyFont));
                        patientTable.AddCell(new Paragraph("MR", bodyFont));

                        pdfDocument.Add(patientTable);
                    }
                    // End Append Patient's Data

                    #endregion
                    pdfDocument.Add(Chunk.NEWLINE);
                    Paragraph observation_Heading = new Paragraph("Order Observation".ToString(), tableHeaderFont);
                    observation_Heading.SpacingAfter = -12;
                    observation_Heading.SpacingBefore = -5;
                    observation_Heading.Alignment = Element.ALIGN_CENTER;
                    pdfDocument.Add(observation_Heading);
                    pdfDocument.Add(Chunk.NEWLINE);
                    pdfDocument.Add(Chunk.NEWLINE);

                    #region Provider's Data

                    // Start Append Provider's Data
                    Paragraph provider_Heading = new Paragraph("Ordering Provider".ToString(), tableHeaderFont);
                    provider_Heading.SpacingAfter = 4;
                    provider_Heading.SpacingBefore = -5;
                    provider_Heading.Alignment = Element.ALIGN_CENTER;
                    pdfDocument.Add(provider_Heading);
                    //pdfDocument.Add(Chunk.NEWLINE);

                    PdfPTable providerTable = new PdfPTable(2);
                    widths = new float[] { 12f, 12f };
                    providerTable.TotalWidth = 575f;
                    providerTable.LockedWidth = true;

                    providerTable.AddCell(cellElement);
                    providerTable.AddCell(cellData);

                    foreach (DSLabOrder.LabOrderPdfRow dr in dsLabResult.Tables[dsLabOrder.LabOrderPdf.TableName].Rows)
                    {
                        providerTable.AddCell(new Paragraph("Name", componentHeaderFont));
                        providerTable.AddCell(new Paragraph(HttpUtility.HtmlDecode(MDVUtility.ToStr(dr[dsLabOrder.LabOrderPdf.ProviderColumn.ColumnName])), bodyFont));
                        providerTable.AddCell(new Paragraph("Identifier Number", componentHeaderFont));
                        providerTable.AddCell(new Paragraph(HttpUtility.HtmlDecode(MDVUtility.ToStr(dr[dsLabOrder.LabOrderPdf.ProviderIdColumn.ColumnName])), bodyFont));
                        providerTable.AddCell(new Paragraph("Name Type Code", componentHeaderFont));
                        providerTable.AddCell(new Paragraph("L", bodyFont));
                        providerTable.AddCell(new Paragraph("Identifier Type", componentHeaderFont));
                        providerTable.AddCell(new Paragraph("NPI", bodyFont));
                        pdfDocument.Add(providerTable);
                    }
                    // End Append Patient's Data

                    #endregion


                    #region "Observation Details"
                    //Start Observation Details
                    pdfDocument.Add(Chunk.NEWLINE);
                    Paragraph ob_Heading = new Paragraph("Observation Details".ToString(), tableHeaderFont);
                    ob_Heading.SpacingAfter = 4;
                    ob_Heading.SpacingBefore = -5;
                    ob_Heading.Alignment = Element.ALIGN_CENTER;
                    pdfDocument.Add(ob_Heading);
                    //pdfDocument.Add(Chunk.NEWLINE);

                    PdfPTable obTable = new PdfPTable(2);
                    widths = new float[] { 12f, 12f };
                    obTable.TotalWidth = 575f;
                    obTable.LockedWidth = true;

                    obTable.AddCell(cellElement);
                    obTable.AddCell(cellData);

                    cellData = new PdfPCell(new Phrase("Observation General Information", tableHeaderFont));
                    cellData.BackgroundColor = new BaseColor(198, 222, 255);
                    obTable.AddCell(cellData);

                    cellData = new PdfPCell(new Phrase("", tableHeaderRowFont));
                    cellData.BackgroundColor = new BaseColor(198, 222, 255);
                    obTable.AddCell(cellData);

                    obTable.AddCell(new Paragraph("Placer Order Number", bodyFont));
                    obTable.AddCell(new Paragraph(MDVUtility.ToStr(dsLabResult.Tables[dsLabOrder.LabOrderPdf.TableName].Rows[0][dsLabOrder.LabOrderPdf.OrderNoColumn.ColumnName]), bodyFont));

                    obTable.AddCell(new Paragraph("Filler Order Number", bodyFont));
                    obTable.AddCell(new Paragraph(MDVUtility.ToStr(dsLabResult.Tables[dsLabOrder.LabOrderPdf.TableName].Rows[0][dsLabOrder.LabOrderPdf.OrderNoColumn.ColumnName]), bodyFont));

                    obTable.AddCell(new Paragraph("Placer Group Number", bodyFont));
                    obTable.AddCell(new Paragraph(MDVUtility.ToStr(dsLabResult.Tables[dsLabOrder.LabOrderPdf.TableName].Rows[0][dsLabOrder.LabOrderPdf.OrderNoColumn.ColumnName]), bodyFont));

                    cellData = new PdfPCell(new Phrase("Parent Universal Service Identifier", tableHeaderFont));
                    cellData.BackgroundColor = new BaseColor(198, 222, 255);
                    obTable.AddCell(cellData);

                    cellData = new PdfPCell(new Phrase("", tableHeaderRowFont));
                    cellData.BackgroundColor = new BaseColor(198, 222, 255);
                    obTable.AddCell(cellData);

                    obTable.AddCell(new Paragraph("Identifier", bodyFont));
                    obTable.AddCell(new Paragraph(MDVUtility.ToStr(dsLabResult.Tables[dsLabOrder.LabOrderTest.TableName].Rows[0][dsLabOrder.LabOrderTest.CPTCodeColumn.ColumnName]), bodyFont));

                    obTable.AddCell(new Paragraph("Text", bodyFont));
                    obTable.AddCell(new Paragraph(MDVUtility.ToStr(dsLabResult.Tables[dsLabOrder.LabOrderTest.TableName].Rows[0][dsLabOrder.LabOrderTest.CPTCodeDescriptionColumn.ColumnName]), bodyFont));

                    obTable.AddCell(new Paragraph("Alt Identifier", bodyFont));
                    obTable.AddCell(new Paragraph(MDVUtility.ToStr(""), bodyFont));

                    obTable.AddCell(new Paragraph("Alt Text", bodyFont));
                    obTable.AddCell(new Paragraph(MDVUtility.ToStr(""), bodyFont));

                    obTable.AddCell(new Paragraph("Original Text", bodyFont));
                    obTable.AddCell(new Paragraph(MDVUtility.ToStr(""), bodyFont));

                    cellData = new PdfPCell(new Phrase("Observation Details", tableHeaderFont));
                    cellData.BackgroundColor = new BaseColor(198, 222, 255);
                    obTable.AddCell(cellData);

                    cellData = new PdfPCell(new Phrase("", tableHeaderRowFont));
                    cellData.BackgroundColor = new BaseColor(198, 222, 255);
                    obTable.AddCell(cellData);

                    if (dsLabResult.LabOrderResultDetail.Rows.Count > 0)
                    {
                        obTable.AddCell(new Paragraph("Universal Service Identifier", bodyFont));
                        obTable.AddCell(new Paragraph(MDVUtility.ToStr(dsLabResult.Tables[dsLabResult.LabOrderResultDetail.TableName].Rows[0][dsLabResult.LabOrderResultDetail.CPTCodeColumn.ColumnName]), bodyFont));

                        obTable.AddCell(new Paragraph("Observation Date/Time", bodyFont));
                        obTable.AddCell(new Paragraph(MDVUtility.ToStr(dsLabResult.Tables[dsLabResult.LabOrderResultDetail.TableName].Rows[0][dsLabResult.LabOrderResultDetail.ObservationDateColumn.ColumnName]), bodyFont));

                        obTable.AddCell(new Paragraph("Observation end Date/Time", bodyFont));
                        obTable.AddCell(new Paragraph(MDVUtility.ToStr(dsLabResult.Tables[dsLabResult.LabOrderResultDetail.TableName].Rows[0][dsLabResult.LabOrderResultDetail.ObservationDateColumn.ColumnName]), bodyFont));
                    }
                    else
                    {
                        obTable.AddCell(new Paragraph("Universal Service Identifier", bodyFont));
                        obTable.AddCell(string.Empty);

                        obTable.AddCell(new Paragraph("Observation Date/Time", bodyFont));
                        obTable.AddCell(string.Empty);

                        obTable.AddCell(new Paragraph("Observation end Date/Time", bodyFont));
                        obTable.AddCell(string.Empty);
                    }

                    obTable.AddCell(new Paragraph("Specimen Action Code", bodyFont));
                    DSLabResult.LabOrderResultDetailRow[] labResultsSpecimen = null;
