                            hCell.HorizontalAlignment = Element.ALIGN_CENTER;
                            hCell.BackgroundColor = new BaseColor(70, 130, 180);
                            labResultHeader.AddCell(hCell);
                            //labResultHeader.AddCell(new Paragraph(MDVUtility.ToStr(drTest[dsLabOrder.LabOrderTest.CPTCodeColumn.ColumnName]) + ' ' + MDVUtility.ToStr(drTest[dsLabOrder.LabOrderTest.CPTCodeDescriptionColumn.ColumnName]), bodyFont));
                            pdfDocument.Add(labResultHeader);

                            labResultHeader = new PdfPTable(2);
                            widths = new float[] { 4f, 16f };
                            labResultHeader.TotalWidth = 575f;
                            labResultHeader.LockedWidth = true;

