                            hCell.HorizontalAlignment = Element.ALIGN_CENTER;
                            hCell.VerticalAlignment = Element.ALIGN_CENTER;
                            hCell.BackgroundColor = new BaseColor(70, 130, 180);
                            labResultHeader.AddCell(hCell);

