                            hCell.VerticalAlignment = Element.ALIGN_CENTER;
                            hCell.BackgroundColor = new BaseColor(70, 130, 180);
                            labResultHeader.AddCell(hCell);

                            hCell = new PdfPCell(new Phrase("Notes", tableHeaderRowFont));
                            hCell.PaddingTop = 5;
                            hCell.PaddingBottom = 5;
                            hCell.HorizontalAlignment = Element.ALIGN_CENTER;
                            hCell.VerticalAlignment = Element.ALIGN_CENTER;
                            hCell.BackgroundColor = new BaseColor(70, 130, 180);
                            labResultHeader.AddCell(hCell);

                            pdfDocument.Add(labResultHeader);

                            PdfPTable labResultTable = new PdfPTable(8);
                            widths = new float[] { 12f, 8f, 8f, 8f, 8f, 8f, 8f, 8f };
                            labResultTable.TotalWidth = 575f;
                            labResultTable.LockedWidth = true;

                            DSLabResult.LabOrderResultDetailRow[] resultDetail = (DSLabResult.LabOrderResultDetailRow[])dsLabResult.LabOrderResultDetail.Select(dsLabResult.LabOrderResultDetail.CPTCodeColumn.ColumnName + '=' + MDVUtility.ToLINQFormatString(drTest[dsLabOrder.LabOrderTest.CPTCodeColumn.ColumnName]));

                            foreach (DSLabResult.LabOrderResultDetailRow drDetail in resultDetail)
                            {
                                string cptCode = MDVUtility.ToStr(drDetail[dsLabResult.LabOrderResultDetail.CPTCodeColumn.ColumnName]);
                                if (cptCode == "625-4")
                                {
                                    labResultTable.AddCell(new Paragraph(MDVUtility.ToStr(drDetail[dsLabResult.LabOrderResultDetail.LOINCDescriptionColumn.ColumnName]), bodyFontParent));
                                    labResultTable.AddCell(new Paragraph(MDVUtility.ToStr(drDetail[dsLabResult.LabOrderResultDetail.ResultColumn.ColumnName]), bodyFontParent));
                                    labResultTable.AddCell(new Paragraph(MDVUtility.ToStr(drDetail[dsLabResult.LabOrderResultDetail.UoMColumn.ColumnName]), bodyFontParent));
                                    labResultTable.AddCell(new Paragraph(MDVUtility.ToStr(drDetail[dsLabResult.LabOrderResultDetail.RangeColumn.ColumnName]), bodyFontParent));
                                    labResultTable.AddCell(new Paragraph(MDVUtility.ToStr(drDetail[dsLabResult.LabOrderResultDetail.FlagColumn.ColumnName]), bodyFontParent));
                                    labResultTable.AddCell(new Paragraph(resultStatus, bodyFontParent));
                                    labResultTable.AddCell(new Paragraph(MDVUtility.ToDateTime(drDetail[dsLabResult.LabOrderResultDetail.ObservationDateColumn.ColumnName]).ToString(), bodyFontParent));
                                    labResultTable.AddCell(new Paragraph(MDVUtility.ToStr(drDetail[dsLabResult.LabOrderResultDetail.CommentsColumn.ColumnName]), bodyFontParent));
                                    DSLabResult.LabOrderResultDetailRow[] labResultDetailChild = (DSLabResult.LabOrderResultDetailRow[])dsLabResult.LabOrderResultDetail.Select(dsLabResult.LabOrderResultDetail.CPTCodeColumn.ColumnName + '=' + "'50545-3'");
                                    foreach (DSLabResult.LabOrderResultDetailRow drDetailChild in labResultDetailChild)
                                    {
                                        labResultTable.AddCell(new Paragraph(MDVUtility.ToStr(drDetailChild[dsLabResult.LabOrderResultDetail.LOINCDescriptionColumn.ColumnName]), bodyFont));
                                        labResultTable.AddCell(new Paragraph(MDVUtility.ToStr(drDetailChild[dsLabResult.LabOrderResultDetail.ResultColumn.ColumnName]), bodyFont));
                                        labResultTable.AddCell(new Paragraph(MDVUtility.ToStr(drDetailChild[dsLabResult.LabOrderResultDetail.UoMColumn.ColumnName]), bodyFont));
                                        labResultTable.AddCell(new Paragraph(MDVUtility.ToStr(drDetailChild[dsLabResult.LabOrderResultDetail.RangeColumn.ColumnName]), bodyFont));
                                        labResultTable.AddCell(new Paragraph(MDVUtility.ToStr(drDetailChild[dsLabResult.LabOrderResultDetail.FlagColumn.ColumnName]), bodyFont));
                                        labResultTable.AddCell(new Paragraph(resultStatus, bodyFont));
                                        labResultTable.AddCell(new Paragraph(MDVUtility.ToDateTime(drDetailChild[dsLabResult.LabOrderResultDetail.ObservationDateColumn.ColumnName]).ToString(), bodyFont));
                                        labResultTable.AddCell(new Paragraph(MDVUtility.ToStr(drDetailChild[dsLabResult.LabOrderResultDetail.CommentsColumn.ColumnName]), bodyFont));
                                    }

                                }
                                else
                                {
                                    if (cptCode != "50545-3")
                                    {
                                        labResultTable.AddCell(new Paragraph(MDVUtility.ToStr(drDetail[dsLabResult.LabOrderResultDetail.LOINCDescriptionColumn.ColumnName]), bodyFont));
                                        labResultTable.AddCell(new Paragraph(MDVUtility.ToStr(drDetail[dsLabResult.LabOrderResultDetail.ResultColumn.ColumnName]), bodyFont));
                                        labResultTable.AddCell(new Paragraph(MDVUtility.ToStr(drDetail[dsLabResult.LabOrderResultDetail.UoMColumn.ColumnName]), bodyFont));
                                        labResultTable.AddCell(new Paragraph(MDVUtility.ToStr(drDetail[dsLabResult.LabOrderResultDetail.RangeColumn.ColumnName]), bodyFont));
                                        labResultTable.AddCell(new Paragraph(MDVUtility.ToStr(drDetail[dsLabResult.LabOrderResultDetail.FlagColumn.ColumnName]), bodyFont));
                                        labResultTable.AddCell(new Paragraph(resultStatus, bodyFont));
                                        labResultTable.AddCell(new Paragraph(MDVUtility.ToDateTime(drDetail[dsLabResult.LabOrderResultDetail.ObservationDateColumn.ColumnName]).ToString(), bodyFont));
                                        if (cptCode == "HepABC Panel" || cptCode == "11011-4")
                                        {
                                            labResultTable.AddCell(new Paragraph(string.Empty, bodyFont));
                                        }
                                        else
                                        {
                                            labResultTable.AddCell(new Paragraph(MDVUtility.ToStr(drDetail[dsLabResult.LabOrderResultDetail.CommentsColumn.ColumnName]), bodyFont));
                                        }

                                    }
                                }

                            }

                            pdfDocument.Add(labResultTable);

                        }

                        // End Append Lab Result's Data
                    }

                    #endregion

                    pdf.Document.Close();
                    pdf.Writer.Close();

                    newByteArr = stream_.GetBuffer();
                }

                return new BLObject<byte[]>(newByteArr);
            }
            catch (Exception ex)
            {
                MDVLogger.BLLErrorLog("BLLClinical::viewPdfLabResult", ex);
                return new BLObject<byte[]>(null, ex.Message);
            }

            //End 08-04-2016 Edit By Humaira Yousaf Bug# EMR-577

        }

        /// <summary>
        /// Module Name: viewBlankPdfLabResult
        /// Author: Humaira Yousaf
