                    spTable.AddCell(new Paragraph("Alt Specimen Reject Reason", bodyFont));
                    spTable.AddCell(string.Empty);

                    spTable.AddCell(new Paragraph("Reject Reason Original Text", bodyFont));
                    spTable.AddCell(string.Empty);

                    spTable.AddCell(new Paragraph("Specimen Condition", bodyFont));
                    spTable.AddCell(string.Empty);

                    spTable.AddCell(new Paragraph("Alt Specimen Condition", bodyFont));
                    spTable.AddCell(string.Empty);

                    spTable.AddCell(new Paragraph("Condition Original Text", bodyFont));
                    spTable.AddCell(string.Empty);

                    pdfDocument.Add(spTable);

                    #endregion
                    #region Lab Result's Data

                    // Start Append Lab Results's Data
                    pdfDocument.Add(Chunk.NEWLINE);
                    PdfPTable labResultHeader = new PdfPTable(1);
                    labResultHeader.TotalWidth = 575f;
                    labResultHeader.LockedWidth = true;
                    PdfPCell hCell = new PdfPCell(new Phrase("Lab Result", tableHeaderFont));
                    hCell.HorizontalAlignment = Element.ALIGN_CENTER;
                    hCell.BackgroundColor = BaseColor.BLUE;
                    labResultHeader.AddCell(hCell);
                    pdfDocument.Add(labResultHeader);

                    labResultHeader = new PdfPTable(8);
                    widths = new float[] { 12f, 8f, 8f, 8f, 8f, 8f, 8f, 8f };
                    labResultHeader.TotalWidth = 575f;
                    labResultHeader.LockedWidth = true;

                    hCell = new PdfPCell(new Phrase("Observation", tableHeaderFont));
                    hCell.HorizontalAlignment = Element.ALIGN_CENTER;
                    hCell.BackgroundColor = BaseColor.BLUE;
                    labResultHeader.AddCell(hCell);

                    hCell = new PdfPCell(new Phrase("Result", tableHeaderFont));
                    hCell.HorizontalAlignment = Element.ALIGN_CENTER;
                    hCell.BackgroundColor = BaseColor.BLUE;
                    labResultHeader.AddCell(hCell);

                    hCell = new PdfPCell(new Phrase("UOM", tableHeaderFont));
                    hCell.HorizontalAlignment = Element.ALIGN_CENTER;
                    hCell.BackgroundColor = BaseColor.BLUE;
                    labResultHeader.AddCell(hCell);

                    hCell = new PdfPCell(new Phrase("Range", tableHeaderFont));
                    hCell.HorizontalAlignment = Element.ALIGN_CENTER;
                    hCell.BackgroundColor = BaseColor.BLUE;
                    labResultHeader.AddCell(hCell);

                    hCell = new PdfPCell(new Phrase("Abnormal Flag", tableHeaderFont));
                    hCell.HorizontalAlignment = Element.ALIGN_CENTER;
                    hCell.BackgroundColor = BaseColor.BLUE;
                    labResultHeader.AddCell(hCell);

                    hCell = new PdfPCell(new Phrase("Status", tableHeaderFont));
                    hCell.HorizontalAlignment = Element.ALIGN_CENTER;
                    hCell.BackgroundColor = BaseColor.BLUE;
                    labResultHeader.AddCell(hCell);

                    hCell = new PdfPCell(new Phrase("Date/Time of Observation", tableHeaderFont));
                    hCell.HorizontalAlignment = Element.ALIGN_CENTER;
                    hCell.BackgroundColor = BaseColor.BLUE;
                    labResultHeader.AddCell(hCell);

                    hCell = new PdfPCell(new Phrase("Notes", tableHeaderFont));
                    hCell.HorizontalAlignment = Element.ALIGN_CENTER;
                    hCell.BackgroundColor = BaseColor.BLUE;
                    labResultHeader.AddCell(hCell);

                    pdfDocument.Add(labResultHeader);

                    PdfPTable labResultTable = new PdfPTable(8);
                    widths = new float[] { 12f, 8f, 8f, 8f, 8f, 8f, 8f, 8f };
                    labResultTable.TotalWidth = 575f;
                    labResultTable.LockedWidth = true;


                    pdfDocument.Add(labResultTable);
                    // End Append Lab Result's Data

                    #endregion

                    pdf.Document.Close();
                    pdf.Writer.Close();

                    newByteArr = stream_.GetBuffer();
                }

                return new BLObject<byte[]>(newByteArr);
            }
            catch (Exception ex)
            {
                MDVLogger.BLLErrorLog("BLLClinical::viewPdfLabResult", ex);
                return new BLObject<byte[]>(null, ex.Message);
            }

        }


