        // Author:  Abid Ali
        // Created Date: 17/03/2016
        //OverView: Method to Insert/Update RadiologyOrder

        public BLObject<DSRadiologyOrder> InsertUpdateRadiologyOrder(DSRadiologyOrder ds, RadiologyOrderModel model, List<object> lstRadiologyObjects)
        {
            IDBManager dbManager = ClientConfiguration.GetDBManager();
            IDBManager dbManagerAudit = ClientConfiguration.GetDBManager();
            DSDBAudit dsDBAudit = new DSDBAudit();
            try
            {
                DataTable dtTempRadiologyOrder = null;
                DataTable dtTempRadiologyOrderProblem = null;
                DataTable dtTempCurrRadiologyOrderProblem = null;
                DataTable dtTempRadiologyOrderTest = null;

                DSRadiologyOrder dsCurrentOrderProblems = null;
                DSRadiologyOrder dsRadiologyOrderProblem = new DSRadiologyOrder();
                DSRadiologyOrder dsRadiologyOrderForTest = null;

                dtTempRadiologyOrder = ds.RadiologyOrder.GetChanges();
                if (!string.IsNullOrWhiteSpace(model.RadiologyOrderId) && model.RadiologyOrderId != "-1")
                {
                    dsCurrentOrderProblems = new DALRadiologyOrder().loadRadiologyOrderProblems(0, Convert.ToInt32(model.RadiologyOrderId), 0);
                    dtTempRadiologyOrderProblem = dsCurrentOrderProblems.RadiologyOrderProblem;

                    dsRadiologyOrderForTest = RadiologyOrderTestList(MDVUtility.ToInt64(model.RadiologyOrderId), lstRadiologyObjects, true, model.UpdateTestValues);
                }

                try
                {
                    dbManager.BeginTransaction();

                    ds = new DALRadiologyOrder().InsertUpdateRadiologyOrder(ds, dbManager);

                    Int64 RadiologyOrderId = MDVUtility.ToInt64(ds.Tables[ds.RadiologyOrder.TableName].Rows[0][ds.RadiologyOrder.RadiologyOrderIdColumn.ColumnName]);
                    if (model.RadiologyOrderProblemList != null && !string.IsNullOrWhiteSpace(model.RadiologyOrderId) && model.RadiologyOrderId != "-1")
                    {
                        DeleteRadiologyOrderProblems(MDVUtility.ToStr(RadiologyOrderId), dbManager);
                    }

                    if (model.RadiologyOrderProblemList != null && model.RadiologyOrderProblemList.Count > 0)
                    {
                        model.RadiologyOrderProblemList.ForEach(cc => cc.RadiologyOrderId = MDVUtility.ToStr(RadiologyOrderId));
                        foreach (var m in model.RadiologyOrderProblemList)
                        {
                            DSRadiologyOrder.RadiologyOrderProblemRow dr = dsRadiologyOrderProblem.RadiologyOrderProblem.NewRadiologyOrderProblemRow();
                            dr.RadiologyOrderId = RadiologyOrderId;
                            dr.ProblemId = MDVUtility.ToInt32(m.ProblemId);
                            dr.Comments = string.Empty;
                            dr.IsActive = true;
                            dr.CreatedBy = MDVUtility.DecryptFrom64(MDVSession.Current.AppUserName);
                            dr.CreatedOn = DateTime.Now;
                            dr.ModifiedBy = MDVUtility.DecryptFrom64(MDVSession.Current.AppUserName);
                            dr.ModifiedOn = DateTime.Now;
                            dsRadiologyOrderProblem.RadiologyOrderProblem.AddRadiologyOrderProblemRow(dr);
                        }
                        dtTempCurrRadiologyOrderProblem = dsRadiologyOrderProblem.RadiologyOrderProblem.GetChanges();
                        InsertUpdateRadiologyOrderProblems(dsRadiologyOrderProblem, dbManager);
                    }

                    if (string.IsNullOrWhiteSpace(model.RadiologyOrderId) || model.RadiologyOrderId == "-1")
                    {
                        dsRadiologyOrderForTest = RadiologyOrderTestList(RadiologyOrderId, lstRadiologyObjects, false, model.UpdateTestValues);
                    }
                    dtTempRadiologyOrderTest = dsRadiologyOrderForTest.RadiologyOrderTest.GetChanges();
                    insertUpdateRadiologyOrderTest(dsRadiologyOrderForTest, dbManager);

                    dbManager.CommitTransaction();
                }
                catch (Exception exTrans)
                {
                    dbManager.RollBackTransaction();
                    throw exTrans;
                }

                dbManagerAudit.Open();

                if (dtTempRadiologyOrder != null)
                {
                    dsDBAudit = new DBActivityAudit().InsertDBAudit(dtTempRadiologyOrder, dbManagerAudit, ds.RadiologyOrder.Rows[0][ds.RadiologyOrder.RadiologyOrderIdColumn].ToString(), null, ds.RadiologyOrder.Rows[0][ds.RadiologyOrder.RadiologyOrderIdColumn].ToString());
                    dsDBAudit.AcceptChanges();
                }

                if (dtTempRadiologyOrderProblem != null)
                {
                    if (dsCurrentOrderProblems.RadiologyOrderProblem.Rows.Count > 1)
                    {
                        dsDBAudit = new DBActivityAudit().InsertDBAudit(dtTempRadiologyOrderProblem, dbManagerAudit, dsCurrentOrderProblems.RadiologyOrderProblem.Rows[0].ToString(), null, dsCurrentOrderProblems.RadiologyOrderProblem.Rows[0][dsCurrentOrderProblems.RadiologyOrderProblem.RadiologyOrderIdColumn].ToString(), false, false, true);
                        dsDBAudit.AcceptChanges();
                    }
                }

                if (dtTempCurrRadiologyOrderProblem != null)
                {
                    dtTempCurrRadiologyOrderProblem.Columns.Add("PrimaryKey");
                    dtTempCurrRadiologyOrderProblem.Columns.Add("PatientId");
                    for (int i = 0; i < dsRadiologyOrderProblem.RadiologyOrderProblem.Rows.Count; i++)
                    {
                        dtTempCurrRadiologyOrderProblem.Rows[i]["PrimaryKey"] = dsRadiologyOrderProblem.RadiologyOrderProblem.Rows[i][dsRadiologyOrderProblem.RadiologyOrderProblem.RadiologyOrderProblemIdColumn];
                        dtTempCurrRadiologyOrderProblem.Rows[i]["PatientId"] = model.PatientId;
                    }

                    dsDBAudit = new DBActivityAudit().InsertDBAudit(dtTempCurrRadiologyOrderProblem, dbManagerAudit, dsRadiologyOrderProblem.RadiologyOrderProblem.Rows[0][dsRadiologyOrderProblem.RadiologyOrderProblem.RadiologyOrderProblemIdColumn].ToString(), null, dsRadiologyOrderProblem.RadiologyOrderProblem.Rows[0][dsRadiologyOrderProblem.RadiologyOrderProblem.RadiologyOrderIdColumn].ToString());
                    dsDBAudit.AcceptChanges();
                }

                if (dtTempRadiologyOrderTest != null)
                {
                    dtTempRadiologyOrderTest.Columns.Add("PrimaryKey");
                    for (int i = 0; i < dsRadiologyOrderForTest.RadiologyOrderTest.Rows.Count; i++)
                    {
                        dtTempRadiologyOrderTest.Rows[i]["PrimaryKey"] = dsRadiologyOrderForTest.RadiologyOrderTest.Rows[i][dsRadiologyOrderForTest.RadiologyOrderTest.RadiologyOrderTestIdColumn];
                    }
                    dsDBAudit = new DBActivityAudit().InsertDBAudit(dtTempRadiologyOrderTest, dbManagerAudit, dsRadiologyOrderForTest.RadiologyOrderTest.Rows[0][dsRadiologyOrderForTest.RadiologyOrderTest.RadiologyOrderTestIdColumn].ToString(), null, dsRadiologyOrderForTest.RadiologyOrderTest.Rows[0][dsRadiologyOrderForTest.RadiologyOrderTest.RadiologyOrderTestIdColumn].ToString());
                    dsDBAudit.AcceptChanges();
                }

                dbManagerAudit.Dispose();
                return new BLObject<DSRadiologyOrder>(ds);
            }
            catch (Exception ex)
            {
                MDVLogger.BLLErrorLog("BLLClinical::InsertUpdateRadiologyOrder", ex);
                dbManagerAudit.Dispose();
                throw ex;
                //return new BLObject<DSRadiologyOrder>(null, ex.Message);
            }
        }

        public DSRadiologyOrder RadiologyOrderTestList(Int64 RadiologyId, List<object> lstObjects, bool IsUpdate, string UpdateTestValues = "1")
        {
            try
            {
                DSRadiologyOrder dsRadiologyOrder = new DSRadiologyOrder();
                BLObject<DSRadiologyOrder> objRadiologyOrderTest = new BLObject<DSRadiologyOrder>();
                if (IsUpdate)
                {
                    objRadiologyOrderTest = LoadRadiologyOrderTest(RadiologyId, 0, 0, "1", "2000");
                }
                else
                {
                    objRadiologyOrderTest = new BLObject<DSRadiologyOrder>(new DSRadiologyOrder());
                }
                dsRadiologyOrder = objRadiologyOrderTest.Data;
                List<RadiologyOrderTestModel> lstRadiologyOrder = lstObjects.OfType<RadiologyOrderTestModel>().ToList();

                int id = -1;
                foreach (RadiologyOrderTestModel CurrentModel in lstRadiologyOrder)
                {
                    Int32 currentRadiologyTestId = MDVUtility.ToInt32(CurrentModel.RadiologyOrderTestId);
                    currentRadiologyTestId = currentRadiologyTestId == 0 ? id-- : currentRadiologyTestId;

                    DSRadiologyOrder.RadiologyOrderTestRow RowRadiologyOrderTest = null;
                    DSRadiologyOrder.RadiologyOrderTestRow[] arrRadiologyOrderTestRows = (DSRadiologyOrder.RadiologyOrderTestRow[])dsRadiologyOrder.RadiologyOrderTest.Select(dsRadiologyOrder.RadiologyOrderTest.RadiologyOrderTestIdColumn.ColumnName + "=" + CurrentModel.RadiologyOrderTestId);

                    if (arrRadiologyOrderTestRows.Length > 0)
                    {
                        RowRadiologyOrderTest = arrRadiologyOrderTestRows[0];
                    }
                    else
                    {
                        RowRadiologyOrderTest = dsRadiologyOrder.RadiologyOrderTest.NewRadiologyOrderTestRow();
                        RowRadiologyOrderTest.RadiologyOrderTestId = currentRadiologyTestId;
                    }
                    if (RowRadiologyOrderTest != null)
                    {
                        RowRadiologyOrderTest.RadiologyOrderId = RadiologyId;
                        if (!string.IsNullOrEmpty(CurrentModel.CPTDescription))
                        {
                            RowRadiologyOrderTest[dsRadiologyOrder.RadiologyOrderTest.CPTCodeDescriptionColumn] = MDVUtility.ToStr(CurrentModel.CPTDescription);
                        }
                        else
                        {
                            RowRadiologyOrderTest[dsRadiologyOrder.RadiologyOrderTest.CPTCodeDescriptionColumn] = DBNull.Value;
                        }

                        if (!string.IsNullOrEmpty(CurrentModel.CPTCode))
                        {
                            RowRadiologyOrderTest[dsRadiologyOrder.RadiologyOrderTest.CPTCodeColumn] = MDVUtility.ToStr(CurrentModel.CPTCode);
                        }
                        else
                        {
                            RowRadiologyOrderTest[dsRadiologyOrder.RadiologyOrderTest.CPTCodeColumn] = DBNull.Value;
                        }

                        if (!string.IsNullOrEmpty(CurrentModel.CPTSNOMEDDescription))
                        {
                            RowRadiologyOrderTest[dsRadiologyOrder.RadiologyOrderTest.CPTSNOMEDDescriptionColumn] = MDVUtility.ToStr(CurrentModel.CPTSNOMEDDescription);
                        }
                        else
                        {
                            RowRadiologyOrderTest[dsRadiologyOrder.RadiologyOrderTest.CPTSNOMEDDescriptionColumn] = DBNull.Value;
                        }

                        if (!string.IsNullOrEmpty(CurrentModel.CPTSNOMEDCodeId))
                        {
                            RowRadiologyOrderTest[dsRadiologyOrder.RadiologyOrderTest.CPTSNOMEDIDColumn] = MDVUtility.ToStr(CurrentModel.CPTSNOMEDCodeId);
                        }
                        else
                        {
                            RowRadiologyOrderTest[dsRadiologyOrder.RadiologyOrderTest.CPTSNOMEDIDColumn] = DBNull.Value;
                        }
                        if (!string.IsNullOrEmpty(CurrentModel.dtpRadiologyDate))
                        {
                            RowRadiologyOrderTest[dsRadiologyOrder.RadiologyOrderTest.TestDateColumn] = MDVUtility.ToDateTime(CurrentModel.dtpRadiologyDate);
                        }
                        else
                        {
                            RowRadiologyOrderTest[dsRadiologyOrder.RadiologyOrderTest.TestDateColumn] = DBNull.Value;
                        }

                        if (!string.IsNullOrEmpty(CurrentModel.tpRadiologyTime))
                        {
                            RowRadiologyOrderTest[dsRadiologyOrder.RadiologyOrderTest.TestTimeColumn] = MDVUtility.ToStr(CurrentModel.tpRadiologyTime);
                        }
                        else
                        {
                            RowRadiologyOrderTest[dsRadiologyOrder.RadiologyOrderTest.TestTimeColumn] = DBNull.Value;
                        }

                        if (!string.IsNullOrEmpty(CurrentModel.RadiologyProcedure))
                        {
                            RowRadiologyOrderTest[dsRadiologyOrder.RadiologyOrderTest.CPTCodeDescriptionColumn] = MDVUtility.ToStr(CurrentModel.CPTDescription);
                        }
                        else
                        {
                            RowRadiologyOrderTest[dsRadiologyOrder.RadiologyOrderTest.CPTCodeDescriptionColumn] = DBNull.Value;
                        }

                        if (!string.IsNullOrEmpty(CurrentModel.CollectedAt))
                        {
                            RowRadiologyOrderTest[dsRadiologyOrder.RadiologyOrderTest.CollectedAtIdColumn] = MDVUtility.ToInt32(CurrentModel.CollectedAt);
                        }

                        if (!string.IsNullOrEmpty(CurrentModel.Urgency))
                        {
                            RowRadiologyOrderTest[dsRadiologyOrder.RadiologyOrderTest.UrgencyIdColumn] = MDVUtility.ToInt32(CurrentModel.Urgency);
                        }

                        if (!string.IsNullOrEmpty(CurrentModel.Specimen))
                        {
                            RowRadiologyOrderTest[dsRadiologyOrder.RadiologyOrderTest.SpecimenIdColumn] = MDVUtility.ToInt32(CurrentModel.Specimen);
                        }

                        if (!string.IsNullOrEmpty(CurrentModel.PatientInstructions))
                        {
                            RowRadiologyOrderTest[dsRadiologyOrder.RadiologyOrderTest.PatientInstructionColumn] = MDVUtility.ToStr(CurrentModel.PatientInstructions);
                        }

                        if (!string.IsNullOrEmpty(CurrentModel.VolumeText))
                        {
                            RowRadiologyOrderTest[dsRadiologyOrder.RadiologyOrderTest.VolumeLengthColumn] = MDVUtility.ToStr(CurrentModel.VolumeText);
                        }

                        if (!string.IsNullOrEmpty(CurrentModel.VolumeDDL))
                        {
                            RowRadiologyOrderTest[dsRadiologyOrder.RadiologyOrderTest.VolumeIdColumn] = MDVUtility.ToInt32(CurrentModel.VolumeDDL);
                        }
                        if (!string.IsNullOrEmpty(CurrentModel.FillerInstructions))
                        {
                            RowRadiologyOrderTest[dsRadiologyOrder.RadiologyOrderTest.FillerInstructionColumn] = MDVUtility.ToStr(CurrentModel.FillerInstructions);
                        }
                        if (!string.IsNullOrEmpty(UpdateTestValues) && UpdateTestValues == "1")
                        {
                            if (!string.IsNullOrEmpty(CurrentModel.Reason))
                            {
                                RowRadiologyOrderTest[dsRadiologyOrder.RadiologyOrderTest.ReasonColumn] = MDVUtility.ToStr(CurrentModel.Reason);
                            }
                            else
                            {
                                RowRadiologyOrderTest[dsRadiologyOrder.RadiologyOrderTest.ReasonColumn] = DBNull.Value;
                            }
                            if (!string.IsNullOrEmpty(CurrentModel.BodySite))
                            {
                                RowRadiologyOrderTest[dsRadiologyOrder.RadiologyOrderTest.BodySiteColumn] = MDVUtility.ToStr(CurrentModel.BodySite);
                            }
                            else
                            {
                                RowRadiologyOrderTest[dsRadiologyOrder.RadiologyOrderTest.BodySiteColumn] = DBNull.Value;
                            }
                        }
                        //Start Farooq Ahmad 23/3/2016 Update Soap Text
                        RowRadiologyOrderTest[dsRadiologyOrder.RadiologyOrderTest.SoapTextColumn] = string.Format("{0} {1} {2} {3} {4} {5}", string.Empty, "<b>" + CurrentModel.RadiologyProcedure + "</b>", string.IsNullOrWhiteSpace(CurrentModel.Specimen) ? string.Empty : string.Concat(",Specimen: ", CurrentModel.Specimen_text), string.IsNullOrWhiteSpace(CurrentModel.VolumeText) ? string.Empty : string.Concat(",Volume: ", CurrentModel.VolumeText), string.IsNullOrWhiteSpace(CurrentModel.Urgency) ? string.Empty : CurrentModel.Urgency_text == "- Select -" ? string.Empty : string.Concat(",Urgency: ", (CurrentModel.Urgency == "1" ? "Normal" : "STAT")), "<br>");
                        //End Farooq Ahmad 23/3/2016 Update Soap Text

                        RowRadiologyOrderTest.IsActive = true;
                        RowRadiologyOrderTest.CreatedBy = MDVUtility.DecryptFrom64(MDVSession.Current.AppUserName);
                        RowRadiologyOrderTest.CreatedOn = DateTime.Now;
                        RowRadiologyOrderTest.ModifiedBy = MDVUtility.DecryptFrom64(MDVSession.Current.AppUserName);
                        RowRadiologyOrderTest.ModifiedOn = DateTime.Now;
                        if (arrRadiologyOrderTestRows.Length < 1)
                        {
                            dsRadiologyOrder.RadiologyOrderTest.AddRadiologyOrderTestRow(RowRadiologyOrderTest);
                        }
                    }
                }
                return dsRadiologyOrder;
            }
            catch (Exception ex)
            {
                MDVLogger.BLLErrorLog("BLLClinical::RadiologyOrderTestList", ex);
                throw ex;
            }
        }


