                        //problemsTable.AddCell(string.Empty);

                        //foreach (DSRadiologyOrder.RadiologyOrderProblemRow dr in dsRadiologyOrder.Tables[dsRadiologyOrder.RadiologyOrderProblem.TableName].Rows)
                        //{
                        //    problemsTable.AddCell(string.Empty);
                        //    problemsTable.AddCell(new Paragraph(HttpUtility.HtmlDecode(MDVUtility.ToStr(dr[dsRadiologyOrder.RadiologyOrderProblem.ProblemNameColumn.ColumnName])), bodyFont));
                        //    problemsTable.AddCell(string.Empty);
                        //}
                        //pdfDocument.Add(problemsTable);
                    }
                    else
                    {

                        Paragraph problems_Heading = new Paragraph("Diagnosis Codes \n".ToString(), componentHeadingFontN);
                        problems_Heading.SpacingBefore = problems_Heading.SpacingAfter = 5;
                        pdfDocument.Add(problems_Heading);
                        PdfPTable problemsTable = new PdfPTable(5);
                        float[] widths = new float[] { 1f, 8f, 8f, 8f, 8f };
                        problemsTable.SetWidths(widths);
                        problemsTable.TotalWidth = 575f;
                        problemsTable.LockedWidth = true;
                        problemsTable.DefaultCell.Border = Rectangle.NO_BORDER;
                        problemsTable.AddCell(string.Empty);
                        pdfDocument.Add(problemsTable);
                        Paragraph noProblems = new Paragraph("No Associated Diagnosis Codes Found".ToString(), bodyFont);
                        noProblems.Alignment = Element.ALIGN_CENTER;
                        pdfDocument.Add(noProblems);
                    }
                    // End Append Associated Problems

                    #endregion

                    #region Findings

                    BLObject<List<OrderFindingsModel>> obj = LoadRadiologyOrderTestFindings(radiologyId, isFindingUpdate, notesId);
                    List<OrderFindingsModel> findingsList = obj.Data;

                    if (findingsList != null && findingsList.Count > 0)
                    {
                        Paragraph findings_Heading = new Paragraph("Findings \n".ToString(), componentHeadingFontN);
                        findings_Heading.SpacingBefore = findings_Heading.SpacingAfter = 5;
                        pdfDocument.Add(findings_Heading);

                        PdfPTable testTable = new PdfPTable(1);
                        float[] widths = new float[] { 12f };
                        testTable.SetWidths(widths);
                        testTable.TotalWidth = 575f;
                        testTable.LockedWidth = true;
                        testTable.DefaultCell.Border = Rectangle.NO_BORDER;

                        var groupedFindingsList = findingsList
                                                    .GroupBy(u => u.TestName)
                                                    .Select(grp => grp.ToList())
                                                    .ToList();

                        foreach (List<OrderFindingsModel> findings in groupedFindingsList)
                        {
                            testTable.AddCell(new Paragraph(findings[0].TestName, gridbodyFont));

                            foreach (var item in findings)
                            {
                                //Start 29-09-2017 Humaira Yousaf Bug# EMR-4853
                                if (!string.IsNullOrEmpty(item.Findings))
                                {
                                    Phrase sysName = new Phrase();
                                    sysName.Add(new Chunk(item.SystemName + ": ", findingNameFont));
                                    sysName.Add(new Chunk(item.Findings, bodyFont));
                                    testTable.AddCell(sysName);
                                }
                                //End 29-09-2017 Humaira Yousaf Bug# EMR-4853
                            }
                        }

                        pdfDocument.Add(testTable);
                    }
                    #endregion

                    if (mode == "Edit" && isIncludeComments == true)
                    {

                        DataRow drComments = dsRadiologyOrder.Tables[dsRadiologyOrder.RadiologyOrder.TableName].Rows[0];
                        Paragraph comments_Heading = new Paragraph("Comments \n".ToString(), componentHeadingFontN);
                        comments_Heading.SpacingBefore = comments_Heading.SpacingAfter = 5;
                        pdfDocument.Add(comments_Heading);

                        Paragraph commentsText = new Paragraph(HttpUtility.HtmlDecode(drComments[dsRadiologyOrder.RadiologyOrderTest.CommentsColumn.ColumnName].ToString()), bodyFont);
                        commentsText.Alignment = Element.ALIGN_LEFT;
                        pdfDocument.Add(commentsText);

                    }
                    else if (mode != "Edit" && includeComments == true)
                    {
                        DataRow drComments = dsRadiologyOrder.Tables[dsRadiologyOrder.RadiologyOrder.TableName].Rows[0];
                        Paragraph comments_Heading = new Paragraph("Comments \n".ToString(), componentHeadingFontN);
                        comments_Heading.SpacingBefore = comments_Heading.SpacingAfter = 5;
                        pdfDocument.Add(comments_Heading);

                        Paragraph commentsText = new Paragraph(HttpUtility.HtmlDecode(drComments[dsRadiologyOrder.RadiologyOrderTest.CommentsColumn.ColumnName].ToString()), bodyFont);
                        commentsText.Alignment = Element.ALIGN_LEFT;
                        pdfDocument.Add(commentsText);
                    }

                    //Start 28-03-2016 Humaira Yousaf
                    pdfDocument.Add(Chunk.NEWLINE);
                    pdfDocument.Add(Chunk.NEWLINE);


                    PdfPTable signTable = new PdfPTable(1);
                    signTable.TotalWidth = 575f;
                    signTable.LockedWidth = true;
                    signTable.DefaultCell.Border = Rectangle.NO_BORDER;

                    DataRow signRow = dsRadiologyOrder.Tables[dsProfile.Provider.TableName].Rows[0];
                    if (signRow[dsProfile.Provider.eSignatureColumn.ColumnName] as byte[] != null)
                    {
                        string signString = Convert.ToBase64String(signRow[dsProfile.Provider.eSignatureColumn.ColumnName] as byte[]);

                        Byte[] signBuffer = Convert.FromBase64String(signString);
                        var signStream = new MemoryStream(signBuffer);
                        iTextSharp.text.Image signImg = iTextSharp.text.Image.GetInstance(signBuffer, false);
                        signImg.ScaleAbsoluteHeight(150);
                        signImg.ScaleAbsoluteWidth(150);

                        PdfPCell signCell = new PdfPCell();
                        signCell.AddElement(signImg);
                        signCell.Border = Rectangle.NO_BORDER;
                        signCell.HorizontalAlignment = Element.ALIGN_LEFT;
                        signTable.AddCell(signCell);
                        pdfDocument.Add(signTable);
                    }

                    string modifiedDate = MDVUtility.ToDateTime(dsRadiologyOrder.Tables[dsRadiologyOrder.RadiologyOrder.TableName].Rows[0][dsRadiologyOrder.RadiologyOrder.ModifiedOnColumn.ColumnName]).ToLongDateString();

                    if (!string.IsNullOrEmpty(modifiedDate))
                    {
                        modifiedDate = modifiedDate + " at ";
                    }
                    string modifiedTime = MDVUtility.ToDateTime(dsRadiologyOrder.Tables[dsRadiologyOrder.RadiologyOrder.TableName].Rows[0][dsRadiologyOrder.RadiologyOrder.ModifiedOnColumn.ColumnName]).ToLongTimeString();

                    Paragraph signedByPara = new Paragraph("e-Signed By: " + MDVUtility.ToStr(dsRadiologyOrder.Tables[dsRadiologyOrder.RadiologyOrder.TableName].Rows[0][dsRadiologyOrder.RadiologyOrder.ModifiedByNameColumn.ColumnName]) + " on " + modifiedDate + modifiedTime, bodyFont);
                    signedByPara.Alignment = Element.ALIGN_LEFT;
                    signedByPara.SpacingBefore = -10;
                    pdfDocument.Add(signedByPara);
                    //End 28-03-2016 Humaira Yousaf

                    newByteArr = stream_.GetBuffer();
                    pdf.Document.Close();
                    pdf.Writer.Close();
                    pdfDocument.Close();

                    MemoryStream stream = new MemoryStream(stream_.ToArray());
                    PdfReader npdf = new PdfReader(stream);
                    MemoryStream outstream = new MemoryStream();
                    using (PdfStamper stamper = new PdfStamper(npdf, outstream, '\0', true))
                    {
                        stamper.Writer.CloseStream = false;
                        int PageCount = npdf.NumberOfPages;
                        for (int i = 1; i <= PageCount; i++)
                        {
                            Paragraph para = new Paragraph(String.Format("Page {0}/{1}", i, PageCount), bodyFont);
                            para.Add(setLabOrder_ResultFooter(pdfDocument));
                            ColumnText.ShowTextAligned(stamper.GetOverContent(i), Element.ALIGN_CENTER, para, 555, 17, 0);
                        }
                    }
                    newByteArr = outstream.GetBuffer();
                }

                return new BLObject<byte[]>(newByteArr);
                //End 04-05-2016 Humaira Yousaf for formatting and other changes
            }
            catch (Exception ex)
            {
                MDVLogger.BLLErrorLog("BLLClinical::previewRadiologyOrder", ex);
                return new BLObject<byte[]>(null, ex.Message);
            }
        }
        public BLObject<byte[]> CreateProcedureReport(long noteid, long patientId, long providerId, bool isFindingUpdate = false)
        {
            try
            {
                byte[] newByteArr = null;
                DSProcedures dsProcedure = new DSProcedures();
                DSPatient dsPatient = new DSPatient();
                DSProfile dsProfile = new DSProfile();

                dsProcedure = new DALProcedures().loadProcedures_Obsolete(0, patientId, noteid);
                DataRow[] tblROWS = dsProcedure.Tables[dsProcedure.Procedures.TableName].Select("isNoteLinked = '1'");

                if (dsProcedure.Tables[dsProcedure.Procedures.TableName].Rows.Count > 0 && tblROWS.Length > 0)
                {
                    DataTable dtProcedures = dsProcedure.Tables[dsProcedure.Procedures.TableName].Select("isNoteLinked = '1'").CopyToDataTable();
                    dsProcedure.Tables[dsProcedure.Procedures.TableName].Clear();
                    dsProcedure.Tables[dsProcedure.Procedures.TableName].Merge(dtProcedures);
                    String ProcedureIds = dsProcedure.Tables[dsProcedure.Procedures.TableName].AsEnumerable()
                     .Select(row => row["ProcedureId"].ToString())
                     .Aggregate((s1, s2) => String.Concat(s1, "," + s2));

                    List<ProcedureFindingsModel> lstProcdureFindings = new DALProcedures().loadProcedureFindings(ProcedureIds, noteid, isFindingUpdate);

                    if (lstProcdureFindings.Count > 0)
                    {
                        dsProcedure.Merge(new DALPatient().FillPatient(patientId, "", ""));
                        long practiceId = MDVUtility.ToInt64(dsProcedure.Tables[dsPatient.Patients.TableName].Rows[0][dsPatient.Patients.PracticeIdColumn.ColumnName]);
                        dsProcedure.Merge(new DALPractice().LoadPractice(practiceId, string.Empty, string.Empty, string.Empty, string.Empty, string.Empty));

                        #region header Things
                        string patientName = "";

                        DSReportHeader.ReportHeaderTagsDataTable dtReportHeaderTags;

                        bool IsReportHeaderApplied = false;
                        var dsReportHeader = new MDVision.DataAccess.DAL.ReportHeader.DALReportHeader().getReportHeaderTagsValue(patientId, 0, -1, "Others");
                        IsReportHeaderApplied = false;
                        dtReportHeaderTags = dsReportHeader.ReportHeaderTags;
                        if (IsReportHeaderApplied &&
                             (
                                    !string.IsNullOrEmpty(dsReportHeader.ReportHeaderTags[0]["PatientText"].ToString()) ||
                                    !string.IsNullOrEmpty(dsReportHeader.ReportHeaderTags[0]["ProviderText"].ToString()) ||
                                    !string.IsNullOrEmpty(dsReportHeader.ReportHeaderTags[0]["PracticeText"].ToString()) ||
                                    !string.IsNullOrEmpty(dsReportHeader.ReportHeaderTags[0]["HeaderLogo"].ToString())
                                    )
                            )
                        {
                            IsReportHeaderApplied = true;
                        }
                        else
                        {
                            IsReportHeaderApplied = false;
                        }
                        using (MemoryStream stream_ = new MemoryStream())
                        {
                            bool IsFooterExist = false;
                            string FooterGeneratedBy = "";
                            PdfPTable ReportHeaderTable = new PdfPTable(2);
                            PdfPTable footer = new PdfPTable(1);
                            float bottomMargin = 22;
                            float topMargin = 20;
                            PdfPTable patientTable = new PdfPTable(2);
                            Document pdfDocument = new Document(PageSize.LETTER, 20, 20, topMargin, bottomMargin);

                            // Heading Font Style
                            var fontColour = new BaseColor(102, 178, 255);
                            iTextSharp.text.Font patientNameFont = FontFactory.GetFont("Arial", 12, iTextSharp.text.Font.BOLD, fontColour);
                            iTextSharp.text.Font bodyFont = FontFactory.GetFont("Arial", 10, iTextSharp.text.Font.NORMAL, iTextSharp.text.BaseColor.BLACK);
                            iTextSharp.text.Font componentHeadingFont = FontFactory.GetFont("Arial", 10, iTextSharp.text.Font.NORMAL, fontColour);
                            iTextSharp.text.Font componentHeaderFont = FontFactory.GetFont("Arial", 10, iTextSharp.text.Font.BOLD, iTextSharp.text.BaseColor.BLACK);
                            iTextSharp.text.Font gridbodyFont = FontFactory.GetFont("Arial", 10, iTextSharp.text.Font.BOLD, iTextSharp.text.BaseColor.BLACK);
                            iTextSharp.text.Font findingNameFont = FontFactory.GetFont("Arial", 10, iTextSharp.text.Font.BOLD, new BaseColor(111, 173, 66));
                            iTextSharp.text.Font orderHeadingFont = FontFactory.GetFont("Arial", 12, iTextSharp.text.Font.BOLD, new BaseColor(72, 133, 209));

                            if (IsReportHeaderApplied)
                            {
                                DSReportHeader.ReportHeaderTagsRow drReportHeader = (DSReportHeader.ReportHeaderTagsRow)dtReportHeaderTags.Rows[0];
                                #region Report Header
                                try
                                {
                                    if (IsReportHeaderApplied)
                                    {
                                        ReportHeaderTable.TotalWidth = 630f;
                                        ReportHeaderTable.LockedWidth = true;
                                        ReportHeaderTable.DefaultCell.Border = Rectangle.NO_BORDER;

                                        IsFooterExist = drReportHeader.Field<string>("FooterText") != null;
                                        if (IsFooterExist)
                                        {
                                            FooterGeneratedBy = drReportHeader.FooterText;
                                            footer = setLabOrder_ResultFooterPDF(FooterGeneratedBy);
                                        }
                                        #region Header Logo
                                        if (drReportHeader.Field<string>("HeaderLogo") != null && drReportHeader.Field<string>("HeaderLogo") != "")
                                        {
                                            PdfPTable headerTable = new PdfPTable(1);
                                            headerTable.TotalWidth = 575f;
                                            headerTable.LockedWidth = true;
                                            headerTable.DefaultCell.Border = Rectangle.NO_BORDER;

                                            Byte[] buffer = Convert.FromBase64String(drReportHeader.HeaderLogo.Split(new string[] { "base64," }, StringSplitOptions.None)[1]);
                                            var memoryStream = new MemoryStream(buffer); //new MemoryStream(buffer, offset, count);
                                            System.Drawing.Image newImagej = System.Drawing.Image.FromStream(memoryStream);

                                            iTextSharp.text.Image logo = iTextSharp.text.Image.GetInstance(buffer, false);
                                            logo.ScalePercent(59f);
                                            logo.ScaleAbsoluteHeight(100);
                                            logo.ScaleAbsoluteWidth(150);

                                            PdfPCell cell1 = new PdfPCell();
                                            cell1.AddElement(logo);
                                            cell1.Border = Rectangle.NO_BORDER;
                                            cell1.HorizontalAlignment = Element.ALIGN_LEFT;
                                            ReportHeaderTable.AddCell(cell1);
                                        }

                                        else
                                        {
                                            PdfPTable EmptyHeaderTable = new PdfPTable(1);
                                            EmptyHeaderTable.DefaultCell.Border = Rectangle.NO_BORDER;
                                            EmptyHeaderTable.AddCell(new Paragraph("", bodyFont));
                                            ReportHeaderTable.AddCell(EmptyHeaderTable);
                                        }

                                        #endregion

                                        #region  Patient

                                        PdfPTable PatientTable = new PdfPTable(1);
                                        PatientTable.DefaultCell.Border = Rectangle.NO_BORDER;

                                        if (drReportHeader.Field<string>("PatientText") != null)
                                        {
                                            string[] PatientColumns = drReportHeader.PatientText.Split(new string[] { "<br/>" }, StringSplitOptions.None);
                                            foreach (string PatientColumn in PatientColumns)
                                            {
                                                if (!string.IsNullOrEmpty(PatientColumn) && !string.IsNullOrWhiteSpace(PatientColumn))
                                                {
                                                    PatientTable.AddCell(new Paragraph(PatientColumn, bodyFont));
                                                }
                                            }
                                        }
                                        else
                                        {
                                            PatientTable.AddCell(new Paragraph("", bodyFont));
                                        }
                                        PatientTable.DefaultCell.Padding = 0f;
                                        PatientTable.DefaultCell.UseAscender = true;
                                        ReportHeaderTable.AddCell(PatientTable);
                                        #endregion

                                        #region  Provider

                                        PdfPTable ProviderTable = new PdfPTable(1);
                                        ProviderTable.DefaultCell.Border = Rectangle.NO_BORDER;
                                        ProviderTable.DefaultCell.HorizontalAlignment = Element.ALIGN_RIGHT;
                                        ProviderTable.DefaultCell.PaddingRight = 50;

                                        if (drReportHeader.Field<string>("ProviderText") != null)
                                        {
                                            string[] ProviderColumns = drReportHeader.ProviderText.Split(new string[] { "<br/>" }, StringSplitOptions.None);

                                            foreach (string ProviderColumn in ProviderColumns)
                                            {
                                                if (!string.IsNullOrEmpty(ProviderColumn) && !string.IsNullOrWhiteSpace(ProviderColumn))
                                                {
                                                    ProviderTable.AddCell(new Paragraph(ProviderColumn, bodyFont));
                                                }
                                            }

                                        }
                                        else
                                            ProviderTable.AddCell(new Paragraph("", bodyFont));
                                        ReportHeaderTable.AddCell(ProviderTable);
                                        #endregion
                                    }
                                }
                                catch (Exception ex)
                                {
                                    MDVLogger.BLLErrorLog("BLLAdminClinical::getReportHeaderTagsValue", ex);
                                }
                                #endregion
                            }
                            if (IsReportHeaderApplied)
                            {
                                topMargin = ReportHeaderTable.CalculateHeights() + 33;
                                bottomMargin = 52;
                            }

                            footer = setLabOrder_ResultFooterPDF(FooterGeneratedBy);
                            pdfDocument.SetMargins(20, 20, topMargin, bottomMargin);
                            MDVUtility.PDFCreator pdf = new MDVUtility.PDFCreator(ref pdfDocument, stream_, false, ClientConfiguration.DecryptFrom64(MDVSession.Current.AppUserName), ClientConfiguration.DecryptFrom64(MDVSession.Current.AppUserName), "Procedure Findings");
                            pdf.Writer.PageEvent = new MDVision.Common.Utilities.MDVUtility.AddFooterHeader(ReportHeaderTable, true, null, footer);
                            pdf.Document.Open();
                            if (!IsReportHeaderApplied)
                            {
                                #region Patient/Provider Segment
                                string AccountNumber = dsProcedure.Tables[dsPatient.Patients.TableName].Rows[0]["AccountNumber"].ToString();
                                try
                                {
                                    #region "Facility & Lab"

                                    PdfPTable facilityTable = new PdfPTable(1);
                                    facilityTable.TotalWidth = 575f;
                                    facilityTable.SpacingBefore = 3f;
                                    facilityTable.SpacingAfter = 8f;
                                    facilityTable.LockedWidth = true;
                                    facilityTable.DefaultCell.Border = Rectangle.NO_BORDER;
                                    long facilityId = MDVUtility.ToInt64(dsProcedure.Tables[dsPatient.Patients.TableName].Rows[0][dsPatient.Patients.FacilityIdColumn.ColumnName]);
                                    facilityTable.AddCell(SetFacility(facilityId, patientNameFont, bodyFont));
                                    pdfDocument.Add(facilityTable);

                                    #endregion "Facility & Lab"
                                    LineSeparator separator = new LineSeparator(1f, 100f, new BaseColor(102, 178, 255), iTextSharp.text.Element.ALIGN_CENTER, -1);
                                    separator.Offset = 1;
                                    pdfDocument.Add(new Chunk(separator));
                                    pdfDocument.Add(Chunk.NEWLINE);

                                    PdfPTable ReportPatientProvider = new PdfPTable(2);
                                    ReportPatientProvider.TotalWidth = 575f;
                                    ReportPatientProvider.SpacingBefore = 3f;
                                    ReportPatientProvider.SpacingAfter = 8f;
                                    ReportPatientProvider.LockedWidth = true;
                                    ReportPatientProvider.DefaultCell.Border = Rectangle.NO_BORDER;
                                    ReportPatientProvider.AddCell(SetLabPatient(patientId, patientName, fontColour, bodyFont, componentHeadingFont, patientNameFont, AccountNumber, "Procedure"));
                                    ReportPatientProvider.AddCell(SetLabProvider(providerId, patientNameFont, bodyFont));
                                    pdfDocument.Add(ReportPatientProvider);

                                    pdfDocument.Add(new Chunk(separator));
                                    pdfDocument.Add(Chunk.NEWLINE);
                                }
                                catch (Exception ex)
                                {
                                    MDVLogger.BLLErrorLog("BLLAdminClinical::SetFacility, Patient or Provider Segment", ex);
                                }
                            }
                            #endregion

                            Paragraph req_Heading = new Paragraph("Procedure Report".ToString(), patientNameFont);
                            req_Heading.SpacingAfter = 10;
                            pdfDocument.Add(req_Heading);
                            #endregion
                            #region Procedure Information and Findings
                            // Start Append Procedure Information and Findings
                            foreach (DSProcedures.ProceduresRow dr in dsProcedure.Tables[dsProcedure.Procedures.TableName].Rows)
                            {
                                var lstmdlFindings = lstProcdureFindings.Where(x => x.ProcedureId == MDVUtility.ToInt64(dr[dsProcedure.Procedures.ProcedureIdColumn.ColumnName])).ToList();
                                if (lstmdlFindings.Count > 0)
                                {

                                    Paragraph order_Heading = new Paragraph("Procedure Performed \n".ToString(), componentHeadingFont);
                                    order_Heading.SpacingBefore = order_Heading.SpacingAfter = 5;
                                    pdfDocument.Add(order_Heading);

                                    PdfPTable orderTable = new PdfPTable(2);
                                    float[] widths = new float[] { 3f, 8f };
                                    orderTable.SetWidths(widths);
                                    orderTable.TotalWidth = 575f;
                                    orderTable.LockedWidth = true;
                                    orderTable.DefaultCell.Border = Rectangle.NO_BORDER;

                                    PdfPTable testTable = new PdfPTable(1);
                                    float[] widthss = new float[] { 12f };
                                    testTable.SetWidths(widthss);
                                    testTable.TotalWidth = 575f;
                                    testTable.LockedWidth = true;
                                    testTable.DefaultCell.Border = Rectangle.NO_BORDER;

                                    string cptCodeDesc = MDVUtility.ToStr(dr[dsProcedure.Procedures.CPTCodeColumn.ColumnName] + " " + dr[dsProcedure.Procedures.CPT_DESCRIPTIONColumn.ColumnName]);
                                    orderTable.AddCell(new Paragraph(HttpUtility.HtmlDecode(MDVUtility.ToStr(dr[dsProcedure.Procedures.StartDateColumn.ColumnName])), bodyFont));
                                    orderTable.AddCell(new Paragraph(HttpUtility.HtmlDecode(cptCodeDesc), bodyFont));

                                    pdfDocument.Add(orderTable);

                                    Paragraph order_Heading_Finding = new Paragraph("Findings \n".ToString(), componentHeadingFont);
                                    order_Heading_Finding.SpacingBefore = order_Heading_Finding.SpacingAfter = 5;
                                    pdfDocument.Add(order_Heading_Finding);
                                    testTable.AddCell(new Paragraph(cptCodeDesc, bodyFont));

                                    //Start 02-10-2017 Edit By Humaira Yousaf Bug# EMR-4853
                                    foreach (var item in lstmdlFindings.Where(f => !string.IsNullOrEmpty(f.Findings)))
                                    {
                                        //End 02-10-2017 Edit By Humaira Yousaf Bug# EMR-4853
                                        Phrase sysName = new Phrase();
                                        sysName.Add(new Chunk(item.SystemName + ": ", findingNameFont));
                                        sysName.Add(new Chunk(item.Findings, bodyFont));
                                        testTable.AddCell(sysName);
                                    }
                                    pdfDocument.Add(testTable);

                                }
                            }
                            #endregion

                            pdfDocument.Add(Chunk.NEWLINE);
                            pdfDocument.Add(Chunk.NEWLINE);
                            PdfPTable signTable = new PdfPTable(1);
                            signTable.TotalWidth = 575f;
                            signTable.LockedWidth = true;
                            signTable.DefaultCell.Border = Rectangle.NO_BORDER;
                            dsProcedure.Merge(new DALProvider().LoadProvider(providerId, string.Empty, string.Empty, string.Empty, string.Empty, string.Empty, string.Empty, string.Empty));
                            DataRow signRow = dsProcedure.Tables[dsProfile.Provider.TableName].Rows[0];
                            if (signRow[dsProfile.Provider.eSignatureColumn.ColumnName] as byte[] != null)
                            {
                                string signString = Convert.ToBase64String(signRow[dsProfile.Provider.eSignatureColumn.ColumnName] as byte[]);

                                Byte[] signBuffer = Convert.FromBase64String(signString);
                                var signStream = new MemoryStream(signBuffer);
                                iTextSharp.text.Image signImg = iTextSharp.text.Image.GetInstance(signBuffer, false);
                                signImg.ScaleAbsoluteHeight(150);
                                signImg.ScaleAbsoluteWidth(150);

                                PdfPCell signCell = new PdfPCell();
                                signCell.AddElement(signImg);
                                signCell.Border = Rectangle.NO_BORDER;
                                signCell.HorizontalAlignment = Element.ALIGN_LEFT;
                                signTable.AddCell(signCell);
                                pdfDocument.Add(signTable);
                            }

                            string modifiedDate = MDVUtility.ToDateTime(dsProcedure.Tables[dsProcedure.Procedures.TableName].Rows[0][dsProcedure.Procedures.ModifiedOnColumn.ColumnName]).ToLongDateString();

                            if (!string.IsNullOrEmpty(modifiedDate))
                            {
                                modifiedDate = modifiedDate + " at ";
                            }
                            string modifiedTime = MDVUtility.ToDateTime(dsProcedure.Tables[dsProcedure.Procedures.TableName].Rows[0][dsProcedure.Procedures.ModifiedOnColumn.ColumnName]).ToLongTimeString();

                            Paragraph signedByPara = new Paragraph("e-Signed By: " + MDVUtility.ToStr(dsProcedure.Tables[dsProcedure.Procedures.TableName].Rows[0][dsProcedure.Procedures.ModifiedByColumn.ColumnName]) + " on " + modifiedDate + modifiedTime, bodyFont);
                            signedByPara.Alignment = Element.ALIGN_LEFT;
                            pdfDocument.Add(signedByPara);

                            newByteArr = stream_.GetBuffer();
                            pdf.Document.Close();
                            pdf.Writer.Close();
                            pdfDocument.Close();

                            MemoryStream stream = new MemoryStream(stream_.ToArray());
                            PdfReader npdf = new PdfReader(stream);
                            MemoryStream outstream = new MemoryStream();
                            using (PdfStamper stamper = new PdfStamper(npdf, outstream, '\0', true))
                            {
                                stamper.Writer.CloseStream = false;
                                int PageCount = npdf.NumberOfPages;
                                for (int i = 1; i <= PageCount; i++)
                                {
                                    Paragraph para = new Paragraph(String.Format("Page {0}/{1}", i, PageCount), bodyFont);
                                    para.Add(setLabOrder_ResultFooter(pdfDocument));
                                    ColumnText.ShowTextAligned(stamper.GetOverContent(i), Element.ALIGN_CENTER, para, 555, 17, 0);
                                }
                            }
                            newByteArr = outstream.GetBuffer();
                        }
                    }
                }
                else
                    new DALProcedures().loadProcedureFindings(null, noteid, isFindingUpdate);
                return new BLObject<byte[]>(newByteArr);
            }
            catch (Exception ex)
            {
                MDVLogger.BLLErrorLog("BLLClinical::CreateProcedureReport", ex);
                return new BLObject<byte[]>(null, ex.Message);
            }
        }


        #endregion

