        public BLObject<DSRadiologyResult> InsertUpdateRadiologyResult(DSRadiologyResult ds)
        {
            try
            {
                ds = new DALRadiologyResult().InsertUpdateRadiologyResult(ds);
                return new BLObject<DSRadiologyResult>(ds);
            }
            catch (Exception ex)
            {
                MDVLogger.BLLErrorLog("BLLClinical::InsertUpdateRadiologyResult", ex);
                return new BLObject<DSRadiologyResult>(null, ex.Message);
            }
        }

        // Author:  Abid Ali
        // Created Date: 18/04/2016
        //OverView: Method to Delete Radiology Result
        public BLObject<string> DeleteRadiologyResult(string RadiologyResultId)
        {
            try
            {
                RadiologyResultId = new DALRadiologyResult().DeleteRadiologyResult(Convert.ToInt64(RadiologyResultId));
                return new BLObject<string>(RadiologyResultId);
            }
            catch (Exception ex)
            {
                MDVLogger.BLLErrorLog("BLLClinical::DeleteRadiologyResult", ex);
                return new BLObject<string>(null, ex.Message);
            }
        }

