        /// <summary>
        /// Module Name: previewRadiologyResult
        /// Author: Humaira Yousaf
        /// Created Date: 02-05-2016
        /// Description: Creates PDF to view Radiology Result
        /// </summary>
        /// <param name="radiologyOrderResultId" type="long">radiologyOrderResultId</param>
        /// <param name="radiologyOrderId" type="long">radiologyOrderId</param>
        /// <param name="patientId" type="long">patientId</param>
        public BLObject<byte[]> previewRadiologyResult(long radiologyOrderResultId, long radiologyOrderId, long patientId)
        {
            try
            {
                DSRadiologyResult dsRadiologyResult = new DSRadiologyResult();
                DSPatient dsPatient = new DSPatient();
                DSRadiologyOrder dsRadiologyOrder = new DSRadiologyOrder();
                //DSProfile dsProfile = new DSProfile();
                string patientName = "";


                #region Threading

                //Tasks
                SharedVariable sharedVariable = SharedVariable.GetSharedVariable();
                Task<DSRadiologyResult> LoadRadiologyResultTask;
                Task<DSPatient> FillPatientTask;
                Task<DSRadiologyResult> loadRadiologyResultDetailTask;
                Task<DSRadiologyOrder> LoadRadiologyOrderTask;
                Task<DSRadiologyOrder> LoadRadiologyOrderTestTask;
                Task<DSProfile> LoadPracticeTask;

                dsRadiologyResult = new DALRadiologyResult().LoadRadiologyResult(radiologyOrderResultId, radiologyOrderId, "", "", "", "", 0, "", "", "", patientId, "", "1");
                //LoadRadiologyResultTask = Task<DSRadiologyResult>.Factory.StartNew(() => new DALRadiologyResult(sharedVariable).LoadRadiologyResult(radiologyOrderResultId, radiologyOrderId, "", "", "", "", 0, "", "", "", patientId, "", "1", 0, 0, 0, false, sharedVariable));
                //LoadRadiologyResultTask.Wait();
                //dsRadiologyResult.Merge(LoadRadiologyResultTask.Result);
                long RadiologyOrderResultId = MDVUtility.ToInt64(dsRadiologyResult.RadiologyOrderResult.Rows[0][dsRadiologyResult.RadiologyOrderResult.RadiologyOrderResultIdColumn.ColumnName]);


                //FillPatientTask = Task<DSPatient>.Factory.StartNew(() => new DALPatient(sharedVariable).FillPatient(patientId, "", "", sharedVariable));
                //FillPatientTask.Wait();
                //dsRadiologyResult.Merge(FillPatientTask.Result);
                dsRadiologyResult.Merge(new DALPatient().FillPatient(patientId, "", ""));
                long practiceId = MDVUtility.ToInt64(dsRadiologyResult.Tables[dsPatient.Patients.TableName].Rows[0][dsPatient.Patients.PracticeIdColumn.ColumnName]);
                long providerId = MDVUtility.ToInt64(dsRadiologyResult.Tables[dsPatient.Patients.TableName].Rows[0][dsPatient.Patients.ProviderIdColumn.ColumnName]);
                //depend upon fill patient task to get practice id

                LoadPracticeTask = Task<DSProfile>.Factory.StartNew(() => new DALPractice(sharedVariable).LoadPractice(practiceId, string.Empty, string.Empty, string.Empty, string.Empty, string.Empty, 1, 1000, sharedVariable));
                loadRadiologyResultDetailTask = Task<DSRadiologyResult>.Factory.StartNew(() => new DALRadiologyResult(sharedVariable).loadRadiologyResultDetail(0, RadiologyOrderResultId, sharedVariable));
                LoadRadiologyOrderTask = Task<DSRadiologyOrder>.Factory.StartNew(() => new DALRadiologyOrder(sharedVariable).LoadRadiologyOrder(radiologyOrderId, patientId, 0, "", "", "", "", 0, "", "", "", 0, "", "", sharedVariable));
                LoadRadiologyOrderTestTask = Task<DSRadiologyOrder>.Factory.StartNew(() => new DALRadiologyOrder(sharedVariable).LoadRadiologyOrderTest(radiologyOrderId, 0, patientId, "", "", 0, sharedVariable));


                Task.WaitAll(LoadPracticeTask, loadRadiologyResultDetailTask, LoadRadiologyOrderTask, LoadRadiologyOrderTestTask);


                dsRadiologyResult.Merge(loadRadiologyResultDetailTask.Result);
                dsRadiologyResult.Merge(LoadRadiologyOrderTask.Result);
                dsRadiologyResult.Merge(LoadRadiologyOrderTestTask.Result);
                dsRadiologyResult.Merge(LoadPracticeTask.Result);
                #endregion



                //Start 14-05-2016 Edit By Humaira Yousaf Bug# EMR-1003
                /*
                                dsRadiologyResult = new DALRadiologyResult().LoadRadiologyResult(radiologyOrderResultId, radiologyOrderId, "", "", "", "", 0, "", "", "", patientId, "", "1");
                                long RadiologyOrderResultId = MDVUtility.ToInt64(dsRadiologyResult.RadiologyOrderResult.Rows[0][dsRadiologyResult.RadiologyOrderResult.RadiologyOrderResultIdColumn.ColumnName]);

                                //End 14-05-2016 Edit By Humaira Yousaf Bug# EMR-1003
                                dsRadiologyResult.Merge(new DALPatient().FillPatient(patientId, "", ""));
                                long practiceId = MDVUtility.ToInt64(dsRadiologyResult.Tables[dsPatient.Patients.TableName].Rows[0][dsPatient.Patients.PracticeIdColumn.ColumnName]);
                                long providerId = MDVUtility.ToInt64(dsRadiologyResult.Tables[dsPatient.Patients.TableName].Rows[0][dsPatient.Patients.ProviderIdColumn.ColumnName]);

                                dsRadiologyResult.Merge(new DALRadiologyResult().loadRadiologyResultDetail(0, RadiologyOrderResultId));
                                dsRadiologyResult.Merge(new DALRadiologyOrder().LoadRadiologyOrder(radiologyOrderId, patientId, 0, "", "", "", "", 0, "", "", "", 0));
                                dsRadiologyResult.Merge(new DALRadiologyOrder().LoadRadiologyOrderTest(radiologyOrderId, 0, patientId, "", ""));


                                dsRadiologyResult.Merge(new DALPractice().LoadPractice(practiceId, string.Empty, string.Empty, string.Empty, string.Empty, string.Empty));
                                */





                byte[] newByteArr = null;
                using (MemoryStream stream_ = new MemoryStream())
                {
                    bool IsFooterExist = false;
                    string FooterGeneratedBy = "";
                    PdfPTable ReportHeaderTable = new PdfPTable(2);
                    PdfPTable footer = new PdfPTable(1);
                    float bottomMargin = 22;
                    float topMargin = 20;
                    PdfPTable patientTable = new PdfPTable(2);
                    Document pdfDocument = new Document(PageSize.LETTER, 20, 20, topMargin, bottomMargin);
                    // Heading Font Style
                    var fontColour = new BaseColor(102, 178, 255);
                    iTextSharp.text.Font patientNameFont = FontFactory.GetFont("Arial", 12, iTextSharp.text.Font.BOLD, fontColour);
                    iTextSharp.text.Font bodyFont = FontFactory.GetFont("Arial", 10, iTextSharp.text.Font.NORMAL, iTextSharp.text.BaseColor.BLACK);
                    iTextSharp.text.Font componentHeadingFont = FontFactory.GetFont("Arial", 10, iTextSharp.text.Font.NORMAL, fontColour);
