            //End 08-04-2016 Edit By Humaira Yousaf Bug# EMR-577

        }

        /// <summary>
        /// Module Name: viewPdfRadiologyResult
        /// Author: Humaira Yousaf
        /// Created Date: 09-05-2016
        /// Description: Creates PDF to view Radiology Result
        /// </summary>
        /// <param name="radiologyResultId" type="long">radiologyResultId</param>
        /// <param name="radiologyOrderId" type="long">radiologyOrderId</param>
        /// <param name="patientId" type="long">patientId</param>
        public BLObject<byte[]> viewPdfRadiologyResult(long radiologyResultId, long radiologyOrderId, long patientId)
        {
            try
            {
                DSRadiologyResult dsRadiologyResult = new DSRadiologyResult();
                DSPatient dsPatient = new DSPatient();
                DSRadiologyOrder dsRadiologyOrder = new DSRadiologyOrder();
                DSProfile dsProfile = new DSProfile();



                dsRadiologyResult = new DALRadiologyResult().LoadRadiologyResult(radiologyResultId, radiologyOrderId, "", "", "", "", 0, "", "", "", patientId);
                dsRadiologyResult.Merge(new DALPatient().FillPatient(patientId, "", ""));
                Int64 resultId = dsRadiologyResult.RadiologyOrderResult.Rows.Count > 0 ? MDVUtility.ToInt64(dsRadiologyResult.RadiologyOrderResult.Rows[0][dsRadiologyResult.RadiologyOrderResult.RadiologyOrderResultIdColumn.ColumnName]) : 0;
                string resultStatus = dsRadiologyResult.RadiologyOrderResult.Rows.Count > 0 ? MDVUtility.ToStr(dsRadiologyResult.RadiologyOrderResult.Rows[0][dsRadiologyResult.RadiologyOrderResult.StatusColumn.ColumnName]) : string.Empty;
                dsRadiologyResult.Merge(new DALRadiologyResult().loadRadiologyResultDetail(0, resultId));
                dsRadiologyResult.Merge(new DALRadiologyOrder().LoadRadiologyOrder(radiologyOrderId, patientId, 0, "", "", "", "", 0, "", "", "", 0));
                dsRadiologyResult.Merge(new DALRadiologyOrder().LoadRadiologyOrderTest(radiologyOrderId, 0, 0, "", ""));
                long practiceId = MDVUtility.ToInt64(dsRadiologyResult.Tables[dsPatient.Patients.TableName].Rows[0][dsPatient.Patients.PracticeIdColumn.ColumnName]);
                dsRadiologyResult.Merge(new DALPractice().LoadPractice(practiceId, string.Empty, string.Empty, string.Empty, string.Empty, string.Empty));
                byte[] newByteArr = null;
                using (MemoryStream stream_ = new MemoryStream())
                {
                    Document pdfDocument = new Document(PageSize.LETTER, 20, 20, 20, 20);
                    // Heading Font Style
                    var fontColour = new BaseColor(102, 178, 255);
                    iTextSharp.text.Font patientNameFont = FontFactory.GetFont("Arial", 12, iTextSharp.text.Font.BOLD, fontColour);
                    iTextSharp.text.Font bodyFont = FontFactory.GetFont("Arial", 10, iTextSharp.text.Font.NORMAL, iTextSharp.text.BaseColor.BLACK);
                    iTextSharp.text.Font componentHeadingFont = FontFactory.GetFont("Arial", 10, iTextSharp.text.Font.NORMAL, fontColour);
                    iTextSharp.text.Font componentHeaderFont = FontFactory.GetFont("Arial", 10, iTextSharp.text.Font.NORMAL, iTextSharp.text.BaseColor.BLACK);
                    iTextSharp.text.Font componentGridHeaderFont = FontFactory.GetFont("Arial", 10, iTextSharp.text.Font.NORMAL, new BaseColor(102, 178, 255));
                    iTextSharp.text.Font tableHeaderFont = FontFactory.GetFont("Arial", 10, iTextSharp.text.Font.BOLD, iTextSharp.text.BaseColor.BLACK);

                    MDVUtility.PDFCreator pdf = new MDVUtility.PDFCreator(ref pdfDocument, stream_, false, ClientConfiguration.DecryptFrom64(MDVSession.Current.AppUserName), ClientConfiguration.DecryptFrom64(MDVSession.Current.AppUserName), "Result");
                    pdf.Document.Open();

                    #region Patient's Data

                    // Start Append Patient's Data
                    Paragraph faceSheet_Heading = new Paragraph("Patient Information".ToString(), bodyFont);
                    faceSheet_Heading.SpacingAfter = -12;
                    faceSheet_Heading.SpacingBefore = -5;
                    faceSheet_Heading.Alignment = Element.ALIGN_CENTER;
                    pdfDocument.Add(faceSheet_Heading);
                    pdfDocument.Add(Chunk.NEWLINE);

                    PdfPTable patientTable = new PdfPTable(2);
                    float[] widths = new float[] { 12f, 12f };
                    patientTable.TotalWidth = 575f;
                    patientTable.LockedWidth = true;

                    PdfPCell cellElement = new PdfPCell(new Phrase("Element Name", tableHeaderFont));
                    cellElement.BackgroundColor = BaseColor.BLUE;
                    cellElement.HorizontalAlignment = Element.ALIGN_CENTER;

                    PdfPCell cellData = new PdfPCell(new Phrase("Data", tableHeaderFont));
