        #region Consultation Order

        public BLObject<DSConsultationOrder> insertUpdateConsultationOrder(DSConsultationOrder ds, ConsultationOrderModel model, List<object> lstConsultationObjects)
        {
            IDBManager dbManager = ClientConfiguration.GetDBManager();
            IDBManager dbManagerAudit = ClientConfiguration.GetDBManager();
            DSDBAudit dsDBAudit = new DSDBAudit();
            try
            {
                DataTable dtTempConsultationOrder = null;
                DataTable dtTempConsultationOrderProblem = null;
                DataTable dtTempCurrConsultationOrderProblem = null;
                DataTable dtTempConsultationOrderTest = null;

                DSConsultationOrder dsCDS = new DSConsultationOrder();
                DSConsultationOrder dsCurrentOrderProblems = new DSConsultationOrder();
                DSConsultationOrder dsConsultationOrderProblem = new DSConsultationOrder();
                DSConsultationOrder dsConsultationOrderForTest = null;

                dtTempConsultationOrder = ds.ConsultationOrder.GetChanges();

                model.ConsultationOrderId = MDVUtility.ToStr(ds.Tables[ds.ConsultationOrder.TableName].Rows[0][ds.ConsultationOrder.ConsultationOrderIdColumn.ColumnName]);
                if (!string.IsNullOrWhiteSpace(model.ConsultationOrderId) && model.ConsultationOrderId != "-1")
                {
                    dsCurrentOrderProblems = new DALConsultationOrder().loadConsultationOrderProblems(0, Convert.ToInt32(model.ConsultationOrderId), 0);
                    dtTempConsultationOrderProblem = dsCurrentOrderProblems.ConsultationOrderProblem;

                    dsConsultationOrderForTest = ConsultationOrderTestList(MDVUtility.ToInt64(model.ConsultationOrderId), lstConsultationObjects, true);
                }
                try
                {
                    dbManager.BeginTransaction();
                    dsCDS = new DALConsultationOrder().insertUpdateConsultationOrder(ds, dbManager);

                    long insertedConsultationId = MDVUtility.ToInt64(ds.Tables[ds.ConsultationOrder.TableName].Rows[0][ds.ConsultationOrder.ConsultationOrderIdColumn.ColumnName]);

                    model.ConsultationOrderProblemList.ForEach(cc => cc.ConsultationOrderId = MDVUtility.ToStr(insertedConsultationId));
                    DeleteConsultationOrderProblems(MDVUtility.ToStr(insertedConsultationId), dbManager);

                    foreach (var m in model.ConsultationOrderProblemList)
                    {
                        DSConsultationOrder.ConsultationOrderProblemRow dr = dsConsultationOrderProblem.ConsultationOrderProblem.NewConsultationOrderProblemRow();
                        dr.ConsultationOrderId = MDVUtility.ToInt64(m.ConsultationOrderId);
                        dr.ProblemId = MDVUtility.ToInt32(m.ProblemId);
                        dr.Comments = string.Empty;
                        dr.IsActive = true;
                        dr.CreatedBy = MDVUtility.DecryptFrom64(MDVSession.Current.AppUserName);
                        dr.CreatedOn = DateTime.Now;
                        dr.ModifiedBy = MDVUtility.DecryptFrom64(MDVSession.Current.AppUserName);
                        dr.ModifiedOn = DateTime.Now;
                        dsConsultationOrderProblem.ConsultationOrderProblem.AddConsultationOrderProblemRow(dr);
                    }
                    dtTempCurrConsultationOrderProblem = dsConsultationOrderProblem.ConsultationOrderProblem.GetChanges();

                    InsertUpdateConsultationOrderProblems(dsConsultationOrderProblem, dbManager);

                    if (string.IsNullOrWhiteSpace(model.ConsultationOrderId) || model.ConsultationOrderId == "-1")
                    {
                        dsConsultationOrderForTest = ConsultationOrderTestList(insertedConsultationId, lstConsultationObjects, false);
                    }

                    dtTempConsultationOrderTest = dsConsultationOrderForTest.ConsultationOrderTest.GetChanges();

                    insertUpdateConsultationOrderTest(dsConsultationOrderForTest, dbManager);

                    dbManager.CommitTransaction();
                }
                catch (Exception exTrans)
                {
                    dbManager.RollBackTransaction();
                    throw exTrans;
                }

                dbManagerAudit.Open();

                if (dtTempConsultationOrder != null)
                {
                    dtTempConsultationOrder.Columns.Add("PrimaryKey");
                    for (int i = 0; i < ds.ConsultationOrder.Rows.Count; i++)
                    {
                        dtTempConsultationOrder.Rows[i]["PrimaryKey"] = ds.ConsultationOrder.Rows[i][ds.ConsultationOrder.ConsultationOrderIdColumn];
                    }
                    dsDBAudit = new DBActivityAudit().InsertDBAudit(dtTempConsultationOrder, dbManagerAudit, ds.ConsultationOrder.Rows[0][ds.ConsultationOrder.ConsultationOrderIdColumn].ToString(), null, ds.ConsultationOrder.Rows[0][ds.ConsultationOrder.ConsultationOrderIdColumn].ToString());
                    dsDBAudit.AcceptChanges();
                }

                if (dtTempConsultationOrderProblem != null)
                {
                    if (dsCurrentOrderProblems.ConsultationOrderProblem.Rows.Count > 0)
                    {
                        dsDBAudit = new DBActivityAudit().InsertDBAudit(dtTempConsultationOrderProblem, dbManagerAudit, dsCurrentOrderProblems.ConsultationOrderProblem.Rows[0].ToString(), null, dsCurrentOrderProblems.ConsultationOrderProblem.Rows[0][dsCurrentOrderProblems.ConsultationOrderProblem.ConsultationOrderIdColumn].ToString(), false, false, true);
                        dsDBAudit.AcceptChanges();
                    }
                }

                if (dtTempCurrConsultationOrderProblem != null)
                {
                    dtTempCurrConsultationOrderProblem.Columns.Add("PrimaryKey");
                    dtTempCurrConsultationOrderProblem.Columns.Add("PatientId");
                    for (int i = 0; i < dsConsultationOrderProblem.ConsultationOrderProblem.Rows.Count; i++)
                    {
                        dtTempCurrConsultationOrderProblem.Rows[i]["PrimaryKey"] = dsConsultationOrderProblem.ConsultationOrderProblem.Rows[i][dsConsultationOrderProblem.ConsultationOrderProblem.ConsultationOrderProblemIdColumn];
                        dtTempCurrConsultationOrderProblem.Rows[i]["PatientId"] = model.PatientId;
                    }


                    dsDBAudit = new DBActivityAudit().InsertDBAudit(dtTempCurrConsultationOrderProblem, dbManagerAudit, dsConsultationOrderProblem.ConsultationOrderProblem.Rows[0][dsConsultationOrderProblem.ConsultationOrderProblem.ConsultationOrderProblemIdColumn].ToString(), null, dsConsultationOrderProblem.ConsultationOrderProblem.Rows[0][dsConsultationOrderProblem.ConsultationOrderProblem.ConsultationOrderIdColumn].ToString());
                    dsDBAudit.AcceptChanges();
                }

                if (dtTempConsultationOrderTest != null)
                {
                    dtTempConsultationOrderTest.Columns.Add("PrimaryKey");
                    for (int i = 0; i < dsConsultationOrderForTest.ConsultationOrderTest.Rows.Count; i++)
                    {
                        dtTempConsultationOrderTest.Rows[i]["PrimaryKey"] = dsConsultationOrderForTest.ConsultationOrderTest.Rows[i][dsConsultationOrderForTest.ConsultationOrderTest.ConsultationOrderTestIdColumn];
                    }
                    dsDBAudit = new DBActivityAudit().InsertDBAudit(dtTempConsultationOrderTest, dbManagerAudit, dsConsultationOrderForTest.ConsultationOrderTest.Rows[0][dsConsultationOrderForTest.ConsultationOrderTest.ConsultationOrderTestIdColumn].ToString(), null, dsConsultationOrderForTest.ConsultationOrderTest.Rows[0][dsConsultationOrderForTest.ConsultationOrderTest.ConsultationOrderTestIdColumn].ToString());
                    dsDBAudit.AcceptChanges();
                }

                dbManagerAudit.Dispose();
                return new BLObject<DSConsultationOrder>(dsCDS);
            }
            catch (Exception ex)
            {
                MDVLogger.BLLErrorLog("BLLClinical::insertUpdateConsultationOrder", ex);
                //return new BLObject<DSConsultationOrder>(null, ex.Message);
                throw ex;
            }
        }

        public DSConsultationOrder ConsultationOrderTestList(Int64 ConsultationId, List<object> lstObjects, bool IsUpdate)
        {
            try
            {
                DSConsultationOrder dsConsultationOrder = new DSConsultationOrder();

                BLObject<DSConsultationOrder> objConsultationOrderTest = new BLObject<DSConsultationOrder>();
                if (IsUpdate)
                {
                    objConsultationOrderTest = LoadConsultationOrderTest(MDVUtility.ToInt64(ConsultationId), 0, 0, "1", "2000"); ;
                }
                else
                {
                    objConsultationOrderTest = new BLObject<DSConsultationOrder>(new DSConsultationOrder());
                }
                dsConsultationOrder = objConsultationOrderTest.Data;
                List<ConsultationOrderTestModel> lstConsultationOrder = lstObjects.OfType<ConsultationOrderTestModel>().ToList();

                int id = -1;

                foreach (ConsultationOrderTestModel CurrentModel in lstConsultationOrder)
                {
                    Int32 currentConsultationTestId = MDVUtility.ToInt32(CurrentModel.ConsultationOrderTestId);
                    currentConsultationTestId = currentConsultationTestId == 0 ? id-- : currentConsultationTestId;
                    DSConsultationOrder.ConsultationOrderTestRow RowConsultationOrderTest = null;
                    DSConsultationOrder.ConsultationOrderTestRow[] arrConsultationOrderTestRows = (DSConsultationOrder.ConsultationOrderTestRow[])dsConsultationOrder.ConsultationOrderTest.Select(dsConsultationOrder.ConsultationOrderTest.ConsultationOrderTestIdColumn.ColumnName + "=" + CurrentModel.ConsultationOrderTestId);

                    if (arrConsultationOrderTestRows.Length > 0)
                    {
                        RowConsultationOrderTest = arrConsultationOrderTestRows[0];
                    }
                    else
                    {
                        RowConsultationOrderTest = dsConsultationOrder.ConsultationOrderTest.NewConsultationOrderTestRow();
                        RowConsultationOrderTest.ConsultationOrderTestId = currentConsultationTestId;
                    }
                    if (RowConsultationOrderTest != null)
                    {
                        RowConsultationOrderTest.ConsultationOrderId = ConsultationId;


                        if (!string.IsNullOrEmpty(CurrentModel.dtpConsultationDate))
                        {
                            RowConsultationOrderTest[dsConsultationOrder.ConsultationOrderTest.TestDateColumn] = MDVUtility.ToDateTime(CurrentModel.dtpConsultationDate);
                        }
                        else
                        {
                            RowConsultationOrderTest[dsConsultationOrder.ConsultationOrderTest.TestDateColumn] = DBNull.Value;
                        }

                        if (!string.IsNullOrEmpty(CurrentModel.tpConsultationTime))
                        {
                            RowConsultationOrderTest[dsConsultationOrder.ConsultationOrderTest.TestTimeColumn] = MDVUtility.ToStr(CurrentModel.tpConsultationTime);
                        }
                        else
                        {
                            RowConsultationOrderTest[dsConsultationOrder.ConsultationOrderTest.TestTimeColumn] = DBNull.Value;
                        }

                        if (!string.IsNullOrEmpty(CurrentModel.CPTCode))
                        {
                            RowConsultationOrderTest[dsConsultationOrder.ConsultationOrderTest.CPTCodeColumn] = MDVUtility.ToStr(CurrentModel.CPTCode);

                        }
                        else
                        {
                            RowConsultationOrderTest[dsConsultationOrder.ConsultationOrderTest.CPTCodeColumn] = DBNull.Value;
                        }

                        if (!string.IsNullOrEmpty(CurrentModel.CPTDescription))
                        {
                            RowConsultationOrderTest[dsConsultationOrder.ConsultationOrderTest.CPTCodeDescriptionColumn] = MDVUtility.ToStr(CurrentModel.CPTDescription);

                        }
                        else
                        {
                            RowConsultationOrderTest[dsConsultationOrder.ConsultationOrderTest.CPTCodeDescriptionColumn] = DBNull.Value;
                        }
                        if (!string.IsNullOrEmpty(CurrentModel.CPTSNOMEDCodeId))
                        {
                            RowConsultationOrderTest[dsConsultationOrder.ConsultationOrderTest.CPTSNOMEDIDColumn] = MDVUtility.ToStr(CurrentModel.CPTSNOMEDCodeId);

                        }
                        else
                        {
                            RowConsultationOrderTest[dsConsultationOrder.ConsultationOrderTest.CPTSNOMEDIDColumn] = DBNull.Value;
                        }

                        if (!string.IsNullOrEmpty(CurrentModel.CPTSNOMEDDescription))
                        {
                            RowConsultationOrderTest[dsConsultationOrder.ConsultationOrderTest.CPTSNOMEDDescriptionColumn] = MDVUtility.ToStr(CurrentModel.CPTSNOMEDDescription);

                        }
                        else
                        {
                            RowConsultationOrderTest[dsConsultationOrder.ConsultationOrderTest.CPTSNOMEDDescriptionColumn] = DBNull.Value;
                        }
                        if (!string.IsNullOrEmpty(CurrentModel.Urgency))
                        {
                            RowConsultationOrderTest[dsConsultationOrder.ConsultationOrderTest.UrgencyIdColumn] = MDVUtility.ToInt32(CurrentModel.Urgency);

                        }
                        else
                        {
                            RowConsultationOrderTest[dsConsultationOrder.ConsultationOrderTest.UrgencyIdColumn] = DBNull.Value;
                        }
                        RowConsultationOrderTest.IsActive = true;
                        RowConsultationOrderTest.CreatedBy = MDVUtility.DecryptFrom64(MDVSession.Current.AppUserName);
                        RowConsultationOrderTest.CreatedOn = DateTime.Now;
                        RowConsultationOrderTest.ModifiedBy = MDVUtility.DecryptFrom64(MDVSession.Current.AppUserName);
                        RowConsultationOrderTest.ModifiedOn = DateTime.Now;

                        if (arrConsultationOrderTestRows.Length < 1)
                        {
                            dsConsultationOrder.ConsultationOrderTest.AddConsultationOrderTestRow(RowConsultationOrderTest);
                        }
                    }
                }
                return dsConsultationOrder;
            }
            catch (Exception ex)
            {
                MDVLogger.BLLErrorLog("BLLClinical::ConsultationOrderTestList", ex);
                throw ex;
            }
        }

