        public BLObject<DSProcedureOrder> InsertUpdateProcedureOrder(DSProcedureOrder ds, ProcedureOrderModel model, List<object> lstProcedureObjects)
        {
            string response = string.Empty;
            IDBManager dbManager = ClientConfiguration.GetDBManager();
            IDBManager dbManagerAudit = ClientConfiguration.GetDBManager();
            DSDBAudit dsDBAudit = new DSDBAudit();
            string patientId = string.Empty;
            try
            {
                DataTable dtTempProcedureOrderProblem = null;
                DSProcedureOrder dsCurrentOrderProblems = null;
                DSProcedureOrder dsProcedureOrderLoad = new DSProcedureOrder();
                DataTable dtTempCurrentProcedureOrderProblem = null;
                DataTable dtTempProcedureOrderTest = null;
                DSProcedureOrder dsProcedureOrderForTest = null;

                DSProcedureOrder dsProcedureOrder = new DSProcedureOrder();
                // Get changes for audit
                DataTable dtTempProcedureOrder = ds.ProcedureOrder.GetChanges();

                try
                {
                    // Load data for audit
                    if (!string.IsNullOrWhiteSpace(model.ProcedureOrderId) && model.ProcedureOrderId != "-1")
                    {
                        // Load problems for audit
                        dsCurrentOrderProblems = new DALProcedureOrder().loadProcedureOrderProblems(0, Convert.ToInt32(model.ProcedureOrderId), 0);
                        dtTempProcedureOrderProblem = dsCurrentOrderProblems.ProcedureOrderProblem;
                        // Load odrer tests for audit
                        dsProcedureOrderForTest = ProcedureOrderTestList(MDVUtility.ToInt64(model.ProcedureOrderId), lstProcedureObjects, true);
                    }

                    dbManager.BeginTransaction();

                    // Save Procedure Order
                    ds = new DALProcedureOrder().ProcedureOrderInsertUpdate(ds, dbManager);

                    Int64 procedureOrderId = MDVUtility.ToInt64(ds.Tables[ds.ProcedureOrder.TableName].Rows[0][ds.ProcedureOrder.ProcedureOrderIdColumn.ColumnName]);
                    patientId = MDVUtility.ToStr(ds.Tables[ds.ProcedureOrder.TableName].Rows[0][ds.ProcedureOrder.PatientIdColumn.ColumnName]);

                    model.ProcedureOrderProblemList.ForEach(cc => cc.ProcedureOrderId = MDVUtility.ToStr(procedureOrderId));

                    // Delete Procedure Order Problems
                    DeleteProcedureOrderProblems(MDVUtility.ToStr(procedureOrderId), dbManager);

                    foreach (var m in model.ProcedureOrderProblemList)
                    {
                        DSProcedureOrder.ProcedureOrderProblemRow dr = dsProcedureOrder.ProcedureOrderProblem.NewProcedureOrderProblemRow();
                        dr.ProcedureOrderId = MDVUtility.ToInt64(m.ProcedureOrderId);
                        dr.ProblemId = MDVUtility.ToInt32(m.ProblemId);
                        dr.Comments = string.Empty;
                        dr.IsActive = true;
                        dr.CreatedBy = MDVUtility.DecryptFrom64(MDVSession.Current.AppUserName);
                        dr.CreatedOn = DateTime.Now;
                        dr.ModifiedBy = MDVUtility.DecryptFrom64(MDVSession.Current.AppUserName);
                        dr.ModifiedOn = DateTime.Now;
                        dsProcedureOrder.ProcedureOrderProblem.AddProcedureOrderProblemRow(dr);
                    }
                    // Get changes for audit
                    dtTempCurrentProcedureOrderProblem = ds.ProcedureOrderProblem.GetChanges();

                    // Save Procedure Order Problems
                    BLObject<DSProcedureOrder> obj = InsertUpdateProcedureOrderProblems(dsProcedureOrder, dbManager);
                    if (string.IsNullOrWhiteSpace(model.ProcedureOrderId) || model.ProcedureOrderId == "-1")
                    {
                        dsProcedureOrderForTest = ProcedureOrderTestList(procedureOrderId, lstProcedureObjects, false);
                    }
                    dtTempProcedureOrderTest = dsProcedureOrderForTest.ProcedureOrderTest.GetChanges();
                    // Save or Update Procedure Order tests
                    BLObject<DSProcedureOrder> objInsertedProcedureTest = insertUpdateProcedureOrderTest(dsProcedureOrderForTest, dbManager);

                    dbManager.CommitTransaction();
                }
                catch (Exception extran)
                {
                    MDVLogger.BLLErrorLog("BLLClinical::InsertUpdateProcedureOrder", extran);
                    dbManager.RollBackTransaction();
                    throw extran;
                }

                dbManagerAudit.Open();
                if (dtTempProcedureOrder != null)
                {
                    dsDBAudit = new DBActivityAudit().InsertDBAudit(dtTempProcedureOrder, dbManagerAudit, ds.ProcedureOrder.Rows[0][ds.ProcedureOrder.ProcedureOrderIdColumn].ToString(), null, ds.ProcedureOrder.Rows[0][ds.ProcedureOrder.ProcedureOrderIdColumn].ToString());
                    dsDBAudit.AcceptChanges();
                }

                if (dtTempProcedureOrderProblem != null && dsCurrentOrderProblems != null)
                {
                    if (dsCurrentOrderProblems.ProcedureOrderProblem.Rows.Count > 0)
                    {
                        dsDBAudit = new DBActivityAudit().InsertDBAudit(dtTempProcedureOrderProblem, dbManagerAudit, dsCurrentOrderProblems.ProcedureOrderProblem.Rows[0].ToString(), null, dsCurrentOrderProblems.ProcedureOrderProblem.Rows[0][dsCurrentOrderProblems.ProcedureOrderProblem.ProcedureOrderIdColumn].ToString(), false, false, true, patientId);
                        dsDBAudit.AcceptChanges();
                    }
                }

                if (dtTempCurrentProcedureOrderProblem != null)
                {
                    dtTempCurrentProcedureOrderProblem.Columns.Add("PrimaryKey");
                    for (int i = 0; i < ds.ProcedureOrderProblem.Rows.Count; i++)
                    {
                        dtTempCurrentProcedureOrderProblem.Rows[i]["PrimaryKey"] = dsProcedureOrder.ProcedureOrderProblem.Rows[i][dsProcedureOrder.ProcedureOrderProblem.ProcedureOrderProblemIdColumn];
                    }

                    dsDBAudit = new DBActivityAudit().InsertDBAudit(dtTempCurrentProcedureOrderProblem, dbManager, dsProcedureOrder.ProcedureOrderProblem.Rows[0][dsProcedureOrder.ProcedureOrderProblem.ProcedureOrderProblemIdColumn].ToString(), null, dsProcedureOrder.ProcedureOrderProblem.Rows[0][dsProcedureOrder.ProcedureOrderProblem.ProcedureOrderIdColumn].ToString(), false, false, false, patientId);
                    dsDBAudit.AcceptChanges();
                }

                if (dtTempProcedureOrderTest != null)
                {
                    dtTempProcedureOrderTest.Columns.Add("PrimaryKey");
                    for (int i = 0; i < dsProcedureOrderForTest.ProcedureOrderTest.Rows.Count; i++)
                    {
                        dtTempProcedureOrderTest.Rows[i]["PrimaryKey"] = dsProcedureOrderForTest.ProcedureOrderTest.Rows[i][dsProcedureOrderForTest.ProcedureOrderTest.ProcedureOrderTestIdColumn];
                    }
                    dsDBAudit = new DBActivityAudit().InsertDBAudit(dtTempProcedureOrderTest, dbManagerAudit, dsProcedureOrderForTest.ProcedureOrderTest.Rows[0][dsProcedureOrderForTest.ProcedureOrderTest.ProcedureOrderTestIdColumn].ToString(), null, dsProcedureOrderForTest.ProcedureOrderTest.Rows[0][dsProcedureOrderForTest.ProcedureOrderTest.ProcedureOrderIdColumn].ToString(), false, false, false, patientId);
                    dsDBAudit.AcceptChanges();
                }
                dbManagerAudit.Dispose();
                return new BLObject<DSProcedureOrder>(ds);
            }
            catch (Exception ex)
            {
                MDVLogger.BLLErrorLog("BLLClinical::InsertUpdateProcedureOrder", ex);
                dbManagerAudit.Dispose();
                return new BLObject<DSProcedureOrder>(null, ex.Message);
            }
        }

        public DSProcedureOrder ProcedureOrderTestList(Int64 ProcedureId, List<object> lstObjects, bool IsUpdate)
        {
            try
            {
                DSProcedureOrder dsProcedureOrder = new DSProcedureOrder();

                BLObject<DSProcedureOrder> objProcedureOrderTest = new BLObject<DSProcedureOrder>();
                if (IsUpdate)
                {
                    objProcedureOrderTest = LoadProcedureOrderTest(ProcedureId, 0, 0, "1", "2000");
                }
                else
                {
                    objProcedureOrderTest = new BLObject<DSProcedureOrder>(new DSProcedureOrder());
                }
                dsProcedureOrder = objProcedureOrderTest.Data;
                //dsProcedureOrder = objProcedureOrder.Data;
                List<ProcedureOrderTestModel> lstProcedureOrder = lstObjects.OfType<ProcedureOrderTestModel>().ToList();

                int id = -1;

                foreach (ProcedureOrderTestModel CurrentModel in lstProcedureOrder)
                {
                    Int32 currentProcedureTestId = MDVUtility.ToInt32(CurrentModel.ProcedureOrderTestId);
                    currentProcedureTestId = currentProcedureTestId == 0 ? id-- : currentProcedureTestId;

                    DSProcedureOrder.ProcedureOrderTestRow RowProcedureOrderTest = null;
                    DSProcedureOrder.ProcedureOrderTestRow[] arrProcedureOrderTestRows = (DSProcedureOrder.ProcedureOrderTestRow[])dsProcedureOrder.ProcedureOrderTest.Select(dsProcedureOrder.ProcedureOrderTest.ProcedureOrderTestIdColumn.ColumnName + "=" + CurrentModel.ProcedureOrderTestId);

                    if (arrProcedureOrderTestRows.Length > 0)
                    {
                        RowProcedureOrderTest = arrProcedureOrderTestRows[0];
                    }
                    else
                    {
                        RowProcedureOrderTest = dsProcedureOrder.ProcedureOrderTest.NewProcedureOrderTestRow();
                        RowProcedureOrderTest.ProcedureOrderTestId = currentProcedureTestId;
                    }
                    if (RowProcedureOrderTest != null)
                    {
                        RowProcedureOrderTest.ProcedureOrderId = ProcedureId;


                        if (!string.IsNullOrEmpty(CurrentModel.dtpProcedureDate))
                        {
                            RowProcedureOrderTest[dsProcedureOrder.ProcedureOrderTest.TestDateColumn] = MDVUtility.ToDateTime(CurrentModel.dtpProcedureDate);
                        }
                        else
                        {
                            RowProcedureOrderTest[dsProcedureOrder.ProcedureOrderTest.TestDateColumn] = DBNull.Value;
                        }

                        if (!string.IsNullOrEmpty(CurrentModel.tpProcedureTime))
                        {
                            RowProcedureOrderTest[dsProcedureOrder.ProcedureOrderTest.TestTimeColumn] = MDVUtility.ToStr(CurrentModel.tpProcedureTime);
                        }
                        else
                        {
                            RowProcedureOrderTest[dsProcedureOrder.ProcedureOrderTest.TestTimeColumn] = DBNull.Value;
                        }

                        if (!string.IsNullOrEmpty(CurrentModel.CPTCode))
                        {
                            RowProcedureOrderTest[dsProcedureOrder.ProcedureOrderTest.CPTCodeColumn] = MDVUtility.ToStr(CurrentModel.CPTCode);

                        }
                        else
                        {
                            RowProcedureOrderTest[dsProcedureOrder.ProcedureOrderTest.CPTCodeColumn] = DBNull.Value;
                        }

                        if (!string.IsNullOrEmpty(CurrentModel.CPTDescription))
                        {
                            RowProcedureOrderTest[dsProcedureOrder.ProcedureOrderTest.CPTCodeDescriptionColumn] = MDVUtility.ToStr(CurrentModel.CPTDescription);

                        }
                        else
                        {
                            RowProcedureOrderTest[dsProcedureOrder.ProcedureOrderTest.CPTCodeDescriptionColumn] = DBNull.Value;
                        }

                        if (!string.IsNullOrEmpty(CurrentModel.CPTSNOMEDCodeId))
                        {
                            RowProcedureOrderTest[dsProcedureOrder.ProcedureOrderTest.CPTSNOMEDIDColumn] = MDVUtility.ToStr(CurrentModel.CPTSNOMEDCodeId);

                        }
                        else
                        {
                            RowProcedureOrderTest[dsProcedureOrder.ProcedureOrderTest.CPTSNOMEDIDColumn] = DBNull.Value;
                        }

                        if (!string.IsNullOrEmpty(CurrentModel.CPTSNOMEDDescription))
                        {
                            RowProcedureOrderTest[dsProcedureOrder.ProcedureOrderTest.CPTSNOMEDDescriptionColumn] = MDVUtility.ToStr(CurrentModel.CPTSNOMEDDescription);

                        }
                        else
                        {
                            RowProcedureOrderTest[dsProcedureOrder.ProcedureOrderTest.CPTSNOMEDDescriptionColumn] = DBNull.Value;
                        }

                        if (!string.IsNullOrEmpty(CurrentModel.Urgency))
                        {
                            RowProcedureOrderTest[dsProcedureOrder.ProcedureOrderTest.UrgencyIdColumn] = MDVUtility.ToInt32(CurrentModel.Urgency);

                        }
                        else
                        {
                            RowProcedureOrderTest[dsProcedureOrder.ProcedureOrderTest.UrgencyIdColumn] = DBNull.Value;
                        }
                        RowProcedureOrderTest.IsActive = true;
                        RowProcedureOrderTest.CreatedBy = MDVUtility.DecryptFrom64(MDVSession.Current.AppUserName);
                        RowProcedureOrderTest.CreatedOn = DateTime.Now;
                        RowProcedureOrderTest.ModifiedBy = MDVUtility.DecryptFrom64(MDVSession.Current.AppUserName);
                        RowProcedureOrderTest.ModifiedOn = DateTime.Now;
                        //Start 05-04-2016 Humaira Yousaf for comments
                        RowProcedureOrderTest.Comments = CurrentModel.Comments;
                        //End 05-04-2016 Humaira Yousaf for comments

                        if (arrProcedureOrderTestRows.Length < 1)
                        {
                            dsProcedureOrder.ProcedureOrderTest.AddProcedureOrderTestRow(RowProcedureOrderTest);
                        }
                        //dsProcedureOrder.ProcedureOrderTest.AddProcedureOrderTestRow(RowProcedureOrderTest);

                    }
                }

                //#region Database Insertion/Updation

                //BLObject<DSProcedureOrder> objInsertedProcedureTest = insertUpdateProcedureOrderTest(dsProcedureOrder,dbManager);
                return dsProcedureOrder;
            }
            catch (Exception ex)
            {
                MDVLogger.BLLErrorLog("BLLClinical::ProcedureOrderTestInsertUpdate", ex);
                throw ex;
            }
        }


