        /// <summary>
        /// Module Name: previewProcedureOrder
        /// Author: Humaira Yousaf
        /// Created Date: 22-03-2016
        /// Description: Creates PDF to view Procedure Order
        /// </summary>
        /// <param name="procedureId" type="long">procedureId</param>
        /// <param name="PatientId" type="long">PatientId</param>



        public BLObject<byte[]> previewProcedureOrder(long procedureId, long PatientId, bool isFindingUpdated = false, long notesId = 0)
        {
            try
            {
                //Start 04-05-2016 Humaira Yousaf for formatting and other changes
                DSProcedureOrder dsProcedureOrder = new DSProcedureOrder();
                DSPatient dsPatient = new DSPatient();
                DSProfile dsProfile = new DSProfile();

                //Start 14-05-2016 Edit By Humaira Yousaf Bug# EMR-1003
                dsProcedureOrder = new DALProcedureOrder().loadProcedureOrder(procedureId, PatientId, "", "", 0, "", "", "", 1, 1000, "0", "1");
                dsProcedureOrder.Merge(new DALPatient().FillPatient(PatientId, "", ""));
                dsProcedureOrder.Merge(new DALProcedureOrder().loadProcedureOrderProblems(0, procedureId, PatientId));
                dsProcedureOrder.Merge(new DALProcedureOrder().LoadProcedureOrderTest(procedureId, 0, PatientId, "", ""));
                long practiceId = MDVUtility.ToInt64(dsProcedureOrder.Tables[dsPatient.Patients.TableName].Rows[0][dsPatient.Patients.PracticeIdColumn.ColumnName]);
                long providerId = MDVUtility.ToInt64(dsProcedureOrder.ProcedureOrder.Rows[0][dsProcedureOrder.ProcedureOrder.ProviderIdColumn.ColumnName]);
                dsProcedureOrder.Merge(new DALPractice().LoadPractice(practiceId, string.Empty, string.Empty, string.Empty, string.Empty, string.Empty));
                long facilityId = MDVUtility.ToInt64(dsProcedureOrder.Tables[dsPatient.Patients.TableName].Rows[0][dsPatient.Patients.FacilityIdColumn.ColumnName]);
                dsProcedureOrder.Merge(new DALProvider().LoadProvider(providerId, string.Empty, string.Empty, string.Empty, string.Empty, string.Empty, string.Empty, string.Empty));

                string patientName = "";
                //long providerId = MDVUtility.ToInt64(null);


                DSReportHeader.ReportHeaderTagsDataTable dtReportHeaderTags;

                bool IsReportHeaderApplied = false;
                var dsReportHeader = new MDVision.DataAccess.DAL.ReportHeader.DALReportHeader().getReportHeaderTagsValue(PatientId, 0, -1, "Others");
                IsReportHeaderApplied = false;//dsReportHeader.ReportHeaderTags.Count > 0; // No report header will be displayed now
                dtReportHeaderTags = dsReportHeader.ReportHeaderTags;
                if (IsReportHeaderApplied &&
                     (
                            !string.IsNullOrEmpty(dsReportHeader.ReportHeaderTags[0]["PatientText"].ToString()) ||
                            !string.IsNullOrEmpty(dsReportHeader.ReportHeaderTags[0]["ProviderText"].ToString()) ||
                            !string.IsNullOrEmpty(dsReportHeader.ReportHeaderTags[0]["PracticeText"].ToString()) ||
                            !string.IsNullOrEmpty(dsReportHeader.ReportHeaderTags[0]["HeaderLogo"].ToString())
                            )
                    )
                {
                    IsReportHeaderApplied = true;
                }
                else
                {
                    IsReportHeaderApplied = false;
                }
                // return new BLObject<DSReportHeader>(dsReportHeader);

                byte[] newByteArr = null;
                using (MemoryStream stream_ = new MemoryStream())
                {
                    bool IsFooterExist = false;
                    string FooterGeneratedBy = "";
                    PdfPTable ReportHeaderTable = new PdfPTable(2);
                    PdfPTable footer = new PdfPTable(1);
                    float bottomMargin = 22;
                    float topMargin = 20;
                    PdfPTable patientTable = new PdfPTable(2);
                    Document pdfDocument = new Document(PageSize.LETTER, 20, 20, topMargin, bottomMargin);

                    // Heading Font Style
                    var fontColour = new BaseColor(102, 178, 255);
                    iTextSharp.text.Font patientNameFont = FontFactory.GetFont("Arial", 12, iTextSharp.text.Font.BOLD, fontColour);
                    iTextSharp.text.Font bodyFont = FontFactory.GetFont("Arial", 10, iTextSharp.text.Font.NORMAL, iTextSharp.text.BaseColor.BLACK);
                    iTextSharp.text.Font componentHeadingFont = FontFactory.GetFont("Arial", 10, iTextSharp.text.Font.NORMAL, fontColour);
                    iTextSharp.text.Font componentHeaderFont = FontFactory.GetFont("Arial", 9.9f, iTextSharp.text.Font.BOLD, iTextSharp.text.BaseColor.BLACK);
                    iTextSharp.text.Font gridbodyFont = FontFactory.GetFont("Arial", 10, iTextSharp.text.Font.BOLD, iTextSharp.text.BaseColor.BLACK);
                    iTextSharp.text.Font orderHeadingFont = FontFactory.GetFont("Arial", 12, iTextSharp.text.Font.BOLD, new BaseColor(72, 133, 209));
                    iTextSharp.text.Font componentHeadingFontN = FontFactory.GetFont("Arial", 10, iTextSharp.text.Font.BOLD, fontColour);
                    iTextSharp.text.Font findingNameFont = FontFactory.GetFont("Arial", 10, iTextSharp.text.Font.BOLD, new BaseColor(111, 173, 66));

                    if (IsReportHeaderApplied)
                    {
                        DSReportHeader.ReportHeaderTagsRow drReportHeader = (DSReportHeader.ReportHeaderTagsRow)dtReportHeaderTags.Rows[0];
                        #region Report Header

                        try
