                            facilityTable.AddCell(SetFacility(facilityId, patientNameFont, bodyFont));
                            pdfDocument.Add(facilityTable);

                            #endregion "Facility & Lab"
                            LineSeparator separator = new LineSeparator(1f, 100f, new BaseColor(102, 178, 255), iTextSharp.text.Element.ALIGN_CENTER, -1);
                            separator.Offset = 1;
                            pdfDocument.Add(new Chunk(separator));
                            pdfDocument.Add(Chunk.NEWLINE);
                            PdfPTable ReportPatientProvider = new PdfPTable(2);
                            ReportPatientProvider.TotalWidth = 575f;
                            ReportPatientProvider.SpacingBefore = 3f;
                            ReportPatientProvider.SpacingAfter = 8f;
                            ReportPatientProvider.LockedWidth = true;
                            ReportPatientProvider.DefaultCell.Border = Rectangle.NO_BORDER;

                            ReportPatientProvider.AddCell(SetLabPatient(PatientId, patientName, fontColour, bodyFont, componentHeadingFont, patientNameFont, AccountNumber));
                            ReportPatientProvider.AddCell(SetLabProvider(providerId, patientNameFont, bodyFont));
                            pdfDocument.Add(ReportPatientProvider);
                            pdfDocument.Add(new Chunk(separator));
                            pdfDocument.Add(Chunk.NEWLINE);
                        }
                        catch (Exception ex)
                        {
                            MDVLogger.BLLErrorLog("BLLAdminClinical::LabOrderPreview, Patient or Provider Segment", ex);
                        }

                    }
                    #endregion

                    Paragraph faceSheet_Heading = new Paragraph("Procedure Order Requisition".ToString(), patientNameFont);
                    //End 28-03-2016 Edit By Humaira Yousaf Bug# EMR-576
                    LineSeparator line = new LineSeparator(1f, 100f, fontColour, iTextSharp.text.Element.ALIGN_CENTER, -1);
                    line.Offset = 1;
                    pdfDocument.Add(new Chunk(line));
                    faceSheet_Heading.SpacingAfter = -12;
                    faceSheet_Heading.SpacingBefore = -5;
                    pdfDocument.Add(faceSheet_Heading);
                    Chunk c = new Chunk(line);

                    //pdfDocument.Add(new Chunk(line));
                    pdfDocument.Add(Chunk.NEWLINE);
                    #region Order Information

                    // Start Append Order Information
                    if (dsProcedureOrder.Tables[dsProcedureOrder.ProcedureOrder.TableName].Rows.Count > 0)
                    {
                        Paragraph order_Heading = new Paragraph("Order Information \n".ToString(), componentHeadingFont);
                        order_Heading.SpacingBefore = order_Heading.SpacingAfter = 5;

                        pdfDocument.Add(order_Heading);


                        PdfPTable orderTable = new PdfPTable(4);
                        float[] widths = new float[] { 8f, 8f, 8f, 8f };
                        orderTable.SetWidths(widths);
                        orderTable.TotalWidth = 575f;
                        orderTable.LockedWidth = true;
                        orderTable.DefaultCell.Border = Rectangle.NO_BORDER;

                        foreach (DSProcedureOrder.ProcedureOrderRow dr in dsProcedureOrder.Tables[dsProcedureOrder.ProcedureOrder.TableName].Rows)
                        {

                            orderTable.AddCell(new Paragraph("Provider:", componentHeaderFont));
                            orderTable.AddCell(new Paragraph(HttpUtility.HtmlDecode(MDVUtility.ToStr(dr[dsProcedureOrder.ProcedureOrder.ProviderNameColumn.ColumnName])), bodyFont));
                            orderTable.AddCell(new Paragraph("Date & Time:", componentHeaderFont));
                            orderTable.AddCell(new Paragraph(MDVUtility.ToDateTime(dr[dsProcedureOrder.ProcedureOrder.OrderDateColumn.ColumnName]).ToShortDateString() + ' ' + dr[dsProcedureOrder.ProcedureOrder.OrderTimeColumn.ColumnName].ToString(), bodyFont));
                            orderTable.AddCell(new Paragraph("Assignee:", componentHeaderFont));
                            orderTable.AddCell(new Paragraph(HttpUtility.HtmlDecode(MDVUtility.ToStr(dr[dsProcedureOrder.ProcedureOrder.AssigneeNameColumn.ColumnName])), bodyFont));
                            orderTable.AddCell(new Paragraph("Order Number:", componentHeaderFont));
                            orderTable.AddCell(new Paragraph(dr[dsProcedureOrder.ProcedureOrder.OrderNoColumn.ColumnName].ToString(), bodyFont));
                        }
                        pdfDocument.Add(orderTable);
                    }
                    else
                    {

                        Paragraph order_Heading = new Paragraph("Order Information \n".ToString(), componentHeadingFont);
                        order_Heading.SpacingBefore = order_Heading.SpacingAfter = 5;
                        pdfDocument.Add(order_Heading);

                        PdfPTable orderTable = new PdfPTable(5);
                        float[] widths = new float[] { 1f, 8f, 8f, 8f, 8f };
                        orderTable.SetWidths(widths);
                        orderTable.TotalWidth = 575f;
                        orderTable.LockedWidth = true;
                        orderTable.DefaultCell.Border = Rectangle.NO_BORDER;
                        orderTable.AddCell(string.Empty);
                        orderTable.AddCell(new Paragraph("Provider", componentHeaderFont));
                        orderTable.AddCell(new Paragraph("Date & Time", componentHeaderFont));
                        orderTable.AddCell(new Paragraph("Assignee", componentHeaderFont));
                        orderTable.AddCell(new Paragraph("Order Number", componentHeaderFont));
                        orderTable.AddCell(string.Empty);
                        pdfDocument.Add(orderTable);
                        Paragraph noProblemList = new Paragraph("No Order Information Found".ToString());
                        noProblemList.Alignment = Element.ALIGN_CENTER;
                        pdfDocument.Add(noProblemList);
                    }
                    // End Append Order Information

                    #endregion

                    //Start 23-03-2016 Humaira Yousaf for test information
                    #region Procedure Information

                    // Start Append Test Information
                    if (dsProcedureOrder.Tables[dsProcedureOrder.ProcedureOrderTest.TableName].Rows.Count > 0)
                    {
                        //Begin 28-03-2016 Edit By Humaira Yousaf Bug# EMR-576
                        Paragraph test_Heading = new Paragraph("Procedure Information \n".ToString(), componentHeadingFont);
                        //End 28-03-2016 Edit By Humaira Yousaf Bug# EMR-576
                        test_Heading.SpacingBefore = test_Heading.SpacingAfter = 5;
                        pdfDocument.Add(test_Heading);

                        PdfPTable testTable = new PdfPTable(4);
                        float[] widths = new float[] { 8f, 8f, 8f, 8f };
                        testTable.SetWidths(widths);
                        testTable.TotalWidth = 575f;
                        testTable.LockedWidth = true;
                        testTable.DefaultCell.Border = Rectangle.NO_BORDER;

                        foreach (DSProcedureOrder.ProcedureOrderTestRow dr in dsProcedureOrder.Tables[dsProcedureOrder.ProcedureOrderTest.TableName].Rows)
                        {
                            testTable.AddCell(new Paragraph(MDVUtility.ToDateTime(dr[dsProcedureOrder.ProcedureOrderTest.TestDateColumn.ColumnName]).ToShortDateString() + ' ' + dr[dsProcedureOrder.ProcedureOrderTest.TestTimeColumn.ColumnName].ToString(), bodyFont));
                            testTable.AddCell(new Paragraph(HttpUtility.HtmlDecode(MDVUtility.ToStr(dr[dsProcedureOrder.ProcedureOrderTest.CPTCodeDescriptionColumn.ColumnName])), bodyFont));
                            testTable.AddCell(string.Empty);
                            if (!string.IsNullOrEmpty(dr[dsProcedureOrder.ProcedureOrderTest.UrgencyNameColumn.ColumnName].ToString()))
                            {
                                testTable.AddCell(new Paragraph("Urgency: " + dr[dsProcedureOrder.ProcedureOrderTest.UrgencyNameColumn.ColumnName].ToString(), bodyFont));
                            }
                            else
                            {
                                testTable.AddCell(string.Empty);
                            }
                        }
                        pdfDocument.Add(testTable);
                    }
                    else
                    {
                        //Begin 28-03-2016 Edit By Humaira Yousaf Bug# EMR-576
                        Paragraph test_Heading = new Paragraph("Procedure Information \n".ToString(), componentHeadingFont);
                        //End 28-03-2016 Edit By Humaira Yousaf Bug# EMR-576
                        test_Heading.SpacingBefore = test_Heading.SpacingAfter = 5;
                        pdfDocument.Add(test_Heading);
                        PdfPTable testTable = new PdfPTable(5);
                        float[] widths = new float[] { 8f, 8f, 8f, 8f, 8f };
                        testTable.SetWidths(widths);
                        testTable.TotalWidth = 575f;
                        testTable.LockedWidth = true;
                        testTable.DefaultCell.Border = Rectangle.NO_BORDER;
                        testTable.AddCell(string.Empty);
                        pdfDocument.Add(testTable);
                        Paragraph noTest = new Paragraph("No Procedure Information Found".ToString());
                        noTest.Alignment = Element.ALIGN_CENTER;
                        pdfDocument.Add(noTest);
                    }
                    // End Append Associated Problems

                    #endregion
                    //End 23-03-2016 Humaira Yousaf for test information

                    #region Problem List

                    // Start Append Associated Problems
                    if (dsProcedureOrder.Tables[dsProcedureOrder.ProcedureOrderProblem.TableName].Rows.Count > 0)
                    {

                        Paragraph problems_Heading = new Paragraph("Associated Problems \n".ToString(), componentHeadingFont);
                        problems_Heading.SpacingBefore = problems_Heading.SpacingAfter = 5;
                        pdfDocument.Add(problems_Heading);

                        PdfPTable problemsTable = new PdfPTable(1);
                        float[] widths = new float[] { 8f };
                        problemsTable.SetWidths(widths);
                        problemsTable.TotalWidth = 575f;
                        problemsTable.LockedWidth = true;
                        problemsTable.DefaultCell.Border = Rectangle.NO_BORDER;
                        problemsTable.AddCell(string.Empty);

                        foreach (DSProcedureOrder.ProcedureOrderProblemRow dr in dsProcedureOrder.Tables[dsProcedureOrder.ProcedureOrderProblem.TableName].Rows)
                        {
                            problemsTable.AddCell(string.Empty);
                            problemsTable.AddCell(new Paragraph(HttpUtility.HtmlDecode(MDVUtility.ToStr(dr[dsProcedureOrder.ProcedureOrderProblem.ProblemNameColumn.ColumnName])), bodyFont));
                            problemsTable.AddCell(string.Empty);
                        }
                        pdfDocument.Add(problemsTable);
                    }
                    else
                    {

                        Paragraph problems_Heading = new Paragraph("Associated Problems \n".ToString(), componentHeadingFont);
                        problems_Heading.SpacingBefore = problems_Heading.SpacingAfter = 5;
                        pdfDocument.Add(problems_Heading);
                        PdfPTable problemsTable = new PdfPTable(5);
                        float[] widths = new float[] { 1f, 8f, 8f, 8f, 8f };
                        problemsTable.SetWidths(widths);
                        problemsTable.TotalWidth = 575f;
                        problemsTable.LockedWidth = true;
                        problemsTable.DefaultCell.Border = Rectangle.NO_BORDER;
                        problemsTable.AddCell(string.Empty);
                        pdfDocument.Add(problemsTable);
                        Paragraph noAllergy = new Paragraph("No Associated Problems Found".ToString());
                        noAllergy.Alignment = Element.ALIGN_CENTER;
                        pdfDocument.Add(noAllergy);
                    }
                    // End Append Associated Problems

                    #endregion

                    #region Findings

                    BLObject<List<OrderFindingsModel>> obj = LoadProcedureOrderTestFindings(procedureId, isFindingUpdated, notesId);
                    List<OrderFindingsModel> findingsList = obj.Data;

                    if (findingsList != null && findingsList.Count > 0)
                    {
                        Paragraph findings_Heading = new Paragraph("Findings \n".ToString(), componentHeadingFontN);
                        findings_Heading.SpacingBefore = findings_Heading.SpacingAfter = 5;
                        pdfDocument.Add(findings_Heading);

                        PdfPTable testTable = new PdfPTable(1);
                        float[] widths = new float[] { 12f };
                        testTable.SetWidths(widths);
                        testTable.TotalWidth = 575f;
                        testTable.LockedWidth = true;
                        testTable.DefaultCell.Border = Rectangle.NO_BORDER;

                        var groupedFindingsList = findingsList
                                                    .GroupBy(u => u.TestName)
                                                    .Select(grp => grp.ToList())
                                                    .ToList();

                        foreach (List<OrderFindingsModel> findings in groupedFindingsList)
                        {
                            testTable.AddCell(new Paragraph(findings[0].TestName, gridbodyFont));

                            //Start 02-10-2017 Edit By Humaira Yousaf Bug# EMR-4853
                            foreach (var item in findings.Where(f => !string.IsNullOrEmpty(f.Findings)))
                            {
                                //End 02-10-2017 Edit By Humaira Yousaf Bug# EMR-4853
                                Phrase sysName = new Phrase();
                                sysName.Add(new Chunk(item.SystemName + ": ", findingNameFont));
                                sysName.Add(new Chunk(item.Findings, bodyFont));
                                testTable.AddCell(sysName);
                            }
                        }

                        pdfDocument.Add(testTable);
                    }
                    #endregion
                    //Start 28-03-2016 Humaira Yousaf
                    pdfDocument.Add(Chunk.NEWLINE);
                    pdfDocument.Add(Chunk.NEWLINE);


                    PdfPTable signTable = new PdfPTable(1);
                    signTable.TotalWidth = 575f;
                    signTable.LockedWidth = true;
                    signTable.DefaultCell.Border = Rectangle.NO_BORDER;

                    DataRow signRow = dsProcedureOrder.Tables[dsProfile.Provider.TableName].Rows[0];
                    if (signRow[dsProfile.Provider.eSignatureColumn.ColumnName] as byte[] != null)
                    {
                        string signString = Convert.ToBase64String(signRow[dsProfile.Provider.eSignatureColumn.ColumnName] as byte[]);

                        Byte[] signBuffer = Convert.FromBase64String(signString);
                        var signStream = new MemoryStream(signBuffer);
                        iTextSharp.text.Image signImg = iTextSharp.text.Image.GetInstance(signBuffer, false);
                        signImg.ScaleAbsoluteHeight(150);
                        signImg.ScaleAbsoluteWidth(150);

                        PdfPCell signCell = new PdfPCell();
                        signCell.AddElement(signImg);
                        signCell.Border = Rectangle.NO_BORDER;
                        signCell.HorizontalAlignment = Element.ALIGN_LEFT;
                        signTable.AddCell(signCell);
                        pdfDocument.Add(signTable);
                    }


                    string modifiedDate = MDVUtility.ToDateTime(dsProcedureOrder.Tables[dsProcedureOrder.ProcedureOrder.TableName].Rows[0][dsProcedureOrder.ProcedureOrder.ModifiedOnColumn.ColumnName]).ToLongDateString();
                    if (!string.IsNullOrEmpty(modifiedDate))
                    {
                        modifiedDate = modifiedDate + " at ";
                    }
                    string modifiedTime = MDVUtility.ToDateTime(dsProcedureOrder.Tables[dsProcedureOrder.ProcedureOrder.TableName].Rows[0][dsProcedureOrder.ProcedureOrder.ModifiedOnColumn.ColumnName]).ToLongTimeString();
                    Paragraph signedByPara = new Paragraph("e-Signed By: " + MDVUtility.ToStr(dsProcedureOrder.Tables[dsProcedureOrder.ProcedureOrder.TableName].Rows[0][dsProcedureOrder.ProcedureOrder.ModifiedByNameColumn.ColumnName]) + " on " + modifiedDate + modifiedTime, bodyFont);
                    signedByPara.Alignment = Element.ALIGN_LEFT;
                    pdfDocument.Add(signedByPara);
                    //End 28-03-2016 Humaira Yousaf

                    newByteArr = stream_.GetBuffer();
                    pdf.Document.Close();
                    pdf.Writer.Close();
                    pdfDocument.Close();

                    MemoryStream stream = new MemoryStream(stream_.ToArray());
                    PdfReader npdf = new PdfReader(stream);
                    MemoryStream outstream = new MemoryStream();
                    using (PdfStamper stamper = new PdfStamper(npdf, outstream, '\0', true))
                    {
                        stamper.Writer.CloseStream = false;
                        int PageCount = npdf.NumberOfPages;
                        for (int i = 1; i <= PageCount; i++)
                        {
                            Paragraph para = new Paragraph(String.Format("Page {0}/{1}", i, PageCount), bodyFont);
                            para.Add(setLabOrder_ResultFooter(pdfDocument));
                            ColumnText.ShowTextAligned(stamper.GetOverContent(i), Element.ALIGN_CENTER, para, 555, 17, 0);
                        }
                    }
                    newByteArr = outstream.GetBuffer();
                }

                return new BLObject<byte[]>(newByteArr);
                //End 04-05-2016 Humaira Yousaf for formatting and other changes
            }
            catch (Exception ex)
            {
                MDVLogger.BLLErrorLog("BLLClinical::previewRadiologyOrder", ex);
                return new BLObject<byte[]>(null, ex.Message);
            }
        }



