        public BLObject<DSFavoriteList> getAllFavoriteListMedication(long FavoriteListId, string ListType, long? EntityId, byte IsActive = 1, Int32 PageNumber = 0, Int32 RowsPerPage = 0, string isViewOrder = "", string isPrintOrder = "", long LabId = 0, long ProviderId = 0, bool IsSelectForUpdate = false)
        {
            try
            {
                DSFavoriteList ds = new DSFavoriteList();
                DSFavoriteList objFavListMedicationlist = new DSFavoriteList();
                ds = new DALFavoriteList().loadClinical_FavoriteList(FavoriteListId, ListType, EntityId, IsActive, PageNumber, RowsPerPage, isViewOrder, isPrintOrder, LabId, ProviderId, IsSelectForUpdate);
                objFavListMedicationlist = new DALFavoriteList().loadClinicalFavoriteListMedication(0, FavoriteListId, 0, 0);
                if (objFavListMedicationlist != null)
                    ds.Merge(objFavListMedicationlist.FavoriteListMedication);
                return new BLObject<DSFavoriteList>(ds);
            }
            catch (Exception ex)
            {
                MDVLogger.BLLErrorLog("BLLClinical::getAllFavoriteListMedication", ex);
                return new BLObject<DSFavoriteList>(null, ex.Message);
            }
        }
