        public BLObject<DSFavoriteList> insertClinical_FavoriteList(DSFavoriteList ds, string ProviderIds)
        {
            try
            {
                if (ds.FavoriteList.Rows.Count > 0)
                {
                    ds = new DALFavoriteList().insertClinical_FavoriteList(ds);
                    for (int i = 0; i < ds.FavoriteListICD.Rows.Count; i++)
                    {
                        ds.FavoriteListICD.Rows[i]["FavoriteListId"] = ds.FavoriteList.Rows[0]["FavoriteListId"];
                    }
                }

                //ds.AcceptChanges();
                ds = new DALFavoriteList().insertClinical_FavoriteListICD(ds);
                if (!string.IsNullOrEmpty(ProviderIds))
                {
                    List<string> ProviderId = ProviderIds.Split(',').ToList();
                    var ListId = MDVUtility.ToInt64(ds.FavoriteList.Rows[0]["FavoriteListId"]);
                    for (int i = 0; i < ProviderId.Count; i++)
                    {
                        DSFavoriteList.FavoriteListProviderRow dr2 = null;
                        dr2 = ds.FavoriteListProvider.NewFavoriteListProviderRow();
                        dr2.FavListProviderId = -i;
                        dr2.ProviderId = ProviderId[i];
                        dr2.FavListId = ListId.ToString();

                        ds.FavoriteListProvider.AddFavoriteListProviderRow(dr2);
                    }
                    insertClinical_FavoriteListProviders(ds);
                }
                return new BLObject<DSFavoriteList>(ds);
            }
            catch (Exception ex)
            {
                MDVLogger.BLLErrorLog("BLLClinical::InsertClinical_FavoriteList", ex);
                return new BLObject<DSFavoriteList>(null, ex.Message);
            }
        }
        public BLObject<DSFavoriteList> insertClinicalFavoriteList(DSFavoriteList ds, string favListType = "CPT", string ProviderIds = "", string ListType = "")
        {
            try
            {
                ds = new DALFavoriteList().insertClinical_FavoriteList(ds);

                var ListId = MDVUtility.ToInt64(ds.FavoriteList.Rows[0]["FavoriteListId"]);
                //Delete All CPT against FavouriteList id
                // var deleted = new DALFavoriteList().deleteClinicalFavoriteListCPT(-1, ListId);

                if (favListType == "CPT")
                {
                    for (int i = 0; i < ds.FavoriteListCPT.Rows.Count; i++)
                    {
                        var favListId = ds.FavoriteListCPT.Rows[i]["FavoriteListId"].ToString();
                        if (string.IsNullOrEmpty(favListId))
                        {
                            ds.FavoriteListCPT.Rows[i]["FavoriteListId"] = ds.FavoriteList.Rows[0]["FavoriteListId"];
                        }
                    }
                    var insDs = insertClinicalFavoriteListCPT(ds);

                }
                else if (favListType == "ICD")
                {
                    for (int i = 0; i < ds.FavoriteListICD.Rows.Count; i++)
                    {
                        var favListId = ds.FavoriteListICD.Rows[i]["FavoriteListId"].ToString();
                        if (string.IsNullOrEmpty(favListId))
                        {
                            ds.FavoriteListICD.Rows[i]["FavoriteListId"] = ds.FavoriteList.Rows[0]["FavoriteListId"];
                        }
                        ds.FavoriteListICD.Rows[i]["FavoriteListId"] = ListId.ToString();
                    }

                    var insDs = insertClinical_FavoriteListICD(ds);
                }
                //else if (favListType == "Medication")
                //{
                //    for (int i = 0; i < ds.FavoriteListICD.Rows.Count; i++)
                //    {
                //        var favListId = ds.FavoriteListICD.Rows[i]["FavoriteListId"].ToString();
                //        if (string.IsNullOrEmpty(favListId))
                //        {
                //            ds.FavoriteListICD.Rows[i]["FavoriteListId"] = ds.FavoriteList.Rows[0]["FavoriteListId"];
                //        }
                //        ds.FavoriteListICD.Rows[i]["FavoriteListId"] = ListId.ToString();
                //    }

                //    var insDs = insertClinical_FavoriteListICD(ds);
                //}
                if ((ListType == "RadiologyOrder" || ListType == "LabOrder" || ListType == "LabOrderGroup" || ListType == "Procedure" || ListType == "SurgicalHistory" || ListType == "ProcedureOrder" || ListType == "ConsultationOrder" || ListType == "Medication") && !string.IsNullOrEmpty(ProviderIds))
                {
                    List<string> ProviderId = ProviderIds.Split(',').ToList();
                    for (int i = 0; i < ProviderId.Count; i++)
                    {
                        DSFavoriteList.FavoriteListProviderRow dr2 = null;
                        dr2 = ds.FavoriteListProvider.NewFavoriteListProviderRow();
                        dr2.FavListProviderId = -i;
                        dr2.ProviderId = ProviderId[i];
                        dr2.FavListId = ListId.ToString();

                        ds.FavoriteListProvider.AddFavoriteListProviderRow(dr2);
                    }
                    insertClinical_FavoriteListProviders(ds);
                }
                return new BLObject<DSFavoriteList>(ds);
            }
            catch (Exception ex)
            {
                MDVLogger.BLLErrorLog("BLLClinical::insertClinicalFavoriteList", ex);
                return new BLObject<DSFavoriteList>(null, ex.Message);
            }
        }


        public BLObject<DSFavoriteList> updateClinical_FavoriteList(DSFavoriteList ds, string favListType = "CPT", string ProviderIds = "", string ListType = "", bool IsDeleted = false)
        {
            try
            {
                ds = new DALFavoriteList().updateClinical_FavoriteList(ds);

                var ListId = MDVUtility.ToInt64(ds.FavoriteList.Rows[0]["FavoriteListId"]);

                if (favListType == "CPT")
                {
                    //Delete All CPT against FavouriteList id
                    if (!IsDeleted)
                    {
                        var deleted = new DALFavoriteList().deleteClinicalFavoriteListCPT(-1, ListId);
                    }
                    for (int i = 0; i < ds.FavoriteListCPT.Rows.Count; i++)
                    {
                        var favListId = ds.FavoriteListCPT.Rows[i]["FavoriteListId"].ToString();
                        if (string.IsNullOrEmpty(favListId))
                        {
                            ds.FavoriteListCPT.Rows[i]["FavoriteListId"] = ds.FavoriteList.Rows[0]["FavoriteListId"];
                        }
                    }
                    var insDs = insertClinicalFavoriteListCPT(ds);
                }
                else if (favListType == "ICD")
                {
                    //var deleted = new DALFavoriteList().deleteClinicalFavoriteListICD(-1, ListId);
                    for (int i = 0; i < ds.FavoriteListICD.Rows.Count; i++)
                    {
                        var favListId = ds.FavoriteListICD.Rows[i]["FavoriteListId"].ToString();
                        if (string.IsNullOrEmpty(favListId))
                        {
                            ds.FavoriteListICD.Rows[i]["FavoriteListId"] = ds.FavoriteList.Rows[0]["FavoriteListId"];

                        }
                        ds.FavoriteListICD.Rows[i]["FavoriteListId"] = ListId.ToString();
                    }
                    var insDs = insertClinical_FavoriteListICD(ds);
                }
                if ((ListType == "RadiologyOrder" || ListType == "SurgicalHistory" || ListType == "Problems" || ListType == "LabOrderGroup" || ListType == "LabOrder" || ListType == "Complaints" || ListType == "Procedure" || ListType == "ProcedureOrder" || ListType == "ConsultationOrder" || ListType == "Medication") && !string.IsNullOrEmpty(ProviderIds))
                {
                    UpdateClinical_FavoriteListProviders(ProviderIds, MDVUtility.ToStr(ListId));
                }
                return new BLObject<DSFavoriteList>(ds);
            }
            catch (Exception ex)
            {
                MDVLogger.BLLErrorLog("BLLClinical::updateClinical_FavoriteList", ex);
                return new BLObject<DSFavoriteList>(null, ex.Message);
            }
        }
        /// <summary>
        /// Module Name: insertClinicalFavoriteHistoryList
        /// Author: Humaira Yousaf
        /// Created Date: 16-06-2016
        /// Description: Inserts Favorite History List
        /// </summary>
        /// <param name="ds" type="DSPhysicalExam">dataset contains data to insert/update</param>
        public BLObject<DSFavoriteList> insertClinicalFavoriteHistoryList(DSFavoriteList ds, string ProviderIds = "", string CustomFormsIds = "")
        {
            try
            {
                ds = new DALFavoriteList().insertClinicalFavoriteHistoryList(ds);
                var ListId = MDVUtility.ToInt64(ds.FavoriteList.Rows[0]["FavoriteListId"]);

                List<string> ProviderId = ProviderIds.Split(',').ToList();
                for (int i = 0; i < ProviderId.Count; i++)
                {
                    DSFavoriteList.FavoriteListProviderRow dr2 = null;
                    dr2 = ds.FavoriteListProvider.NewFavoriteListProviderRow();
                    dr2.FavListProviderId = -i;
                    dr2.ProviderId = ProviderId[i];
                    dr2.FavListId = ListId.ToString();

                    ds.FavoriteListProvider.AddFavoriteListProviderRow(dr2);
                }
                insertClinical_FavoriteListProviders(ds);



                if (!string.IsNullOrEmpty(CustomFormsIds))
                {
                    List<string> CustomFormId = CustomFormsIds.Split(',').ToList();
                    for (int i = 0; i < CustomFormId.Count; i++)
                    {
                        DSFavoriteList.FavoriteListCustomFormRow dr2 = null;
                        dr2 = ds.FavoriteListCustomForm.NewFavoriteListCustomFormRow();
                        dr2.FavoriteListCustomFormId = -i;
                        dr2.CustomFormId = MDVUtility.ToInt64(CustomFormId[i]);
                        dr2.FavoriteListId = ListId;

                        ds.FavoriteListCustomForm.AddFavoriteListCustomFormRow(dr2);
                    }
                    insertClinical_FavoriteListCustomForms(ds);
                }

                return new BLObject<DSFavoriteList>(ds);
            }
            catch (Exception ex)
            {
                MDVLogger.BLLErrorLog("BLLClinical::insertClinicalFavoriteList", ex);
                return new BLObject<DSFavoriteList>(null, ex.Message);
            }
        }

