        #region Clinical Lab Admin Section (CRUD)

        public BLObject<DSClinicalLab> loadClinicalLab(long labId, string name, string listType, long entityId, byte isActive, Int32 PageNumber = 0, Int32 RowsPerPage = 0)
        {
            try
            {
                DSClinicalLab ds = new DSClinicalLab();
                ds = new DALClinicalLab().loadClinicalLab(labId, name, listType, entityId, isActive, PageNumber, RowsPerPage);
                if (labId > 0)
                {
                    DSClinicalLab dsLabTest = new DALClinicalLab().LoadLabTest(0, labId, "", "1");
                    ds.Merge(dsLabTest);
                }

                return new BLObject<DSClinicalLab>(ds);
            }
