        public BLObject<DSClinicalSummary> InsertImportCDS(long patientId, string FileName, int ReferenceID)
        {
            try
            {
                DSClinicalSummary ds = new DSClinicalSummary();
                DSClinicalSummary.PatientMiscellaneousStatusRow objPatientMiscellaneousStatusRow = ds.PatientMiscellaneousStatus.NewPatientMiscellaneousStatusRow();
                objPatientMiscellaneousStatusRow.PatientId = patientId;
                objPatientMiscellaneousStatusRow.DocumentName = FileName;
                objPatientMiscellaneousStatusRow.Value = true;
                objPatientMiscellaneousStatusRow.ReferenceDataId = ReferenceID;
                objPatientMiscellaneousStatusRow.PatientMiscellaneousStatusId = -1;
                ds.PatientMiscellaneousStatus.AddPatientMiscellaneousStatusRow(objPatientMiscellaneousStatusRow);

                ds = new DALClinicalSummary().InsertImportCDS(ds);
                return new BLObject<DSClinicalSummary>(ds);

            }
            catch (Exception ex)
            {
                MDVLogger.BLLErrorLog("BLLClinical::InsertImportCDS", ex);
                return new BLObject<DSClinicalSummary>(null, ex.Message);
            }
        }

