        #region Clinical Summary HTML Data
        /*
         * Author: Muhammad Arshad
         * Date: 06/04/2016
         * Overview: load ClinicalSumamryHTML Data
         */
        public BLObject<DSNotes> loadClinicalSummaryHTMLData(long PatientId, long ProviderId, long NoteId, Dictionary<int, string> lstComopent, Int64 referralProvider = 0, Dictionary<string, object> ReportsParamaters = null, bool loadSexual = false)
        {
            try
            {
                DSNotes ds = new DSNotes();
                if (NoteId > 0)
                {
                    ds = new DALNotes().loadClinical_Notes(PatientId, NoteId, 0, 1, 2000);
                }

                if (PatientId > 0)
                {
                    DSPatient dsPatientInfo = new DALPatient().SelectPatientCCDA(PatientId);
                    if (dsPatientInfo != null)
                    {
                        ds.Merge(dsPatientInfo);
                        if (dsPatientInfo.Patients.Rows.Count > 0)
                        {
                            try
                            {
                                int PracticeId = MDVUtility.ToInt32(dsPatientInfo.Patients.Rows[0][dsPatientInfo.Patients.PracticeIdColumn.ColumnName]);
                                DSProfile dsProfile = new DSProfile();
                                dsProfile = new DALPractice().LoadPractice(PracticeId, string.Empty, string.Empty, string.Empty, string.Empty, string.Empty);
                                if (dsProfile != null)
                                {
                                    ds.Merge(dsProfile);
                                }
                            }
                            catch (Exception ex)
                            {

                            }

                        }
                        try
                        {
                            var careTeamMember = lstComopent.Where(a => a.Value.ToLower().IndexOf("careteammember") > -1).Select(a => a.Value).FirstOrDefault();
                            if (!string.IsNullOrEmpty(careTeamMember))
                            {
                                DSCCM dsCareTeam = new DALClinicalSummary().loadCareTeamCCDA(PatientId);
                                if (dsCareTeam != null)
                                {
                                    ds.Merge(dsCareTeam);
                                }
                            }
                        }
                        catch (Exception ex)
                        {

                            throw;
                        }
                    }
                }

                if (ProviderId > 0)
                {
                    DSProfile dsProvider = new DALProvider().LoadProvider(ProviderId, "", "", "", "", "", "", "", 1, 2000);
                    if (dsProvider != null)
                    {
                        ds.Merge(dsProvider);
                    }
                }

                ds = loadClinicalSummaryNoteComponentData(lstComopent, ds, PatientId, NoteId, referralProvider, ReportsParamaters, loadSexual);

                return new BLObject<DSNotes>(ds);
            }
            catch (Exception ex)
            {
                MDVLogger.BLLErrorLog("BLLClinical::LoadClinical_Notes", ex);
                return new BLObject<DSNotes>(null, ex.Message);
            }
        }

        public BLObject<DSNotes> loadCaseReportsHTMLData(long PatientId, long ProviderId, long NoteId, Dictionary<int, string> lstComopent, Int64 referralProvider = 0)
        {
            try
            {
                DSNotes ds = new DSNotes();
                if (NoteId > 0)
                {
                    ds = new DALNotes().loadClinical_Notes(PatientId, NoteId, 0, 1, 2000);
                }

                if (PatientId > 0)
                {
                    DSPatient dsPatientInfo = new DALPatient().SelectPatientCCDA(PatientId);
                    if (dsPatientInfo != null)
                    {
                        ds.Merge(dsPatientInfo);
                        if (dsPatientInfo.Patients.Rows.Count > 0)
                        {
                            try
                            {
                                int PracticeId = MDVUtility.ToInt32(dsPatientInfo.Patients.Rows[0][dsPatientInfo.Patients.PracticeIdColumn.ColumnName]);
                                DSProfile dsProfile = new DSProfile();
                                dsProfile = new DALPractice().LoadPractice(PracticeId, string.Empty, string.Empty, string.Empty, string.Empty, string.Empty);
                                if (dsProfile != null)
                                {
                                    ds.Merge(dsProfile);
                                }
                            }
                            catch (Exception ex)
                            {

                            }

                        }
                        //try
                        //{
                        //    var careTeamMember = lstComopent.Where(a => a.Value == "CareTeamMembers").Select(a => a.Value).FirstOrDefault();
                        //    if (!string.IsNullOrEmpty(careTeamMember))
                        //    {
                        //        DSCCM dsCareTeam = new DALClinicalSummary().loadCareTeamCCDA(PatientId);
                        //        if (dsCareTeam != null)
                        //        {
                        //            ds.Merge(dsCareTeam);
                        //        }
                        //    }
                        //}
                        //catch (Exception ex)
                        //{

                        //    throw;
                        //}
                    }
                }

                if (ProviderId > 0)
                {
                    DSProfile dsProvider = new DALProvider().LoadProvider(ProviderId, "", "", "", "", "", "", "", 1, 2000);
                    if (dsProvider != null)
                    {
                        ds.Merge(dsProvider);
                    }
                }

                ds = loadCaseReportsNoteComponentData(lstComopent, ds, PatientId, NoteId, referralProvider);

                return new BLObject<DSNotes>(ds);
            }
            catch (Exception ex)
            {
                MDVLogger.BLLErrorLog("BLLClinical::LoadClinical_Notes", ex);
                return new BLObject<DSNotes>(null, ex.Message);
            }
        }


