        public BLObject<DSImmunization> VaccineHxUpdate(DSImmunization ds, string VaccineHxId, bool PreviousVoid, bool IsAddProcedures, string NotesId)
        {
            DSDBAudit dsDBAudit = new DSDBAudit();
            IDBManager dbManager = ClientConfiguration.GetDBManager();
            try
            {
                DataTable dtTempVaccineHx = ds.VaccineHx.GetChanges();
                DSProcedures.ProceduresDataTable dtProcedures = null;// new DSProcedures.ProceduresDataTable();
                string ProcedureIds = string.Empty;
                if (!string.IsNullOrWhiteSpace(VaccineHxId))//for a time no db aduit
                {
                    dtProcedures = new DALProcedures().GetProcedureData(VaccineHxId, ref ProcedureIds);
                }
                BLObject<string> strdeleteProcedure = new BLObject<string>();
                try
                {
                    dbManager.BeginTransaction();

                    if (!string.IsNullOrWhiteSpace(VaccineHxId))//for a time no db aduit
                    {
                        strdeleteProcedure = ProcedureDeleteForImmuniztion(VaccineHxId, dbManager);
                    }
                    string errorMsg = "Record Associated with Notes so it Cannot be deleted";
                    if (string.IsNullOrWhiteSpace(strdeleteProcedure.Data) || strdeleteProcedure.Data != errorMsg)
                        ds = new DALImmunization().VaccineHxUpdate(ds, PreviousVoid, IsAddProcedures, NotesId, dbManager);

                    dbManager.CommitTransaction();
                }
                catch (Exception ex1)
                {
                    dbManager.RollBackTransaction();
                    MDVLogger.BLLErrorLog("BLLClinical::VaccineHxUpdate", ex1);
                    return new BLObject<DSImmunization>(null, ex1.Message);
                }

                IDBManager dbManagerAudit = ClientConfiguration.GetDBManager();
                dbManagerAudit.Open();
                if (dtTempVaccineHx != null)
                {
                    dsDBAudit = new DBActivityAudit().InsertDBAudit(dtTempVaccineHx, dbManagerAudit, ds.VaccineHx.Rows[0][ds.VaccineHx.VaccineHxIdColumn].ToString(), null, ds.VaccineHx.Rows[0][ds.VaccineHx.VaccineHxIdColumn].ToString());
                    dsDBAudit.AcceptChanges();
                }
                if (dtProcedures != null)
                {
                    if (!string.IsNullOrWhiteSpace(ProcedureIds))
                    {
                        string[] strProcedureIds = ProcedureIds.Split(',').ToArray();
                        foreach (string procedure in strProcedureIds)
                        {
                            dsDBAudit = new DBActivityAudit().InsertDBAudit(dtProcedures, dbManagerAudit, procedure, null, "", false, false, true);
                            dsDBAudit.AcceptChanges();
                        }
                    }
                }
                dbManagerAudit.Dispose();
                return new BLObject<DSImmunization>(ds, strdeleteProcedure.Data);
            }
            catch (Exception ex)
            {
                ds.RejectChanges();
                dsDBAudit.RejectChanges();
                MDVLogger.BLLErrorLog("BLLClinical::VaccineHxUpdate Audit", ex);
                return new BLObject<DSImmunization>(null, ex.Message);
            }
        }

        //End//11/04/2016//Abid Ali//Update Immunization Vaccine Hx




