        public BLObject<DSImmunization> loadClinicalSchedulerDataForPreView(long PatientId)
        {
            try
            {
                DSImmunization ds = new DSImmunization();
                if (PatientId > 0)
                {
                    DSImmunization dsImmunizationCategory = new DALImmunization().GetSystemCategory();
                    if (dsImmunizationCategory != null)
                    {
                        ds.Merge(dsImmunizationCategory);
                        if (dsImmunizationCategory.LookUpVaccineGroup.Rows.Count > 0)
                        {
                            try
                            {

                                DSImmunization dsSchedulerData_B_2 = new DSImmunization();
                                dsSchedulerData_B_2 = new DALImmunization().loadSchedulerDataForPreview("Birth - 2 Years", PatientId);
                                DSImmunization dsSchedulerData_2_18 = new DSImmunization();
                                dsSchedulerData_2_18 = new DALImmunization().loadSchedulerDataForPreview("2 - 18 Years", PatientId);
                                if (dsSchedulerData_B_2 != null)
                                {
                                    ds.Merge(dsSchedulerData_B_2);
                                }
                                if (dsSchedulerData_2_18 != null)
                                {
                                    ds.Merge(dsSchedulerData_2_18);
                                }
                            }
                            catch (Exception ex)
                            {

                            }

                        }
                    }
                }
                return new BLObject<DSImmunization>(ds);
            }
            catch (Exception ex)
            {
                MDVLogger.BLLErrorLog("BLLClinical::loadClinicalSchedulerData", ex);
                return new BLObject<DSImmunization>(null, ex.Message);
            }
        }

