        #region immunization preview

        /// Module Name: previewImmunization
        /// Author: M Ahmad Imran
        /// Created Date: 17-05-2016
        /// Description: Creates PDF to view Referral
        /// </summary>
        /// <param name="consultationOrderId" type="long">ReferralId</param>
        /// <param name="PatientId" type="long">PatientId</param>
        public BLObject<byte[]> Preview_Immunization(long patientId)
        {
            try
            {

                //BLObject<byte[]> a = new BLObject<byte[]>();
                //return a;
                DSImmunization dsImmunization = new DSImmunization();
                DSPatient dsPatient = new DSPatient();
                DSProfile dsProfile = new DSProfile();
                dsImmunization = new DALImmunization().loadImmunizationForPrint(patientId);
                dsImmunization.Merge(new DALPatient().FillPatient(patientId, "", ""));
                long practiceId = MDVUtility.ToInt64(dsImmunization.Tables[dsPatient.Patients.TableName].Rows[0][dsPatient.Patients.PracticeIdColumn.ColumnName]);
                long providerId = MDVUtility.ToInt64(dsImmunization.Tables[dsPatient.Patients.TableName].Rows[0][dsPatient.Patients.ProviderIdColumn.ColumnName]);
                dsImmunization.Merge(new DALPractice().LoadPractice(practiceId, string.Empty, string.Empty, string.Empty, string.Empty, string.Empty));
                DSReportHeader.ReportHeaderTagsDataTable dtReportHeaderTags;
                string patientName = "";

                bool IsReportHeaderApplied = false;
                var dsReportHeader = new MDVision.DataAccess.DAL.ReportHeader.DALReportHeader().getReportHeaderTagsValue(patientId, 0, -1, "Immunization");
                IsReportHeaderApplied = dsReportHeader.ReportHeaderTags.Count > 0;
                dtReportHeaderTags = dsReportHeader.ReportHeaderTags;
                if (IsReportHeaderApplied &&
                     (
                            !string.IsNullOrEmpty(dsReportHeader.ReportHeaderTags[0]["PatientText"].ToString()) ||
                            !string.IsNullOrEmpty(dsReportHeader.ReportHeaderTags[0]["ProviderText"].ToString()) ||
                            !string.IsNullOrEmpty(dsReportHeader.ReportHeaderTags[0]["PracticeText"].ToString()) ||
                            !string.IsNullOrEmpty(dsReportHeader.ReportHeaderTags[0]["HeaderLogo"].ToString())
                            )
                    )
                {
                    IsReportHeaderApplied = true;
                }
                else
                {
                    IsReportHeaderApplied = false;
                }
                // return new BLObject<DSReportHeader>(dsReportHeader);

                byte[] newByteArr = null;
                using (MemoryStream stream_ = new MemoryStream())
                {
                    // Heading Font Style
                    var fontColour = new BaseColor(102, 178, 255);
                    iTextSharp.text.Font patientNameFont = FontFactory.GetFont("Arial", 12, iTextSharp.text.Font.BOLD, fontColour);
                    iTextSharp.text.Font bodyFont = FontFactory.GetFont("Arial", 10, iTextSharp.text.Font.NORMAL, iTextSharp.text.BaseColor.BLACK);
                    iTextSharp.text.Font componentHeadingFont = FontFactory.GetFont("Arial", 10, iTextSharp.text.Font.NORMAL, fontColour);
                    iTextSharp.text.Font componentHeaderFont = FontFactory.GetFont("Arial", 10, iTextSharp.text.Font.BOLD, iTextSharp.text.BaseColor.BLACK);
                    iTextSharp.text.Font componentHeaderFontWithBlue = FontFactory.GetFont("Arial", 10, iTextSharp.text.Font.NORMAL, fontColour);
                    iTextSharp.text.Font EndText = FontFactory.GetFont("Arial", 10, iTextSharp.text.Font.NORMAL, iTextSharp.text.BaseColor.GRAY);
                    iTextSharp.text.Font ImmunizationMainHeading = FontFactory.GetFont("Arial", 14, iTextSharp.text.Font.BOLD, iTextSharp.text.BaseColor.BLACK);
                    iTextSharp.text.Font BoldFontImmCount = FontFactory.GetFont("Arial", 12, iTextSharp.text.Font.BOLD, iTextSharp.text.BaseColor.BLACK);
                    bool IsFooterExist = false;
                    string FooterGeneratedBy = "";
                    PdfPTable ReportHeaderTable = new PdfPTable(2);
                    PdfPTable ReportHeaderTable1 = new PdfPTable(2);
                    PdfPTable footer = new PdfPTable(1);

                    float bottomMargin = 22;
                    float topMargin = 20;
                    PdfPTable patientTable = new PdfPTable(2);
                    Document pdfDocument = new Document(PageSize.LETTER, 20, 20, topMargin, bottomMargin);
                    if (IsReportHeaderApplied)
                    {
                        DSReportHeader.ReportHeaderTagsRow drReportHeader = (DSReportHeader.ReportHeaderTagsRow)dtReportHeaderTags.Rows[0];
                        #region Report Header

                        try
                        {
                            //------------------------------------  DSReportHeader.ReportHeaderTags dtReportHeaderTags =
                            if (IsReportHeaderApplied)
                            {
                                ReportHeaderTable.TotalWidth = 630f;
                                ReportHeaderTable.LockedWidth = true;
                                ReportHeaderTable.DefaultCell.Border = Rectangle.NO_BORDER;

                                ReportHeaderTable1.TotalWidth = 630f;
                                ReportHeaderTable1.LockedWidth = true;
                                ReportHeaderTable1.DefaultCell.Border = Rectangle.NO_BORDER;



                                IsFooterExist = drReportHeader.Field<string>("FooterText") != null;
                                if (IsFooterExist)
                                {
                                    FooterGeneratedBy = drReportHeader.FooterText;
                                    footer = setLabOrder_ResultFooterPDF(FooterGeneratedBy);
                                }
                                #region Header Logo
                                if (drReportHeader.Field<string>("HeaderLogo") != null && drReportHeader.Field<string>("HeaderLogo") != "")
                                {
                                    PdfPTable headerTable = new PdfPTable(1);
                                    headerTable.TotalWidth = 575f;
                                    headerTable.LockedWidth = true;
                                    headerTable.DefaultCell.Border = Rectangle.NO_BORDER;



                                    Byte[] buffer = Convert.FromBase64String(drReportHeader.HeaderLogo.Split(new string[] { "base64," }, StringSplitOptions.None)[1]);
                                    var memoryStream = new MemoryStream(buffer); //new MemoryStream(buffer, offset, count);
                                    System.Drawing.Image newImagej = System.Drawing.Image.FromStream(memoryStream);

                                    iTextSharp.text.Image logo = iTextSharp.text.Image.GetInstance(buffer, false);
                                    logo.ScalePercent(59f);
                                    logo.ScaleAbsoluteHeight(100);
                                    logo.ScaleAbsoluteWidth(150);

                                    PdfPCell cell1 = new PdfPCell();
                                    cell1.AddElement(logo);
                                    cell1.Border = Rectangle.NO_BORDER;
                                    cell1.HorizontalAlignment = Element.ALIGN_LEFT;
                                    ReportHeaderTable.AddCell(cell1);
                                }

                                else
                                {
                                    PdfPTable EmptyHeaderTable = new PdfPTable(1);
                                    EmptyHeaderTable.DefaultCell.Border = Rectangle.NO_BORDER;
                                    EmptyHeaderTable.AddCell(new Paragraph("", bodyFont));
                                    ReportHeaderTable.AddCell(EmptyHeaderTable);
                                }

                                #endregion

                                #region practice

                                PdfPTable PracticeTable = new PdfPTable(1);
                                PracticeTable.DefaultCell.Border = Rectangle.NO_BORDER;
                                //Begin Edited By Fahad Malik on 28-11-2016 to fix bug#: EMR-2090
                                PracticeTable.DefaultCell.HorizontalAlignment = Element.ALIGN_RIGHT;
                                //PracticeTable.DefaultCell.PaddingRight = 50;
                                //END Edited By Fahad Malik on 28-11-2016 to fix bug#: EMR-2090
                                if (drReportHeader.Field<string>("PracticeText") != null)
                                {
                                    //string[] PracticeColumns = drReportHeader.PracticeText.Split(new string[] { "<br/>" }, StringSplitOptions.None);
                                    var PracticeColumns = drReportHeader.PracticeText.Split(new[] { "<br/>" }, StringSplitOptions.RemoveEmptyEntries).Where(x => !string.IsNullOrWhiteSpace(x));
                                    foreach (string PracticeColumn in PracticeColumns)
                                    {
                                        if (!string.IsNullOrEmpty(PracticeColumn) && !string.IsNullOrWhiteSpace(PracticeColumn))
                                        {
                                            PracticeTable.AddCell(new Paragraph(PracticeColumn, bodyFont));
                                        }
                                    }
                                }
                                else
                                {
                                    PracticeTable.AddCell(new Paragraph("", bodyFont));
                                }
                                ReportHeaderTable.AddCell(PracticeTable);
                                #endregion

                                #region  Patient

                                PdfPTable PatientTable = new PdfPTable(1);
                                PatientTable.DefaultCell.Border = Rectangle.NO_BORDER;

                                if (drReportHeader.Field<string>("PatientText") != null)
                                {
                                    //string[] PatientColumns = drReportHeader.PatientText.Split(new string[] { "<br/>" }, StringSplitOptions.None);
                                    var PatientColumns = drReportHeader.PatientText.Split(new[] { "<br/>" }, StringSplitOptions.RemoveEmptyEntries).Where(x => !string.IsNullOrWhiteSpace(x));
                                    foreach (string PatientColumn in PatientColumns)
                                    {
                                        if (!string.IsNullOrEmpty(PatientColumn) && !string.IsNullOrWhiteSpace(PatientColumn))
                                        {
                                            PatientTable.AddCell(new Paragraph(PatientColumn.Replace("12:00AM", ""), bodyFont));
                                        }
                                    }
                                }
                                else
                                {
                                    PatientTable.AddCell(new Paragraph("", bodyFont));
                                }
                                PatientTable.DefaultCell.Padding = 0f;
                                PatientTable.DefaultCell.UseAscender = true;
                                ReportHeaderTable1.AddCell(PatientTable);
                                #endregion

                                #region  Provider

                                PdfPTable ProviderTable = new PdfPTable(1);
                                ProviderTable.DefaultCell.Border = Rectangle.NO_BORDER;
                                //Begin Edited By Fahad Malik on 28-11-2016 to fix bug#: EMR-2090
                                ProviderTable.DefaultCell.HorizontalAlignment = Element.ALIGN_RIGHT;
                                //ProviderTable.DefaultCell.PaddingRight = 50;
                                //End Edited By Fahad Malik on 28-11-2016 to fix bug#: EMR-2090
                                if (drReportHeader.Field<string>("ProviderText") != null)
                                {
                                    //string[] ProviderColumns = drReportHeader.ProviderText.Split(new string[] { "<br/>" }, StringSplitOptions.None);

                                    var ProviderColumns = drReportHeader.ProviderText.Split(new[] { "<br/>" }, StringSplitOptions.RemoveEmptyEntries).Where(x => !string.IsNullOrWhiteSpace(x));
                                    foreach (string ProviderColumn in ProviderColumns)
                                    {
                                        if (!string.IsNullOrEmpty(ProviderColumn) && !string.IsNullOrWhiteSpace(ProviderColumn))
                                        {
                                            ProviderTable.AddCell(new Paragraph(ProviderColumn, bodyFont));
                                        }
                                    }

                                }
                                else
                                {
                                    ProviderTable.AddCell(new Paragraph("", bodyFont));
                                }
                                ReportHeaderTable1.AddCell(ProviderTable);
                                #endregion
                                //ReportHeaderTable.DefaultCell.Padding = -1;
                            }
                        }
                        catch (Exception ex)
                        {
                            MDVLogger.BLLErrorLog("BLLAdminClinical::getReportHeaderTagsValue", ex);
                            // return new BLObject<DSReportHeader>(null, ex.Message);
                        }


                        #endregion
                    }
                    else
                    {
                        #region Patient's Data
                        ReportHeaderTable = setProcedureHeaderPDF(practiceId, bodyFont);
                        ReportHeaderTable1 = setProcedureHeaderPDF(practiceId, bodyFont);
                        footer = setLabOrder_ResultFooterPDF(FooterGeneratedBy);
                        #endregion
                    }

                    if (IsReportHeaderApplied)
                    {
                        topMargin = ReportHeaderTable.CalculateHeights() + 33;
                        bottomMargin = 52;
                    }
                    pdfDocument.SetMargins(20, 20, 30, bottomMargin);
                    // pdfDocument.PageNumber(1,SetMargins(20, 20, topMargin, bottomMargin));
                    //Document pdfDocument = new Document(PageSize.LETTER, 20, 20, topMargin, bottomMargin);
                    MDVUtility.PDFCreator pdf = new MDVUtility.PDFCreator(ref pdfDocument, stream_, false, ClientConfiguration.DecryptFrom64(MDVSession.Current.AppUserName), ClientConfiguration.DecryptFrom64(MDVSession.Current.AppUserName), "Procedure Requisition");
                    pdf.Writer.PageEvent = new MDVision.Common.Utilities.MDVUtility.AddFooterHeader(null, true, null, footer);
                    ReportHeaderTable.TotalWidth = 575f;
                    ReportHeaderTable1.TotalWidth = 575f;
                    ReportHeaderTable.HorizontalAlignment = Element.ALIGN_CENTER;
                    ReportHeaderTable1.HorizontalAlignment = Element.ALIGN_CENTER;
                    // ReportHeaderTable.WriteSelectedRows(0, -1, 20, pdfDocument.PageSize.Height - 30, writer.DirectContent);
                    pdf.Document.Open();
                    BaseColor myColors = WebColors.GetRGBColor("#66B2FF");

                    LineSeparator Headerlinez = new LineSeparator(2f, 100f, iTextSharp.text.BaseColor.BLUE, iTextSharp.text.Element.ALIGN_CENTER, -1);

                    pdfDocument.Add(new Chunk(Headerlinez));
                    pdfDocument.Add(ReportHeaderTable);
                    LineSeparator headerline1 = new LineSeparator(2f, 100f, myColors, iTextSharp.text.Element.ALIGN_CENTER, -1);
                    pdfDocument.Add(new Chunk(headerline1));
                    pdfDocument.Add(ReportHeaderTable1);


                    // line.Offset = 0.5f;

                    pdfDocument.Add(new Chunk(headerline1));
                    //pdfDocument.Add(new Chunk(line));

                    if (!IsReportHeaderApplied)
                    {
                        #region Patient/Provider Segment
                        string AccountNumber = dsImmunization.Tables[dsPatient.Patients.TableName].Rows[0]["AccountNumber"].ToString();
                        try
                        {
                            PdfPTable ReportPatientProvider = new PdfPTable(2);
                            ReportPatientProvider.TotalWidth = 575f;
                            ReportPatientProvider.SpacingBefore = 3f;
                            ReportPatientProvider.SpacingAfter = 8f;
                            ReportPatientProvider.LockedWidth = true;
                            ReportPatientProvider.DefaultCell.Border = Rectangle.NO_BORDER;

                            ReportPatientProvider.AddCell(SetLabPatient(patientId, patientName, fontColour, bodyFont, componentHeadingFont, patientNameFont, AccountNumber));
                            ReportPatientProvider.AddCell(SetLabProvider(providerId, patientNameFont, bodyFont));
                            pdfDocument.Add(ReportPatientProvider);
                        }
                        catch (Exception ex)
                        {
                            MDVLogger.BLLErrorLog("BLLAdminClinical::LabOrderPreview, Patient or Provider Segment", ex);
                        }
                        #endregion
                    }

                    #region Immuization Data

                    if (dsImmunization.Tables[dsImmunization.VaccineSchedulePreview.TableName].Rows.Count > 0)
                    {
                        Paragraph Pa = new Paragraph("Patient Vaccine Administration Record", ImmunizationMainHeading);
                        Pa.Alignment = Element.ALIGN_CENTER;
                        pdfDocument.Add(Pa);
                        BaseColor myColor = WebColors.GetRGBColor("#66B2FF");
                        LineSeparator Headerline = new LineSeparator(12f, 100f, myColor, iTextSharp.text.Element.ALIGN_CENTER, -1);
                        pdfDocument.Add(new Chunk(Headerline));
                        Chunk noOfImmunizationText = new Chunk("No of Immunizations: ");
                        Chunk numberOfImmunization = new Chunk((dsImmunization.Tables[dsImmunization.VaccineSchedulePreview.TableName].Rows.Count).ToString(), BoldFontImmCount);
                        Paragraph mrg = new Paragraph();
                        mrg.SpacingBefore = 3;
                        mrg.Add(noOfImmunizationText);
                        mrg.Add(numberOfImmunization);
                        pdfDocument.Add(mrg);
                        LineSeparator Topline = new LineSeparator(1f, 100f, myColor, iTextSharp.text.Element.ALIGN_CENTER, -1);
                        pdfDocument.Add(new Chunk(Topline));


                        PdfPTable orderTable = new PdfPTable(9);
                        float[] widths = new float[] { 2f, 6f, 7f, 6f, 6f, 6f, 8f, 7f, 6f };
                        orderTable.SetWidths(widths);
                        orderTable.TotalWidth = 575f;
                        orderTable.SpacingBefore = 2;
                        orderTable.LockedWidth = true;
                        orderTable.DefaultCell.Border = iTextSharp.text.Rectangle.NO_BORDER;

                        orderTable.AddCell(string.Empty);

                        orderTable.AddCell(new Paragraph("Vaccine", componentHeaderFont));
                        orderTable.AddCell(new Paragraph("Date Given", componentHeaderFont));
                        orderTable.AddCell(new Paragraph("Dose", componentHeaderFont));
                        orderTable.AddCell(new Paragraph("Site", componentHeaderFont));
                        orderTable.AddCell(new Paragraph("Lot No.", componentHeaderFont));
                        orderTable.AddCell(new Paragraph("Manufacturer", componentHeaderFont));
                        orderTable.AddCell(new Paragraph("Exp. Date", componentHeaderFont));
                        orderTable.AddCell(new Paragraph("Given By", componentHeaderFont));
                        pdfDocument.Add(orderTable);

                        LineSeparator line = new LineSeparator(1f, 100f, iTextSharp.text.BaseColor.GRAY, iTextSharp.text.Element.ALIGN_CENTER, -1);
                        // line.Offset = 0.5f;

                        pdfDocument.Add(new Chunk(line));

                        int count = 1;
                        PdfPTable ImmunizationData = new PdfPTable(9);
                        ImmunizationData.SpacingBefore = 2;
                        ImmunizationData.SpacingAfter = 5;
                        ImmunizationData.SetWidths(widths);
                        ImmunizationData.TotalWidth = 575f;
                        ImmunizationData.LockedWidth = true;
                        ImmunizationData.DefaultCell.Border = iTextSharp.text.Rectangle.NO_BORDER;
                        foreach (DSImmunization.VaccineSchedulePreviewRow dr in dsImmunization.Tables[dsImmunization.VaccineSchedulePreview.TableName].Rows)
                        {

                            if (MDVUtility.ToStr(dr[dsImmunization.VaccineSchedulePreview.VoidDoseColumn.ColumnName]) == "True")
                            {



                                PdfPCell obj = new PdfPCell(new Paragraph(MDVUtility.ToStr(count) + ".", bodyFont));
                                obj.BackgroundColor = BaseColor.LIGHT_GRAY;
                                ImmunizationData.AddCell(obj);

                                PdfPCell obj1 = new PdfPCell(new Paragraph(MDVUtility.ToStr(MDVUtility.ToStr(dr[dsImmunization.VaccineSchedulePreview.VaccineColumn.ColumnName]) != "" ? dr[dsImmunization.VaccineSchedulePreview.VaccineColumn.ColumnName] : ""), bodyFont));
                                obj1.BackgroundColor = BaseColor.LIGHT_GRAY;
                                ImmunizationData.AddCell(obj1);

                                PdfPCell obj2 = new PdfPCell(new Paragraph(MDVUtility.ToStr(MDVUtility.ToStr(dr[dsImmunization.VaccineSchedulePreview.DateGivenColumn.ColumnName]) != "" ? MDVUtility.ToDateTime(dr[dsImmunization.VaccineSchedulePreview.DateGivenColumn.ColumnName]).ToShortDateString() : ""), bodyFont));
                                obj2.BackgroundColor = BaseColor.LIGHT_GRAY;
                                ImmunizationData.AddCell(obj2);

                                PdfPCell obj3 = new PdfPCell(new Paragraph(MDVUtility.ToStr(MDVUtility.ToStr(dr[dsImmunization.VaccineSchedulePreview.DoseColumn.ColumnName]) != "" ? dr[dsImmunization.VaccineSchedulePreview.DoseColumn.ColumnName] + " " + dr[dsImmunization.VaccineSchedulePreview.AmountColumn.ColumnName] : ""), bodyFont));
                                obj3.BackgroundColor = BaseColor.LIGHT_GRAY;
                                ImmunizationData.AddCell(obj3);

                                PdfPCell obj4 = new PdfPCell(new Paragraph(MDVUtility.ToStr(MDVUtility.ToStr(dr[dsImmunization.VaccineSchedulePreview.LocationColumn.ColumnName]) != "" ? dr[dsImmunization.VaccineSchedulePreview.LocationColumn.ColumnName] : ""), bodyFont));
                                obj4.BackgroundColor = BaseColor.LIGHT_GRAY;
                                ImmunizationData.AddCell(obj4);

                                PdfPCell obj5 = new PdfPCell(new Paragraph(MDVUtility.ToStr(MDVUtility.ToStr(dr[dsImmunization.VaccineSchedulePreview.LotNoColumn.ColumnName]) != "" ? dr[dsImmunization.VaccineSchedulePreview.LotNoColumn.ColumnName] : ""), bodyFont));
                                obj5.BackgroundColor = BaseColor.LIGHT_GRAY;
                                ImmunizationData.AddCell(obj5);

                                PdfPCell obj6 = new PdfPCell(new Paragraph(MDVUtility.ToStr(MDVUtility.ToStr(dr[dsImmunization.VaccineSchedulePreview.ManufacturerColumn.ColumnName]) != "" ? dr[dsImmunization.VaccineSchedulePreview.ManufacturerColumn.ColumnName] : ""), bodyFont));
                                obj6.BackgroundColor = BaseColor.LIGHT_GRAY;
                                ImmunizationData.AddCell(obj6);

                                PdfPCell obj7 = new PdfPCell(new Paragraph(MDVUtility.ToStr(MDVUtility.ToStr(dr[dsImmunization.VaccineSchedulePreview.ExpiryDateColumn.ColumnName]) != "" ? MDVUtility.ToDateTime(dr[dsImmunization.VaccineSchedulePreview.ExpiryDateColumn.ColumnName]).ToShortDateString() : ""), bodyFont));
                                obj7.BackgroundColor = BaseColor.LIGHT_GRAY;
                                ImmunizationData.AddCell(obj7);

                                //PdfPCell obj8 = new PdfPCell(new Paragraph(MDVUtility.ToStr(MDVUtility.ToStr(dr[dsImmunization.VaccineSchedulePreview.GivenByColumn.ColumnName]) != "" ? dr[dsImmunization.VaccineSchedulePreview.GivenByColumn.ColumnName] : ""), bodyFont));
                                PdfPCell obj8 = new PdfPCell(new Paragraph(MDVUtility.ToStr(MDVUtility.ToStr(dr[dsImmunization.VaccineSchedulePreview.GivenByNameColumn.ColumnName]) != "" ? dr[dsImmunization.VaccineSchedulePreview.GivenByNameColumn.ColumnName] : ""), bodyFont));
                                obj8.BackgroundColor = BaseColor.LIGHT_GRAY;
                                ImmunizationData.AddCell(obj8);




                                count++;
                            }
                            else
                            {
                                ImmunizationData.AddCell(new Paragraph(MDVUtility.ToStr(count) + ".", bodyFont));

                                ImmunizationData.AddCell(new Paragraph(MDVUtility.ToStr(MDVUtility.ToStr(dr[dsImmunization.VaccineSchedulePreview.VaccineColumn.ColumnName]) != "" ? dr[dsImmunization.VaccineSchedulePreview.VaccineColumn.ColumnName] : ""), bodyFont));

                                ImmunizationData.AddCell(new Paragraph(MDVUtility.ToStr(MDVUtility.ToStr(dr[dsImmunization.VaccineSchedulePreview.DateGivenColumn.ColumnName]) != "" ? MDVUtility.ToDateTime(dr[dsImmunization.VaccineSchedulePreview.DateGivenColumn.ColumnName]).ToShortDateString() : ""), bodyFont));
                                ImmunizationData.AddCell(new Paragraph(MDVUtility.ToStr(MDVUtility.ToStr(dr[dsImmunization.VaccineSchedulePreview.DoseColumn.ColumnName]) != "" ? dr[dsImmunization.VaccineSchedulePreview.DoseColumn.ColumnName] + " " + dr[dsImmunization.VaccineSchedulePreview.AmountColumn.ColumnName] : ""), bodyFont));
                                ImmunizationData.AddCell(new Paragraph(MDVUtility.ToStr(MDVUtility.ToStr(dr[dsImmunization.VaccineSchedulePreview.LocationColumn.ColumnName]) != "" ? dr[dsImmunization.VaccineSchedulePreview.LocationColumn.ColumnName] : ""), bodyFont));
                                ImmunizationData.AddCell(new Paragraph(MDVUtility.ToStr(MDVUtility.ToStr(dr[dsImmunization.VaccineSchedulePreview.LotNoColumn.ColumnName]) != "" ? dr[dsImmunization.VaccineSchedulePreview.LotNoColumn.ColumnName] : ""), bodyFont));
                                ImmunizationData.AddCell(new Paragraph(MDVUtility.ToStr(MDVUtility.ToStr(dr[dsImmunization.VaccineSchedulePreview.ManufacturerColumn.ColumnName]) != "" ? dr[dsImmunization.VaccineSchedulePreview.ManufacturerColumn.ColumnName] : ""), bodyFont));
                                ImmunizationData.AddCell(new Paragraph(MDVUtility.ToStr(MDVUtility.ToStr(dr[dsImmunization.VaccineSchedulePreview.ExpiryDateColumn.ColumnName]) != "" ? MDVUtility.ToDateTime(dr[dsImmunization.VaccineSchedulePreview.ExpiryDateColumn.ColumnName]).ToShortDateString() : ""), bodyFont));
                                //ImmunizationData.AddCell(new Paragraph(MDVUtility.ToStr(MDVUtility.ToStr(dr[dsImmunization.VaccineSchedulePreview.GivenByColumn.ColumnName]) != "" ? dr[dsImmunization.VaccineSchedulePreview.GivenByColumn.ColumnName] : ""), bodyFont));
                                ImmunizationData.AddCell(new Paragraph(MDVUtility.ToStr(MDVUtility.ToStr(dr[dsImmunization.VaccineSchedulePreview.GivenByNameColumn.ColumnName]) != "" ? dr[dsImmunization.VaccineSchedulePreview.GivenByNameColumn.ColumnName] : ""), bodyFont));
                                count++;
                            }

                        }
                        pdfDocument.Add(ImmunizationData);

                        LineSeparator line1 = new LineSeparator(1f, 100f, iTextSharp.text.BaseColor.GRAY, iTextSharp.text.Element.ALIGN_CENTER, -1);
                        //line1.Offset = 0.2;
                        pdfDocument.Add(new Chunk(line1));
                        //Paragraph Pa = new Paragraph("Record generated by MDVision PM EMR Software (www.MDVisionEMR.com)", EndText);
                        //Pa.Alignment = Element.ALIGN_RIGHT;
                        //pdfDocument.Add(Pa);
                    }
                    else
                    {
                        PdfPTable orderTable = new PdfPTable(5);
                        float[] widths = new float[] { 1f, 8f, 8f, 8f, 8f };
                        orderTable.SetWidths(widths);
                        orderTable.TotalWidth = 575f;
                        orderTable.LockedWidth = true;
                        orderTable.DefaultCell.Border = iTextSharp.text.Rectangle.NO_BORDER;
                        orderTable.AddCell(string.Empty);
                        pdfDocument.Add(orderTable);
                        Paragraph noOrder = new Paragraph("No Immunization Found".ToString());
                        noOrder.Alignment = Element.ALIGN_CENTER;
                        pdfDocument.Add(noOrder);

                    }
                    //Rectangle rec=new Rectangle(10f,10f);
                    //pdfDocument.Add(rec);

                    //PdfPSXObject
                    //contentunder.SetColorStroke(BaseColor.RED);
                    //contentunder.Rectangle(PageSize.A4.Width / 7, PageSize.A4.Height * 3 / 4, PageSize.A4.Width / 2, PageSize.A4.Height / 5);
                    //contentunder.Stroke();


                    PdfPTable hintTable = new PdfPTable(2);
                    float[] widths1 = new float[] { .3f, 10f };
                    hintTable.SetWidths(widths1);
                    hintTable.TotalWidth = 575f;
                    hintTable.LockedWidth = true;

                    hintTable.DefaultCell.Border = iTextSharp.text.Rectangle.NO_BORDER;

                    PdfPCell cell = new PdfPCell();
                    cell.AddElement(new Paragraph(string.Empty));

                    cell.BorderColor = BaseColor.BLACK;
                    cell.BackgroundColor = BaseColor.LIGHT_GRAY;


                    hintTable.AddCell(cell);

                    cell = new PdfPCell();
                    cell.AddElement(new Paragraph("* Void dose is showing in gray.", bodyFont));
                    cell.HorizontalAlignment = Element.ALIGN_LEFT;
                    cell.VerticalAlignment = Element.ALIGN_CENTER;
                    cell.Border = iTextSharp.text.Rectangle.NO_BORDER;
                    hintTable.AddCell(cell);
                    hintTable.HorizontalAlignment = Element.ALIGN_LEFT;
                    pdfDocument.Add(hintTable);






                    #endregion

                    pdf.Document.Close();
                    pdf.Writer.Close();

                    pdfDocument.Close();
                    // adding paging label in footer
                    MemoryStream stream = new MemoryStream(stream_.ToArray());
                    bottomMargin = bottomMargin > 30 ? bottomMargin - 20 : 30;
                    PdfReader npdf = new PdfReader(stream);
                    MemoryStream outstream = new MemoryStream();
                    #region footer
                    var colors = System.Drawing.ColorTranslator.FromHtml("#fff");
                    var fontcolors = new BaseColor(colors);
                    Font componentFooterFonts = FontFactory.GetFont("Arial", 8, Font.NORMAL, fontcolors);
                    if (!IsFooterExist)
                    {
                        componentFooterFonts = bodyFont;
                    }

                    using (PdfStamper stamper = new PdfStamper(npdf, outstream, '\0', true))
                    {
                        stamper.Writer.CloseStream = false;
                        int PageCount = npdf.NumberOfPages;
                        for (int i = 1; i <= PageCount; i++)
                            ColumnText.ShowTextAligned(stamper.GetOverContent(i), Element.ALIGN_CENTER, new Paragraph(String.Format("Page {0} of {1}", i, PageCount), componentFooterFonts), 555, 18, 0);
                    }
                    #endregion
                    newByteArr = outstream.GetBuffer();
                }






                return new BLObject<byte[]>(newByteArr);
            }
            catch (Exception ex)
            {
                MDVLogger.BLLErrorLog("BLLClinical::previewConsultationOrder", ex);
                return new BLObject<byte[]>(null, ex.Message);
            }
        }


        /// Module Name: previewImmunization
        /// Author: M Ahmad Imran
        /// Created Date: 17-05-2016
        /// Description: Creates PDF to view Referral
        /// </summary>
        /// <param name="consultationOrderId" type="long">ReferralId</param>
        /// <param name="PatientId" type="long">PatientId</param>
        public BLObject<byte[]> GetImmunizationAlertForPrint(long patientId)
        {
            try
            {

                //BLObject<byte[]> a = new BLObject<byte[]>();
                //return a;
                DSImmunization dsImmunization = new DSImmunization();

                dsImmunization = new DALImmunization().LoadImmunizationAlertForPrint(patientId);


                byte[] newByteArr = null;
                using (MemoryStream stream_ = new MemoryStream())
                {
                    Document pdfDocument = new Document(PageSize.LETTER, 20, 20, 20, 20);
                    // Heading Font Style
                    var fontColour = new BaseColor(102, 178, 255);
                    iTextSharp.text.Font patientNameFont = FontFactory.GetFont("Arial", 12, iTextSharp.text.Font.BOLD, fontColour);
                    iTextSharp.text.Font bodyFont = FontFactory.GetFont("Arial", 8, iTextSharp.text.Font.NORMAL, iTextSharp.text.BaseColor.BLACK);
                    iTextSharp.text.Font componentHeadingFont = FontFactory.GetFont("Arial", 10, iTextSharp.text.Font.NORMAL, fontColour);
                    iTextSharp.text.Font componentHeaderFont = FontFactory.GetFont("Arial", 10, iTextSharp.text.Font.BOLD, iTextSharp.text.BaseColor.BLACK);
                    iTextSharp.text.Font componentHeaderFontWithBlue = FontFactory.GetFont("Arial", 10, iTextSharp.text.Font.NORMAL, fontColour);

                    iTextSharp.text.Font OverDuebodyFont = FontFactory.GetFont("Arial", 8, iTextSharp.text.Font.NORMAL, iTextSharp.text.BaseColor.RED);
                    iTextSharp.text.Font DuebodyFont = FontFactory.GetFont("Arial", 8, iTextSharp.text.Font.NORMAL, iTextSharp.text.BaseColor.ORANGE);




                    iTextSharp.text.Font EndText = FontFactory.GetFont("Arial", 10, iTextSharp.text.Font.NORMAL, iTextSharp.text.BaseColor.GRAY);

                    MDVUtility.PDFCreator pdf = new MDVUtility.PDFCreator(ref pdfDocument, stream_, false, ClientConfiguration.DecryptFrom64(MDVSession.Current.AppUserName), ClientConfiguration.DecryptFrom64(MDVSession.Current.AppUserName), "Requisition");
                    pdf.Document.Open();

                    bool IsFooterExist = false;
                    string FooterGeneratedBy = "";

                    #region Report Header


                    try
                    {
                        bool IsReportHeaderApplied = false;

                        DSReportHeader.ReportHeaderTagsDataTable dtReportHeaderTags;

                        var dsReportHeader = new MDVision.DataAccess.DAL.ReportHeader.DALReportHeader().getReportHeaderTagsValue(patientId, 0, -1, "Immunization");
                        IsReportHeaderApplied = dsReportHeader.ReportHeaderTags.Count > 0;
                        dtReportHeaderTags = dsReportHeader.ReportHeaderTags;

                        DSReportHeader.ReportHeaderTagsRow drReportHeader = (DSReportHeader.ReportHeaderTagsRow)dtReportHeaderTags.Rows[0];


                        if (IsReportHeaderApplied)
                        {

                            PdfPTable ReportHeaderTable = new PdfPTable(2);
                            ReportHeaderTable.TotalWidth = 568f;
                            ReportHeaderTable.LockedWidth = true;
                            ReportHeaderTable.DefaultCell.Border = Rectangle.NO_BORDER;
                            LineSeparator line1 = new LineSeparator(1f, 100f, iTextSharp.text.BaseColor.BLACK, iTextSharp.text.Element.ALIGN_CENTER, -1);
                            line1.Offset = 1;
                            pdfDocument.Add(new Chunk(line1));

                            IsFooterExist = drReportHeader.Field<string>("FooterText") != null;
                            if (IsFooterExist)
                            {
                                FooterGeneratedBy = drReportHeader.FooterText;
                            }


                            #region Header Logo

                            if (drReportHeader.Field<string>("HeaderLogo") != null)
                            {


                                PdfPTable headerTable = new PdfPTable(1);
                                headerTable.TotalWidth = 575f;
                                headerTable.LockedWidth = true;
                                headerTable.DefaultCell.Border = Rectangle.NO_BORDER;


                                Byte[] buffer = Convert.FromBase64String(drReportHeader.HeaderLogo.Split(new string[] { "base64," }, StringSplitOptions.None)[1]);
                                var memoryStream = new MemoryStream(buffer); //new MemoryStream(buffer, offset, count);
                                System.Drawing.Image newImagej = System.Drawing.Image.FromStream(memoryStream);

                                //   System.Drawing.Imaging.ImageFormat format = new System.Drawing.Imaging.ImageFormat();



                                iTextSharp.text.Image logo = iTextSharp.text.Image.GetInstance(buffer, false);
                                logo.ScalePercent(59f);
                                logo.ScaleAbsoluteHeight(100);
                                logo.ScaleAbsoluteWidth(150);

                                PdfPCell cell1 = new PdfPCell();
                                cell1.AddElement(logo);
                                cell1.Border = Rectangle.NO_BORDER;
                                cell1.HorizontalAlignment = Element.ALIGN_LEFT;
                                ReportHeaderTable.AddCell(cell1);
                            }

                            else
                            {
                                PdfPTable EmptyHeaderTable = new PdfPTable(1);
                                EmptyHeaderTable.DefaultCell.Border = Rectangle.NO_BORDER;
                                EmptyHeaderTable.AddCell(new Paragraph("", bodyFont));
                                ReportHeaderTable.AddCell(EmptyHeaderTable);
                            }

                            #endregion

                            #region practice

                            PdfPTable PracticeTable = new PdfPTable(1);
                            PracticeTable.DefaultCell.Border = Rectangle.NO_BORDER;
                            PracticeTable.DefaultCell.HorizontalAlignment = Element.ALIGN_RIGHT;

                            if (drReportHeader.Field<string>("PracticeText") != null)
                            {
                                string[] PracticeColumns = drReportHeader.PracticeText.Split(new string[] { "<br/>" }, StringSplitOptions.None);

                                foreach (string PracticeColumn in PracticeColumns)
                                {
                                    if (!string.IsNullOrEmpty(PracticeColumn) && !string.IsNullOrWhiteSpace(PracticeColumn))
                                    {
                                        PracticeTable.AddCell(new Paragraph(PracticeColumn, bodyFont));
                                    }
                                }

                            }
                            else
                            {
                                PracticeTable.AddCell(new Paragraph("", bodyFont));
                            }


                            ReportHeaderTable.AddCell(PracticeTable);


                            #endregion

                            LineSeparator line2 = new LineSeparator(1f, 100f, iTextSharp.text.BaseColor.BLUE, iTextSharp.text.Element.ALIGN_CENTER, -1);
                            line2.Offset = 1;
                            pdfDocument.Add(new Chunk(line2));


                            #region  Patient

                            PdfPTable PatientTable = new PdfPTable(1);
                            PatientTable.DefaultCell.Border = Rectangle.NO_BORDER;

                            if (drReportHeader.Field<string>("PatientText") != null)
                            {
                                string[] PatientColumns = drReportHeader.PatientText.Split(new string[] { "<br/>" }, StringSplitOptions.None);

                                foreach (string PatientColumn in PatientColumns)
                                {
                                    if (!string.IsNullOrEmpty(PatientColumn) && !string.IsNullOrWhiteSpace(PatientColumn))
                                    {
                                        PatientTable.AddCell(new Paragraph(PatientColumn, bodyFont));
                                    }
                                }

                            }
                            else
                            {
                                PatientTable.AddCell(new Paragraph("", bodyFont));
                            }
                            ReportHeaderTable.AddCell(PatientTable);


                            #endregion


                            #region  Provider

                            PdfPTable ProviderTable = new PdfPTable(1);
                            ProviderTable.DefaultCell.Border = Rectangle.NO_BORDER;
                            ProviderTable.DefaultCell.HorizontalAlignment = Element.ALIGN_RIGHT;

                            if (drReportHeader.Field<string>("ProviderText") != null)
                            {
                                string[] ProviderColumns = drReportHeader.ProviderText.Split(new string[] { "<br/>" }, StringSplitOptions.None);

                                foreach (string ProviderColumn in ProviderColumns)
                                {
                                    if (!string.IsNullOrEmpty(ProviderColumn) && !string.IsNullOrWhiteSpace(ProviderColumn))
                                    {
                                        ProviderTable.AddCell(new Paragraph(ProviderColumn, bodyFont));
                                    }
                                }

                            }
                            else
                            {
                                ProviderTable.AddCell(new Paragraph("", bodyFont));
                            }



                            ReportHeaderTable.AddCell(ProviderTable);


                            #endregion



                            LineSeparator line3 = new LineSeparator(1f, 100f, iTextSharp.text.BaseColor.BLACK, iTextSharp.text.Element.ALIGN_CENTER, -1);
                            line3.Offset = 1;
                            pdfDocument.Add(new Chunk(line3));
                            ReportHeaderTable.DefaultCell.Padding = 4;
                            pdfDocument.Add(ReportHeaderTable);
                        }


                    }
                    catch (Exception ex)
                    {
                        MDVLogger.BLLErrorLog("BLLAdminClinical::Preview_Immunization", ex);
                    }


                    #endregion

                    #region Immuization Data

                    if (dsImmunization.Tables[dsImmunization.PatientImmunizationAlert.TableName].Rows.Count > 0)
                    {

                        Paragraph noOfImmunization = new Paragraph(("No of Immunization Alerts " + dsImmunization.Tables[dsImmunization.PatientImmunizationAlert.TableName].Rows.Count).ToString(), componentHeaderFont);
                        noOfImmunization.Alignment = Element.ALIGN_LEFT;
                        pdfDocument.Add(noOfImmunization);
                        LineSeparator Topline = new LineSeparator(1f, 100f, iTextSharp.text.BaseColor.BLUE, iTextSharp.text.Element.ALIGN_CENTER, -1);
                        pdfDocument.Add(new Chunk(Topline));


                        PdfPTable orderTable = new PdfPTable(4);
                        float[] widths = new float[] { 2f, 10f, 10f, 10f };
                        orderTable.SetWidths(widths);
                        orderTable.TotalWidth = 575f;
                        orderTable.SpacingBefore = 5;
                        orderTable.LockedWidth = true;
                        orderTable.DefaultCell.Border = iTextSharp.text.Rectangle.NO_BORDER;

                        orderTable.AddCell(string.Empty);
                        orderTable.AddCell(new Paragraph("Vaccine", componentHeaderFont));
                        orderTable.AddCell(new Paragraph("Alert", componentHeaderFont));
                        orderTable.AddCell(new Paragraph("Due/Overdue Date", componentHeaderFont));
                        pdfDocument.Add(orderTable);

                        LineSeparator line = new LineSeparator(1f, 100f, iTextSharp.text.BaseColor.GRAY, iTextSharp.text.Element.ALIGN_CENTER, -1);
                        // line.Offset = 0.5f;

                        pdfDocument.Add(new Chunk(line));

                        int count = 1;
                        PdfPTable ImmunizationData = new PdfPTable(4);
                        ImmunizationData.SpacingBefore = 2;
                        ImmunizationData.SpacingAfter = 5;
                        ImmunizationData.SetWidths(widths);
                        ImmunizationData.TotalWidth = 575f;
                        ImmunizationData.LockedWidth = true;
                        ImmunizationData.DefaultCell.Border = iTextSharp.text.Rectangle.NO_BORDER;
                        foreach (DSImmunization.PatientImmunizationAlertRow dr in dsImmunization.Tables[dsImmunization.PatientImmunizationAlert.TableName].Rows)
                        {
                            ImmunizationData.AddCell(new Paragraph(MDVUtility.ToStr(count) + ".", bodyFont));

                            ImmunizationData.AddCell(new Paragraph(MDVUtility.ToStr(MDVUtility.ToStr(dr[dsImmunization.PatientImmunizationAlert.VaccineNameColumn.ColumnName]) != "" ? dr[dsImmunization.PatientImmunizationAlert.VaccineNameColumn.ColumnName] : ""), bodyFont));
                            if (MDVUtility.ToStr(dr[dsImmunization.PatientImmunizationAlert.AlertColumn.ColumnName]) != "")
                            {
                                if (MDVUtility.ToStr(dr[dsImmunization.PatientImmunizationAlert.AlertColumn.ColumnName]) == "Overdue")
                                {
                                    ImmunizationData.AddCell(new Paragraph(MDVUtility.ToStr(dr[dsImmunization.PatientImmunizationAlert.AlertColumn.ColumnName]), OverDuebodyFont));
                                }
                                else if (MDVUtility.ToStr(dr[dsImmunization.PatientImmunizationAlert.AlertColumn.ColumnName]) == "Due")
                                {
                                    ImmunizationData.AddCell(new Paragraph(MDVUtility.ToStr(dr[dsImmunization.PatientImmunizationAlert.AlertColumn.ColumnName]), DuebodyFont));
                                }
                            }

                            ImmunizationData.AddCell(new Paragraph(MDVUtility.ToStr(MDVUtility.ToStr(dr[dsImmunization.PatientImmunizationAlert.DueDateColumn.ColumnName]) != "" ? MDVUtility.ToDateTime(dr[dsImmunization.PatientImmunizationAlert.DueDateColumn.ColumnName]).ToShortDateString() : ""), bodyFont));
                            count++;
                        }
                        pdfDocument.Add(ImmunizationData);

                        LineSeparator line1 = new LineSeparator(1f, 100f, iTextSharp.text.BaseColor.GRAY, iTextSharp.text.Element.ALIGN_CENTER, -1);
                        //line1.Offset = 0.2;
                        pdfDocument.Add(new Chunk(line1));
                        //Paragraph Pa = new Paragraph("Record generated by MDVision PM EMR Software (www.MDVisionEMR.com)", EndText);
                        //Pa.Alignment = Element.ALIGN_RIGHT;
                        //pdfDocument.Add(Pa);
                    }
                    else
                    {
                        PdfPTable orderTable = new PdfPTable(5);
                        float[] widths = new float[] { 1f, 8f, 8f, 8f, 8f };
                        orderTable.SetWidths(widths);
                        orderTable.TotalWidth = 575f;
                        orderTable.LockedWidth = true;
                        orderTable.DefaultCell.Border = iTextSharp.text.Rectangle.NO_BORDER;
                        orderTable.AddCell(string.Empty);
                        pdfDocument.Add(orderTable);
                        Paragraph noOrder = new Paragraph("No Immunization Alert Found".ToString());
                        noOrder.Alignment = Element.ALIGN_CENTER;
                        pdfDocument.Add(noOrder);

                    }


                    #endregion

                    #region Footer
                    if (IsFooterExist)
                    {
                        Paragraph noComplaint = new Paragraph("Generated By: " + FooterGeneratedBy.ToString(), bodyFont);
                        noComplaint.Alignment = Element.ALIGN_LEFT;
                        pdfDocument.Add(noComplaint);

                    }
                    #endregion

                    pdf.Document.Close();
                    pdf.Writer.Close();

                    newByteArr = stream_.GetBuffer();
                }


                return new BLObject<byte[]>(newByteArr);
            }
            catch (Exception ex)
            {
                MDVLogger.BLLErrorLog("BLLClinical::previewConsultationOrder", ex);
                return new BLObject<byte[]>(null, ex.Message);
            }
        }



