        /// <summary>
        /// Method Name: loadClinicalSummaryData
        /// Author:  Ahmad Raza
        /// Created Date: 07/04/2016
        /// Description: This function will handle Load of Clinical Summary  Data
        /// </summary>
        /// <param name="lstComopent"></param>
        /// <returns></returns>
        public DSNotes loadClinicalSummaryNoteComponentData(Dictionary<int, string> lstComopent, DSNotes ds, long patientId, long NoteId, Int64 referralProvider = 0,
            Dictionary<string, object> ReportsParamaters = null, bool loadSexual = false)
        {
            try
            {
                //DSNotes ds = new DSNotes();
                bool probLoaded = false;
                foreach (KeyValuePair<int, string> entry in lstComopent)
                {
                    try
                    {

                        long componentId = entry.Key;
                        string componentName = entry.Value;
                        long cuurentPatientId = 0;
                        if (componentId < 0)
                        {
                            componentId = 0;
                            cuurentPatientId = patientId;
                        }
                        if (componentName.ToLower().IndexOf("assessment") > -1)
                        {
                            componentName = "problem";
                        }

                        if (!probLoaded && componentName.ToLower().IndexOf("problem") > -1)
                        {

                            DSProblemLists dsProblem = new DALClinicalSummary().LoadProblemListsCCDA(patientId, NoteId);
                            if (dsProblem != null)
                            {
                                ds.Merge(dsProblem);
                            }
                            probLoaded = true;
                        }
                        else if (componentName.ToLower().IndexOf("vital") > -1)
                        {
                            DSVitals dsVital = null;
                            dsVital = new DALClinicalSummary().LoadVitalsForCCDA(cuurentPatientId, componentId, NoteId);
                            if (dsVital != null)
                            {
                                ds.Merge(dsVital);
                            }
                        }
                        else if (componentName.ToLower().IndexOf("allerg") > -1)
                        {
                            DSAllergies dsAllergy = new DALClinicalSummary().loadAllergiesCCDA(cuurentPatientId, NoteId);
                            if (dsAllergy != null)
                            {
                                ds.Merge(dsAllergy);
                            }
                        }
                        else if (componentName.ToLower().IndexOf("social") > -1)
                        {
                            BLObject<DSSocialHistory> dsSocialHx = LoadSocialHxForCCDA(cuurentPatientId, componentId, NoteId, "tobacco");
                            if (dsSocialHx.Data != null)
                            {
                                ds.Merge(dsSocialHx.Data);
                                dsSocialHx = LookupTobaccoSmokingStatus();
                                if (dsSocialHx.Data != null)
                                {
                                    ds.Merge(dsSocialHx.Data);
                                }
                            }
                            if (loadSexual)
                            {
                                BLObject<DSSocialHistory> dsSexualHx = LoadSocialHxForCCDA(cuurentPatientId, componentId, NoteId, "sexual");
                                if (dsSexualHx.Data != null)
                                {
                                    ds.Merge(dsSexualHx.Data);
                                }
                            }

                        }
                        else if (componentName.ToLower().IndexOf("medicalhx") > -1)
                        {
                            DSMedicalHx dsMedicalHx = new DALClinicalSummary().LoadMedicalHx(cuurentPatientId, componentId);
                            if (dsMedicalHx != null)
                            {
                                ds.Merge(dsMedicalHx);
                            }
                        }
                        else if (componentName.ToLower().IndexOf("surgicalhx") > -1)
                        {
                            DSSurgicalHx dsSurgicalHx = new DALClinicalSummary().LoadSurgicalHx(cuurentPatientId, componentId);
                            if (dsSurgicalHx != null)
                            {
                                ds.Merge(dsSurgicalHx);
                            }
                        }
                        else if (componentName.ToLower().IndexOf("hospitalizationhx") > -1)
                        {
                            DSHospitalizationHx dsHospitalizationHx = new DALClinicalSummary().LoadHospitalizationHx(cuurentPatientId, componentId);
                            if (dsHospitalizationHx != null)
                            {
                                ds.Merge(dsHospitalizationHx);
                            }
                        }
                        else if (componentName.ToLower().IndexOf("familyhx") > -1)
                        {
                            DSFamilyHx dsFamilyHx = new DALClinicalSummary().LoadFamilyHx(cuurentPatientId, componentId);
                            if (dsFamilyHx != null)
                            {
                                ds.Merge(dsFamilyHx);
                            }
                        }
                        else if (componentName.ToLower().IndexOf("birthhx") > -1)
                        {
                            DSBirthHistory dsBirthHistory = new DALClinicalSummary().loadBirthHx(cuurentPatientId, componentId);
                            if (dsBirthHistory != null)
                            {
                                ds.Merge(dsBirthHistory);
                            }
                        }
                        else if (componentName.ToLower().IndexOf("physicalex") > -1)
                        {
                            DSPhysicalExam dsPhysicalExam = new DALClinicalSummary().loadPatientPhysicalExam(cuurentPatientId, componentId, NoteId);
                            if (dsPhysicalExam != null)
                            {
                                ds.Merge(dsPhysicalExam);
                            }
                        }
                        else if (componentName.ToLower().IndexOf("medication") > -1)
                        {

                            DSClinicalMedication dsMedication = null;
                            if (componentId > 0)
                                dsMedication = new DALClinicalSummary().loadMedications(componentId, cuurentPatientId, 0, true);

                            if (dsMedication != null && dsMedication.Tables[dsMedication.Medication.TableName].Rows.Count > 0)
                            {
                                DataTable dtMedicationsAdministered = new DataTable("MedicationsAdministered");
                                dtMedicationsAdministered = dsMedication.Tables[dsMedication.Medication.TableName].Copy();
                                dtMedicationsAdministered.TableName = "MedicationsAdministered";
                                ds.Merge(dtMedicationsAdministered);
                            }
                            //Load All Medication of Patient
                            DSClinicalMedication dsPatientMedication = new DALClinicalSummary().loadMedicationsCCDA(patientId, NoteId);
                            if (dsPatientMedication != null)
                            {
                                ds.Merge(dsPatientMedication);
                            }
                        }
                        else if (componentName.ToLower().IndexOf("procedure") > -1)
                        {
                            DSProcedures dsProcedures = new DALClinicalSummary().loadProceduresCCDA(patientId, NoteId);
                            if (dsProcedures != null)
                            {
                                ds.Merge(dsProcedures);
                            }

                        }
