        public DSNotes loadCaseReportsNoteComponentData(Dictionary<int, string> lstComopent, DSNotes ds, long patientId, long NoteId, Int64 referralProvider = 0)
        {
            try
            {
                //DSNotes ds = new DSNotes();
                foreach (KeyValuePair<int, string> entry in lstComopent)
                {
                    try
                    {

                        long componentId = entry.Key;
                        string componentName = entry.Value;
                        long cuurentPatientId = 0;
                        if (componentId < 0)
                        {
                            componentId = 0;
                            cuurentPatientId = patientId;
                        }


                        if (componentName.ToLower().IndexOf("problem") > -1)
                        {

                            DSProblemLists dsProblem = new DALCaseReports().LoadProblemListsCaseReports(patientId, NoteId);
                            if (dsProblem != null)
                            {
                                ds.Merge(dsProblem);
                            }
                        }
                        else if (componentName.ToLower().IndexOf("vital") > -1)
                        {
                            DSVitals dsVital = null;
                            dsVital = new DALClinicalSummary().LoadVitalsForCCDA(cuurentPatientId, componentId, NoteId);
                            if (dsVital != null)
                            {
                                ds.Merge(dsVital);
                            }
                        }
                        else if (componentName.ToLower().IndexOf("allerg") > -1)
                        {
                            DSAllergies dsAllergy = new DALClinicalSummary().loadAllergies(componentId, cuurentPatientId, NoteId);
                            if (dsAllergy != null)
                            {
                                ds.Merge(dsAllergy);
                            }
                        }
                        else if (componentName.ToLower().IndexOf("social") > -1)
                        {
                            BLObject<DSSocialHistory> dsSocialHx = LoadSocialHxForCCDA(cuurentPatientId, componentId, NoteId, "tobacco");
                            DSSocialHistory dsSocialHxDetails = new DALCaseReports().LoadSocialHxCaseReports(patientId, NoteId);
                            dsSocialHxDetails.Merge(dsSocialHx.Data);

                            if (dsSocialHxDetails != null)
                            {
                                ds.Merge(dsSocialHxDetails);
                                dsSocialHx = LookupTobaccoSmokingStatus();
                                if (dsSocialHx.Data != null)
                                {
                                    ds.Merge(dsSocialHx.Data);
                                }
                            }
                        }
                        else if (componentName.ToLower().IndexOf("medicalhx") > -1)
                        {
                            DSMedicalHx dsMedicalHx = new DALClinicalSummary().LoadMedicalHx(cuurentPatientId, componentId);
                            if (dsMedicalHx != null)
                            {
                                ds.Merge(dsMedicalHx);
                            }
                        }
                        else if (componentName.ToLower().IndexOf("surgicalhx") > -1)
                        {
                            DSSurgicalHx dsSurgicalHx = new DALClinicalSummary().LoadSurgicalHx(cuurentPatientId, componentId);
                            if (dsSurgicalHx != null)
                            {
                                ds.Merge(dsSurgicalHx);
                            }
                        }
                        else if (componentName.ToLower().IndexOf("hospitalizationhx") > -1)
                        {
                            DSHospitalizationHx dsHospitalizationHx = new DALClinicalSummary().LoadHospitalizationHx(cuurentPatientId, componentId);
                            if (dsHospitalizationHx != null)
                            {
                                ds.Merge(dsHospitalizationHx);
                            }
                        }
                        else if (componentName.ToLower().IndexOf("familyhx") > -1)
                        {
                            DSFamilyHx dsFamilyHx = new DALClinicalSummary().LoadFamilyHx(cuurentPatientId, componentId);
                            if (dsFamilyHx != null)
                            {
                                ds.Merge(dsFamilyHx);
                            }
                        }
                        else if (componentName.ToLower().IndexOf("birthhx") > -1)
                        {
                            DSBirthHistory dsBirthHistory = new DALClinicalSummary().loadBirthHx(cuurentPatientId, componentId);
                            if (dsBirthHistory != null)
                            {
                                ds.Merge(dsBirthHistory);
                            }
                        }
                        else if (componentName.ToLower().IndexOf("physicalex") > -1)
                        {
                            DSPhysicalExam dsPhysicalExam = new DALClinicalSummary().loadPatientPhysicalExam(cuurentPatientId, componentId, NoteId);
                            if (dsPhysicalExam != null)
                            {
                                ds.Merge(dsPhysicalExam);
                            }
                        }
                        else if (componentName.ToLower().IndexOf("medication") > -1)
                        {

                            DSClinicalMedication dsMedication = null;
                            if (componentId > 0)
                                dsMedication = new DALClinicalSummary().loadMedications(componentId, cuurentPatientId, 0, true);

                            //Load All Medication of Patient
                            DSClinicalMedication dsPatientMedication = new DALCaseReports().loadMedicationsCaseReporting(patientId, NoteId);
                            if (dsPatientMedication != null)
                            {
                                ds.Merge(dsPatientMedication);
                            }

                            if (dsPatientMedication != null && dsPatientMedication.Tables[dsPatientMedication.Medication.TableName].Rows.Count > 0)
                            {
                                DataTable dtMedicationsAdministered = new DataTable("MedicationsAdministered");
                                dtMedicationsAdministered = dsPatientMedication.Tables[dsPatientMedication.Medication.TableName].Copy();
                                dtMedicationsAdministered.TableName = "MedicationsAdministered";
                                ds.Merge(dtMedicationsAdministered);
                            }
                        }
                        else if (componentName.ToLower().IndexOf("procedure") > -1)
                        {
                            DSProcedures dsProcedures = new DALClinicalSummary().loadProceduresCCDA(patientId, NoteId);
                            if (dsProcedures != null)
                            {
                                ds.Merge(dsProcedures);
                            }

                        }
                        else if (componentName.ToLower().IndexOf("immunization") > -1)
                        {
                            var dsImmunization = new DALClinicalSummary().LoadVaccineHxClinicalSummary(patientId, componentId);
                            if (dsImmunization != null)
                            {
                                ds.Merge(dsImmunization);
                            }

                        }
                        else if (componentName.ToLower().IndexOf("planofcare") > -1)
                        {
                            DSClinicalSummary dsClinicalSummary = new DALClinicalSummary().loadPlanOfCare(componentId, patientId, NoteId, 1, 2000);
                            if (dsClinicalSummary != null)
                            {
                                ds.Merge(dsClinicalSummary);

                                if (componentId == 0)
                                {
                                    if (dsClinicalSummary.Tables[dsClinicalSummary.PlanofCare.TableName].Rows.Count > 0)
                                    {
                                        componentId = MDVUtility.ToInt64(dsClinicalSummary.Tables[dsClinicalSummary.PlanofCare.TableName].Rows[0][dsClinicalSummary.PlanofCare.PlanofCareIdColumn.ColumnName]);
                                    }
                                }

                                if (componentId > 0)
                                {
                                    dsClinicalSummary = new DALClinicalSummary().loadPlanOfCareGoal(componentId, 0);
                                    if (dsClinicalSummary != null)
                                    {
                                        ds.Merge(dsClinicalSummary);
                                    }
                                }
                            }

                            DSConsultationOrder dsConsultationOrder = new DALClinicalSummary().loadConsultationOrder(0, cuurentPatientId, NoteId);

                            if (dsConsultationOrder != null && dsConsultationOrder.Tables[dsConsultationOrder.ConsultationOrder.TableName].Rows.Count > 0)
                            {
                                ds.Merge(dsConsultationOrder);
                                long ProviderId = MDVUtility.ToInt64(dsConsultationOrder.Tables[dsConsultationOrder.ConsultationOrder.TableName].Rows[0][dsConsultationOrder.ConsultationOrder.ProviderIdColumn.ColumnName]);
                                DSProfile dsProvider = new DALClinicalSummary().LoadProvider(ProviderId, string.Empty, string.Empty, string.Empty, string.Empty, string.Empty, string.Empty, "1");
                                DataTable dtreferralProvider = new DataTable("ReferralProvider");
                                if (dsProvider != null && dsProvider.Tables[dsProvider.Provider.TableName] != null)
                                {
                                    dtreferralProvider = dsProvider.Tables[dsProvider.Provider.TableName];
                                    dtreferralProvider.TableName = "ReferralProvider";
                                    ds.Merge(dtreferralProvider);
                                }
                            }
                        }
                        else if (componentName.ToLower().IndexOf("planoftreatment") > -1)
                        {
                            DSLabOrder dsLab = new DALCaseReports().LoadLabOrdersForCaseReports(cuurentPatientId, NoteId);

                            if (dsLab != null)
                                ds.Merge(dsLab);
                        }
                        else if (componentName.ToLower().IndexOf("labresults") > -1)
                        {
                            DSLabResult dsLabResultDetail = new DALCaseReports().loadLabResultDetail(patientId, NoteId);

                            if (dsLabResultDetail != null)
                                ds.Merge(dsLabResultDetail);
                            if (componentId > 0)
                            {
                                DSLabResult dsLabResults = new DALClinicalSummary().LoadLabResult(componentId);
                                if (dsLabResults != null)
                                    ds.Merge(dsLabResults);
                            }

                            DSRadiologyResult dsRadiologyResult = new DALRadiologyResult().LoadRadiologyResult(0, 0, "", "", "", "", 0, "", "", "", patientId, "", "", NoteId);
                            if (dsRadiologyResult != null)
                            {
                                ds.Merge(dsRadiologyResult);
                            }

                            foreach (DSRadiologyResult.RadiologyOrderResultRow dr in dsRadiologyResult.Tables[dsRadiologyResult.RadiologyOrderResult.TableName].Rows)
                            {
                                DSRadiologyResult dsRadiologyResultDetail = new DALRadiologyResult().loadRadiologyResultDetail(0, dr.RadiologyOrderResultId);

                                if (dsRadiologyResultDetail != null)
                                {
                                    ds.Merge(dsRadiologyResultDetail);
                                }
                            }
                        }
                        else if (componentName.ToLower().IndexOf("hpi") > -1)
                        {

                            DSClinicalComplaint dsComp = new DALCaseReports().LoadComplaintsCaseReports(patientId, NoteId);
                            if (dsComp != null)
                            {
                                ds.Merge(dsComp);
                            }
                        }
                        else if (componentName.ToLower().IndexOf("cognitive") > -1)
                        {
                            DSClinicalSummary dsClinicalSummary = new DALClinicalSummary().loadCognitive_CognitiveFunctionalStatus(patientId, NoteId);
                            if (dsClinicalSummary != null)
                            {
                                ds.Merge(dsClinicalSummary);
                            }
                        }
                        else if (componentName.ToLower().IndexOf("refferralreason") > -1 && referralProvider > 0)
                        {
                            DSProfile dsReferringProvider = new DSProfile();
                            dsReferringProvider = new DALReferringProvider().LoadReferringProvider(referralProvider, null, null, null, null, null, 1, 2000);
                            if (dsReferringProvider != null)
                            {
                                ds.Merge(dsReferringProvider);
                            }
                        }
                        else if (componentName.ToLower().IndexOf("refferral") > -1)
                        {
                            DSPatientReferral dsPatientReferral = new DSPatientReferral();
                            dsPatientReferral = new DALClinicalSummary().getLatestReferralByPatientId(patientId, NoteId);
                            if (dsPatientReferral != null)
                            {
                                ds.Merge(dsPatientReferral);
                            }
                        }
                        else if (componentName.ToLower().IndexOf("encounterdiagnostic") > -1)
                        {
                            DSClinicalSummary dsEncounterdiagnostic = new DSClinicalSummary();
                            dsEncounterdiagnostic = new DALClinicalSummary().loadCCDAEncounterDiagnostic(patientId, NoteId);
                            if (dsEncounterdiagnostic != null)
                            {
                                ds.Merge(dsEncounterdiagnostic);
                            }
                        }
                        else if (componentName.ToLower().IndexOf("visitreason") > -1)
                        {
                            //DSClinicalSummary dsReferralReason = new DSClinicalSummary();
                            //dsReferralReason = new DALClinicalSummary().LoadComplaintsByNoteId(NoteId);
                            //if (dsReferralReason != null)
                            //{
                            //    ds.Merge(dsReferralReason);
                            //}
                        }
                        else if (componentName.ToLower().IndexOf("payerssection") > -1)
                        {
                            DSNotes dsInsurance = new DALPatientInsurance().LoadPatientInsuranceCCDA(patientId);
                            if (dsInsurance != null)
                            {
                                ds.Merge(dsInsurance);
                            }
                        }
                        else if (componentName.ToLower().IndexOf("mentalstatus") > -1)
                        {
                            DSClinicalSummary dsClinicalSummary = new DALClinicalSummary().loadeMentalStatusCCDA(NoteId, patientId);
                            if (dsClinicalSummary != null)
                            {
                                ds.Merge(dsClinicalSummary);
                            }
                        }
                    }
                    catch (Exception ex)
                    {
                        MDVLogger.BLLErrorLog("BLLClinical::loadClinicalSummaryData", ex);

                    }
                }
                return ds;
            }
            catch (Exception ex)
            {
                MDVLogger.BLLErrorLog("BLLClinical::loadClinicalSummaryData", ex);
                return ds;
            }
        }

