        /// <summary>
        /// Module Name: LoadAuditReport
        /// Created Date: 15-04-2016
        /// Author Name: Ahmad Raza
        /// Description: This Method will load Audit Report
        /// </summary>
        /// <param name="ModuleName"></param>
        /// <param name="UserName"></param>
        /// <param name="ColumnKeyId"></param>
        /// <param name="ProfileName"></param>
        /// <param name="DBAuditId"></param>
        /// <param name="PatientId"></param>
        /// <param name="VisitId"></param>
        /// <param name="createdDate"></param>
        /// <param name="ActivityType"></param>
        /// <param name="DBTableName"></param>
        /// <param name="ParentKeyColumnId"></param>
        /// <param name="ActionName"></param>
        /// <param name="CreatedDateFrom"></param>
        /// <param name="CreatedDateTo"></param>
        /// <returns></returns>
        public BLObject<DSDBAudit> LoadAuditReport(string ModuleName, ref DataTable UserIds, string ColumnKeyId, string ProfileName, string DBAuditId, ref DataTable PatientIds, string VisitId, DateTime? createdDate, string ActivityType, string DBTableName = null, string ParentKeyColumnId = "", string ActionName = "", string CreatedDateFrom = "", string CreatedDateTo = "", int PageNumber = 1, int RowsPerPage = 1000, string LookUpID = null)
        {
            try
            {

                DSDBAudit ds = new DSDBAudit();
                ds = new DBActivityAudit().LoadDBAuditSelectForMultiUsers(ModuleName, ref UserIds, ColumnKeyId, ProfileName, DBAuditId, ref PatientIds, VisitId, createdDate, DBTableName, ParentKeyColumnId, ActionName, CreatedDateFrom, CreatedDateTo, PageNumber, RowsPerPage, LookUpID);
                return new BLObject<DSDBAudit>(ds);
            }
            catch (Exception ex)
            {
                MDVLogger.BLLErrorLog("BLLClinical::LoadAuditReport", ex);
                return new BLObject<DSDBAudit>(null, ex.Message);
            }
        }
        public List<ActivityLogUser> LoadUserAuditReport(string UserType, ref DataTable AuditUserIds, string FromDate, string ToDate, string AuditAction, string PageNumber, string RowsPerPage)
        {


            List<ActivityLogUser> objList_ActivityLog = new List<ActivityLogUser>();
            try
            {
                objList_ActivityLog = new DBActivityAudit().LoadUserAuditReport(UserType, ref AuditUserIds, FromDate, ToDate, AuditAction, int.Parse(PageNumber), int.Parse(RowsPerPage));
            }

            catch (Exception ex)
            {

                MDVLogger.BLLErrorLog("BLLClinical::LoadUserAuditReport", ex);
                throw ex.InnerException;

            }
            return objList_ActivityLog;
        }

