        /// <summary>
        /// Module Name: previewAuditReport
        /// Created Date: 16-04-2016
        /// Author Name: Ahmad Raza
        /// Description: This Method will show Audit Report in PDF View
        /// </summary>
        /// <param name="ModuleName"></param>
        /// <param name="UserName"></param>
        /// <param name="ColumnKeyId"></param>
        /// <param name="ProfileName"></param>
        /// <param name="DBAuditId"></param>
        /// <param name="PatientId"></param>
        /// <param name="VisitId"></param>
        /// <param name="createdDate"></param>
        /// <param name="ActivityType"></param>
        /// <param name="DBTableName"></param>
        /// <param name="ParentKeyColumnId"></param>
        /// <param name="ActionName"></param>
        /// <param name="CreatedDateFrom"></param>
        /// <param name="CreatedDateTo"></param>
        /// <returns></returns>
        public BLObject<byte[]> previewAuditReport(string ModuleName, string UserName, string ColumnKeyId, string ProfileName, string DBAuditId, string PatientId, string VisitId, DateTime? createdDate, string ActivityType, string DBTableName = null, string ParentKeyColumnId = "", string ActionName = "", string CreatedDateFrom = "", string CreatedDateTo = "")
        {
            try
            {
                DSDBAudit ds = new DSDBAudit();
                ds = new DBActivityAudit().LoadDBAudit(ModuleName, UserName, ColumnKeyId, ProfileName, DBAuditId, PatientId, VisitId, createdDate, DBTableName, ParentKeyColumnId, ActionName, CreatedDateFrom, CreatedDateTo);

                byte[] newByteArr = null;
                using (MemoryStream stream_ = new MemoryStream())
                {
                    Document pdfDocument = new Document(PageSize.A4, 10, 10, 20, 20);
                    // Heading Font Style
                    var fontColour = new BaseColor(102, 178, 255);
                    iTextSharp.text.Font patientNameFont = FontFactory.GetFont("Arial", 12, iTextSharp.text.Font.BOLD, fontColour);
                    iTextSharp.text.Font bodyFont = FontFactory.GetFont("Arial", 10, iTextSharp.text.Font.NORMAL, iTextSharp.text.BaseColor.BLACK);
                    iTextSharp.text.Font componentHeadingFont = FontFactory.GetFont("Arial", 10, iTextSharp.text.Font.NORMAL, fontColour);
                    iTextSharp.text.Font componentHeaderFont = FontFactory.GetFont("Arial", 9, iTextSharp.text.Font.BOLD, fontColour);

                    MDVUtility.PDFCreator pdf = new MDVUtility.PDFCreator(ref pdfDocument, stream_, false, ClientConfiguration.DecryptFrom64(MDVSession.Current.AppUserName), ClientConfiguration.DecryptFrom64(MDVSession.Current.AppUserName), "Audit Report");
                    pdf.Document.Open();
                    Paragraph faceSheet_Heading = new Paragraph("Audit Report".ToString(), patientNameFont);
                    LineSeparator line = new LineSeparator(1f, 100f, iTextSharp.text.BaseColor.BLACK, iTextSharp.text.Element.ALIGN_CENTER, -1);
                    line.Offset = 1;
                    pdfDocument.Add(new Chunk(line));
                    faceSheet_Heading.SpacingAfter = -12;
                    faceSheet_Heading.SpacingBefore = -5;
                    pdfDocument.Add(faceSheet_Heading);
                    Chunk c = new Chunk(line);

                    pdfDocument.Add(new Chunk(line));
                    pdfDocument.Add(Chunk.NEWLINE);
                    #region Problem List Data

                    if (ds.Tables[ds.DBAudit.TableName].Rows.Count > 0)
                    {
                        PdfPTable auditReportTable = new PdfPTable(10);
                        float[] widths = new float[] { 1f, 4f, 4f, 4f, 5f, 3f, 5f, 5f, 5f, 1f };
                        auditReportTable.SetWidths(widths);
                        auditReportTable.TotalWidth = 570f;
                        auditReportTable.LockedWidth = true;
                        auditReportTable.DefaultCell.Border = Rectangle.NO_BORDER;
                        auditReportTable.AddCell(string.Empty);
                        auditReportTable.AddCell(new Paragraph("Date", componentHeaderFont));
                        auditReportTable.AddCell(new Paragraph("PatientName", componentHeaderFont));
                        auditReportTable.AddCell(new Paragraph("UserName", componentHeaderFont));
                        auditReportTable.AddCell(new Paragraph("Module", componentHeaderFont));
                        auditReportTable.AddCell(new Paragraph("Action", componentHeaderFont));
                        auditReportTable.AddCell(new Paragraph("Field", componentHeaderFont));
                        auditReportTable.AddCell(new Paragraph("Original Value", componentHeaderFont));
                        auditReportTable.AddCell(new Paragraph("Current Value", componentHeaderFont));
                        auditReportTable.AddCell(string.Empty);
                        foreach (DSDBAudit.DBAuditRow dr in ds.Tables[ds.DBAudit.TableName].Rows)
                        {
                            //Start 27-05-2016 Humaira Yousaf to exclude note text
                            if (dr[ds.DBAudit.ModuleNameColumn.ColumnName].ToString() != "Notes" && dr[ds.DBAudit.DisplayNameColumn.ColumnName].ToString() != "Note Text")
                            {
                                auditReportTable.AddCell(string.Empty);
                                auditReportTable.AddCell(new Paragraph(dr[ds.DBAudit.CreatedDateColumn.ColumnName].ToString(), bodyFont));
                                auditReportTable.AddCell(new Paragraph(dr[ds.DBAudit.PatientNameColumn.ColumnName].ToString(), bodyFont));
                                auditReportTable.AddCell(new Paragraph(dr[ds.DBAudit.UserNameColumn.ColumnName].ToString(), bodyFont));
                                auditReportTable.AddCell(new Paragraph(dr[ds.DBAudit.ModuleNameColumn.ColumnName].ToString(), bodyFont));
                                auditReportTable.AddCell(new Paragraph(dr[ds.DBAudit.DBAuditActionColumn.ColumnName].ToString(), bodyFont));
                                auditReportTable.AddCell(new Paragraph(dr[ds.DBAudit.DisplayNameColumn.ColumnName].ToString(), bodyFont));
                                //Start 25-05-2016 Edit By Humaira Yousaf Bug# EMR-1207
                                string originalvalue = dr[ds.DBAudit.OriginalValueColumn.ColumnName].ToString();
                                string originalValueNew = removeHTMLTags(originalvalue);

                                string currentValue = dr[ds.DBAudit.CurrentValueColumn.ColumnName].ToString();
                                string currentValueNew = removeHTMLTags(currentValue);

                                auditReportTable.AddCell(new Paragraph(originalValueNew, bodyFont));
                                auditReportTable.AddCell(new Paragraph(currentValueNew, bodyFont));
                                //End 25-05-2016 Edit By Humaira Yousaf Bug# EMR-1207
                                auditReportTable.AddCell(string.Empty);
                            }
                            //End 27-05-2016 Humaira Yousaf to exclude note text
                        }
                        pdfDocument.Add(auditReportTable);
                    }
                    else
                    {

                        PdfPTable auditReportTable = new PdfPTable(10);
                        float[] widths = new float[] { 1f, 4f, 4f, 4f, 3f, 3f, 5f, 5f, 5f, 1f };
                        auditReportTable.SetWidths(widths);
                        auditReportTable.TotalWidth = 570f;
                        auditReportTable.LockedWidth = true;
                        auditReportTable.DefaultCell.Border = Rectangle.NO_BORDER;
                        auditReportTable.AddCell(string.Empty);
                        auditReportTable.AddCell(new Paragraph("Date", componentHeaderFont));
                        auditReportTable.AddCell(new Paragraph("PatientName", componentHeaderFont));
                        auditReportTable.AddCell(new Paragraph("UserName", componentHeaderFont));
                        auditReportTable.AddCell(new Paragraph("Module", componentHeaderFont));
                        auditReportTable.AddCell(new Paragraph("Action", componentHeaderFont));
                        auditReportTable.AddCell(new Paragraph("Field", componentHeaderFont));
                        auditReportTable.AddCell(new Paragraph("Original Value", componentHeaderFont));
                        auditReportTable.AddCell(new Paragraph("Current Value", componentHeaderFont));
                        auditReportTable.AddCell(string.Empty);
                        pdfDocument.Add(auditReportTable);
                        Paragraph noProblemList = new Paragraph("No Audit Report Found".ToString());
                        noProblemList.Alignment = Element.ALIGN_CENTER;
                        pdfDocument.Add(noProblemList);
                    }

                    #endregion
                    pdf.Document.Close();
                    pdf.Writer.Close();

                    newByteArr = stream_.GetBuffer();
                }

                return new BLObject<byte[]>(newByteArr);
            }
            catch (Exception ex)
            {
                MDVLogger.BLLErrorLog("BLLClinical::previewFaceSheet", ex);
                return new BLObject<byte[]>(null, ex.Message);
            }
        }

        public static string removeHTMLTags(string source)
        {
            string noHTML = Regex.Replace(source, @"<[^>]+>|&nbsp;", "").Trim();
            string noHTMLNormalised = Regex.Replace(noHTML, @"\s{2,}", " ");

            return noHTMLNormalised;
        }

