        #region Billing Information

        public BLObject<DSProblemLists> LoadProblemAndProcedureList(long NoteId, long PatientId = 0)
        {
            DSProblemLists ds = new DSProblemLists();
            DSBillingInformation dsDSBillingInformation = new DSBillingInformation();
            try
            {
                ds = new DALProblemLists().LoadProblemLists(0, PatientId, NoteId, "0", "1", 1, 1000, "", "", "1", "1");
                DSProblemLists dstwo = new DSProblemLists();
                DSProblemLists dsTreatmentProblems = new DSProblemLists();
                DSProblemLists dsTreatmentLabOrderProblems = new DSProblemLists();
                DSProcedures dsTreatmentProc = new DSProcedures();
                DSProcedures dsTreatmentLabProc = new DSProcedures();
                DSProcedures dstemp = new DSProcedures();
                if (NoteId > 0)
                {
                    dsTreatmentProblems = new DALProblemLists().LoadTreatmentProblems(NoteId);
                    dsTreatmentLabOrderProblems = new DALProblemLists().LoadTreatmentProblemListsInLabOrder(NoteId);
                    dstwo = new DALProblemLists().LoadProblemListsInLabOrder(NoteId);
                }

                ds.ProblemList.Merge(dstwo.ProblemList);
                ds.ProblemList.Merge(dsTreatmentProblems.ProblemList);
                ds.ProblemList.Merge(dsTreatmentLabOrderProblems.ProblemList);

                DSProcedures dsProcedure = new DALProcedures().loadProcedures_Obsolete(0, PatientId, NoteId, "0", "", 1, 1000, "", "", "", "1", "1", "1");
                if (NoteId > 0)
                {
                    dstemp = new DALProcedures().loadLabBasedProcedures(NoteId);
                    dsTreatmentProc = new DALProcedures().loadTreatmentProcedures(NoteId);
                    dsTreatmentLabProc = new DALProcedures().loadLabBasedTreatmentProcedures(NoteId);
                }
                dsProcedure.Procedures.Merge(dsTreatmentProc.Procedures);
                dstemp.Procedures.Merge(dsTreatmentLabProc.Procedures);
                try
                {
                    BLObject<DSBillingInformation> obj = BillingInfo_SELECT(MDVUtility.ToInt64(NoteId), PatientId, 0);
                    if (obj.Data != null)
                    {
                        dsDSBillingInformation = obj.Data;
                        long BillingInfoId = MDVUtility.ToInt64(dsDSBillingInformation.Tables[dsDSBillingInformation.BillingInfo.TableName].Rows[0][dsDSBillingInformation.BillingInfo.BillingInfoIdColumn.ColumnName]);
                        if (BillingInfoId > 0)
                        {
                            obj = BillingInfoCPT_SELECT(MDVUtility.ToInt64(BillingInfoId));
                            if (obj.Data != null)
                            {
                                dsDSBillingInformation = obj.Data;
                                foreach (DataRow row in dstemp.Tables[dstemp.Procedures.TableName].Rows)
                                {
                                    var cptcode = MDVUtility.ToStr(row[dstemp.Tables[dstemp.Procedures.TableName].Columns[dstemp.Procedures.CPTCodeColumn.ColumnName].ColumnName]);
                                    var cptdesc = MDVUtility.ToStr(row[dstemp.Tables[dstemp.Procedures.TableName].Columns[dstemp.Procedures.CPT_DESCRIPTIONColumn.ColumnName].ColumnName]);

                                    DSBillingInformation.BillingInfoCPTRow cptBillRows = (DSBillingInformation.BillingInfoCPTRow)dsDSBillingInformation.BillingInfoCPT.Select(dsDSBillingInformation.BillingInfoCPT.BillingInfoIdColumn + "=" + BillingInfoId + " AND " + dsDSBillingInformation.BillingInfoCPT.CPTCodeColumn + "='" + cptcode + "' AND " + dsDSBillingInformation.BillingInfoCPT.CPTCodeDescriptionColumn + "='" + cptdesc + "'").FirstOrDefault();
                                    if (cptBillRows != null)
                                    {
                                        row[dstemp.Tables[dstemp.Procedures.TableName].Columns[dstemp.Procedures.Modifier1Column.ColumnName].ColumnName] = cptBillRows.Modifier1;
                                        row[dstemp.Tables[dstemp.Procedures.TableName].Columns[dstemp.Procedures.Modifier2Column.ColumnName].ColumnName] = cptBillRows.Modifier2;
                                        row[dstemp.Tables[dstemp.Procedures.TableName].Columns[dstemp.Procedures.Modifier3Column.ColumnName].ColumnName] = cptBillRows.Modifier3;
                                        row[dstemp.Tables[dstemp.Procedures.TableName].Columns[dstemp.Procedures.Modifier4Column.ColumnName].ColumnName] = cptBillRows.Modifier4;

                                        row[dstemp.Tables[dstemp.Procedures.TableName].Columns[dstemp.Procedures.ICDPointer1Column.ColumnName].ColumnName] = cptBillRows.ICDPointer1;
                                        row[dstemp.Tables[dstemp.Procedures.TableName].Columns[dstemp.Procedures.ICDPointer2Column.ColumnName].ColumnName] = cptBillRows.ICDPointer2;
                                        row[dstemp.Tables[dstemp.Procedures.TableName].Columns[dstemp.Procedures.ICDPointer3Column.ColumnName].ColumnName] = cptBillRows.ICDPointer3;
                                        row[dstemp.Tables[dstemp.Procedures.TableName].Columns[dstemp.Procedures.ICDPointer4Column.ColumnName].ColumnName] = cptBillRows.ICDPointer4;

                                        row[dstemp.Tables[dstemp.Procedures.TableName].Columns[dstemp.Procedures.UnitColumn.ColumnName].ColumnName] = cptBillRows.Units;
                                    }
                                }
                            }
