        public BLObject<DSProblemLists> LoadProblemAndProcedureListForSign(long NoteId, long PatientId = 0, long BillingInfoId = 0)
        {
            DSProblemLists ds = new DSProblemLists();
            try
            {
                ds = new DALProblemLists().LoadProblemLists(0, PatientId, NoteId, "0", "1");

                DSProcedures dsProcedure = new DALProcedures().loadProceduresForSign(0, PatientId, NoteId, BillingInfoId);
                DSProcedures dstemp = new DALProcedures().loadLabBasedProcedures(NoteId);

                DataView view = dsProcedure.Procedures.DefaultView;
                view.Sort = "ProcedureId ASC";
                DataTable dt = view.ToTable();

                DSProcedures newDsProcedure = new DSProcedures();
                newDsProcedure.Procedures.Merge(dt);
                newDsProcedure.Procedures.Merge(dstemp.Procedures);

                ds.Merge(newDsProcedure);
                return new BLObject<DSProblemLists>(ds);
            }
            catch (Exception ex)
            {
                MDVLogger.BLLErrorLog("BLLClinical::LoadProblemAndProcedureList", ex);
                return new BLObject<DSProblemLists>(null, ex.Message);
            }
        }


