        public BLObject<BLLBillingInformationModel> BillingInformationSave(DSBillingInformation ds, BillingInformationModel model, bool isDrFirstRequired)
        {
            long BillingInfoId = 0;
            BLLBillingInformationModel infomodel = new BLLBillingInformationModel();
            IDBManager dbManager = ClientConfiguration.GetDBManager();
            try
            {
                //Step 1
                dbManager.BeginTransaction();

                DSBillingInformation objBillingInfo = new DALBillingInformation().BillingInfo_Save(dbManager, ds, model.PatientId);
                if (objBillingInfo != null)
                {
                    ds = objBillingInfo;
                    BillingInfoId = MDVUtility.ToInt64(ds.Tables[ds.BillingInfo.TableName].Rows[0][ds.BillingInfo.BillingInfoIdColumn.ColumnName]);
                    if (BillingInfoId > 0)
                    {
                        if (model.Status != "Signed")
                        {
                            DSProblemLists dsProblemList = BillingInfoCPT_Save(dbManager, model, BillingInfoId);
                            if (dsProblemList != null)
                            {
                                DSProcedures dsProcedure = new DSProcedures();
                                infomodel.CPTS_JSON = MDVUtility.JSON_DataTable(dsProblemList.Tables[dsProcedure.Procedures.TableName]);
                            }
                        }

                        if (model.Status != "Signed")
                        {
                            BillingInfoICD_Save(dbManager, model, BillingInfoId, isDrFirstRequired);
                        }
                    }

                    infomodel.BillingInfoId = BillingInfoId;

                    //Step 2
                    if (dbManager.Connection != null)
                        dbManager.CommitTransaction();

                    return new BLObject<BLLBillingInformationModel>(infomodel);
                }
                else
                {
                    throw new Exception("Unable to Save Record.");
                }

            }
            catch (Exception ex)
            {
                //Step 3
                dbManager.RollBackTransaction();
                string message = ex.Message.Contains("duplicate") ? "CDS Title already exists" : ex.Message.Contains("VisitId") ? "Unable to Save Record." : ex.Message;
                string[] temp = message.Split('\r');
                if (temp.Length >= 0)
                    message = temp[0];

                throw new Exception(message);
            }
            finally
            {
                dbManager.Dispose();
            }
        }
        private DSProblemLists BillingInfoCPT_Save(IDBManager dbManager, BillingInformationModel model, long BillingInfoId)
        {
            try
            {
                DSBillingInformation dsDSBillingInformation = new DALBillingInformation().BillingInfoCPT_SELECT(BillingInfoId);
                DALProcedures DALProcedures = new DALProcedures();
