        private bool BillingInfoICD_Save(IDBManager dbManager, BillingInformationModel model, long BillingInfoId, bool isDrFirstRequired)
        {
            bool isSuccess = false;
            try
            {
                DSBillingInformation dsDSBillingInformation = new DSBillingInformation();
                BLObject<DSBillingInformation> obj = BillingInfoICD_SELECT(MDVUtility.ToInt64(BillingInfoId));
                DALProblemLists DALProblemLists = new DALProblemLists();

                if (obj.Data != null)
                {
                    dsDSBillingInformation = obj.Data;
                    //DSBillingInformation.BillingInfoICDRow cdsRow = null;
                    DSBillingInformation.BillingInfoICDRow[] cdsRows = (DSBillingInformation.BillingInfoICDRow[])dsDSBillingInformation.BillingInfoICD.Select(dsDSBillingInformation.BillingInfoICD.BillingInfoIdColumn + "=" + BillingInfoId);
                    DSProblemLists dsProblemLists = new DSProblemLists();
                    BLObject<DSProblemLists> objProblemList = null;

                    if (model.ShowCustomFormData)
                    {
                        objProblemList = LoadProblemLists(0, MDVUtility.ToInt64(model.PatientId), model.NotesId, "0", "1", 1, 1000, "", "", "1");
                    }
                    else
                    {
                        objProblemList = LoadProblemLists(0, MDVUtility.ToInt64(model.PatientId), model.NotesId, "0", "1");
                    }

                    if (objProblemList.Data != null)
                    {
                        dsProblemLists = objProblemList.Data;
                    }
                    if (model.NotesId > 0)
                    {
                        DSProblemLists dsTreatmentProblems = new DALProblemLists().LoadTreatmentProblems(model.NotesId);
                        foreach (var a in dsTreatmentProblems.ProblemList)
                        {
                            var abc = dsProblemLists.ProblemList.AsEnumerable().FirstOrDefault(x => x.ProblemListId == a.ProblemListId);
                            if (abc == null)
                            {
                                dsProblemLists.ProblemList.ImportRow(a);
                            }
                        }
                        DSProblemLists dsTreatmentLabOrderProblems = new DALProblemLists().LoadTreatmentProblemListsInLabOrder(model.NotesId);
                        foreach (var a in dsTreatmentLabOrderProblems.ProblemList)
                        {
                            var abc = dsProblemLists.ProblemList.AsEnumerable().FirstOrDefault(x => x.ProblemListId == a.ProblemListId);
                            if (abc == null)
                            {
                                dsProblemLists.ProblemList.ImportRow(a);
                            }
                        }
                    }

