                                DataRow[] drRows = dsProblemLists.Tables[dsProblemLists.ProblemList.TableName].Select(string.Concat(dsProblemLists.ProblemList.ICD10Column, "=", MDVUtility.ToLINQFormatString(result.FirstOrDefault().ICDCode10), " AND ", dsProblemLists.ProblemList.SNOMEDIDColumn, "=", MDVUtility.ToLINQFormatString(result.FirstOrDefault().SNOMEDCode)));

                                if (drRows.Count() > 0)
                                {
                                    if (model.NotesId > 0 && MDVUtility.ToInt64(drRows[0][dsProblemLists.ProblemList.ProblemListIdColumn.ColumnName]) > 0)
                                    {
                                        //if (!ProblemsList.Contains(MDVUtility.ToStr(drRows[0][dsProblemLists.ProblemList.ProblemListIdColumn.ColumnName])))
                                        //    ProblemsList.Add(MDVUtility.ToStr(drRows[0][dsProblemLists.ProblemList.ProblemListIdColumn.ColumnName]));

