                    {
                        bool isEdit = true;
                        DSBillingInformation.BillingInfoICDRow cdsRow = null;

                        ProblemListModel objProblemListModel = new ProblemListModel();
                        objProblemListModel.PatientId = model.PatientId;
                        objProblemListModel.ICD9 = item.ICDCode9;
                        objProblemListModel.ICD10 = item.ICDCode10;
                        objProblemListModel.ICD9_Description = item.ICDDescription9;
                        objProblemListModel.ICD10_Description = item.ICDDescription10;
                        objProblemListModel.SNOMEDID = item.SNOMEDCode;
                        objProblemListModel.SNOMED_DESCRIPTION = item.SNOMEDDescription;
                        if (!string.IsNullOrEmpty(item.ICDDescription10))
                        {
                            objProblemListModel.ProblemName = item.ICDDescription10;
                        }
                        else if (!string.IsNullOrEmpty(item.ICDDescription9))
                        {
                            objProblemListModel.ProblemName = item.ICDDescription9;
                        }
                        else if (!string.IsNullOrEmpty(item.SNOMEDDescription))
                        {
                            objProblemListModel.ProblemName = item.SNOMEDDescription;
                        }
                        objProblemListModel.Description = string.Concat(MDVUtility.ToStr(item.ICDCode9), " - ", MDVUtility.ToStr(item.ICDCode10), " - ", MDVUtility.ToStr(item.ICDDescription10));

                        if (cdsRows.Length > 0 && MDVUtility.ToInt64(BillingInfoId) > 0 && (!string.IsNullOrEmpty(item.ICDCode10) || !string.IsNullOrEmpty(item.ICDCode9)))
                        {
                            var BillingId = MDVUtility.ToInt64(BillingInfoId);
                            if (!string.IsNullOrEmpty(item.ICDCode10))
                                cdsRow = cdsRows.Where(p => p.BillingInfoId == BillingId && p.ICDCode == item.ICDCode10).FirstOrDefault();
                            else
                                cdsRow = cdsRows.Where(p => p.BillingInfoId == BillingId && p.ICDCode == item.ICDCode9).FirstOrDefault();
                        }
                        if (cdsRow == null)
                        {
                            isEdit = false;
                            cdsRow = dsDSBillingInformation.BillingInfoICD.NewBillingInfoICDRow();
                        }
                        if (cdsRow != null)
                        {
                            if (!isEdit)
                                cdsRow.BillingInfoICDId = BillingInfoICDId_Nagitive--;


                            cdsRow.BillingInfoId = MDVUtility.ToInt64(BillingInfoId);

                            if (!string.IsNullOrEmpty(item.ICDCode10) && !string.IsNullOrEmpty(item.ICDDescription10))
                            {
                                cdsRow.ICDType = 10;
                                cdsRow.ICDCode = item.ICDCode10;
                                cdsRow.ICDCodeDescription = item.ICDDescription10;
                                try
                                {
                                    var output = dsDSBillingInformation.BillingInfoICD.Where(p => p.ICDCode == item.ICDCode10);
                                    if (output.ToList().Count > 0)
                                        continue;

                                }
                                catch (Exception ex) { }

                            }
                            else if (!string.IsNullOrEmpty(item.ICDCode9) && !string.IsNullOrEmpty(item.ICDDescription9))
                            {
                                cdsRow.ICDType = 9;
                                cdsRow.ICDCode = item.ICDCode9;
                                cdsRow.ICDCodeDescription = item.ICDDescription9;

                                try
                                {
                                    var output = dsDSBillingInformation.BillingInfoICD.Where(p => p.ICDCode == item.ICDCode9);
                                    if (output.ToList().Count > 0)
                                        continue;

                                }
                                catch (Exception ex) { }

                            }
                            else
                            {
                                continue;
                            }

                            cdsRow.SNOMEDID = item.SNOMEDCode;
                            cdsRow.SNOMEDDescription = item.SNOMEDDescription;


                            if (!isEdit)
                            {
                                dsDSBillingInformation.BillingInfoICD.AddBillingInfoICDRow(cdsRow);

                                try
                                {
                                    DataRow[] drRows = dsProblemLists.Tables[dsProblemLists.ProblemList.TableName].Select(string.Concat(dsProblemLists.ProblemList.ICD10Column, "=", MDVUtility.ToLINQFormatString(objProblemListModel.ICD10)));

                                    if (drRows.Count() == 0)
                                    {
                                        objProblemListModel.ProblemOrder = "0";
                                        var problemResponse = SaveProblemList(dbManager, objProblemListModel, isDrFirstRequired);
                                        var problemObject = (Newtonsoft.Json.Linq.JObject)Newtonsoft.Json.JsonConvert.DeserializeObject(problemResponse);
                                        if (!problemResponse.Contains("Problem already exists"))
                                        {
                                            if (model.NotesId > 0 && MDVUtility.ToInt64(problemObject["ProblemListId"]) > 0)
                                            {
                                                //if (!AttatchedProblems.Contains(MDVUtility.ToStr(problemObject["ProblemListId"])))
                                                //    AttatchedProblems.Add(MDVUtility.ToStr(problemObject["ProblemListId"]));

                                                DALProblemLists.attachProblemListWithNotes(dbManager, MDVUtility.ToStr(problemObject["ProblemListId"]), model.NotesId);
                                            }
                                        }
                                    }
                                    else if (drRows.Count() > 0)
                                    {
                                        /* Start 11-04-2017 Humaira Yousaf Bug# EMR-3484
                                         The dataset dsProblemLists has information of all problems attached to any note of selected patient.
                                         Previous code was attaching first problem with note irrespective of whether it was associated with current note or not 
                                         and resulting in attaching a problem with current note which user has not attached. Upon deleting problems from note, those problems were not deleting and were showing up in eSuperbill.
                                         Modified code to filter that problem among all notes which is attached to current note. */
                                        DataRow drProblems = drRows.Where(row => MDVUtility.ToStr(row["NoteId"]).Split(',').Contains(MDVUtility.ToStr(model.NotesId))).FirstOrDefault();
                                        if (drProblems != null)
                                        {
                                            if (model.NotesId > 0 && MDVUtility.ToInt64(drProblems[dsProblemLists.ProblemList.ProblemListIdColumn.ColumnName]) > 0)
                                            {
                                                //if (!DeattatchAttatchProblems.Contains(MDVUtility.ToStr(drProblems[dsProblemLists.ProblemList.ProblemListIdColumn.ColumnName])))
                                                //    DeattatchAttatchProblems.Add(MDVUtility.ToStr(drProblems[dsProblemLists.ProblemList.ProblemListIdColumn.ColumnName]));

                                                DALProblemLists.detachProblemListsFromNotes(dbManager, MDVUtility.ToStr(drProblems[dsProblemLists.ProblemList.ProblemListIdColumn.ColumnName]), model.NotesId);
                                                DALProblemLists.attachProblemListWithNotes(dbManager, MDVUtility.ToStr(drProblems[dsProblemLists.ProblemList.ProblemListIdColumn.ColumnName]), model.NotesId);
                                            }
                                        }
                                        else
                                        {
                                            objProblemListModel.ProblemOrder = "0";
                                            var problemResponse = SaveProblemList(dbManager, objProblemListModel, isDrFirstRequired);
                                            var problemObject = (Newtonsoft.Json.Linq.JObject)Newtonsoft.Json.JsonConvert.DeserializeObject(problemResponse);
                                            if (!problemResponse.Contains("Problem already exists"))
                                            {
                                                if (model.NotesId > 0 && MDVUtility.ToInt64(problemObject["ProblemListId"]) > 0)
                                                {
                                                    //if (!AttatchedProblems.Contains(MDVUtility.ToStr(problemObject["ProblemListId"])))
                                                    //    AttatchedProblems.Add(MDVUtility.ToStr(problemObject["ProblemListId"]));

                                                    DALProblemLists.attachProblemListWithNotes(dbManager, MDVUtility.ToStr(problemObject["ProblemListId"]), model.NotesId);
                                                }
                                            }
                                        }

                                        // End 11-04-2017 Humaira Yousaf Bug# EMR-3484
                                    }

                                }
                                catch (Exception innerEx) { }
                            }
                        }
                    }

                    // detach and attach problem
                    //string ProbIDs = string.Join(",", DeattatchAttatchProblems.Select(n => n.ToString()).ToArray());
                    //if (!string.IsNullOrEmpty(ProbIDs) && model.NotesId > 0)
                    //{
                    //    detachProblemListFromNotes(ProbIDs, model.NotesId);
                    //    attachProblemListWithNotes(ProbIDs, model.NotesId);
                    //}

                    ////attach problem
                    //string AttatchProbIDs = string.Join(",", AttatchedProblems.Select(n => n.ToString()).ToArray());
                    //if (!string.IsNullOrEmpty(AttatchProbIDs) && model.NotesId > 0)
                    //{
                    //    attachProblemListWithNotes(AttatchProbIDs, model.NotesId);
                    //}

                    #region Database Insertion/Updation

                    BLObject<DSBillingInformation> objCDS = BillingInfoICD_Save(dbManager, dsDSBillingInformation, model.PatientId);
                    dsDSBillingInformation = objCDS.Data;

                    if (objCDS.Data != null)
                    {
                        isSuccess = true;
                    }
                    else
                    {
                        throw new Exception(objCDS.Message);
                    }

                    #endregion

                    return isSuccess;
                }
                else
                {
                    throw new Exception(obj.Message);
                }
            }
            catch (Exception ex)
            {
                throw ex;
            }
        }

