        public BLObject<DSClinicalLab> LoadLabTestAndAttributes(long LabTestId, long LabId, string LOINC, string LOINCDescription)
        {
            try
            {
                DSClinicalLab ds = new DSClinicalLab();
                ds = new DALClinicalLab().LoadLabTest(LabTestId, LabId, LOINC,"1", LOINCDescription);
                if (ds.Tables[ds.LabTest.TableName].Rows.Count > 0)
                {
                    Int64 labTestId = MDVUtility.ToInt64(ds.Tables[ds.LabTest.TableName].Rows[0][ds.LabTest.LabTestIdColumn.ColumnName]);
                    if (labTestId > 0)
                    {
                        DSClinicalLab dsClinicalLab = new DALClinicalLab().LoadLabTestAttribute(0, labTestId);
                        ds.Merge(dsClinicalLab);
                    }
                }
                return new BLObject<DSClinicalLab>(ds);
            }
            catch (Exception ex)
            {
                MDVLogger.BLLErrorLog("BLLClinical::LoadLabTest", ex);
                return new BLObject<DSClinicalLab>(null, ex.Message);
            }
        }

