        public bool updateClinicalNotesForAmendment(DSNotes dsNotes, List<NoteComponentModel> CompModelList, string CompXML)
        {
            IDBManager dbManager = ClientConfiguration.GetDBManager();
            try
            {
                dbManager.BeginTransaction();

                BLObject<DSNotes> obj = updateClinical_Notes(dsNotes, dbManager);
                if (obj.Data != null)
                {
                    if (CompModelList.Count > 0 && !string.IsNullOrEmpty(CompXML))
                    {
                        var response_ = insertNoteComponentsBulk(CompXML, dbManager);
                    }
                    dbManager.CommitTransaction();
                    return true;
                }
                else
                {
                    dbManager.RollBackTransaction();
                    return false;
                }
            }
            catch (Exception ex)
            {
                dbManager.RollBackTransaction();
                MDVLogger.BLLErrorLog("BLLClinical::updateClinicalNotesForAmendment", ex);
                return false;
            }
            finally
            {
                dbManager.Dispose();
            }
        }
