        public BLObject<string> SaveOrthopedicComplaints(string Complaint)
        {
            try
            {
                OrthopedicComplaintsModel model = new OrthopedicComplaintsModel();
                model.UserId = MDVUtility.ToLong(MDVSession.Current.AppUserId);
                model.Complaint = Complaint;
                model.IsActive = true;
                return new BLObject<string>(new DALLOrthopedic().SaveOrthopedicComplaints(model));
            }
            catch (Exception ex)
            {
                MDVLogger.BLLErrorLog("BLLClinical::SaveOrthopedicComplaints", ex);
                return new BLObject<string>(null, ex.Message);
            }


        }

